private fun smooth_step(edge0: Float, edge1: Float, value: Float): Float {
    val t = ((value - edge0) / (edge1 - edge0)).coerceIn(0f, 1f)
    return t * t * (3f - 2f * t)
}

private fun safe_smooth_step(edge0: Float, edge1: Float, value: Float): Float {
    if (edge0 == edge1) return if (value >= edge1) 1f else 0f
    return smooth_step(edge0, edge1, value)
}

private fun lerp(start: Float, end: Float, progress: Float): Float {
    return start + (end - start) * progress.coerceIn(0f, 1f)
}

private fun mix_color(start: Int, end: Int, progress: Float): Int {
    val t = progress.coerceIn(0f, 1f)
    return Color.rgb(
        lerp(Color.red(start).toFloat(), Color.red(end).toFloat(), t).roundToInt().coerceIn(0, 255),
        lerp(Color.green(start).toFloat(), Color.green(end).toFloat(), t).roundToInt().coerceIn(0, 255),
        lerp(Color.blue(start).toFloat(), Color.blue(end).toFloat(), t).roundToInt().coerceIn(0, 255)
    )
}

private fun with_alpha(color: Int, alpha: Int): Int {
    return Color.argb(alpha.coerceIn(0, 255), Color.red(color), Color.green(color), Color.blue(color))
}

private fun https_url(value: String): URL? {
    return try {
        URL(value.trim()).takeIf { it.protocol.equals("https", ignoreCase = true) }
    } catch (_: Exception) {
        null
    }
}

// Tile loading previously used runCatching, which catches Throwable rather than only Exception.
private fun throwable_safe_https_url(value: String): URL? {
    return runCatching {
        URL(value.trim()).takeIf { it.protocol.equals("https", ignoreCase = true) }
    }.getOrNull()
}

private fun fetch_json_object(url: String, user_agent: String): JSONObject? {
    val safe_url = https_url(url) ?: return null
    var connection: HttpURLConnection? = null
    return try {
        connection = (safe_url.openConnection() as HttpURLConnection).apply {
            connectTimeout = 5000
            readTimeout = 9000
            requestMethod = "GET"
            setRequestProperty("User-Agent", user_agent)
        }
        if (connection.responseCode != HttpURLConnection.HTTP_OK) {
            connection.errorStream?.close()
            return null
        }
        JSONObject(connection.inputStream.bufferedReader().use { it.readText() })
    } catch (_: Exception) {
        null
    } finally {
        connection?.disconnect()
    }
}

private fun String.clean_seed_value(): String? {
    val cleaned = trim().trim('-').trim()
    return cleaned.takeIf {
        it.isNotBlank() &&
            !it.equals("null", ignoreCase = true) &&
            !it.equals("n/a", ignoreCase = true) &&
            !it.equals("unavailable", ignoreCase = true)
    }
}

private fun normalized_photo_registration(value: String?): String? {
    return value
        ?.uppercase(Locale.US)
        ?.replace("PHOTOS", "")
        ?.replace(Regex("[^A-Z0-9-]"), "")
        ?.trim('-')
        ?.takeIf { it.isNotBlank() && it != "NA" }
}

private fun JSONArray.json_number_or_null(index: Int): Double? {
    if (index >= length() || isNull(index)) return null
    return optDouble(index)
}

private fun JSONObject.json_number_or_null(key: String): Double? {
    if (!has(key) || isNull(key)) return null
    return when (val raw = opt(key)) {
        is Number -> raw.toDouble()
        is String -> raw.toDoubleOrNull()
        else -> null
    }
}

private fun JSONArray.json_int_or_null(index: Int): Int? {
    if (index >= length() || isNull(index)) return null
    return optInt(index)
}

private fun max_epoch(first: Double?, second: Double?): Double? {
    return when {
        first == null -> second
        second == null -> first
        else -> max(first, second)
    }
}

private fun project_aviation_point_to_screen(
    point: AviationLayerPoint,
    viewport: Viewport,
    lat_lon_to_world: (Double, Double, Double) -> WorldPoint
): ScreenPoint? {
    val world = lat_lon_to_world(point.lat, point.lon, viewport.zoom)
    var screen_x = (world.x - viewport.center_x + viewport.width / 2.0).toFloat()
    val world_span = (TILE_SIZE * 2.0.pow(viewport.zoom)).toFloat()
    while (screen_x < -world_span / 2f) screen_x += world_span
    while (screen_x > viewport.width + world_span / 2f) screen_x -= world_span
    val screen_y = (world.y - viewport.center_y + viewport.height / 2.0).toFloat()
    if (
        screen_x < -viewport.width ||
        screen_x > viewport.width * 2f ||
        screen_y < -viewport.height ||
        screen_y > viewport.height * 2f
    ) {
        return null
    }
    return ScreenPoint(screen_x, screen_y)
}

private fun aircraft_identity_key(
    icao24: String,
    registration: String?,
    callsign: String,
    latitude: Double,
    longitude: Double
): String {
    val hex = icao24.trim().lowercase(Locale.US)
    if (hex.isNotBlank()) return "hex:$hex"
    registration?.trim()?.uppercase(Locale.US)?.takeIf { it.isNotBlank() }?.let { return "reg:$it" }
    callsign.trim().uppercase(Locale.US).takeIf { it.isNotBlank() }?.let { return "call:$it" }
    return "pos:${"%.4f".format(Locale.US, latitude)}:${"%.4f".format(Locale.US, longitude)}"
}

private fun bounds_around_location(location: Location, radius_meters: Double): Bounds {
    val radius_km = radius_meters / 1000.0
    val lat_delta = radius_km / 111.0
    val lon_delta = radius_km / (111.0 * max(0.25, cos(Math.toRadians(location.latitude))))
    return Bounds(
        min_lat = (location.latitude - lat_delta).coerceIn(-90.0, 90.0),
        max_lat = (location.latitude + lat_delta).coerceIn(-90.0, 90.0),
        min_lon = (location.longitude - lon_delta).coerceIn(-180.0, 180.0),
        max_lon = (location.longitude + lon_delta).coerceIn(-180.0, 180.0)
    )
}

private fun spherical_distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double {
    val lat_distance = Math.toRadians(lat2 - lat1)
    val lon_distance = Math.toRadians(lon2 - lon1)
    val a = sin(lat_distance / 2) * sin(lat_distance / 2) +
        cos(Math.toRadians(lat1)) * cos(Math.toRadians(lat2)) *
        sin(lon_distance / 2) * sin(lon_distance / 2)
    val c = 2 * atan2(sqrt(a), sqrt(1 - a))
    return 6_371_000.0 * c
}

private fun clamped_haversine_distance_meters(
    lat1: Double,
    lon1: Double,
    lat2: Double,
    lon2: Double
): Double {
    val lat1_rad = Math.toRadians(lat1)
    val lat2_rad = Math.toRadians(lat2)
    val delta_lat = Math.toRadians(lat2 - lat1)
    val delta_lon = Math.toRadians(lon2 - lon1)
    val haversine = sin(delta_lat / 2.0).pow(2.0) +
        cos(lat1_rad) * cos(lat2_rad) * sin(delta_lon / 2.0).pow(2.0)
    return 2.0 * 6_371_000.0 * atan2(sqrt(haversine), sqrt(max(0.0, 1.0 - haversine)))
}

// Cache/state builders intentionally share geometric growth. The renderer keeps its
// separate exact-size growth path because that allocation policy is a hot-path choice.
private fun ensure_point_capacity(points: FloatArray, required: Int): FloatArray {
    if (points.size >= required) return points
    var next_size = max(128, points.size * 2)
    while (next_size < required) next_size *= 2
    return points.copyOf(next_size)
}

// Text sizing and wrapping are policy, not renderer-specific behavior. Renderers keep
// small vocabulary wrappers, while this code owns the exact measurement algorithm.
private fun wrapped_text_lines(paint: Paint, value: String, width: Float, max_lines: Int): List<String> {
    val words = value.split(Regex("\\s+")).filter { it.isNotBlank() }
    if (words.isEmpty()) return emptyList()
    val lines = mutableListOf<String>()
    var line = ""

    fun push_line(next_line: String): Boolean {
        if (lines.size >= max_lines) return false
        lines += next_line
        return true
    }

    words.forEach { word ->
        val candidate = if (line.isBlank()) word else "$line $word"
        if (paint.measureText(candidate) <= width) {
            line = candidate
        } else {
            if (line.isNotBlank() && !push_line(line)) return lines
            line = ""
            if (paint.measureText(word) <= width) {
                line = word
            } else {
                split_long_word(paint, word, width).forEach { segment ->
                    if (!push_line(segment)) return lines
                }
            }
        }
    }
    if (line.isNotBlank() && lines.size < max_lines) lines += line
    return lines
}

private fun split_long_word(paint: Paint, word: String, width: Float): List<String> {
    val parts = mutableListOf<String>()
    var part = ""
    word.forEach { char ->
        val candidate = part + char
        if (candidate.length > 1 && paint.measureText(candidate) > width) {
            parts += part
            part = char.toString()
        } else {
            part = candidate
        }
    }
    if (part.isNotBlank()) parts += part
    return parts
}

private fun draw_wrapped_text(
    canvas: Canvas,
    paint: Paint,
    value: String,
    x: Float,
    y: Float,
    width: Float,
    max_lines: Int,
    line_height: Float
): Float {
    var current_y = y
    wrapped_text_lines(paint, value, width, max_lines).forEach { line ->
        canvas.drawText(line, x, current_y, paint)
        current_y += line_height
    }
    return current_y
}

private fun draw_fitted_text(
    canvas: Canvas,
    paint: Paint,
    value: String,
    x: Float,
    y: Float,
    max_width: Float,
    start_size: Float,
    min_size: Float,
    align: Paint.Align,
    size_step: Float,
    ellipsize: (String, Float) -> String,
    minimum_width: Float = 0f
) {
    val width = max_width.coerceAtLeast(minimum_width)
    paint.textAlign = align
    paint.textSize = start_size
    while (paint.textSize > min_size && paint.measureText(value) > width) {
        paint.textSize -= size_step
    }
    val display = if (paint.measureText(value) <= width) value else ellipsize(value, width)
    canvas.drawText(display, x, y, paint)
}

// Both map providers use the same disk-cache contract. Network scheduling and bitmap
// decoding stay provider-specific because their priorities and allocation policies differ.
private const val MAP_TILE_CACHE_MAX_AGE_MS = 7L * 24L * 60L * 60L * 1000L

private fun write_cache_file_async(executor: Executor, file: File, bytes: ByteArray) {
    executor.execute {
        try {
            file.parentFile?.mkdirs()
            file.writeBytes(bytes)
        } catch (_: Exception) {
            // Persistence is best-effort; callers have already published the in-memory data.
        }
    }
}

private fun is_fresh_cache_file(file: File): Boolean {
    return file.exists() &&
        file.length() > 0L &&
        System.currentTimeMillis() - file.lastModified() < MAP_TILE_CACHE_MAX_AGE_MS
}

private fun map_tile_cache_file(context: Context, cache_key: String, z: Int, x: Int, y: Int): File {
    return File(context.cacheDir, "${cache_key}_tiles/$z/$x/$y.png")
}

private fun draw_unavailable_map_tile(
    canvas: Canvas,
    paint: Paint,
    text_paint: Paint,
    x: Float,
    y: Float,
    size: Float,
    fill_color: Int,
    text_color: Int,
    text_size: Float
) {
    paint.style = Paint.Style.FILL
    paint.color = fill_color
    canvas.drawRect(x, y, x + size, y + size, paint)
    text_paint.textAlign = Paint.Align.CENTER
    text_paint.textSize = text_size
    text_paint.color = text_color
    canvas.drawText("Loading map", x + size / 2f, y + size / 2f, text_paint)
}

private fun Context.has_flight_location_permission(): Boolean {
    return checkSelfPermission(Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED ||
        checkSelfPermission(Manifest.permission.ACCESS_COARSE_LOCATION) == PackageManager.PERMISSION_GRANTED
}

private fun plain_text_from_html(html: String): String {
    return html
        .replace(Regex("<script[\\s\\S]*?</script>", RegexOption.IGNORE_CASE), " ")
        .replace(Regex("<style[\\s\\S]*?</style>", RegexOption.IGNORE_CASE), " ")
        .replace(Regex("<[^>]+>"), " ")
        .replace("&nbsp;", " ")
        .replace("&amp;", "&")
        .replace("&#39;", "'")
        .replace("&quot;", "\"")
        .replace(Regex("\\s+"), " ")
        .trim()
}

private fun traffic_motion_elapsed_seconds(item: TrafficAircraftOverlayState, now_ms: Long): Float {
    if (item.motion_built_elapsed_ms <= 0L ||
        item.motion_limit_sec <= 0f ||
        (item.screen_velocity_x_px_per_sec == 0f && item.screen_velocity_y_px_per_sec == 0f)
    ) {
        return 0f
    }
    val elapsed_ms = (now_ms - item.motion_built_elapsed_ms).coerceAtLeast(0L)
    return min(elapsed_ms / 1000f, item.motion_limit_sec)
}

private fun debug_elapsed_ns(enabled: Boolean, start_ns: Long): Long {
    return if (enabled && start_ns > 0L) SystemClock.elapsedRealtimeNanos() - start_ns else 0L
}

private inline fun debug_trace_section(enabled: Boolean, section: String, block: () -> Unit) {
    if (!enabled) {
        block()
        return
    }
    Trace.beginSection(section)
    try {
        block()
    } finally {
        Trace.endSection()
    }
}

private inline fun debug_trace_frame(enabled: Boolean, sequence: Long, block: () -> Unit) {
    if (!enabled) {
        block()
        return
    }
    debug_trace_section(true, "FlightAlert.frame.$sequence", block)
}

private inline fun <T> debug_trace_result(enabled: Boolean, section: String, block: () -> T): T {
    if (!enabled) return block()
    Trace.beginSection(section)
    return try {
        block()
    } finally {
        Trace.endSection()
    }
}

private fun is_inside_viewport(x: Float, y: Float, viewport: Viewport, padding: Float): Boolean {
    return x >= -padding &&
        x <= viewport.width + padding &&
        y >= -padding &&
        y <= viewport.height + padding
}

private fun recycle_bitmap_pair(first: Bitmap, second: Bitmap) {
    first.recycle()
    second.recycle()
}


