internal object AirplanesLiveHttp {
    const val GLOBE_BASE_URL = "https://globe.airplanes.live"
    const val API_BASE_URL = "https://api.airplanes.live/v2"
    const val STATIC_DB_BASE_URL = "https://static.airplanes.live/db"

    private const val BROWSER_USER_AGENT =
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 " +
            "(KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36"
    private const val REST_MIN_INTERVAL_MS = 1100L
    private val rest_lock = Any()

    @Volatile
    private var next_rest_request_at_ms = 0L

    fun apply_browser_headers(
        connection: HttpURLConnection,
        app_user_agent: String,
        referer: String? = GLOBE_BASE_URL,
        accept: String = "application/json,text/plain,*/*"
    ) {
        connection.setRequestProperty("User-Agent", browser_user_agent(app_user_agent))
        connection.setRequestProperty("Accept", accept)
        connection.setRequestProperty("Accept-Language", "en-US,en;q=0.9")
        connection.setRequestProperty("Cache-Control", "no-cache")
        referer?.let { connection.setRequestProperty("Referer", it) }
    }

    fun wait_for_rest_api_slot() {
        synchronized(rest_lock) {
            val now = System.currentTimeMillis()
            val wait_ms = next_rest_request_at_ms - now
            if (wait_ms > 0L) {
                try {
                    Thread.sleep(wait_ms)
                } catch (_: InterruptedException) {
                    Thread.currentThread().interrupt()
                }
            }
            next_rest_request_at_ms = System.currentTimeMillis() + REST_MIN_INTERVAL_MS
        }
    }

    fun back_off_rest_api(retry_after_seconds: Long?) {
        val retry_ms = (retry_after_seconds ?: 2L).coerceAtLeast(1L) * 1000L
        synchronized(rest_lock) {
            next_rest_request_at_ms = maxOf(next_rest_request_at_ms, System.currentTimeMillis() + retry_ms)
        }
    }

    fun browser_user_agent(app_user_agent: String): String {
        val trimmed = app_user_agent.trim()
        if (trimmed.contains("Mozilla/", ignoreCase = true)) return trimmed
        return if (trimmed.isEmpty()) BROWSER_USER_AGENT else "$BROWSER_USER_AGENT $trimmed"
    }
}


class AircraftDetailsClient(private val user_agent: String) {
    private val details_cache = linkedMapOf<String, CachedDetails>()
    private val static_aircraft_db_cache = linkedMapOf<String, JSONObject?>()

    fun fetch_details(
        hex: String,
        callsign: String,
        registration_hint: String? = null,
        metadata_seed: AircraftMetadataSeed? = null,
        telemetry_seed: AircraftTelemetry? = null,
        latitude: Double? = null,
        longitude: Double? = null
    ): AircraftDetails {
        val normalized_hex = hex.trim().trimStart('~').lowercase(Locale.US)
        val clean_callsign = callsign.trim().replace(" ", "")
        val cache_key = details_cache_key(normalized_hex, clean_callsign, metadata_seed)
        cached_details(cache_key)?.let { cached ->
            return cached.copy(telemetry = cached.telemetry?.with_fallback(telemetry_seed) ?: telemetry_seed)
        }
        val seed_details = details_from_seed(normalized_hex, registration_hint, metadata_seed, telemetry_seed)
        val airplanes_live = fetch_airplanes_live_metadata(normalized_hex)
        val static_airplanes_live = if (airplanes_live?.has_aircraft_identity == true) {
            null
        } else {
            fetch_airplanes_live_static_metadata(normalized_hex)
        }
        val feed_registration = details_normalized_registration(registration_hint)
        val seed_registration = details_normalized_registration(seed_details?.registration)
        val decoded_us_registration = details_decode_us_n_number(normalized_hex)
        val airplanes_registration = details_normalized_registration(airplanes_live?.registration ?: static_airplanes_live?.registration)
        val adsb_aircraft = fetch_adsb_db_aircraft(normalized_hex, airplanes_registration ?: feed_registration ?: seed_registration ?: decoded_us_registration)
        val aircraft = fetch_json("https://hexdb.io/api/v1/aircraft/$normalized_hex")
        val registration = details_first_present(
            airplanes_registration,
            adsb_aircraft?.registration,
            aircraft?.details_json_string_or_null("Registration")?.let(::details_normalized_registration),
            feed_registration,
            seed_registration,
            decoded_us_registration
        )
        val faa = registration?.takeIf { it.startsWith("N", ignoreCase = true) }?.let { fetch_faa_registry(it) }
        val adsb_route = if (clean_callsign.isNotEmpty() && clean_callsign.lowercase(Locale.US) != normalized_hex) {
            fetch_adsb_db_route(clean_callsign)
        } else {
            null
        }
        val route = if (clean_callsign.isNotEmpty() && clean_callsign.lowercase(Locale.US) != normalized_hex) {
            fetch_json("https://hexdb.io/api/v1/route/icao/$clean_callsign")
        } else {
            null
        }
        val route_codes = route?.details_json_string_or_null("route")?.split("-")?.takeIf { it.size >= 2 }
        val adsb_im_route = if (
            adsb_route == null &&
            clean_callsign.isNotEmpty() &&
            clean_callsign.lowercase(Locale.US) != normalized_hex
        ) {
            fetch_adsb_im_route(clean_callsign, latitude, longitude)
        } else {
            null
        }
        val origin = adsb_route?.origin ?: adsb_im_route?.origin ?: route_codes?.firstOrNull()?.let { fetch_airport(it) }
        val destination = adsb_route?.destination ?: adsb_im_route?.destination ?: route_codes?.lastOrNull()?.let { fetch_airport(it) }
        val route_source = when {
            adsb_route != null -> AircraftRouteSource.ADSBDB_CALLSIGN
            adsb_im_route != null -> AircraftRouteSource.ADSBIM_ROUTESET
            route_codes != null -> AircraftRouteSource.HEXDB_CALLSIGN
            else -> null
        }
        if (clean_callsign.isNotEmpty()) {
            Log.d(
                DETAILS_TAG,
                "Route lookup hex=$normalized_hex callsign=$clean_callsign " +
                    "adsb=${adsb_route?.route ?: "none"} adsbim=${adsb_im_route?.route ?: "none"} hexdb=${route?.details_json_string_or_null("route") ?: "none"} " +
                    "origin=${origin?.icao ?: "none"} destination=${destination?.icao ?: "none"}"
            )
        }
        val feed_type = airplanes_live?.description ?: static_airplanes_live?.description
        val api_manufacturer = faa?.manufacturer ?: adsb_aircraft?.manufacturer ?: aircraft?.details_json_string_or_null("Manufacturer")
        val api_type = faa?.model ?: adsb_aircraft?.type ?: aircraft?.details_json_string_or_null("Type")
        val api_type_code = airplanes_live?.type_code
            ?: static_airplanes_live?.type_code
            ?: adsb_aircraft?.icao_type
            ?: aircraft?.details_json_string_or_null("ICAOTypeCode")
        val seed_type = seed_details?.type
        val internet = if (feed_type == null && api_type == null && seed_type == null) {
            fetch_internet_aircraft_metadata(api_manufacturer ?: seed_details?.manufacturer, seed_type, api_type_code ?: seed_details?.type_code)
        } else {
            null
        }
        val manufacturer = api_manufacturer ?: seed_details?.manufacturer ?: internet?.manufacturer
        val type = feed_type ?: api_type ?: seed_type ?: internet?.model
        val owner = faa?.registered_owner
            ?: adsb_aircraft?.registered_owner
            ?: aircraft?.details_json_string_or_null("RegisteredOwners")
            ?: airplanes_live?.owner_operator
            ?: seed_details?.owner

        val metadata_sources = mutableListOf<String>()
        if (seed_details?.registry_source != null) metadata_sources += seed_details.registry_source
        if (airplanes_live?.has_metadata == true) metadata_sources += airplanes_live.source_name
        if (static_airplanes_live?.has_metadata == true) metadata_sources += static_airplanes_live.source_name
        if (faa != null) metadata_sources += faa.source_name
        if (adsb_aircraft != null) metadata_sources += "ADSBdb"
        if (aircraft != null) metadata_sources += "HexDB"
        if (internet?.model != null && internet.model == type) metadata_sources += internet.source_name
        if (metadata_sources.isEmpty() && registration != null && registration == feed_registration) metadata_sources += "Aircraft feed"
        if (metadata_sources.isEmpty() && registration != null && registration == decoded_us_registration) metadata_sources += "Mode S N-number decode"

        return AircraftDetails(
            icao24 = normalized_hex,
            registration = faa?.registration ?: registration,
            manufacturer = manufacturer,
            type = type,
            type_code = api_type_code ?: seed_details?.type_code,
            owner = owner,
            manufactured_year = faa?.manufactured_year ?: airplanes_live?.year ?: seed_details?.manufactured_year,
            registry_source = metadata_sources.distinct().joinToString(" + ").ifEmpty { null },
            operator_code = adsb_aircraft?.operator_code
                ?: aircraft?.details_json_string_or_null("OperatorFlagCode")
                ?: airplanes_live?.operator_code
                ?: static_airplanes_live?.operator_code
                ?: seed_details?.operator_code,
            route = adsb_route?.route ?: adsb_im_route?.route ?: route?.details_json_string_or_null("route") ?: seed_details?.route,
            route_updated_epoch_sec = route?.details_json_long_or_null("updatetime") ?: seed_details?.route_updated_epoch_sec,
            route_source = route_source ?: seed_details?.route_source,
            origin_airport = origin ?: seed_details?.origin_airport,
            destination_airport = destination ?: seed_details?.destination_airport,
            telemetry = telemetry_seed
        ).also { cache_details(cache_key, it) }
    }

    private fun details_from_seed(
        normalized_hex: String,
        registration_hint: String?,
        seed: AircraftMetadataSeed?,
        telemetry_seed: AircraftTelemetry?
    ): AircraftDetails? {
        if ((seed == null || !seed.has_details) && telemetry_seed?.has_values != true) return null
        val registration = details_first_present(
            details_normalized_registration(seed?.registration),
            details_normalized_registration(registration_hint),
            details_decode_us_n_number(normalized_hex)
        )
        val manufacturer = seed?.manufacturer?.clean_seed_value()
        val type = seed?.type?.clean_seed_value()
        val type_code = seed?.type_code?.clean_seed_value()
        val owner = seed?.owner?.clean_seed_value()
        val year = seed?.manufactured_year?.clean_seed_value()?.take(4)
        val operator_code = seed?.operator_code?.clean_seed_value()
        if (listOf(registration, manufacturer, type, type_code, owner, year, operator_code).all { it.isNullOrBlank() } && telemetry_seed?.has_values != true) {
            return null
        }
        return AircraftDetails(
            icao24 = normalized_hex,
            registration = registration,
            manufacturer = manufacturer,
            type = type,
            type_code = type_code,
            owner = owner,
            manufactured_year = year,
            registry_source = seed?.source_name,
            operator_code = operator_code,
            route = null,
            route_updated_epoch_sec = null,
            route_source = null,
            origin_airport = null,
            destination_airport = null,
            telemetry = telemetry_seed
        )
    }

    private fun details_cache_key(normalized_hex: String, clean_callsign: String, seed: AircraftMetadataSeed?): String {
        val source = seed?.source_name?.takeIf { seed.has_details } ?: "network"
        return "$normalized_hex|${clean_callsign.uppercase(Locale.US)}|$source"
    }

    private fun cached_details(key: String): AircraftDetails? {
        val now = System.currentTimeMillis()
        return synchronized(details_cache) {
            val cached = details_cache[key] ?: return@synchronized null
            if (now - cached.stored_at_ms > DETAILS_CACHE_MAX_AGE_MS) {
                details_cache.remove(key)
                null
            } else {
                cached.details
            }
        }
    }

    private fun cache_details(key: String, details: AircraftDetails) {
        synchronized(details_cache) {
            details_cache[key] = CachedDetails(details, System.currentTimeMillis())
            while (details_cache.size > DETAILS_CACHE_MAX_ENTRIES) {
                val first_key = details_cache.keys.firstOrNull() ?: break
                details_cache.remove(first_key)
            }
        }
    }

    private fun fetch_internet_aircraft_metadata(
        manufacturer: String?,
        model: String?,
        type_code: String?
    ): InternetAircraftMetadata? {
        val queries = listOfNotNull(
            listOfNotNull(manufacturer, model).joinToString(" ").takeIf { it.isNotBlank() }?.let { "$it aircraft" },
            type_code?.takeIf { it.length >= 3 }?.let { "$it aircraft" },
            model?.takeIf { it.length >= 3 }?.let { "$it aircraft" }
        ).distinctBy { it.uppercase(Locale.US) }
        for (query in queries) {
            fetch_wikipedia_aircraft_metadata(query)?.let { return it }
        }
        return null
    }

    private fun fetch_wikipedia_aircraft_metadata(query: String): InternetAircraftMetadata? {
        val encoded = URLEncoder.encode(query, "UTF-8")
        val search = fetch_json("https://en.wikipedia.org/w/api.php?action=query&format=json&list=search&srlimit=3&srsearch=$encoded")
            ?.optJSONObject("query")
            ?.optJSONArray("search")
            ?: return null
        for (index in 0 until search.length()) {
            val result = search.optJSONObject(index) ?: continue
            val title = result.details_json_string_or_null("title") ?: continue
            val snippet = plain_text_from_html(result.details_json_string_or_null("snippet").orEmpty())
            if (!details_looks_like_aircraft_page(title, snippet)) continue
            val summary = fetch_wikipedia_summary(title) ?: continue
            if (!details_looks_like_aircraft_page(summary.title, summary.extract)) continue
            return InternetAircraftMetadata(
                manufacturer = null,
                model = summary.title,
                source_name = "Wikipedia summary"
            )
        }
        return null
    }

    private fun fetch_wikipedia_summary(title: String): WikipediaSummary? {
        val encoded_title = URLEncoder.encode(title.replace(' ', '_'), "UTF-8").replace("+", "%20")
        val json = fetch_json("https://en.wikipedia.org/api/rest_v1/page/summary/$encoded_title") ?: return null
        val extract = json.details_json_string_or_null("extract") ?: return null
        return WikipediaSummary(
            title = json.details_json_string_or_null("title") ?: title,
            extract = extract
        )
    }

    private fun fetch_airplanes_live_metadata(hex: String): AirplanesLiveMetadata? {
        if (hex.isBlank()) return null
        var best = fetch_airplanes_live_rest_metadata(hex)
        if (best?.has_core_metadata == true) return best
        best = best.merge_airplanes_live(fetch_airplanes_live_trace_metadata(hex, recent = true))
        if (best?.has_aircraft_identity == true) return best
        return best.merge_airplanes_live(fetch_airplanes_live_trace_metadata(hex, recent = false))
    }

    private fun fetch_airplanes_live_trace_metadata(hex: String, recent: Boolean): AirplanesLiveMetadata? {
        val folder = hex.takeLast(2)
        val trace_name = if (recent) "trace_recent_$hex.json" else "trace_full_$hex.json"
        val json = fetch_json("${AirplanesLiveHttp.GLOBE_BASE_URL}/data/traces/$folder/$trace_name", browser_headers = true)
            ?: return null
        return json.to_airplanes_live_metadata(if (recent) "Airplanes.Live trace_recent" else "Airplanes.Live trace_full")
    }

    private fun fetch_airplanes_live_rest_metadata(hex: String): AirplanesLiveMetadata? {
        AirplanesLiveHttp.wait_for_rest_api_slot()
        val json = fetch_json("${AirplanesLiveHttp.API_BASE_URL}/hex/$hex", browser_headers = true) ?: return null
        val aircraft = json.optJSONArray("aircraft") ?: json.optJSONArray("ac") ?: return null
        for (index in 0 until aircraft.length()) {
            val item = aircraft.optJSONObject(index) ?: continue
            val item_hex = item.details_json_string_or_null("hex")?.trim()?.trimStart('~')?.lowercase(Locale.US)
            if (item_hex == hex) return item.to_airplanes_live_metadata("Airplanes.Live")
        }
        return null
    }

    private fun fetch_airplanes_live_static_metadata(hex: String): AirplanesLiveMetadata? {
        val clean_hex = hex.trim().trimStart('~').uppercase(Locale.US)
        if (!clean_hex.matches(Regex("[0-9A-F]{6}"))) return null
        val row = fetch_airplanes_live_static_row(clean_hex) ?: return null
        return AirplanesLiveMetadata(
            source_name = "Airplanes.Live static aircraft DB",
            registration = row.details_json_string_or_null(0),
            type_code = row.details_json_string_or_null(1),
            description = row.details_json_string_or_null(3),
            owner_operator = null,
            operator_code = null,
            year = null
        ).takeIf { it.has_metadata }
    }

    private fun fetch_airplanes_live_static_row(clean_hex: String): JSONArray? {
        var level = 1
        while (level <= clean_hex.length) {
            val bkey = clean_hex.substring(0, level)
            val dkey = clean_hex.substring(level)
            val chunk = fetch_airplanes_live_static_chunk(bkey) ?: return null
            chunk.optJSONArray(dkey)?.let { return it }
            val next_child = clean_hex.substring(0, (level + 1).coerceAtMost(clean_hex.length))
            if (!static_chunk_has_child(chunk, next_child)) return null
            level++
        }
        return null
    }

    private fun fetch_airplanes_live_static_chunk(bkey: String): JSONObject? {
        val key = bkey.uppercase(Locale.US)
        synchronized(static_aircraft_db_cache) {
            if (static_aircraft_db_cache.containsKey(key)) return static_aircraft_db_cache[key]
        }
        val chunk = fetch_json("${AirplanesLiveHttp.STATIC_DB_BASE_URL}/$key.js", browser_headers = true)
        synchronized(static_aircraft_db_cache) {
            static_aircraft_db_cache[key] = chunk
            while (static_aircraft_db_cache.size > DETAILS_STATIC_DB_CACHE_MAX_ENTRIES) {
                val first_key = static_aircraft_db_cache.keys.firstOrNull() ?: break
                static_aircraft_db_cache.remove(first_key)
            }
        }
        return chunk
    }

    private fun fetch_faa_registry(registration: String): FaaRegistryRecord? {
        val n_number = registration.trim().removePrefix("N").removePrefix("n")
        if (n_number.isEmpty()) return null
        val encoded = URLEncoder.encode(n_number, "UTF-8")
        val html = fetch_text("https://registry.faa.gov/AircraftInquiry/Search/NNumberResult?nNumberTxt=$encoded") ?: return null
        val result_html = html.substringAfter("<div id=\"mainDiv\"", html)
        val result_text = plain_text_from_html(result_html)
        val details_normalized_registration = "N${n_number.uppercase(Locale.US)}"
        if (!result_text.contains("$details_normalized_registration is Assigned", ignoreCase = true)) return null

        val owner_section = details_registered_owner_table_section(result_html)
        val private_owner = owner_section
            ?.let(::plain_text_from_html)
            ?.contains("requested to keep this data private", ignoreCase = true) == true
        val owner_name = if (private_owner) {
            "Private under 49 USC 44114"
        } else {
            owner_section?.let { details_value_from_data_label(it, "Name") }
        }

        return FaaRegistryRecord(
            registration = details_normalized_registration,
            manufacturer = details_value_from_data_label(result_html, "Manufacturer Name"),
            model = details_value_from_data_label(result_html, "Model"),
            manufactured_year = details_value_from_data_label(result_html, "Mfr Year")?.take(4),
            registered_owner = owner_name,
            source_name = "FAA Registry"
        )
    }

    private fun fetch_adsb_db_aircraft(hex: String, registration: String?): AdsbDbAircraftRecord? {
        val keys = listOfNotNull(hex.takeIf { it.isNotBlank() }, registration)
            .distinctBy { it.uppercase(Locale.US) }
        for (key in keys) {
            val encoded = URLEncoder.encode(key, "UTF-8")
            val aircraft = fetch_json("https://api.adsbdb.com/v0/aircraft/$encoded")
                ?.optJSONObject("response")
                ?.optJSONObject("aircraft")
                ?: continue
            val mode_s = aircraft.details_json_string_or_null("mode_s")?.trim()?.trimStart('~')?.lowercase(Locale.US)
            if (key.equals(hex, ignoreCase = true) && mode_s != null && mode_s != hex) continue
            val found_registration = details_normalized_registration(aircraft.details_json_string_or_null("registration"))
            if (
                registration != null &&
                key.equals(registration, ignoreCase = true) &&
                found_registration != null &&
                found_registration != registration
            ) {
                continue
            }
            return AdsbDbAircraftRecord(
                registration = found_registration,
                manufacturer = aircraft.details_json_string_or_null("manufacturer"),
                type = aircraft.details_json_string_or_null("type"),
                icao_type = aircraft.details_json_string_or_null("icao_type"),
                registered_owner = aircraft.details_json_string_or_null("registered_owner"),
                operator_code = aircraft.details_json_string_or_null("registered_owner_operator_flag_code")
            )
        }
        return null
    }

    private fun fetch_airport(icao: String): AirportDetails? {
        val json = fetch_json("https://hexdb.io/api/v1/airport/icao/${icao.trim()}") ?: return null
        return AirportDetails(
            icao = json.details_json_string_or_null("icao") ?: icao,
            iata = json.details_json_string_or_null("iata_code") ?: json.details_json_string_or_null("iata"),
            name = json.details_json_string_or_null("airport"),
            country_code = json.details_json_string_or_null("country_code"),
            region_name = json.details_json_string_or_null("region_name"),
            latitude = json.details_json_double_or_null("latitude"),
            longitude = json.details_json_double_or_null("longitude")
        )
    }

    private fun fetch_adsb_db_route(callsign: String): RouteLookup? {
        val encoded = URLEncoder.encode(callsign.trim(), "UTF-8")
        val route = fetch_json("https://api.adsbdb.com/v0/callsign/$encoded")
            ?.optJSONObject("response")
            ?.optJSONObject("flightroute")
            ?: run {
                Log.d(DETAILS_TAG, "ADSBdb route unavailable callsign=${callsign.trim()}")
                return null
            }
        val origin = route.optJSONObject("origin")?.details_to_adsb_db_airport()
        val destination = route.optJSONObject("destination")?.details_to_adsb_db_airport()
        if (origin == null && destination == null) return null
        val route_label = listOfNotNull(
            origin?.icao ?: origin?.iata,
            destination?.icao ?: destination?.iata
        ).joinToString("-").ifEmpty { null }
        return RouteLookup(route_label, origin, destination)
    }

    private fun fetch_adsb_im_route(callsign: String, latitude: Double?, longitude: Double?): RouteLookup? {
        val lat = latitude?.takeIf { it.isFinite() && it in -90.0..90.0 } ?: return null
        val lon = longitude?.takeIf { it.isFinite() && it in -180.0..180.0 } ?: return null
        val clean_callsign = callsign.trim().replace(" ", "").uppercase(Locale.US)
        val request_body = JSONObject()
            .put(
                "planes",
                JSONArray().put(
                    JSONObject()
                        .put("callsign", clean_callsign)
                        .put("lat", lat)
                        .put("lng", lon)
                )
            )
            .toString()
        val route = post_adsb_im_routeset(request_body)
            ?.optJSONObject(0)
            ?: return null
        val returned_callsign = route.details_json_string_or_null("callsign")?.replace(" ", "")?.uppercase(Locale.US)
        if (returned_callsign != null && returned_callsign != clean_callsign) return null
        val airports = route.optJSONArray("_airports")?.details_to_route_airports().orEmpty()
        if (airports.isEmpty()) return null
        val route_label = route.details_json_string_or_null("airport_codes")
            ?: airports.mapNotNull { airport -> airport.icao.takeIf { it.isNotBlank() } }.takeIf { it.size >= 2 }?.joinToString("-")
            ?: return null
        val display_route = if (route.has("plausible") && !route.optBoolean("plausible", true)) {
            "?? $route_label"
        } else {
            route_label
        }
        return RouteLookup(display_route, airports.firstOrNull(), airports.lastOrNull()?.takeIf { airports.size >= 2 })
    }

    private fun post_adsb_im_routeset(body: String): JSONArray? {
        val safe_url = https_url("https://adsb.im/api/0/routeset") ?: return null
        var connection: HttpURLConnection? = null
        return try {
            connection = (safe_url.openConnection() as HttpURLConnection).apply {
                connectTimeout = 4000
                readTimeout = 6000
                requestMethod = "POST"
                doOutput = true
                setRequestProperty("User-Agent", AirplanesLiveHttp.browser_user_agent(user_agent))
                setRequestProperty("Accept", "application/json,text/plain,*/*")
                setRequestProperty("Content-Type", "application/json; charset=utf-8")
            }
            connection.outputStream.use { output -> output.write(body.toByteArray(Charsets.UTF_8)) }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                return null
            }
            JSONArray(connection.inputStream.bufferedReader().use { it.readText() })
        } catch (_: Exception) {
            null
        } finally {
            connection?.disconnect()
        }
    }

    private fun fetch_json(url: String, browser_headers: Boolean = false): JSONObject? {
        val body = fetch_text(url, browser_headers) ?: return null
        return try {
            JSONObject(body).takeUnless { it.details_json_string_or_null("status") == "404" }
        } catch (_: Exception) {
            null
        }
    }

    private fun fetch_text(url: String, browser_headers: Boolean = false): String? {
        val safe_url = https_url(url) ?: return null
        var connection: HttpURLConnection? = null
        return try {
            connection = (safe_url.openConnection() as HttpURLConnection).apply {
                connectTimeout = 4000
                readTimeout = 6000
                requestMethod = "GET"
                if (browser_headers) {
                    AirplanesLiveHttp.apply_browser_headers(this, user_agent)
                } else {
                    setRequestProperty("User-Agent", user_agent)
                    setRequestProperty("Accept", "application/json,text/plain,*/*")
                }
            }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                if (connection.responseCode == DETAILS_HTTP_TOO_MANY_REQUESTS && safe_url.host.equals("api.airplanes.live", ignoreCase = true)) {
                    AirplanesLiveHttp.back_off_rest_api(connection.getHeaderField("Retry-After")?.toLongOrNull())
                }
                connection.errorStream?.close()
                return null
            }
            connection.inputStream.bufferedReader().use { it.readText() }
        } catch (_: Exception) {
            null
        } finally {
            connection?.disconnect()
        }
    }

    }

private fun details_registered_owner_table_section(html: String): String? {
    val caption_regex = Regex("<caption[^>]*>\\s*Registered Owner\\s*</caption>", setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL))
    val start = caption_regex.find(html)?.range?.first ?: return null
    val end = html.indexOf("</table>", start, ignoreCase = true).takeIf { it >= 0 } ?: return null
    return html.substring(start, end)
}

private fun details_looks_like_aircraft_page(title: String, text: String): Boolean {
    val combined = "$title $text".uppercase(Locale.US)
    val aircraft_terms = listOf(
        "AIRCRAFT",
        "AIRPLANE",
        "AEROPLANE",
        "HELICOPTER",
        "ROTORCRAFT",
        "JET",
        "TURBOPROP",
        "PISTON",
        "GLIDER",
        "UAV",
        "DRONE"
    )
    val rejected_topics = listOf(
        "AIRPORT",
        "AIRLINE",
        "AIRWAYS",
        "ACCIDENT",
        "INCIDENT",
        "CRASH",
        "HIJACKING"
    )
    return aircraft_terms.any { combined.contains(it) } &&
        rejected_topics.none { combined.contains(it) }
}

internal fun JSONObject.to_airplanes_live_metadata(source_name: String): AirplanesLiveMetadata {
    return AirplanesLiveMetadata(
        source_name = source_name,
        registration = details_json_first_string_or_null("r", "registration", "reg"),
        type_code = details_json_first_string_or_null("t", "icaoType", "icao_type", "type_code"),
        description = details_json_first_string_or_null("desc", "typeLong", "description", "typeDescription", "type_description"),
        owner_operator = details_json_first_string_or_null("ownOp", "owner_operator", "operator", "owner"),
        operator_code = details_json_first_string_or_null("ownOpCode", "operator_code"),
        year = details_json_first_string_or_null("year", "mfrYear", "manufacturedYear", "manufactureYear", "mfr_year", "manufacture_year")
            ?.let(::normalized_year)
    )
}

internal fun AirplanesLiveMetadata?.merge_airplanes_live(newer: AirplanesLiveMetadata?): AirplanesLiveMetadata? {
    if (this == null) return newer
    newer ?: return this
    return AirplanesLiveMetadata(
        source_name = listOf(this.source_name, newer.source_name).distinct().joinToString(" + "),
        registration = newer.registration ?: registration,
        type_code = newer.type_code ?: type_code,
        description = newer.description ?: description,
        owner_operator = newer.owner_operator ?: owner_operator,
        operator_code = newer.operator_code ?: operator_code,
        year = newer.year ?: year
    )
}

private fun details_value_from_data_label(html: String, label: String): String? {
    val regex = Regex("<td[^>]*data-label=[\"']${Regex.escape(label)}[\"'][^>]*>([\\s\\S]*?)</td>", RegexOption.IGNORE_CASE)
    return regex.find(html)
        ?.groupValues
        ?.getOrNull(1)
        ?.let(::plain_text_from_html)
        ?.let(::details_clean_registry_value)
}


private fun details_clean_registry_value(value: String): String? {
    val cleaned = value.trim().trim('-').trim()
    if (cleaned.isEmpty() || cleaned.equals("none", ignoreCase = true)) return null
    val page_chrome_terms = listOf("Lookup Aircraft By", "N-Number Availability", "Aircraft Inquiry Search")
    if (page_chrome_terms.any { cleaned.contains(it, ignoreCase = true) }) return null
    return cleaned
}

internal fun normalized_year(value: String): String? {
    return Regex("\\b(19|20)\\d{2}\\b")
        .find(value)
        ?.value
}


private fun details_normalized_registration(value: String?): String? {
    return value
        ?.uppercase(Locale.US)
        ?.replace(Regex("[^A-Z0-9-]"), "")
        ?.trim('-')
        ?.takeIf { it.isNotBlank() && it != "NA" }
}

private fun details_first_present(vararg values: String?): String? {
    return values.firstOrNull { !it.isNullOrBlank() }
}

private fun details_decode_us_n_number(hex: String): String? {
    val value = hex.toLongOrNull(16) ?: return null
    if (value !in DETAILS_US_N_NUMBER_ICAO_START..DETAILS_US_N_NUMBER_ICAO_END) return null

    var offset = (value - DETAILS_US_N_NUMBER_ICAO_START).toInt()
    val registration = StringBuilder("N")
    registration.append(offset / DETAILS_FIRST_N_NUMBER_STRIDE + 1)
    offset %= DETAILS_FIRST_N_NUMBER_STRIDE
    details_append_n_number_suffix(offset, registration)?.let { return it }

    offset -= DETAILS_N_NUMBER_SUFFIX_COUNT
    if (offset < 0) return null
    registration.append(offset / DETAILS_SECOND_N_NUMBER_STRIDE)
    offset %= DETAILS_SECOND_N_NUMBER_STRIDE
    details_append_n_number_suffix(offset, registration)?.let { return it }

    offset -= DETAILS_N_NUMBER_SUFFIX_COUNT
    if (offset < 0) return null
    registration.append(offset / DETAILS_THIRD_N_NUMBER_STRIDE)
    offset %= DETAILS_THIRD_N_NUMBER_STRIDE
    details_append_n_number_suffix(offset, registration)?.let { return it }

    offset -= DETAILS_N_NUMBER_SUFFIX_COUNT
    if (offset < 0) return null
    registration.append(offset / DETAILS_FOURTH_N_NUMBER_STRIDE)
    offset %= DETAILS_FOURTH_N_NUMBER_STRIDE
    if (offset <= DETAILS_N_NUMBER_ALPHABET.length) {
        return registration.append(details_n_number_single_suffix(offset)).toString()
    }

    val last_digit = offset - DETAILS_N_NUMBER_ALPHABET.length - 1
    return registration.append(last_digit).toString()
}

private fun details_append_n_number_suffix(offset: Int, registration: StringBuilder): String? {
    if (offset > DETAILS_MAX_TWO_LETTER_SUFFIX_OFFSET) return null
    return registration.append(details_n_number_suffix(offset)).toString()
}

private fun details_n_number_suffix(offset: Int): String {
    if (offset <= 0) return ""
    val index = offset - 1
    if (index < DETAILS_N_NUMBER_ALPHABET.length) return DETAILS_N_NUMBER_ALPHABET[index].toString()
    val double_index = index - DETAILS_N_NUMBER_ALPHABET.length
    val first = double_index / DETAILS_N_NUMBER_ALPHABET.length
    val second = double_index % DETAILS_N_NUMBER_ALPHABET.length
    return "${DETAILS_N_NUMBER_ALPHABET[first]}${DETAILS_N_NUMBER_ALPHABET[second]}"
}

private fun details_n_number_single_suffix(offset: Int): String {
    return if (offset <= 0) "" else DETAILS_N_NUMBER_ALPHABET[offset - 1].toString()
}

private data class AdsbDbAircraftRecord(
    val registration: String?,
    val manufacturer: String?,
    val type: String?,
    val icao_type: String?,
    val registered_owner: String?,
    val operator_code: String?
)

internal data class AirplanesLiveMetadata(
    val source_name: String,
    val registration: String?,
    val type_code: String?,
    val description: String?,
    val owner_operator: String?,
    val operator_code: String?,
    val year: String?
) {
    val has_metadata: Boolean
        get() = listOf(registration, type_code, description, owner_operator, operator_code, year).any { !it.isNullOrBlank() }

    val has_core_metadata: Boolean
        get() = listOf(registration, type_code, description, owner_operator, operator_code, year).all { !it.isNullOrBlank() }

    val has_aircraft_identity: Boolean
        get() = listOf(registration, type_code, description).all { !it.isNullOrBlank() }
}

private data class InternetAircraftMetadata(
    val manufacturer: String?,
    val model: String?,
    val source_name: String
)

private data class WikipediaSummary(
    val title: String,
    val extract: String
)

private data class CachedDetails(
    val details: AircraftDetails,
    val stored_at_ms: Long
)

private data class RouteLookup(
    val route: String?,
    val origin: AirportDetails?,
    val destination: AirportDetails?
)

private fun JSONObject.details_to_adsb_db_airport(): AirportDetails {
    return AirportDetails(
        icao = details_json_string_or_null("icao_code") ?: details_json_string_or_null("icao") ?: "Unavailable",
        iata = details_json_string_or_null("iata_code") ?: details_json_string_or_null("iata"),
        name = details_json_string_or_null("name"),
        country_code = details_json_string_or_null("country_iso_name") ?: details_json_string_or_null("country_iso"),
        region_name = details_json_string_or_null("municipality"),
        latitude = details_json_double_or_null("latitude"),
        longitude = details_json_double_or_null("longitude")
    )
}

private fun JSONArray.details_to_route_airports(): List<AirportDetails> {
    val result = ArrayList<AirportDetails>(length())
    for (index in 0 until length()) {
        val item = optJSONObject(index) ?: continue
        val icao = item.details_json_string_or_null("icao") ?: item.details_json_string_or_null("icao_code") ?: continue
        result += AirportDetails(
            icao = icao,
            iata = item.details_json_string_or_null("iata") ?: item.details_json_string_or_null("iata_code"),
            name = item.details_json_string_or_null("name") ?: item.details_json_string_or_null("airport"),
            country_code = item.details_json_string_or_null("countryiso2")
                ?: item.details_json_string_or_null("country_code")
                ?: item.details_json_string_or_null("country"),
            region_name = item.details_json_string_or_null("location") ?: item.details_json_string_or_null("region_name"),
            latitude = item.details_json_double_or_null("lat") ?: item.details_json_double_or_null("latitude"),
            longitude = item.details_json_double_or_null("lon") ?: item.details_json_double_or_null("lng") ?: item.details_json_double_or_null("longitude")
        )
    }
    return result
}

private fun JSONObject.details_json_string_or_null(key: String): String? {
    if (!has(key) || isNull(key)) return null
    return optString(key).trim().ifEmpty { null }
}

private fun JSONObject.details_json_first_string_or_null(vararg keys: String): String? {
    for (key in keys) {
        details_json_string_or_null(key)?.let { return it }
    }
    return null
}

internal fun static_chunk_has_child(chunk: JSONObject, child_key: String): Boolean {
    val children = chunk.opt("children") ?: return false
    val normalized_child = child_key.uppercase(Locale.US)
    return when (children) {
        is JSONArray -> {
            for (index in 0 until children.length()) {
                if (children.optString(index).uppercase(Locale.US) == normalized_child) return true
            }
            false
        }
        else -> children.toString().uppercase(Locale.US).contains(normalized_child)
    }
}

private fun JSONArray.details_json_string_or_null(index: Int): String? {
    if (index !in 0 until length() || isNull(index)) return null
    return optString(index).trim().ifEmpty { null }
}

private fun JSONObject.details_json_long_or_null(key: String): Long? {
    return if (has(key) && !isNull(key)) optLong(key) else null
}

private fun JSONObject.details_json_double_or_null(key: String): Double? {
    return if (has(key) && !isNull(key)) optDouble(key) else null
}

private const val DETAILS_US_N_NUMBER_ICAO_START = 0xA00001L
private const val DETAILS_HTTP_TOO_MANY_REQUESTS = FlightAlertSettings.AircraftDetails.HTTP_TOO_MANY_REQUESTS
private const val DETAILS_CACHE_MAX_AGE_MS = FlightAlertSettings.AircraftDetails.CACHE_MAX_AGE_MS
private const val DETAILS_CACHE_MAX_ENTRIES = FlightAlertSettings.AircraftDetails.CACHE_MAX_ENTRIES
private const val DETAILS_STATIC_DB_CACHE_MAX_ENTRIES = FlightAlertSettings.AircraftDetails.STATIC_DB_CACHE_MAX_ENTRIES
private const val DETAILS_TAG = FlightAlertSettings.App.TAG
private const val DETAILS_US_N_NUMBER_ICAO_END = 0xADF7C7L
private const val DETAILS_FIRST_N_NUMBER_STRIDE = 101711
private const val DETAILS_SECOND_N_NUMBER_STRIDE = 10111
private const val DETAILS_THIRD_N_NUMBER_STRIDE = 951
private const val DETAILS_FOURTH_N_NUMBER_STRIDE = 35
private const val DETAILS_N_NUMBER_SUFFIX_COUNT = 601
private const val DETAILS_MAX_TWO_LETTER_SUFFIX_OFFSET = DETAILS_N_NUMBER_SUFFIX_COUNT - 1
private const val DETAILS_N_NUMBER_ALPHABET = "ABCDEFGHJKLMNPQRSTUVWXYZ"


// Live aircraft feed client: viewport coverage and exact-search detail stay separate until both real sources answer.
@Suppress("FunctionName")
class AircraftFeedClient(private val user_agent: String) {

    // Fetch the visible area first, then merge an exact search result if the user is filtering for one aircraft.
    fun fetch_aircraft(bounds: FeedBounds, own_lat: Double, own_lon: Double, exact_search: String? = null): FeedResult {
        val viewport_result = fetch_viewport_aircraft(bounds, own_lat, own_lon)
        val search_result = fetch_airplanes_live_exact_search(exact_search, own_lat, own_lon)
        return merge_viewport_and_search(viewport_result, search_result)
    }

    // Prefer Airplanes.Live coverage, then fall back to OpenSky only when the primary source is not usable.
    private fun fetch_viewport_aircraft(bounds: FeedBounds, own_lat: Double, own_lon: Double): FeedResult {
        val now = System.currentTimeMillis()
        val airplanes_result = if (now >= airplanes_live_retry_after_ms) {
            fetch_airplanes_live(bounds, own_lat, own_lon)
        } else {
            FeedResult(FeedStatus.RATE_LIMITED, FeedSource.AIRPLANES_LIVE, http_code = HTTP_TOO_MANY_REQUESTS)
        }
        if (airplanes_result.status == FeedStatus.OK) {
            return airplanes_result
        }

        val open_sky_result = if (now >= open_sky_retry_after_ms) fetch_open_sky(bounds, own_lat, own_lon) else null
        if (open_sky_result?.status == FeedStatus.OK) return open_sky_result

        return open_sky_result ?: airplanes_result
    }

    private fun merge_viewport_and_search(viewport: FeedResult, search: FeedResult?): FeedResult {
        if (search == null) return viewport
        if (search.status != FeedStatus.OK) return viewport
        if (viewport.status != FeedStatus.OK) return search
        if (search.aircraft.isEmpty()) return viewport.copy(query_count = viewport.query_count + search.query_count)
        return merge_complete_coverage_with_detail(viewport, search)
    }

    // Merge detail rows into complete coverage by aircraft key, keeping the newest real report for each aircraft.
    private fun merge_complete_coverage_with_detail(complete: FeedResult, detail: FeedResult): FeedResult {
        val merged = linkedMapOf<String, FeedAircraft>()
        complete.aircraft.forEach { item ->
            merged[item.feed_key()] = item
        }
        detail.aircraft.forEach { item ->
            val key = item.feed_key()
            merged[key] = newer_aircraft(merged[key], item)
        }
        return FeedResult(
            status = FeedStatus.OK,
            source = merged_source(complete.source, detail.source),
            aircraft = merged.values.sortedBy { it.distance_m },
            epoch_sec = max_epoch(complete.epoch_sec, detail.epoch_sec),
            query_count = complete.query_count + detail.query_count,
            partial_coverage = false
        )
    }

    private fun fetch_open_sky(bounds: FeedBounds, own_lat: Double, own_lon: Double): FeedResult {
        var connection: HttpURLConnection? = null
        return try {
            val url = URL(
                String.format(
                    Locale.US,
                    "https://opensky-network.org/api/states/all?lamin=%.5f&lomin=%.5f&lamax=%.5f&lomax=%.5f&extended=1",
                    bounds.min_lat,
                    bounds.min_lon,
                    bounds.max_lat,
                    bounds.max_lon
                )
            )
            connection = open_connection(url)
            when (val code = connection.responseCode) {
                HttpURLConnection.HTTP_OK -> {
                    val body = connection.inputStream.bufferedReader().use { it.readText() }
                    val json = JSONObject(body)
                    FeedResult(
                        status = FeedStatus.OK,
                        source = FeedSource.OPENSKY,
                        aircraft = parse_open_sky_aircraft(json, own_lat, own_lon),
                        epoch_sec = json.feed_json_finite_double_or_null("time")
                    )
                }
                HTTP_TOO_MANY_REQUESTS -> {
                    val retry_seconds = connection.getHeaderField("X-Rate-Limit-Retry-After-Seconds")?.toLongOrNull()
                    open_sky_retry_after_ms = System.currentTimeMillis() + ((retry_seconds ?: DEFAULT_OPENSKY_BACKOFF_SECONDS) * 1000L)
                    connection.errorStream?.close()
                    FeedResult(FeedStatus.RATE_LIMITED, FeedSource.OPENSKY, http_code = code)
                }
                else -> {
                    connection.errorStream?.close()
                    FeedResult(FeedStatus.UNAVAILABLE, FeedSource.OPENSKY, http_code = code)
                }
            }
        } catch (_: Exception) {
            FeedResult(FeedStatus.UNAVAILABLE, FeedSource.OPENSKY)
        } finally {
            connection?.disconnect()
        }
    }

    // Split large bounds into real point queries so Airplanes.Live can cover the visible area honestly.
    private fun fetch_airplanes_live(bounds: FeedBounds, own_lat: Double, own_lon: Double): FeedResult {
        val plan = airplanes_live_query_plan(bounds)
        val merged = linkedMapOf<String, FeedAircraft>()
        var latest_epoch_sec: Double? = null
        var saw_ok = false
        var saw_rate_limit = false
        var last_http_code: Int? = null
        val query_results = fetch_airplanes_live_points(plan.queries, own_lat, own_lon)
        val timed_out = query_results.size < plan.queries.size

        for (result in query_results) {
            latest_epoch_sec = max_epoch(latest_epoch_sec, result.epoch_sec)
            last_http_code = result.http_code ?: last_http_code
            when (result.status) {
                FeedStatus.OK -> {
                    saw_ok = true
                    result.aircraft.forEach { item ->
                        val key = item.feed_key()
                        merged[key] = newer_aircraft(merged[key], item)
                    }
                }
                FeedStatus.RATE_LIMITED -> {
                    saw_rate_limit = true
                    last_http_code = result.http_code ?: HTTP_TOO_MANY_REQUESTS
                }
                FeedStatus.UNAVAILABLE -> Unit
            }
        }

        return when {
            saw_ok -> FeedResult(
                status = FeedStatus.OK,
                source = FeedSource.AIRPLANES_LIVE,
                aircraft = merged.values.sortedBy { it.distance_m },
                epoch_sec = latest_epoch_sec,
                query_count = plan.queries.size,
                partial_coverage = plan.partial_coverage || timed_out
            )
            saw_rate_limit -> FeedResult(
                status = FeedStatus.RATE_LIMITED,
                source = FeedSource.AIRPLANES_LIVE,
                http_code = last_http_code,
                query_count = plan.queries.size,
                partial_coverage = plan.partial_coverage
            )
            else -> FeedResult(
                status = FeedStatus.UNAVAILABLE,
                source = FeedSource.AIRPLANES_LIVE,
                http_code = last_http_code,
                query_count = plan.queries.size,
                partial_coverage = plan.partial_coverage || timed_out
            )
        }
    }

    private fun fetch_airplanes_live_points(
        queries: List<AirplanesLiveQuery>,
        own_lat: Double,
        own_lon: Double
    ): List<FeedResult> {
        return queries.map { query -> fetch_airplanes_live_point(query, own_lat, own_lon) }
    }

    private fun fetch_airplanes_live_point(query: AirplanesLiveQuery, own_lat: Double, own_lon: Double): FeedResult {
        val path = String.format(
            Locale.US,
            "point/%.5f/%.5f/%.0f",
            query.center_lat,
            query.center_lon,
            query.radius_nm
        )
        return fetch_airplanes_live_path(path, own_lat, own_lon)
    }

    private fun fetch_airplanes_live_exact_search(search: String?, own_lat: Double, own_lon: Double): FeedResult? {
        val path = airplanes_live_search_path(search) ?: return null
        if (System.currentTimeMillis() < airplanes_live_retry_after_ms) {
            return FeedResult(FeedStatus.RATE_LIMITED, FeedSource.AIRPLANES_LIVE, http_code = HTTP_TOO_MANY_REQUESTS)
        }
        return fetch_airplanes_live_path(path, own_lat, own_lon)
    }

    // All Airplanes.Live REST calls pass through the shared rate limiter and report failure instead of inventing data.
    private fun fetch_airplanes_live_path(path: String, own_lat: Double, own_lon: Double): FeedResult {
        var connection: HttpURLConnection? = null
        return try {
            AirplanesLiveHttp.wait_for_rest_api_slot()
            val url = URL("${AirplanesLiveHttp.API_BASE_URL}/$path")
            connection = open_connection(url)
            val code = connection.responseCode
            if (code == HttpURLConnection.HTTP_OK) {
                val body = connection.inputStream.bufferedReader().use { it.readText() }
                val json = JSONObject(body)
                FeedResult(
                    status = FeedStatus.OK,
                    source = FeedSource.AIRPLANES_LIVE,
                    aircraft = parse_airplanes_live_aircraft(json, own_lat, own_lon),
                    epoch_sec = json.feed_json_finite_double_or_null("now")?.let { normalize_epoch_seconds(it) },
                    query_count = 1
                )
            } else {
                if (code == HTTP_TOO_MANY_REQUESTS) {
                    val retry_seconds = connection.getHeaderField("Retry-After")?.toLongOrNull()
                        ?: DEFAULT_AIRPLANES_LIVE_BACKOFF_SECONDS
                    AirplanesLiveHttp.back_off_rest_api(retry_seconds)
                    airplanes_live_retry_after_ms = System.currentTimeMillis() + retry_seconds * 1000L
                }
                connection.errorStream?.close()
                FeedResult(
                    status = if (code == HTTP_TOO_MANY_REQUESTS) FeedStatus.RATE_LIMITED else FeedStatus.UNAVAILABLE,
                    source = FeedSource.AIRPLANES_LIVE,
                    http_code = code,
                    query_count = 1
                )
            }
        } catch (_: Exception) {
            FeedResult(FeedStatus.UNAVAILABLE, FeedSource.AIRPLANES_LIVE, query_count = 1)
        } finally {
            connection?.disconnect()
        }
    }

    private fun airplanes_live_search_path(search: String?): String? {
        val raw = search?.trim().orEmpty()
        if (raw.length < 2) return null
        val compact = raw.replace("\\s+".toRegex(), "").take(MAX_EXACT_SEARCH_CHARS)
        if (!EXACT_SEARCH_ALLOWED.matches(compact)) return null
        val upper = compact.uppercase(Locale.US)
        return when {
            MODE_S_HEX.matches(upper) -> "hex/${upper.lowercase(Locale.US)}"
            looks_like_registration_search(upper) -> "reg/${url_encode(upper)}"
            CALLSIGN_SEARCH.matches(upper) -> "callsign/${url_encode(upper)}"
            else -> null
        }
    }

    private fun looks_like_registration_search(upper: String): Boolean {
        return upper.startsWith("N") || upper.contains("-")
    }

    private fun url_encode(value: String): String = URLEncoder.encode(value, "UTF-8")

    // Build a bounded grid of point queries; mark partial coverage when the viewport is too large for one pass.
    private fun airplanes_live_query_plan(bounds: FeedBounds): AirplanesLiveQueryPlan {
        val normalized = bounds.normalized()
        val center_lat = (normalized.min_lat + normalized.max_lat) / 2.0
        val center_lon = (normalized.min_lon + normalized.max_lon) / 2.0
        val width_m = feed_distance_meters(center_lat, normalized.min_lon, center_lat, normalized.max_lon)
        val height_m = feed_distance_meters(normalized.min_lat, center_lon, normalized.max_lat, center_lon)
        val target_cell_span_m = MAX_AIRPLANES_RADIUS_NM * METERS_PER_NAUTICAL_MILE * AIRPLANES_GRID_CELL_RADIUS_FACTOR
        var columns = ceil(width_m / target_cell_span_m).toInt().coerceAtLeast(1)
        var rows = ceil(height_m / target_cell_span_m).toInt().coerceAtLeast(1)
        val needed_rows = rows
        val needed_columns = columns
        while (rows * columns > MAX_AIRPLANES_LIVE_QUERIES) {
            if (columns >= rows && columns > 1) columns-- else if (rows > 1) rows-- else break
        }

        val queries = mutableListOf<AirplanesLiveQuery>()
        for (row in 0 until rows) {
            val min_lat = lerp(normalized.min_lat, normalized.max_lat, row.toDouble() / rows)
            val max_lat = lerp(normalized.min_lat, normalized.max_lat, (row + 1.0) / rows)
            for (column in 0 until columns) {
                val min_lon = lerp(normalized.min_lon, normalized.max_lon, column.toDouble() / columns)
                val max_lon = lerp(normalized.min_lon, normalized.max_lon, (column + 1.0) / columns)
                val cell = FeedBounds(min_lat, min_lon, max_lat, max_lon)
                val cell_center_lat = (min_lat + max_lat) / 2.0
                val cell_center_lon = (min_lon + max_lon) / 2.0
                queries += AirplanesLiveQuery(
                    center_lat = cell_center_lat,
                    center_lon = cell_center_lon,
                    radius_nm = radius_nm_for(cell, cell_center_lat, cell_center_lon)
                        .times(AIRPLANES_QUERY_RADIUS_PADDING)
                        .coerceIn(MIN_AIRPLANES_RADIUS_NM, MAX_AIRPLANES_RADIUS_NM)
                )
            }
        }

        return AirplanesLiveQueryPlan(
            queries = queries.ifEmpty {
                listOf(AirplanesLiveQuery(center_lat, center_lon, MIN_AIRPLANES_RADIUS_NM))
            },
            partial_coverage = rows < needed_rows || columns < needed_columns
        )
    }

    private fun open_connection(url: URL): HttpURLConnection {
        require(url.protocol.equals("https", ignoreCase = true)) { "Only HTTPS aircraft feeds are allowed" }
        return (url.openConnection() as HttpURLConnection).apply {
            connectTimeout = 4000
            readTimeout = 6000
            requestMethod = "GET"
            if (url.host.equals("api.airplanes.live", ignoreCase = true)) {
                AirplanesLiveHttp.apply_browser_headers(this, user_agent)
            } else {
                setRequestProperty("User-Agent", user_agent)
                setRequestProperty("Accept", "application/json")
            }
        }
    }

    // Translate OpenSky arrays into the app feed model while leaving missing fields null.
    private fun parse_open_sky_aircraft(json: JSONObject, own_lat: Double, own_lon: Double): List<FeedAircraft> {
        val rows = json.optJSONArray("states") ?: JSONArray()
        val parsed = mutableListOf<FeedAircraft>()
        for (index in 0 until rows.length()) {
            val row = rows.optJSONArray(index) ?: continue
            val lon = row.json_number_or_null(5) ?: continue
            val lat = row.json_number_or_null(6) ?: continue
            val icao24 = row.optString(0).trim()
            val callsign = row.optString(1).trim().ifEmpty { icao24.ifEmpty { "Unknown" } }
            val altitude_m = row.json_number_or_null(7) ?: row.json_number_or_null(13)
            val velocity_ms = row.json_number_or_null(9)
            val vertical_rate_ms = row.json_number_or_null(11)
            parsed += FeedAircraft(
                icao24 = icao24,
                callsign = callsign,
                registration = null,
                type_code = null,
                db_flags = null,
                lat = lat,
                lon = lon,
                on_ground = row.feed_json_array_boolean_or_null(8),
                altitude_m = altitude_m,
                velocity_ms = velocity_ms,
                track_deg = row.json_number_or_null(10),
                vertical_rate_ms = vertical_rate_ms,
                category = row.json_int_or_null(17),
                position_time_sec = row.json_number_or_null(3),
                last_contact_sec = row.json_number_or_null(4),
                distance_m = feed_distance_meters(own_lat, own_lon, lat, lon),
                telemetry = AircraftTelemetry(
                    source_type = "OpenSky",
                    baro_altitude_m = altitude_m,
                    ground_speed_ms = velocity_ms,
                    baro_rate_ms = vertical_rate_ms
                ).takeIf { it.has_values }
            )
        }
        return parsed.sortedBy { it.distance_m }
    }

    // Translate Airplanes.Live objects into the app feed model without filling missing source fields.
    private fun parse_airplanes_live_aircraft(json: JSONObject, own_lat: Double, own_lon: Double): List<FeedAircraft> {
        val now_sec = json.feed_json_finite_double_or_null("now")?.let { normalize_epoch_seconds(it) } ?: (System.currentTimeMillis() / 1000.0)
        val rows = json.optJSONArray("aircraft") ?: json.optJSONArray("ac") ?: JSONArray()
        val parsed = mutableListOf<FeedAircraft>()
        for (index in 0 until rows.length()) {
            val item = rows.optJSONObject(index) ?: continue
            val lat = item.feed_json_finite_double_or_null("lat") ?: item.optJSONObject("lastPosition")?.feed_json_finite_double_or_null("lat") ?: continue
            val lon = item.feed_json_finite_double_or_null("lon") ?: item.optJSONObject("lastPosition")?.feed_json_finite_double_or_null("lon") ?: continue
            val icao24 = item.optString("hex").trim().lowercase(Locale.US)
            val callsign = item.optString("flight").trim().ifEmpty { item.optString("r").trim().ifEmpty { icao24.ifEmpty { "Unknown" } } }
            val type_code = item.optString("t").trim().ifEmpty { null }
            val altitude_feet = item.json_number_or_null("alt_baro") ?: item.json_number_or_null("alt_geom")
            val seen_position_sec = item.feed_json_finite_double_or_null("seen_pos")
            val seen_message_sec = item.feed_json_finite_double_or_null("seen")
            val last_position_time = seen_position_sec?.let { now_sec - it }
            val last_contact_time = seen_message_sec?.let { now_sec - it } ?: last_position_time
            val vertical_rate_ms = (item.feed_json_finite_double_or_null("baro_rate") ?: item.feed_json_finite_double_or_null("geom_rate"))
                ?.let { feed_feet_per_minute_to_meters_per_second(it) }
            val telemetry = item.airplanes_live_telemetry()
            parsed += FeedAircraft(
                icao24 = icao24,
                callsign = callsign,
                registration = item.optString("r").trim().ifEmpty { null },
                type_code = type_code,
                db_flags = item.feed_json_int_or_null("dbFlags"),
                lat = lat,
                lon = lon,
                on_ground = item.optString("alt_baro") == "ground",
                altitude_m = altitude_feet?.let { it / FEET_PER_METER },
                velocity_ms = item.feed_json_finite_double_or_null("gs")?.let { feed_knots_to_meters_per_second(it) },
                track_deg = item.feed_json_finite_double_or_null("track"),
                vertical_rate_ms = vertical_rate_ms,
                category = category_from_airplanes_live(item.optString("category"), item.optString("t")),
                position_time_sec = last_position_time,
                last_contact_sec = last_contact_time,
                distance_m = feed_distance_meters(own_lat, own_lon, lat, lon),
                telemetry = telemetry
            )
        }
        return parsed.sortedBy { it.distance_m }
    }

    private fun JSONObject.airplanes_live_telemetry(): AircraftTelemetry? {
        val telemetry = AircraftTelemetry(
            source_type = feed_json_string_or_null("type") ?: feed_json_string_or_null("source_type"),
            squawk = feed_json_string_or_null("squawk"),
            baro_altitude_m = json_number_or_null("alt_baro")?.let { it / FEET_PER_METER },
            geom_altitude_m = json_number_or_null("alt_geom")?.let { it / FEET_PER_METER },
            ground_speed_ms = feed_json_finite_double_or_null("gs")?.let { feed_knots_to_meters_per_second(it) },
            true_speed_ms = feed_json_finite_double_or_null("tas")?.let { feed_knots_to_meters_per_second(it) },
            indicated_speed_ms = feed_json_finite_double_or_null("ias")?.let { feed_knots_to_meters_per_second(it) },
            mach = feed_json_finite_double_or_null("mach"),
            baro_rate_ms = feed_json_finite_double_or_null("baro_rate")?.let { feed_feet_per_minute_to_meters_per_second(it) },
            geom_rate_ms = feed_json_finite_double_or_null("geom_rate")?.let { feed_feet_per_minute_to_meters_per_second(it) },
            selected_altitude_m = (json_number_or_null("nav_altitude_mcp") ?: json_number_or_null("nav_altitude_fms"))?.let { it / FEET_PER_METER },
            selected_heading_deg = feed_json_finite_double_or_null("nav_heading"),
            wind_speed_ms = feed_json_finite_double_or_null("ws")?.let { feed_knots_to_meters_per_second(it) },
            wind_direction_deg = feed_json_finite_double_or_null("wd"),
            tat_c = feed_json_finite_double_or_null("tat"),
            oat_c = feed_json_finite_double_or_null("oat"),
            qnh_hpa = feed_json_finite_double_or_null("nav_qnh"),
            true_heading_deg = feed_json_finite_double_or_null("true_heading"),
            magnetic_heading_deg = feed_json_finite_double_or_null("mag_heading"),
            magnetic_declination_deg = feed_json_finite_double_or_null("mag_declination"),
            track_rate_deg_per_sec = feed_json_finite_double_or_null("track_rate"),
            roll_deg = feed_json_finite_double_or_null("roll"),
            nav_modes = feed_json_string_list("nav_modes"),
            adsb_version = feed_json_number_as_string_or_null("version")?.let { "v$it" },
            nac_p = feed_json_int_or_null("nac_p"),
            nac_v = feed_json_int_or_null("nac_v"),
            sil = feed_json_int_or_null("sil"),
            sil_type = feed_json_string_or_null("sil_type"),
            nic_baro = feed_json_number_as_string_or_null("nic_baro"),
            rc_m = feed_json_finite_double_or_null("rc"),
            rssi = feed_json_finite_double_or_null("rssi"),
            message_rate = feed_json_message_rate_or_null(),
            receiver_count_label = feed_json_receiver_count_label(),
            category_label = feed_json_string_or_null("category")
        )
        return telemetry.takeIf { it.has_values }
    }

    private fun radius_nm_for(bounds: FeedBounds, center_lat: Double, center_lon: Double): Double {
        val corners = listOf(
            bounds.min_lat to bounds.min_lon,
            bounds.min_lat to bounds.max_lon,
            bounds.max_lat to bounds.min_lon,
            bounds.max_lat to bounds.max_lon
        )
        return corners.maxOf { (lat, lon) -> feed_distance_meters(center_lat, center_lon, lat, lon) } / METERS_PER_NAUTICAL_MILE
    }

    private fun category_from_airplanes_live(category: String, type_code: String): Int? {
        val normalized = category.trim().uppercase(Locale.US)
        if (normalized.startsWith("A7") || normalized.startsWith("B7")) return 8
        if (normalized.startsWith("B1")) return 9
        if (normalized.startsWith("B6")) return 14
        if (normalized.startsWith("C") || normalized.startsWith("D")) return 15
        val type = type_code.trim().uppercase(Locale.US)
        return when {
            type.startsWith("H") || type.startsWith("R") -> 8
            type.startsWith("GL") -> 9
            type.startsWith("UAV") || type.startsWith("DRON") -> 14
            else -> null
        }
    }

    private fun normalize_epoch_seconds(value: Double): Double {
        return if (value > 10_000_000_000.0) value / 1000.0 else value
    }

    
    // When two feeds report the same aircraft, keep the one with the newest contact time.
    private fun newer_aircraft(existing: FeedAircraft?, incoming: FeedAircraft): FeedAircraft {
        if (existing == null) return incoming
        val existing_time = existing.last_contact_sec ?: existing.position_time_sec ?: 0.0
        val incoming_time = incoming.last_contact_sec ?: incoming.position_time_sec ?: 0.0
        return if (incoming_time >= existing_time) incoming else existing
    }

    private fun lerp(start: Double, end: Double, amount: Double): Double {
        return start + (end - start) * amount
    }

    private fun merged_source(first: FeedSource, second: FeedSource): FeedSource {
        return if (first == second) first else FeedSource.COMBINED
    }

    companion object {
        private const val HTTP_TOO_MANY_REQUESTS = FlightAlertSettings.AircraftFeed.HTTP_TOO_MANY_REQUESTS
        private const val DEFAULT_OPENSKY_BACKOFF_SECONDS = FlightAlertSettings.AircraftFeed.DEFAULT_OPENSKY_BACKOFF_SECONDS
        private const val DEFAULT_AIRPLANES_LIVE_BACKOFF_SECONDS = FlightAlertSettings.AircraftFeed.DEFAULT_AIRPLANES_LIVE_BACKOFF_SECONDS
        private const val MIN_AIRPLANES_RADIUS_NM = FlightAlertSettings.AircraftFeed.MIN_AIRPLANES_RADIUS_NM
        private const val MAX_AIRPLANES_RADIUS_NM = FlightAlertSettings.AircraftFeed.MAX_AIRPLANES_RADIUS_NM
        private const val MAX_AIRPLANES_LIVE_QUERIES = FlightAlertSettings.AircraftFeed.MAX_AIRPLANES_LIVE_QUERIES
        private const val AIRPLANES_GRID_CELL_RADIUS_FACTOR = FlightAlertSettings.AircraftFeed.AIRPLANES_GRID_CELL_RADIUS_FACTOR
        private const val AIRPLANES_QUERY_RADIUS_PADDING = FlightAlertSettings.AircraftFeed.AIRPLANES_QUERY_RADIUS_PADDING
        private const val METERS_PER_NAUTICAL_MILE = 1852.0
        private const val FEET_PER_METER = 3.28084
        private const val MAX_EXACT_SEARCH_CHARS = FlightAlertSettings.AircraftFeed.MAX_EXACT_SEARCH_CHARS
        private val EXACT_SEARCH_ALLOWED = Regex("^[A-Za-z0-9-]+$")
        private val MODE_S_HEX = Regex("^[0-9A-F]{6}$")
        private val CALLSIGN_SEARCH = Regex("^[A-Z0-9]{2,12}$")

        @Volatile
        private var open_sky_retry_after_ms = 0L

        @Volatile
        private var airplanes_live_retry_after_ms = 0L
    }
}

private data class AirplanesLiveQuery(val center_lat: Double, val center_lon: Double, val radius_nm: Double)

private data class AirplanesLiveQueryPlan(val queries: List<AirplanesLiveQuery>, val partial_coverage: Boolean)


private fun JSONArray.feed_json_array_boolean_or_null(index: Int): Boolean? {
    if (index >= length() || isNull(index)) return null
    return optBoolean(index)
}

private fun JSONObject.feed_json_int_or_null(key: String): Int? {
    return if (has(key) && !isNull(key)) optInt(key) else null
}

private fun JSONObject.feed_json_finite_double_or_null(key: String): Double? {
    return if (has(key) && !isNull(key)) optDouble(key).takeIf { it.isFinite() } else null
}


private fun JSONObject.feed_json_string_or_null(key: String): String? {
    if (!has(key) || isNull(key)) return null
    return optString(key).trim().takeIf { it.isNotBlank() && !it.equals("n/a", ignoreCase = true) }
}

private fun JSONObject.feed_json_number_as_string_or_null(key: String): String? {
    if (!has(key) || isNull(key)) return null
    return when (val raw = opt(key)) {
        is Number -> raw.toString()
        is String -> raw.trim().takeIf { it.isNotBlank() && !it.equals("n/a", ignoreCase = true) }
        else -> null
    }
}

private fun JSONObject.feed_json_string_list(key: String): List<String> {
    if (!has(key) || isNull(key)) return emptyList()
    val raw = opt(key)
    if (raw is JSONArray) {
        val values = mutableListOf<String>()
        for (index in 0 until raw.length()) {
            raw.optString(index).trim().takeIf { it.isNotBlank() }?.let { values += it }
        }
        return values
    }
    return (raw?.toString() ?: return emptyList())
        .split(",", " ")
        .map { it.trim() }
        .filter { it.isNotBlank() && !it.equals("n/a", ignoreCase = true) }
}

private fun JSONObject.feed_json_message_rate_or_null(): Double? {
    return feed_json_finite_double_or_null("message_rate")
        ?: feed_json_finite_double_or_null("msgRate")
        ?: feed_json_finite_double_or_null("messageRate")
}

private fun JSONObject.feed_json_receiver_count_label(): String? {
    for (key in listOf("receivers", "receiver_count", "receiverCount", "siteCount")) {
        if (!has(key) || isNull(key)) continue
        when (val raw = opt(key)) {
            is Number -> return raw.toInt().toString()
            is String -> raw.trim().takeIf { it.isNotBlank() && !it.equals("n/a", ignoreCase = true) }?.let { return it }
        }
    }
    return null
}

private fun feed_distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double =
    clamped_haversine_distance_meters(lat1, lon1, lat2, lon2)

private fun feed_knots_to_meters_per_second(knots: Double): Double = knots * 0.514444

private fun feed_feet_per_minute_to_meters_per_second(feet_per_minute: Double): Double = feet_per_minute / 196.850394


class AviationLayerClient(private val user_agent: String) {

    fun fetch_layers(
        bounds: AviationLayerBounds,
        include_atc_boundaries: Boolean,
        include_restricted_airspaces: Boolean,
        include_airports: Boolean,
        include_oceanic_tracks: Boolean
    ): AviationLayerSnapshot {
        val statuses = mutableMapOf<AviationLayerKind, AviationLayerStatus>()
        val atc = if (include_atc_boundaries) {
            fetch_feature_layer(
                kind = AviationLayerKind.ATC_BOUNDARIES,
                bounds = bounds,
                base_url = BOUNDARY_AIRSPACE_QUERY_URL,
                where = "TYPE_CODE IN ('ARTCC','FIR','OCA')",
                out_fields = "NAME,IDENT,TYPE_CODE,LOCAL_TYPE,LEVEL_,UPPER_VAL,LOWER_VAL",
                max_records = MAX_BOUNDARY_RECORDS,
                statuses = statuses,
                parser = ::parse_airspace_features
            )
        } else {
            emptyList()
        }
        val restricted = if (include_restricted_airspaces) {
            fetch_feature_layer(
                kind = AviationLayerKind.RESTRICTED_AIRSPACES,
                bounds = bounds,
                base_url = SPECIAL_USE_AIRSPACE_QUERY_URL,
                where = "1=1",
                out_fields = "NAME,TYPE_CODE,UPPER_VAL,LOWER_VAL,UPPER_UOM,LOWER_UOM,TIMESOFUSE,CITY,STATE",
                max_records = MAX_SPECIAL_USE_RECORDS,
                statuses = statuses,
                parser = ::parse_airspace_features
            )
        } else {
            emptyList()
        }
        val airports = if (include_airports) {
            fetch_feature_layer(
                kind = AviationLayerKind.AIRPORTS,
                bounds = bounds,
                base_url = AIRPORT_QUERY_URL,
                where = "OPERSTATUS = 'OPERATIONAL'",
                out_fields = "IDENT,NAME,ICAO_ID,TYPE_CODE,MIL_CODE,SERVCITY,STATE,COUNTRY",
                max_records = MAX_AIRPORT_RECORDS,
                statuses = statuses,
                parser = ::parse_airport_features
            )
        } else {
            emptyList()
        }
        val oceanic = if (include_oceanic_tracks) {
            fetch_oceanic_tracks(statuses)
        } else {
            emptyList()
        }

        return AviationLayerSnapshot(
            atc_boundaries = atc,
            restricted_airspaces = restricted,
            airports = airports,
            oceanic_tracks = oceanic,
            statuses = statuses,
            fetched_at_ms = System.currentTimeMillis()
        )
    }

    private fun <T> fetch_feature_layer(
        kind: AviationLayerKind,
        bounds: AviationLayerBounds,
        base_url: String,
        where: String,
        out_fields: String,
        max_records: Int,
        statuses: MutableMap<AviationLayerKind, AviationLayerStatus>,
        parser: (JSONObject) -> List<T>
    ): List<T> {
        return try {
            val url = URL(
                "$base_url?f=geojson" +
                    "&where=${encode(where)}" +
                    "&geometry=${encode(bounds.arc_gis_envelope())}" +
                    "&geometryType=esriGeometryEnvelope" +
                    "&inSR=4326" +
                    "&spatialRel=esriSpatialRelIntersects" +
                    "&outFields=${encode(out_fields)}" +
                    "&outSR=4326" +
                    "&returnGeometry=true" +
                    "&resultRecordCount=$max_records"
            )
            val json = fetch_json(url)
            val parsed = parser(json)
            statuses[kind] = if (parsed.isEmpty()) {
                AviationLayerStatus(AviationLayerState.EMPTY, "No ${kind.display_name.lowercase(Locale.US)} in view")
            } else {
                AviationLayerStatus(AviationLayerState.LOADED, "${parsed.size} ${kind.display_name.lowercase(Locale.US)} loaded")
            }
            parsed
        } catch (_: Exception) {
            statuses[kind] = AviationLayerStatus(AviationLayerState.UNAVAILABLE, "${kind.display_name} unavailable")
            emptyList()
        }
    }

    private fun fetch_oceanic_tracks(statuses: MutableMap<AviationLayerKind, AviationLayerStatus>): List<AviationOceanicTrack> {
        return try {
            val json = fetch_json_array(URL(NAT_TRACKS_URL))
            val tracks = parse_nat_tracks(json)
            statuses[AviationLayerKind.OCEANIC_TRACKS] = if (tracks.isEmpty()) {
                AviationLayerStatus(AviationLayerState.EMPTY, "No drawable NAT track coordinates")
            } else {
                AviationLayerStatus(AviationLayerState.LOADED, "${tracks.size} NAT tracks loaded")
            }
            tracks
        } catch (_: Exception) {
            statuses[AviationLayerKind.OCEANIC_TRACKS] = AviationLayerStatus(AviationLayerState.UNAVAILABLE, "NAT tracks unavailable")
            emptyList()
        }
    }

    private fun parse_airspace_features(json: JSONObject): List<AviationAirspaceFeature> {
        val features = json.optJSONArray("features") ?: JSONArray()
        val parsed = mutableListOf<AviationAirspaceFeature>()
        for (index in 0 until features.length()) {
            val feature = features.optJSONObject(index) ?: continue
            val properties = feature.optJSONObject("properties") ?: JSONObject()
            val rings = polygon_rings(feature.optJSONObject("geometry")).take(MAX_RINGS_PER_FEATURE)
            if (rings.isEmpty()) continue
            val type = properties.aviation_json_clean_string("TYPE_CODE") ?: properties.aviation_json_clean_string("LOCAL_TYPE") ?: "Airspace"
            val name = properties.aviation_json_clean_string("NAME")
                ?: properties.aviation_json_clean_string("IDENT")
                ?: type
            parsed += AviationAirspaceFeature(
                name = name,
                type = type,
                lower_limit = altitude_label(properties, "LOWER"),
                upper_limit = altitude_label(properties, "UPPER"),
                schedule = properties.aviation_json_clean_string("TIMESOFUSE"),
                city = properties.aviation_json_clean_string("CITY"),
                state = properties.aviation_json_clean_string("STATE"),
                rings = rings,
                bounds = rings.flatten().to_bounds()
            )
        }
        return parsed
    }

    private fun parse_airport_features(json: JSONObject): List<AviationAirportFeature> {
        val features = json.optJSONArray("features") ?: JSONArray()
        val parsed = mutableListOf<AviationAirportFeature>()
        for (index in 0 until features.length()) {
            val feature = features.optJSONObject(index) ?: continue
            val geometry = feature.optJSONObject("geometry") ?: continue
            if (geometry.optString("type") != "Point") continue
            val coordinates = geometry.optJSONArray("coordinates") ?: continue
            val lon = coordinates.json_number_or_null(0) ?: continue
            val lat = coordinates.json_number_or_null(1) ?: continue
            val properties = feature.optJSONObject("properties") ?: JSONObject()
            val ident = properties.aviation_json_clean_string("ICAO_ID")
                ?: properties.aviation_json_clean_string("IDENT")
                ?: continue
            val name = properties.aviation_json_clean_string("NAME") ?: ident
            parsed += AviationAirportFeature(
                ident = ident,
                name = name,
                type = properties.aviation_json_clean_string("TYPE_CODE") ?: "AD",
                military = properties.aviation_json_clean_string("MIL_CODE")?.contains("MIL", ignoreCase = true) == true,
                lat = lat,
                lon = lon
            )
        }
        return parsed
    }

    private fun parse_nat_tracks(json: JSONArray): List<AviationOceanicTrack> {
        val tracks = linkedMapOf<String, AviationOceanicTrack>()
        for (index in 0 until json.length()) {
            val item = json.optJSONObject(index) ?: continue
            val source = item.aviation_json_clean_string("notam_number_formatted") ?: item.aviation_json_clean_string("icao_id") ?: "FAA NMS"
            val window = listOfNotNull(item.aviation_json_clean_string("start_datetime"), item.aviation_json_clean_string("end_datetime"))
                .joinToString(" to ")
                .ifBlank { null }
            val message = item.aviation_json_clean_string("condition_message") ?: continue
            message.split('\n')
                .map { it.trim().trimEnd('-') }
                .forEach { line ->
                    val tokens = line.split(Regex("\\s+")).filter { it.isNotBlank() }
                    if (tokens.size < 3) return@forEach
                    val designator = tokens.first().takeIf { TRACK_DESIGNATOR.matches(it) } ?: return@forEach
                    val points = tokens.drop(1).mapNotNull(::parse_nat_coordinate)
                    if (points.size < 2) return@forEach
                    val key = "$source:$designator"
                    tracks[key] = AviationOceanicTrack(
                        name = "NAT $designator",
                        source = source,
                        active_window = window,
                        points = points,
                        bounds = points.to_bounds()
                    )
                }
        }
        return tracks.values.toList()
    }

    private fun parse_nat_coordinate(raw: String): AviationLayerPoint? {
        val token = raw.trim().uppercase(Locale.US).trimEnd(',', '.', ';')
        val match = NAT_COORDINATE.matchEntire(token) ?: return null
        val lat_degrees = match.groupValues[1].toDoubleOrNull() ?: return null
        val lat_minutes = match.groupValues[2].takeIf { it.isNotBlank() }?.toDoubleOrNull()?.div(60.0) ?: 0.0
        val lon_degrees = match.groupValues[3].toDoubleOrNull() ?: return null
        val lon_minutes = match.groupValues[4].takeIf { it.isNotBlank() }?.toDoubleOrNull()?.div(60.0) ?: 0.0
        val lat = lat_degrees + lat_minutes
        val lon = -(lon_degrees + lon_minutes)
        if (lat !in -90.0..90.0 || lon !in -180.0..180.0) return null
        return AviationLayerPoint(lat, lon)
    }

    private fun polygon_rings(geometry: JSONObject?): List<List<AviationLayerPoint>> {
        geometry ?: return emptyList()
        return when (geometry.optString("type")) {
            "Polygon" -> geometry.optJSONArray("coordinates").polygon_to_rings()
            "MultiPolygon" -> {
                val coordinates = geometry.optJSONArray("coordinates") ?: return emptyList()
                val rings = mutableListOf<List<AviationLayerPoint>>()
                for (index in 0 until coordinates.length()) {
                    rings += coordinates.optJSONArray(index).polygon_to_rings()
                }
                rings
            }
            else -> emptyList()
        }
    }

    private fun JSONArray?.polygon_to_rings(): List<List<AviationLayerPoint>> {
        this ?: return emptyList()
        val rings = mutableListOf<List<AviationLayerPoint>>()
        for (ring_index in 0 until length()) {
            val ring = optJSONArray(ring_index) ?: continue
            val points = mutableListOf<AviationLayerPoint>()
            for (point_index in 0 until ring.length()) {
                val coordinate = ring.optJSONArray(point_index) ?: continue
                val lon = coordinate.json_number_or_null(0) ?: continue
                val lat = coordinate.json_number_or_null(1) ?: continue
                points += AviationLayerPoint(lat, lon)
            }
            if (points.size >= MIN_RING_POINTS) rings += points
        }
        return rings
    }

    private fun altitude_label(properties: JSONObject, prefix: String): String? {
        val value = properties.json_number_or_null("${prefix}_VAL") ?: return null
        if (value <= MISSING_ALTITUDE_SENTINEL) return null
        val unit = properties.aviation_json_clean_string("${prefix}_UOM") ?: return null
        return "${value.toInt()} $unit"
    }

    private fun fetch_json(url: URL): JSONObject {
        return JSONObject(fetch_text(url))
    }

    private fun fetch_json_array(url: URL): JSONArray {
        return JSONArray(fetch_text(url))
    }

    private fun fetch_text(url: URL): String {
        require(url.protocol.equals("https", ignoreCase = true)) { "Only HTTPS aviation layers are allowed" }
        var connection: HttpURLConnection? = null
        return try {
            connection = (url.openConnection() as HttpURLConnection).apply {
                connectTimeout = CONNECT_TIMEOUT_MS
                readTimeout = READ_TIMEOUT_MS
                requestMethod = "GET"
                setRequestProperty("User-Agent", user_agent)
                setRequestProperty("Accept", "application/json")
            }
            val code = connection.responseCode
            if (code != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                throw IllegalStateException("HTTP $code")
            }
            connection.inputStream.bufferedReader().use { it.readText() }
        } finally {
            connection?.disconnect()
        }
    }

    private fun encode(value: String): String = URLEncoder.encode(value, "UTF-8")

    companion object {
        private const val BOUNDARY_AIRSPACE_QUERY_URL =
            "https://services6.arcgis.com/ssFJjBXIUyZDrSYZ/arcgis/rest/services/Boundary_Airspace/FeatureServer/0/query"
        private const val SPECIAL_USE_AIRSPACE_QUERY_URL =
            "https://services6.arcgis.com/ssFJjBXIUyZDrSYZ/arcgis/rest/services/Special_Use_Airspace/FeatureServer/0/query"
        private const val AIRPORT_QUERY_URL =
            "https://services6.arcgis.com/ssFJjBXIUyZDrSYZ/arcgis/rest/services/US_Airport/FeatureServer/0/query"
        private const val NAT_TRACKS_URL = "https://nms.aim.faa.gov/datanat/nat.json"
        private const val CONNECT_TIMEOUT_MS = 5000
        private const val READ_TIMEOUT_MS = 9000
        private const val MAX_BOUNDARY_RECORDS = 80
        private const val MAX_SPECIAL_USE_RECORDS = 140
        private const val MAX_AIRPORT_RECORDS = 220
        private const val MAX_RINGS_PER_FEATURE = 8
        private const val MIN_RING_POINTS = 3
        private const val MISSING_ALTITUDE_SENTINEL = -9000.0
        private val TRACK_DESIGNATOR = Regex("^[A-Z]$")
        private val NAT_COORDINATE = Regex("^(\\d{2})(\\d{2})?/(\\d{2,3})(\\d{2})?$")
    }
}

private fun JSONObject.aviation_json_clean_string(key: String): String? {
    if (!has(key) || isNull(key)) return null
    return optString(key).trim().takeIf { it.isNotBlank() }
}


class FlightTraceClient(private val user_agent: String) {

    fun fetch_flight_trace(
        icao24: String,
        live_point: TrackPoint? = null,
        type_code: String? = null
    ): FlightTrace? {
        val clean_icao = icao24.trim().lowercase(Locale.US)
        if (clean_icao.isEmpty()) return null

        val source = fetch_trace_source(clean_icao) ?: return null
        val trace = parse_adsb_trace(source.name, listOfNotNull(source.full_json, source.recent_json), live_point, type_code)
        return trace.takeIf { it.point_count >= TRACE_MIN_TRACE_POINTS }
    }

    private fun fetch_trace_source(clean_icao: String): TraceSource? {
        for (provider in TRACE_PROVIDERS) {
            val full_json = fetch_trace(provider, clean_icao, "full") ?: continue
            val recent_json = runCatching { fetch_trace(provider, clean_icao, "recent") }.getOrNull()
            return TraceSource(provider.name, full_json, recent_json)
        }
        return null
    }

    private fun fetch_trace(provider: TraceProvider, clean_icao: String, kind: String): JSONObject? {
        val folder = clean_icao.takeLast(2)
        val url = URL("${provider.base_url}/data/traces/$folder/trace_${kind}_$clean_icao.json")
        if (!url.protocol.equals("https", ignoreCase = true)) return null
        val connection = (url.openConnection() as HttpURLConnection).apply {
            connectTimeout = 9000
            readTimeout = 16000
            requestMethod = "GET"
            AirplanesLiveHttp.apply_browser_headers(this, user_agent, provider.referer)
        }

        return try {
            if (connection.responseCode != HttpURLConnection.HTTP_OK) return null
            JSONObject(connection.inputStream.bufferedReader().use { it.readText() })
        } finally {
            connection.disconnect()
        }
    }

    private fun parse_adsb_trace(
        source_name: String,
        jsons: List<JSONObject>,
        live_point: TrackPoint?,
        type_code: String?
    ): FlightTrace {
        if (jsons.isEmpty()) return FlightTrace.empty()
        val metadata = jsons.first()
        val trace_type_code = metadata.optString("t").trim().ifEmpty { null }
        val effective_type_code = type_code?.trim()?.ifEmpty { null } ?: trace_type_code
        val all_points = normalized(jsons.flatMap { parse_trace_points(it) })
        val current_leg = current_flight_leg(all_points)
        val segments = trace_segments(current_leg).toMutableList()
        val current_start_sec = segments.firstOrNull()?.points?.firstOrNull()?.epoch_sec
            ?: current_leg.firstOrNull()?.point?.epoch_sec
        val previous_segments = previous_flight_segments(all_points, current_start_sec)
        val live_state = append_live_point_if_current(segments, live_point)

        if (live_point != null && live_state == LiveTraceState.STALE_OR_DISCONNECTED && !source_trace_is_current(segments)) {
            return FlightTrace.empty()
        }

        val point_count = segments.sumOf { it.points.size }
        val start = segments.firstOrNull()?.points?.firstOrNull()
        val end = segments.lastOrNull()?.points?.lastOrNull()
        val duration = if (start != null && end != null) end.epoch_sec - start.epoch_sec else 0L
        if (point_count < TRACE_MIN_TRACE_POINTS || duration < TRACE_MIN_TRACE_DURATION_SECONDS) {
            return FlightTrace.empty()
        }

        val source_parts = mutableListOf("$source_name trace_full")
        if (jsons.size > 1) source_parts += "trace_recent"
        if (live_state == LiveTraceState.APPENDED) source_parts += "live ADS-B"

        return FlightTrace(
            source = source_parts.joinToString(" + "),
            registration = metadata.optString("r").trim().ifEmpty { null },
            type_code = trace_type_code ?: effective_type_code,
            aircraft_description = metadata.optString("desc").trim().ifEmpty { null },
            segments = segments,
            previous_segments = previous_segments
        )
    }

    private fun parse_trace_points(json: JSONObject): List<TracePointWithFlags> {
        val base_epoch_sec = json.trace_json_double_or_null("timestamp") ?: return emptyList()
        val trace = json.optJSONArray("trace") ?: return emptyList()
        val points = mutableListOf<TracePointWithFlags>()

        for (index in 0 until trace.length()) {
            val row = trace.optJSONArray(index) ?: continue
            val offset_sec = row.json_number_or_null(0) ?: continue
            val lat = row.json_number_or_null(1) ?: continue
            val lon = row.json_number_or_null(2) ?: continue
            val altitude = row.opt(3)
            val flags = row.json_int_or_null(6) ?: 0
            val on_ground = altitude is String && altitude.equals("ground", ignoreCase = true)
            val point = TrackPoint(
                lat = lat,
                lon = lon,
                epoch_sec = (base_epoch_sec + offset_sec).roundToLong(),
                altitude_m = when (altitude) {
                    is Number -> altitude.toDouble() / TRACE_FEET_PER_METER
                    is String -> altitude.toDoubleOrNull()?.div(TRACE_FEET_PER_METER) ?: if (on_ground) 0.0 else null
                    else -> null
                },
                track_deg = row.json_number_or_null(5),
                on_ground = on_ground
            )
            points += TracePointWithFlags(
                point = point,
                starts_new_leg = flags and TRACE_FLAG_NEW_LEG != 0,
                ground_speed_kt = row.json_number_or_null(4)
            )
        }
        return points
    }

    private fun normalized(points: List<TracePointWithFlags>): List<TracePointWithFlags> {
        return points
            .filter {
                it.point.lat.isFinite() &&
                    it.point.lon.isFinite() &&
                    it.point.lat in -90.0..90.0 &&
                    it.point.lon in -180.0..180.0 &&
                    it.point.epoch_sec > 0L
            }
            .distinctBy { "${it.point.epoch_sec}:${"%.5f".format(Locale.US, it.point.lat)}:${"%.5f".format(Locale.US, it.point.lon)}" }
            .sortedBy { it.point.epoch_sec }
    }

    private fun latest_source_leg(points: List<TracePointWithFlags>): List<TracePointWithFlags> {
        if (points.isEmpty()) return emptyList()
        val start_index = points.indexOfLast { it.starts_new_leg }.takeIf { it >= 0 } ?: 0
        return points.drop(start_index)
    }

    private fun trace_segments(points: List<TracePointWithFlags>): List<TraceSegment> {
        return continuous_segments(points)
            .map { segment -> TraceSegment(segment.map { it.point }) }
            .filter { it.points.size >= TRACE_MIN_SEGMENT_POINTS }
    }

    private fun previous_flight_segments(
        points: List<TracePointWithFlags>,
        current_start_sec: Long?
    ): List<TraceSegment> {
        current_start_sec ?: return emptyList()
        val historical_points = points.takeWhile { it.point.epoch_sec < current_start_sec }
        if (historical_points.size < TRACE_MIN_SEGMENT_POINTS) return emptyList()
        return trace_segments(historical_points)
            .filter { segment -> is_completed_previous_flight(segment.points, current_start_sec) }
            .takeLast(TRACE_MAX_PREVIOUS_FLIGHT_SEGMENTS)
    }

    private fun is_completed_previous_flight(points: List<TrackPoint>, current_start_sec: Long): Boolean {
        if (points.size < TRACE_MIN_SEGMENT_POINTS) return false
        val first = points.first()
        val last = points.last()
        if (last.epoch_sec >= current_start_sec || last.epoch_sec - first.epoch_sec < TRACE_MIN_TRACE_DURATION_SECONDS) return false
        val airborne_points = points.count { point ->
            point.on_ground != true && (point.altitude_m == null || point.altitude_m * TRACE_FEET_PER_METER >= TRACE_MIN_PREVIOUS_FLIGHT_ALTITUDE_FT)
        }
        if (airborne_points < TRACE_MIN_SEGMENT_POINTS / 2) return false
        return path_distance_meters(points) >= TRACE_MIN_PREVIOUS_FLIGHT_DISTANCE_M
    }

    private fun path_distance_meters(points: List<TrackPoint>): Double {
        var distance = 0.0
        for (index in 1 until points.size) {
            val previous = points[index - 1]
            val current = points[index]
            distance += distance_meters(previous.lat, previous.lon, current.lat, current.lon)
        }
        return distance
    }

    private fun current_flight_leg(points: List<TracePointWithFlags>): List<TracePointWithFlags> {
        if (points.isEmpty()) return emptyList()
        // tar1090/readsb traces mark new legs at the source; prefer that boundary over app-side trip stitching.
        if (points.any { it.starts_new_leg }) return latest_source_leg(points)
        return latest_moving_leg(points)
    }

    private fun latest_moving_leg(points: List<TracePointWithFlags>, latest_takeoff_index: Int? = latest_takeoff_index(points)): List<TracePointWithFlags> {
        latest_takeoff_index?.let { return points.drop(departure_context_start(points, it)) }
        return latest_source_leg(points)
    }

    private fun latest_takeoff_index(points: List<TracePointWithFlags>): Int? {
        val last_moving_index = points.indexOfLast { it.is_moving_flight_point() }
        if (last_moving_index <= 0) return null
        var takeoff_index: Int? = null
        for (index in 1..last_moving_index) {
            if (!points[index - 1].is_moving_flight_point() && points[index].is_moving_flight_point()) {
                takeoff_index = index
            }
        }
        return takeoff_index
    }

    private fun departure_context_start(points: List<TracePointWithFlags>, takeoff_index: Int): Int {
        val takeoff = points[takeoff_index].point
        var start = takeoff_index
        for (index in takeoff_index - 1 downTo 0) {
            val candidate = points[index]
            if (candidate.starts_new_leg || candidate.is_moving_flight_point()) break
            val age_seconds = takeoff.epoch_sec - candidate.point.epoch_sec
            if (age_seconds > TRACE_MAX_DEPARTURE_CONTEXT_SECONDS) break
            val distance_meters = distance_meters(candidate.point.lat, candidate.point.lon, takeoff.lat, takeoff.lon)
            if (distance_meters > TRACE_MAX_DEPARTURE_CONTEXT_DISTANCE_M) break
            start = index
        }
        return start
    }

    private fun TracePointWithFlags.is_moving_flight_point(): Boolean {
        if (point.on_ground == true) return false
        ground_speed_kt?.let { return it >= TRACE_MIN_MOVING_FLIGHT_SPEED_KT }
        val altitude_feet = point.altitude_m?.times(TRACE_FEET_PER_METER)
        return altitude_feet == null || altitude_feet >= TRACE_MIN_MOVING_FLIGHT_ALTITUDE_FT
    }

    private fun continuous_segments(points: List<TracePointWithFlags>): List<List<TracePointWithFlags>> {
        if (points.size < 2) return emptyList()
        val segments = mutableListOf<List<TracePointWithFlags>>()
        var current = mutableListOf(points.first())
        for (index in 1 until points.size) {
            val previous = current.last()
            val point = points[index]
            if (breaks_continuity(previous, point)) {
                if (current.size >= TRACE_MIN_SEGMENT_POINTS) segments += current
                current = mutableListOf(point)
            } else {
                current += point
            }
        }
        if (current.size >= TRACE_MIN_SEGMENT_POINTS) segments += current
        return segments
    }

    private fun breaks_continuity(a: TracePointWithFlags, b: TracePointWithFlags): Boolean {
        val dt = b.point.epoch_sec - a.point.epoch_sec
        if (dt !in 1L..TRACE_MAX_TRACE_GAP_SECONDS) return true
        if (b.starts_new_leg) return true
        return false
    }

    private fun source_trace_is_current(segments: List<TraceSegment>): Boolean {
        val latest_epoch_sec = segments.flatMap { it.points }.maxOfOrNull { it.epoch_sec } ?: return false
        val now_sec = System.currentTimeMillis() / 1000L
        return latest_epoch_sec >= now_sec - TRACE_MAX_SOURCE_TRACE_AGE_SECONDS
    }

    private fun append_live_point_if_current(segments: MutableList<TraceSegment>, live_point: TrackPoint?): LiveTraceState {
        val live = live_point ?: return LiveTraceState.NOT_PROVIDED
        val now_sec = System.currentTimeMillis() / 1000L
        if (live.epoch_sec < now_sec - TRACE_MAX_LIVE_POINT_AGE_SECONDS) return LiveTraceState.STALE_OR_DISCONNECTED
        val last_segment = segments.lastOrNull() ?: return LiveTraceState.STALE_OR_DISCONNECTED
        val last = last_segment.points.lastOrNull() ?: return LiveTraceState.STALE_OR_DISCONNECTED
        val distance_meters = distance_meters(last.lat, last.lon, live.lat, live.lon)
        if (distance_meters < TRACE_MIN_LIVE_APPEND_DISTANCE_M) return LiveTraceState.ALREADY_CURRENT
        val dt = live.epoch_sec - last.epoch_sec
        if (dt <= -TRACE_SOURCE_CAN_BE_NEWER_SECONDS) return LiveTraceState.ALREADY_CURRENT
        if (dt !in 1L..TRACE_MAX_LIVE_APPEND_GAP_SECONDS) return LiveTraceState.STALE_OR_DISCONNECTED
        if (speed_knots(last, live, dt) > TRACE_MAX_LIVE_CONNECT_SPEED_KT) return LiveTraceState.STALE_OR_DISCONNECTED
        segments[segments.lastIndex] = TraceSegment(last_segment.points + live)
        return LiveTraceState.APPENDED
    }

    private fun speed_knots(a: TrackPoint, b: TrackPoint, seconds: Long): Double {
        return distance_meters(a.lat, a.lon, b.lat, b.lon) / TRACE_METERS_PER_NAUTICAL_MILE / (seconds / 3600.0)
    }

    private fun distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double =
        clamped_haversine_distance_meters(lat1, lon1, lat2, lon2)

    private data class TracePointWithFlags(
        val point: TrackPoint,
        val starts_new_leg: Boolean,
        val ground_speed_kt: Double?
    )

    private data class TraceProvider(
        val name: String,
        val base_url: String,
        val referer: String? = null
    )

    private data class TraceSource(
        val name: String,
        val full_json: JSONObject,
        val recent_json: JSONObject?
    )

    private companion object {
        val TRACE_PROVIDERS = listOf(
            TraceProvider(
                name = "Airplanes.Live",
                base_url = AirplanesLiveHttp.GLOBE_BASE_URL,
                referer = "${AirplanesLiveHttp.GLOBE_BASE_URL}/"
            ),
            TraceProvider(
                name = "ADSB.lol",
                base_url = "https://adsb.lol"
            )
        )
    }

    private enum class LiveTraceState {
        NOT_PROVIDED,
        ALREADY_CURRENT,
        APPENDED,
        STALE_OR_DISCONNECTED
    }
}


private fun JSONObject.trace_json_double_or_null(key: String): Double? {
    return if (has(key) && !isNull(key)) optDouble(key) else null
}

private const val TRACE_FEET_PER_METER = 3.28084
private const val TRACE_FLAG_NEW_LEG = 2
private const val TRACE_METERS_PER_NAUTICAL_MILE = 1852.0
private const val TRACE_MIN_TRACE_POINTS = FlightAlertSettings.FlightTrace.MIN_TRACE_POINTS
private const val TRACE_MIN_SEGMENT_POINTS = FlightAlertSettings.FlightTrace.MIN_SEGMENT_POINTS
private const val TRACE_MIN_TRACE_DURATION_SECONDS = FlightAlertSettings.FlightTrace.MIN_TRACE_DURATION_SECONDS
private const val TRACE_MAX_TRACE_GAP_SECONDS = FlightAlertSettings.FlightTrace.MAX_TRACE_GAP_SECONDS
private const val TRACE_MAX_LIVE_APPEND_GAP_SECONDS = FlightAlertSettings.FlightTrace.MAX_LIVE_APPEND_GAP_SECONDS
private const val TRACE_SOURCE_CAN_BE_NEWER_SECONDS = FlightAlertSettings.FlightTrace.SOURCE_CAN_BE_NEWER_SECONDS
private const val TRACE_MAX_LIVE_CONNECT_SPEED_KT = FlightAlertSettings.FlightTrace.MAX_LIVE_CONNECT_SPEED_KT
private const val TRACE_MIN_LIVE_APPEND_DISTANCE_M = FlightAlertSettings.FlightTrace.MIN_LIVE_APPEND_DISTANCE_M
private const val TRACE_MAX_LIVE_POINT_AGE_SECONDS = FlightAlertSettings.FlightTrace.MAX_LIVE_POINT_AGE_SECONDS
private const val TRACE_MAX_SOURCE_TRACE_AGE_SECONDS = FlightAlertSettings.FlightTrace.MAX_SOURCE_TRACE_AGE_SECONDS
private const val TRACE_MIN_MOVING_FLIGHT_SPEED_KT = FlightAlertSettings.FlightTrace.MIN_MOVING_FLIGHT_SPEED_KT
private const val TRACE_MIN_MOVING_FLIGHT_ALTITUDE_FT = FlightAlertSettings.FlightTrace.MIN_MOVING_FLIGHT_ALTITUDE_FT
private const val TRACE_MAX_DEPARTURE_CONTEXT_SECONDS = FlightAlertSettings.FlightTrace.MAX_DEPARTURE_CONTEXT_SECONDS
private const val TRACE_MAX_DEPARTURE_CONTEXT_DISTANCE_M = FlightAlertSettings.FlightTrace.MAX_DEPARTURE_CONTEXT_DISTANCE_M
private const val TRACE_MIN_PREVIOUS_FLIGHT_DISTANCE_M = FlightAlertSettings.FlightTrace.MIN_PREVIOUS_FLIGHT_DISTANCE_M
private const val TRACE_MIN_PREVIOUS_FLIGHT_ALTITUDE_FT = FlightAlertSettings.FlightTrace.MIN_PREVIOUS_FLIGHT_ALTITUDE_FT
private const val TRACE_MAX_PREVIOUS_FLIGHT_SEGMENTS = FlightAlertSettings.FlightTrace.MAX_PREVIOUS_FLIGHT_SEGMENTS


enum class AviationLayerKind(val display_name: String) {
    ATC_BOUNDARIES("ATC boundaries"),
    RESTRICTED_AIRSPACES("Restricted airspaces"),
    AIRPORTS("Airport labels"),
    OCEANIC_TRACKS("Oceanic tracks")
}

enum class AviationLayerState {
    LOADED,
    EMPTY,
    UNAVAILABLE
}

data class AviationLayerStatus(
    val state: AviationLayerState,
    val message: String
)

data class AviationLayerSnapshot(
    val atc_boundaries: List<AviationAirspaceFeature>,
    val restricted_airspaces: List<AviationAirspaceFeature>,
    val airports: List<AviationAirportFeature>,
    val oceanic_tracks: List<AviationOceanicTrack>,
    val statuses: Map<AviationLayerKind, AviationLayerStatus>,
    val fetched_at_ms: Long
)

data class AviationLayerBounds(
    val min_lat: Double,
    val min_lon: Double,
    val max_lat: Double,
    val max_lon: Double
) {
    fun arc_gis_envelope(): String = "$min_lon,$min_lat,$max_lon,$max_lat"
}

data class AviationLayerPoint(val lat: Double, val lon: Double)

data class AviationGeoBounds(
    val min_lat: Double,
    val min_lon: Double,
    val max_lat: Double,
    val max_lon: Double
) {
    fun intersects(other: AviationGeoBounds): Boolean {
        return max_lat >= other.min_lat &&
            min_lat <= other.max_lat &&
            max_lon >= other.min_lon &&
            min_lon <= other.max_lon
    }
}

data class AviationAirspaceFeature(
    val name: String,
    val type: String,
    val lower_limit: String?,
    val upper_limit: String?,
    val schedule: String?,
    val city: String?,
    val state: String?,
    val rings: List<List<AviationLayerPoint>>,
    val bounds: AviationGeoBounds
)

data class AviationAirportFeature(
    val ident: String,
    val name: String,
    val type: String,
    val military: Boolean,
    val lat: Double,
    val lon: Double
)

data class AviationOceanicTrack(
    val name: String,
    val source: String,
    val active_window: String?,
    val points: List<AviationLayerPoint>,
    val bounds: AviationGeoBounds
)

fun List<AviationLayerPoint>.to_bounds(): AviationGeoBounds {
    if (isEmpty()) return AviationGeoBounds(0.0, 0.0, 0.0, 0.0)
    var min_lat = first().lat
    var max_lat = first().lat
    var min_lon = first().lon
    var max_lon = first().lon
    forEach { point ->
        min_lat = min(min_lat, point.lat)
        max_lat = max(max_lat, point.lat)
        min_lon = min(min_lon, point.lon)
        max_lon = max(max_lon, point.lon)
    }
    return AviationGeoBounds(min_lat, min_lon, max_lat, max_lon)
}


data class FlightTrace(
    val source: String,
    val registration: String?,
    val type_code: String?,
    val aircraft_description: String?,
    val segments: List<TraceSegment>,
    val previous_segments: List<TraceSegment> = emptyList()
) {
    val point_count: Int get() = segments.sumOf { it.points.size }

    val previous_point_count: Int get() = previous_segments.sumOf { it.points.size }

    val all_points: List<TrackPoint> get() = segments.flatMap { it.points }

    companion object {
        fun empty(): FlightTrace = FlightTrace(
            source = "",
            registration = null,
            type_code = null,
            aircraft_description = null,
            segments = emptyList()
        )
    }
}

data class TraceSegment(val points: List<TrackPoint>)

data class TrackPoint(
    val lat: Double,
    val lon: Double,
    val epoch_sec: Long,
    val altitude_m: Double?,
    val track_deg: Double?,
    val on_ground: Boolean?
)


// Direct Airplanes.Live globe inventory source backed by lightweight binCraft HTTP.
class GlobeBinCraftAircraftSource(user_agent: String) {
    var on_snapshot_updated: (() -> Unit)? = null

    private val handler = Handler(Looper.getMainLooper())
    private val parser_executor = Executors.newSingleThreadExecutor()
    private val inventory_client = GlobeBinCraftClient(user_agent)
    private var host_resumed = false
    private var running = false

    @Volatile
    private var source_enabled = false

    @Volatile
    private var destroyed = false

    @Volatile
    private var pending_viewport: GlobeViewport? = null
    private var viewport_generation = 0L

    @Volatile
    private var latest: GlobeSnapshot? = null

    @Volatile
    private var extraction_paused_until_elapsed_ms = 0L

    @Volatile
    private var fetch_in_progress = false

    private val fetcher = Runnable { fetch_inventory() }

    fun start() {
        host_resumed = true
        start_if_allowed()
    }

    fun stop() {
        host_resumed = false
        stop_active(clear_snapshot = false)
    }

    fun destroy() {
        destroyed = true
        stop_active(clear_snapshot = true)
        parser_executor.shutdownNow()
    }

    fun set_enabled(enabled: Boolean) {
        if (Looper.myLooper() != Looper.getMainLooper()) {
            handler.post { set_enabled(enabled) }
            return
        }
        if (source_enabled == enabled) return
        source_enabled = enabled
        if (enabled) {
            start_if_allowed()
        } else {
            stop_active(clear_snapshot = true)
        }
    }

    @Suppress("UNUSED_PARAMETER")
    fun update_viewport(bounds: FeedBounds, center_lat: Double, center_lon: Double, zoom: Double) {
        if (!source_enabled || destroyed) return
        if (Looper.myLooper() != Looper.getMainLooper()) {
            handler.post { update_viewport(bounds, center_lat, center_lon, zoom) }
            return
        }
        val viewport = globe_inventory_viewport()
        val previous = pending_viewport
        if (previous != null && previous.matches(viewport)) return
        viewport_generation += 1L
        val next = viewport.copy(generation = viewport_generation)
        pending_viewport = next
        if (running) schedule_fetch(0L)
    }

    @Suppress("UNUSED_PARAMETER")
    fun latest_snapshot(bounds: FeedBounds, own_lat: Double, own_lon: Double, exact_search: String?): FeedResult? {
        if (!source_enabled || destroyed) return null
        val viewport = pending_viewport ?: return null
        val snapshot = latest ?: return null
        if (snapshot.viewport_generation != viewport.generation) return null
        if (SystemClock.elapsedRealtime() - snapshot.received_elapsed_ms > MAX_SNAPSHOT_AGE_MS) return null
        if (snapshot.aircraft.isEmpty() && snapshot.partial_coverage) return null
        val normalized_search = exact_search?.trim()?.uppercase(Locale.US)?.takeIf { it.isNotBlank() }
        val filtered = ArrayList<FeedAircraft>(snapshot.aircraft.size)
        snapshot.aircraft.forEach { aircraft ->
            if (normalized_search == null || aircraft.matches_search(normalized_search)) {
                filtered += aircraft.with_distance_from(own_lat, own_lon)
            }
        }
        filtered.sortBy { it.distance_m }
        if (normalized_search != null && filtered.isEmpty()) return null
        return FeedResult(
            status = FeedStatus.OK,
            source = FeedSource.AIRPLANES_LIVE_GLOBE,
            aircraft = filtered,
            epoch_sec = snapshot.epoch_sec,
            query_count = 0,
            partial_coverage = snapshot.partial_coverage
        )
    }

    fun pause_inventory_extraction(duration_ms: Long) {
        if (!source_enabled || destroyed) return
        if (duration_ms <= 0L) return
        extraction_paused_until_elapsed_ms = max(
            extraction_paused_until_elapsed_ms,
            SystemClock.elapsedRealtime() + duration_ms.coerceAtLeast(0L)
        )
    }

    private fun start_if_allowed() {
        if (destroyed || !source_enabled || !host_resumed || running) return
        if (pending_viewport == null) {
            viewport_generation += 1L
            pending_viewport = globe_inventory_viewport()
        }
        running = true
        schedule_fetch(0L)
    }

    private fun stop_active(clear_snapshot: Boolean) {
        if (Looper.myLooper() != Looper.getMainLooper()) {
            handler.post { stop_active(clear_snapshot) }
            return
        }
        running = false
        handler.removeCallbacks(fetcher)
        fetch_in_progress = false
        if (clear_snapshot) {
            latest = null
            pending_viewport = null
            viewport_generation = 0L
        }
    }

    private fun schedule_fetch(delay_ms: Long) {
        if (!running) return
        handler.removeCallbacks(fetcher)
        handler.postDelayed(fetcher, delay_ms.coerceAtLeast(0L))
    }

    private fun fetch_inventory() {
        if (!source_enabled || !running || destroyed) return
        if (Looper.myLooper() != Looper.getMainLooper()) {
            handler.post { fetch_inventory() }
            return
        }
        val viewport = pending_viewport ?: run {
            schedule_fetch(STARTUP_RETRY_MS)
            return
        }
        val pause_remaining_ms = extraction_paused_until_elapsed_ms - SystemClock.elapsedRealtime()
        if (pause_remaining_ms > 0L) {
            schedule_fetch(pause_remaining_ms)
            return
        }
        if (fetch_in_progress) return
        fetch_in_progress = true
        val fetch_started_elapsed_ms = SystemClock.elapsedRealtime()
        try {
            parser_executor.execute {
                val snapshot = inventory_client.fetch(viewport.bounds)
                handler.post {
                    fetch_in_progress = false
                    if (!source_enabled || !running || destroyed) return@post
                    if (pending_viewport?.generation != viewport.generation) {
                        schedule_fetch(STARTUP_RETRY_MS)
                        return@post
                    }
                    if (snapshot == null || (snapshot.aircraft.isEmpty() && snapshot.partial_coverage)) {
                        schedule_fetch(STARTUP_RETRY_MS)
                        return@post
                    }
                    val next = GlobeSnapshot(
                        aircraft = snapshot.aircraft,
                        epoch_sec = snapshot.epoch_sec,
                        received_elapsed_ms = SystemClock.elapsedRealtime(),
                        partial_coverage = snapshot.partial_coverage,
                        viewport_generation = viewport.generation
                    )
                    latest = next
                    Log.d(TAG, "Globe binCraft source: ${next.aircraft.size} aircraft, partial=${next.partial_coverage}")
                    on_snapshot_updated?.invoke()
                    schedule_fetch(next_cadence_delay_ms(fetch_started_elapsed_ms))
                }
            }
        } catch (_: RejectedExecutionException) {
            fetch_in_progress = false
        }
    }

    private fun next_cadence_delay_ms(fetch_started_elapsed_ms: Long): Long {
        val elapsed_ms = SystemClock.elapsedRealtime() - fetch_started_elapsed_ms
        return (EXTRACT_INTERVAL_MS - elapsed_ms).coerceAtLeast(0L)
    }

    private fun globe_inventory_viewport(): GlobeViewport {
        return GlobeViewport(
            bounds = WORLD_FEED_BOUNDS,
            center_lat = GLOBE_INVENTORY_CENTER_LAT,
            center_lon = GLOBE_INVENTORY_CENTER_LON,
            zoom = GLOBE_INVENTORY_ZOOM,
            generation = viewport_generation
        )
    }

    private fun FeedAircraft.with_distance_from(own_lat: Double, own_lon: Double): FeedAircraft {
        return copy(distance_m = globe_distance_meters(own_lat, own_lon, lat, lon))
    }

    private fun FeedAircraft.matches_search(search: String): Boolean {
        return icao24.uppercase(Locale.US).contains(search) ||
            callsign.uppercase(Locale.US).replace(" ", "").contains(search.replace(" ", "")) ||
            registration?.uppercase(Locale.US)?.contains(search) == true
    }

    private data class GlobeSnapshot(
        val aircraft: List<FeedAircraft>,
        val epoch_sec: Double,
        val received_elapsed_ms: Long,
        val partial_coverage: Boolean,
        val viewport_generation: Long
    )

    private data class GlobeViewport(
        val bounds: FeedBounds,
        val center_lat: Double,
        val center_lon: Double,
        val zoom: Double,
        val generation: Long
    )

    private fun GlobeViewport.matches(other: GlobeViewport): Boolean {
        return abs(center_lat - other.center_lat) < VIEWPORT_LAT_LON_EPSILON &&
            abs(center_lon - other.center_lon) < VIEWPORT_LAT_LON_EPSILON &&
            abs(zoom - other.zoom) < VIEWPORT_ZOOM_EPSILON &&
            abs(bounds.min_lat - other.bounds.min_lat) < VIEWPORT_LAT_LON_EPSILON &&
            abs(bounds.max_lat - other.bounds.max_lat) < VIEWPORT_LAT_LON_EPSILON &&
            abs(bounds.min_lon - other.bounds.min_lon) < VIEWPORT_LAT_LON_EPSILON &&
            abs(bounds.max_lon - other.bounds.max_lon) < VIEWPORT_LAT_LON_EPSILON
    }

    private companion object {
        private const val TAG = "FlightAlert"
        private const val EXTRACT_INTERVAL_MS = 1000L
        private const val STARTUP_RETRY_MS = 450L
        private const val MAX_SNAPSHOT_AGE_MS = 9000L
        private const val GLOBE_INVENTORY_ZOOM = 0.0
        private const val GLOBE_INVENTORY_CENTER_LAT = 0.0
        private const val GLOBE_INVENTORY_CENTER_LON = 0.0
        private const val VIEWPORT_LAT_LON_EPSILON = 0.01
        private const val VIEWPORT_ZOOM_EPSILON = 0.12
        private val WORLD_FEED_BOUNDS = FeedBounds(-90.0, -180.0, 90.0, 180.0)
    }
}

private fun globe_distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double {
    val lat_distance = Math.toRadians(lat2 - lat1)
    val lon_distance = Math.toRadians(lon2 - lon1)
    val a = sin(lat_distance / 2) * sin(lat_distance / 2) +
        cos(Math.toRadians(lat1)) * cos(Math.toRadians(lat2)) *
        sin(lon_distance / 2) * sin(lon_distance / 2)
    return 2.0 * GLOBE_EARTH_RADIUS_M * atan2(sqrt(a), sqrt(max(0.0, 1.0 - a)))
}

private const val GLOBE_EARTH_RADIUS_M = 6371000.0


internal data class GlobeBinCraftSnapshot(
    val aircraft: List<FeedAircraft>,
    val epoch_sec: Double,
    val partial_coverage: Boolean
)

internal class GlobeBinCraftClient(private val user_agent: String) {
    fun fetch(bounds: FeedBounds): GlobeBinCraftSnapshot? {
        var connection: HttpURLConnection? = null
        return try {
            val normalized = bounds.normalized()
            val url = URL(
                String.format(
                    Locale.US,
                    "%s/re-api/?binCraft&zstd&box=%.6f,%.6f,%.6f,%.6f",
                    AirplanesLiveHttp.GLOBE_BASE_URL,
                    normalized.min_lat,
                    normalized.max_lat,
                    normalized.min_lon,
                    normalized.max_lon
                )
            )
            connection = (url.openConnection() as HttpURLConnection).apply {
                connectTimeout = 5000
                readTimeout = 9000
                requestMethod = "GET"
                AirplanesLiveHttp.apply_browser_headers(
                    connection = this,
                    app_user_agent = user_agent,
                    referer = "${AirplanesLiveHttp.GLOBE_BASE_URL}/?nowebgl",
                    accept = "*/*"
                )
                setRequestProperty("X-Requested-With", "XMLHttpRequest")
            }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                return null
            }
            val compressed = connection.inputStream.use { it.readBytes() }
            val decoded = ZstdInputStream(ByteArrayInputStream(compressed)).use { it.readBytes() }
            parse(decoded)
        } catch (_: Exception) {
            null
        } finally {
            connection?.disconnect()
        }
    }

    private fun parse(bytes: ByteArray): GlobeBinCraftSnapshot? {
        if (bytes.size < HEADER_BYTES) return null
        val buffer = ByteBuffer.wrap(bytes).order(ByteOrder.LITTLE_ENDIAN)
        val now_sec = u32(buffer, 0) / 1000.0 + u32(buffer, 4) * 4294967.296
        val stride = int(buffer, 8)
        if (stride !in MIN_STRIDE_BYTES..MAX_STRIDE_BYTES || bytes.size < stride) return null
        val global_with_position = int(buffer, 12)
        val messages = u32(buffer, 28)
        val bin_craft_version = int(buffer, 40)
        val message_rate = u32(buffer, 44) / 10.0
        val flags = int(buffer, 48)
        val use_message_rate = flags and 1 != 0
        val parsed = ArrayList<FeedAircraft>(global_with_position.coerceIn(512, 32768))
        var offset = stride
        while (offset + stride <= bytes.size) {
            parse_aircraft(buffer, offset, stride, bin_craft_version, use_message_rate, now_sec)?.let(parsed::add)
            offset += stride
        }
        return GlobeBinCraftSnapshot(
            aircraft = parsed,
            epoch_sec = now_sec,
            partial_coverage = parsed.isEmpty() && (global_with_position > 0 || messages > 0 || message_rate > 0.0)
        )
    }

    private fun parse_aircraft(
        buffer: ByteBuffer,
        offset: Int,
        stride: Int,
        version: Int,
        use_message_rate: Boolean,
        now_sec: Double
    ): FeedAircraft? {
        val raw_hex = int(buffer, offset)
        val non_icao = raw_hex and (1 shl 24) != 0
        val hex = (raw_hex and ((1 shl 24) - 1)).toString(16).padStart(6, '0').let {
            if (non_icao) "~$it" else it
        }
        val seen = if (version >= 20240218) int(buffer, offset + 4) / 10.0 else u16(buffer, offset + 6) / 10.0
        val seen_pos = if (version >= 20240218 && stride >= 112) {
            int(buffer, offset + 27 * 4) / 10.0
        } else {
            u16(buffer, offset + 4) / 10.0
        }
        val lon_raw = int(buffer, offset + 8)
        val lat_raw = int(buffer, offset + 12)
        val validity_73 = u8(buffer, offset + 73)
        if (validity_73 and 64 == 0 || lon_raw == Int.MAX_VALUE || lat_raw == Int.MAX_VALUE) return null
        val lon = lon_raw / 1_000_000.0
        val lat = lat_raw / 1_000_000.0
        if (!lat.isFinite() || !lon.isFinite() || lat !in -90.0..90.0 || lon !in -180.0..180.0) return null

        val airground = u8(buffer, offset + 68) and 15
        val on_ground = airground == 1
        val valid_74 = u8(buffer, offset + 74)
        val valid_75 = u8(buffer, offset + 75)
        val valid_76 = u8(buffer, offset + 76)
        val valid_77 = u8(buffer, offset + 77)
        val category = u8(buffer, offset + 64).takeIf { it != 0 }?.toString(16)?.uppercase(Locale.US)
        val type_code = ascii(buffer, offset + 88, 4)
        val registration = ascii(buffer, offset + 92, 12)
        val flight = ascii(buffer, offset + 78, 8)
        val callsign = flight ?: registration ?: hex.trimStart('~')
        val altitude_feet = when {
            on_ground -> 0.0
            validity_73 and 16 != 0 -> s16(buffer, offset + 20) * 25.0
            validity_73 and 32 != 0 -> s16(buffer, offset + 22) * 25.0
            else -> null
        }
        val speed_kt = if (validity_73 and 128 != 0) s16(buffer, offset + 34) / 10.0 else null
        val track = if (valid_74 and 8 != 0) s16(buffer, offset + 40) / 90.0 else null
        val vertical_rate_fpm = when {
            valid_75 and 1 != 0 -> s16(buffer, offset + 16) * 8.0
            valid_75 and 2 != 0 -> s16(buffer, offset + 18) * 8.0
            else -> null
        }
        val db_flags = u16(buffer, offset + 86).takeIf { it != 0 }
        val receiver_count = u8(buffer, offset + 104).takeIf { stride > 104 && it != 0 }
        val rssi = if (stride > 105) {
            if (version >= 20250403) {
                u8(buffer, offset + 105) * (50.0 / 255.0) - 50.0
            } else {
                val level = u8(buffer, offset + 105).let { it * it / 65025.0 + 1.125e-5 }
                10.0 * ln(level) / ln(10.0)
            }
        } else {
            null
        }
        val telemetry = AircraftTelemetry(
            source_type = source_type_label(u8(buffer, offset + 67) ushr 4),
            squawk = if (valid_76 and 4 != 0) squawk(buffer, offset + 32) else null,
            baro_altitude_m = if (validity_73 and 16 != 0 || on_ground) (if (on_ground) 0.0 else s16(buffer, offset + 20) * 25.0 / FEET_PER_METER) else null,
            geom_altitude_m = if (validity_73 and 32 != 0) s16(buffer, offset + 22) * 25.0 / FEET_PER_METER else null,
            ground_speed_ms = speed_kt?.let { it * KNOTS_TO_METERS_PER_SECOND },
            true_speed_ms = if (valid_74 and 2 != 0) u16(buffer, offset + 56) * KNOTS_TO_METERS_PER_SECOND else null,
            indicated_speed_ms = if (valid_74 and 1 != 0) u16(buffer, offset + 58) * KNOTS_TO_METERS_PER_SECOND else null,
            mach = if (valid_74 and 4 != 0) s16(buffer, offset + 36) / 1000.0 else null,
            baro_rate_ms = if (valid_75 and 1 != 0) s16(buffer, offset + 16) * 8.0 / FEET_PER_METER / 60.0 else null,
            geom_rate_ms = if (valid_75 and 2 != 0) s16(buffer, offset + 18) * 8.0 / FEET_PER_METER / 60.0 else null,
            selected_altitude_m = selected_altitude_m(buffer, offset, valid_76),
            selected_heading_deg = if (valid_77 and 2 != 0) s16(buffer, offset + 30) / 90.0 else null,
            wind_speed_ms = if (valid_77 and 16 != 0) s16(buffer, offset + 50) * KNOTS_TO_METERS_PER_SECOND else null,
            wind_direction_deg = if (valid_77 and 16 != 0) s16(buffer, offset + 48).toDouble() else null,
            tat_c = if (valid_77 and 32 != 0) s16(buffer, offset + 54).toDouble() else null,
            oat_c = if (valid_77 and 32 != 0) s16(buffer, offset + 52).toDouble() else null,
            qnh_hpa = if (valid_76 and 32 != 0) s16(buffer, offset + 28) / 10.0 else null,
            true_heading_deg = if (valid_74 and 128 != 0) s16(buffer, offset + 46) / 90.0 else null,
            magnetic_heading_deg = if (valid_74 and 64 != 0) s16(buffer, offset + 44) / 90.0 else null,
            track_rate_deg_per_sec = if (valid_74 and 16 != 0) s16(buffer, offset + 42) / 100.0 else null,
            roll_deg = if (valid_74 and 32 != 0) s16(buffer, offset + 38) / 100.0 else null,
            nav_modes = if (valid_77 and 4 != 0) nav_modes(u8(buffer, offset + 66)) else emptyList(),
            adsb_version = adsb_version_label(buffer, offset),
            nac_p = if (valid_75 and 32 != 0) u8(buffer, offset + 71) and 15 else null,
            nac_v = if (valid_75 and 64 != 0) (u8(buffer, offset + 71) and 240) ushr 4 else null,
            sil = if (valid_75 and 128 != 0) u8(buffer, offset + 72) and 3 else null,
            sil_type = if (valid_75 and 128 != 0) sil_type_label(u8(buffer, offset + 69) and 15) else null,
            nic_baro = if (valid_75 and 16 != 0) (u8(buffer, offset + 73) and 1).toString() else null,
            rc_m = if (u8(buffer, offset + 71) and 15 != 0) u16(buffer, offset + 60).toDouble() else null,
            rssi = rssi,
            message_rate = if (use_message_rate) u16(buffer, offset + 62) / 10.0 else null,
            receiver_count_label = receiver_count?.toString(),
            category_label = category
        ).takeIf { it.has_values }
        return FeedAircraft(
            icao24 = hex,
            callsign = callsign,
            registration = registration,
            type_code = type_code,
            metadata = AircraftMetadataSeed(
                source_name = FeedSource.AIRPLANES_LIVE_GLOBE.display_name,
                registration = registration,
                type_code = type_code
            ).takeIf { it.has_details },
            db_flags = db_flags,
            lat = lat,
            lon = lon,
            on_ground = on_ground,
            altitude_m = altitude_feet?.let { it / FEET_PER_METER },
            velocity_ms = speed_kt?.let { it * KNOTS_TO_METERS_PER_SECOND },
            track_deg = track,
            vertical_rate_ms = vertical_rate_fpm?.let { it / FEET_PER_METER / 60.0 },
            category = category_from_globe(category, type_code),
            position_time_sec = now_sec - seen_pos,
            last_contact_sec = now_sec - seen,
            distance_m = 0.0,
            telemetry = telemetry
        )
    }

    private fun selected_altitude_m(buffer: ByteBuffer, offset: Int, valid_76: Int): Double? {
        val mcp = if (valid_76 and 64 != 0) u16(buffer, offset + 24) * 4.0 else null
        val fms = if (valid_76 and 128 != 0) u16(buffer, offset + 26) * 4.0 else null
        return (mcp ?: fms)?.let { it / FEET_PER_METER }
    }

    private fun source_type_label(type: Int): String {
        return when (type) {
            0 -> "adsb_icao"
            1 -> "adsb_icao_nt"
            2 -> "adsr_icao"
            3 -> "tisb_icao"
            4 -> "adsc"
            5 -> "mlat"
            6 -> "other"
            7 -> "mode_s"
            8 -> "adsb_other"
            9 -> "adsr_other"
            10 -> "tisb_trackfile"
            11 -> "tisb_other"
            12 -> "mode_ac"
            else -> "unknown"
        }
    }

    private fun adsb_version_label(buffer: ByteBuffer, offset: Int): String? {
        val source_type = u8(buffer, offset + 67) ushr 4
        val version = when (source_type) {
            0, 1, 8 -> (u8(buffer, offset + 69) and 240) ushr 4
            2, 9 -> u8(buffer, offset + 70) and 15
            3, 10, 11 -> (u8(buffer, offset + 70) and 240) ushr 4
            else -> return null
        }
        return "v$version"
    }

    private fun sil_type_label(value: Int): String {
        return when (value) {
            1 -> "per_sample"
            2 -> "per_hour"
            else -> value.toString()
        }
    }

    private fun nav_modes(bits: Int): List<String> {
        val result = ArrayList<String>(6)
        if (bits and 1 != 0) result += "autopilot"
        if (bits and 2 != 0) result += "vnav"
        if (bits and 4 != 0) result += "alt_hold"
        if (bits and 8 != 0) result += "approach"
        if (bits and 16 != 0) result += "lnav"
        if (bits and 32 != 0) result += "tcas"
        return result
    }

    private fun squawk(buffer: ByteBuffer, offset: Int): String {
        val raw = u16(buffer, offset).toString(16).padStart(4, '0')
        return if (raw[0] > '9') {
            parse_hex_digit(raw[0]).toString() + raw.substring(1)
        } else {
            raw
        }
    }

    private fun parse_hex_digit(value: Char): Int {
        return value.digitToIntOrNull(16) ?: 0
    }

    private fun ascii(buffer: ByteBuffer, offset: Int, max_length: Int): String? {
        val builder = StringBuilder(max_length)
        var index = 0
        while (index < max_length && offset + index < buffer.limit()) {
            val byte = u8(buffer, offset + index)
            if (byte == 0) break
            builder.append(byte.toChar())
            index++
        }
        return builder.toString().trim().takeIf { it.isNotBlank() }
    }

    private fun category_from_globe(category: String?, type_code: String?): Int? {
        val normalized = category?.trim()?.uppercase(Locale.US).orEmpty()
        if (normalized.startsWith("A7") || normalized.startsWith("B7")) return 8
        if (normalized.startsWith("B1")) return 9
        if (normalized.startsWith("B6")) return 14
        if (normalized.startsWith("C") || normalized.startsWith("D")) return 15
        val type = type_code?.trim()?.uppercase(Locale.US).orEmpty()
        return when {
            type.startsWith("H") || type.startsWith("R") -> 8
            type.startsWith("GL") -> 9
            type.startsWith("UAV") || type.startsWith("DRON") -> 14
            else -> null
        }
    }

    private fun int(buffer: ByteBuffer, offset: Int): Int = buffer.getInt(offset)

    private fun u32(buffer: ByteBuffer, offset: Int): Long = int(buffer, offset).toLong() and 0xffffffffL

    private fun s16(buffer: ByteBuffer, offset: Int): Short = buffer.getShort(offset)

    private fun u16(buffer: ByteBuffer, offset: Int): Int = buffer.getShort(offset).toInt() and 0xffff

    private fun u8(buffer: ByteBuffer, offset: Int): Int = buffer.get(offset).toInt() and 0xff

    private companion object {
        const val HEADER_BYTES = 52
        const val MIN_STRIDE_BYTES = 108
        const val MAX_STRIDE_BYTES = 160
        const val FEET_PER_METER = 3.28084
        const val KNOTS_TO_METERS_PER_SECOND = 0.514444
    }
}

// endregion

// region ANDROID LIFECYCLE AND SAFETY

// Activity stays intentionally thin: permissions, lifecycle, and the single custom map surface.
class MainActivity : ComponentActivity() {
    private var flight_map_view: FlightMapView? = null
    private var globe_bin_craft_aircraft_source: GlobeBinCraftAircraftSource? = null

    // Let Android show the permission popups, then hand the answer back to the map and alert service.
    private val location_permission_launcher = registerForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions()
    ) {
        flight_map_view?.set_location_permission_granted(has_location_permission())
        update_alert_service()
    }
    private val notification_permission_launcher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) {
        update_alert_service()
    }

    // Android calls this once to build the screen; after this, the custom view owns the app flow.
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        configure_system_bars()

        // Give overlays first chance at Back so panels close before Android leaves the app.
        onBackPressedDispatcher.addCallback(
            this,
            object : OnBackPressedCallback(true) {
                override fun handleOnBackPressed() {
                    if (flight_map_view?.handle_back_press() == true) return
                    isEnabled = false
                    onBackPressedDispatcher.onBackPressed()
                    isEnabled = true
                }
            }
        )

        // Make the globe source first. It uses lightweight binCraft HTTP for live wide-area inventory.
        val globe_source = GlobeBinCraftAircraftSource(APP_USER_AGENT)
        globe_source.set_enabled(
            FlightAlertSettings.read_aircraft_feed_mode(this).uses_globe
        )
        globe_bin_craft_aircraft_source = globe_source

        // Make the actual cockpit view. This is the main logic file Android will call to draw and handle input.
        val view = FlightMapView(this, globe_source)
        view.keepScreenOn = true
        configure_high_refresh_rate(view)
        flight_map_view = view
        apply_debug_perf_viewport(intent)

        setContentView(view)
        view.post { configure_high_refresh_rate(view) }

        // Put keyboard focus on FlightMapView so emulator keys and filter typing land in the map controller.
        view.requestFocus()
        request_location_permission_if_needed()
        request_notification_permission_if_needed()
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        apply_debug_perf_viewport(intent)
    }

    override fun onConfigurationChanged(newConfig: Configuration) {
        super.onConfigurationChanged(newConfig)
        configure_system_bars()
        flight_map_view?.let { view ->
            view.requestLayout()
            view.postInvalidateOnAnimation()
        }
    }

    // Android calls this whenever the app comes back on screen; restart live systems here.
    override fun onResume() {
        super.onResume()
        configure_system_bars()
        request_location_permission_if_needed()
        flight_map_view?.let { configure_high_refresh_rate(it) }
        globe_bin_craft_aircraft_source?.start()
        flight_map_view?.start()
        update_alert_service()
    }

    // Android calls this when the app is leaving the foreground; stop screen-only work here.
    override fun onPause() {
        flight_map_view?.stop()
        globe_bin_craft_aircraft_source?.stop()
        super.onPause()
    }

    // Android is tearing down the activity; stop the binCraft source worker.
    override fun onDestroy() {
        globe_bin_craft_aircraft_source?.destroy()
        globe_bin_craft_aircraft_source = null
        super.onDestroy()
    }

    // The map view handles insets; opaque bars keep Android chrome from blending into app UI.
    @Suppress("DEPRECATION")
    private fun configure_system_bars() {
        val system_bar_color = FlightAlertSettings.read_visual_theme(this).colors.system_bar
        window.statusBarColor = system_bar_color
        window.navigationBarColor = system_bar_color
        window.isStatusBarContrastEnforced = false
        window.isNavigationBarContrastEnforced = false
    }

    @Suppress("DEPRECATION")
    private fun configure_high_refresh_rate(view: FlightMapView? = null) {
        val display = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            display
        } else {
            windowManager.defaultDisplay
        } ?: return
        val fastest_mode = display.supportedModes.maxByOrNull { it.refreshRate } ?: return
        if (fastest_mode.refreshRate <= 0f) return
        window.attributes = window.attributes.apply {
            preferredDisplayModeId = fastest_mode.modeId
            preferredRefreshRate = fastest_mode.refreshRate
        }
        if (Build.VERSION.SDK_INT >= 35) {
            view?.requestedFrameRate = fastest_mode.refreshRate
        }
    }

    private fun request_location_permission_if_needed() {
        val granted = has_location_permission()
        flight_map_view?.set_location_permission_granted(granted)
        if (!granted) {
            location_permission_launcher.launch(
                arrayOf(
                    Manifest.permission.ACCESS_FINE_LOCATION,
                    Manifest.permission.ACCESS_COARSE_LOCATION
                )
            )
        }
    }

    private fun has_location_permission(): Boolean = has_flight_location_permission()

    private fun request_notification_permission_if_needed() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU &&
            checkSelfPermission(Manifest.permission.POST_NOTIFICATIONS) != PackageManager.PERMISSION_GRANTED
        ) {
            notification_permission_launcher.launch(Manifest.permission.POST_NOTIFICATIONS)
        }
    }

    // Keep the background watcher alive only when alerts need it and Android has granted location.
    private fun update_alert_service() {
        val prefs = FlightAlertSettings.prefs(this)
        val enabled = prefs.getBoolean(FlightAlertSettings.KEY_ALERTS_ENABLED, true) ||
            prefs.getBoolean(FlightAlertSettings.KEY_PRIORITY_TRACKING_ENABLED, false)
        if (enabled && has_location_permission()) {
            AircraftAlertService.start(this)
        } else {
            AircraftAlertService.stop(this)
        }
    }

    private fun apply_debug_perf_viewport(intent: Intent?) {
        if (!is_debuggable_build() || intent == null) return
        intent.extras?.keySet()
            ?.filter { it.contains("PERF") }
            ?.takeIf { it.isNotEmpty() }
            ?.let { keys -> Log.i(TAG, "Debug perf intent keys=${keys.joinToString()}") }
        if (!intent.hasExtra(EXTRA_PERF_LAT) || !intent.hasExtra(EXTRA_PERF_LON)) return
        val lat = intent.double_extra(EXTRA_PERF_LAT, Double.NaN)
        val lon = intent.double_extra(EXTRA_PERF_LON, Double.NaN)
        val zoom = intent.double_extra(EXTRA_PERF_ZOOM, DEFAULT_PERF_ZOOM)
        val run_id = intent.getStringExtra(EXTRA_PERF_RUN_ID)
        val map_source = intent.getStringExtra(EXTRA_PERF_MAP_SOURCE)
            ?.let { value -> TileSource.entries.firstOrNull { it.name.equals(value, ignoreCase = true) } }
        val map_labels = intent.optional_boolean_extra(EXTRA_PERF_MAP_LABELS_ENABLED)
        val map_roads = intent.optional_boolean_extra(EXTRA_PERF_MAP_ROADS_ENABLED)
        val map_borders = intent.optional_boolean_extra(EXTRA_PERF_MAP_BORDERS_ENABLED)
        val restricted = intent.optional_boolean_extra(EXTRA_PERF_RESTRICTED_AIRSPACES_ENABLED)
        val clear_selection = intent.optional_boolean_extra(EXTRA_PERF_CLEAR_SELECTION) == true
        val focus_open_map = intent.optional_boolean_extra(EXTRA_PERF_FOCUS_OPEN_MAP) == true
        val focus_x_fraction = intent.optional_double_extra(EXTRA_PERF_FOCUS_X_FRACTION)
        val focus_y_fraction = intent.optional_double_extra(EXTRA_PERF_FOCUS_Y_FRACTION)
        val skip_map = intent.optional_boolean_extra(EXTRA_PERF_SKIP_MAP) == true
        val skip_traffic = intent.optional_boolean_extra(EXTRA_PERF_SKIP_TRAFFIC) == true
        val skip_chrome = intent.optional_boolean_extra(EXTRA_PERF_SKIP_CHROME) == true
        val skip_top_status = intent.optional_boolean_extra(EXTRA_PERF_SKIP_TOP_STATUS) == true
        val skip_controls = intent.optional_boolean_extra(EXTRA_PERF_SKIP_CONTROLS) == true
        val skip_traffic_panel = intent.optional_boolean_extra(EXTRA_PERF_SKIP_TRAFFIC_PANEL) == true
        val traffic_detail_timing = intent.optional_boolean_extra(EXTRA_PERF_TRAFFIC_DETAIL_TIMING) == true
        val map_detail_timing = intent.optional_boolean_extra(EXTRA_PERF_MAP_DETAIL_TIMING) == true
        val frame_metrics_probe = intent.optional_boolean_extra(EXTRA_PERF_FRAME_METRICS_PROBE) == true
        flight_map_view?.apply_debug_perf_viewport(
            lat = lat,
            lon = lon,
            target_zoom = zoom,
            run_id = run_id,
            perf_map_source = map_source,
            perf_map_labels_enabled = map_labels,
            perf_map_roads_enabled = map_roads,
            perf_map_borders_enabled = map_borders,
            perf_restricted_airspaces_enabled = restricted,
            perf_clear_selection = clear_selection,
            perf_focus_open_map = focus_open_map,
            perf_focus_x_fraction = focus_x_fraction,
            perf_focus_y_fraction = focus_y_fraction,
            perf_skip_map = skip_map,
            perf_skip_traffic = skip_traffic,
            perf_skip_chrome = skip_chrome,
            perf_skip_top_status = skip_top_status,
            perf_skip_controls = skip_controls,
            perf_skip_traffic_panel = skip_traffic_panel,
            perf_traffic_detail_timing = traffic_detail_timing,
            perf_frame_metrics_probe = frame_metrics_probe,
            perf_map_detail_timing = map_detail_timing
        )
    }

    private fun Intent.double_extra(name: String, fallback: Double): Double {
        getStringExtra(name)?.toDoubleOrNull()?.let { return it }
        return try {
            getDoubleExtra(name, fallback)
        } catch (_: ClassCastException) {
            fallback
        }
    }

    private fun Intent.optional_boolean_extra(name: String): Boolean? {
        if (!hasExtra(name)) return null
        return try {
            getBooleanExtra(name, false)
        } catch (_: ClassCastException) {
            getStringExtra(name)?.let { value ->
                value.equals("true", ignoreCase = true) || value == "1"
            }
        }
    }

    private fun Intent.optional_double_extra(name: String): Double? {
        if (!hasExtra(name)) return null
        return double_extra(name, Double.NaN).takeIf { it.isFinite() }
    }

    private fun is_debuggable_build(): Boolean {
        return (applicationInfo.flags and ApplicationInfo.FLAG_DEBUGGABLE) != 0
    }

    private companion object {
        const val APP_USER_AGENT = FlightAlertSettings.App.USER_AGENT
        const val TAG = FlightAlertSettings.App.TAG
        const val EXTRA_PERF_LAT = "com.flightalert.PERF_LAT"
        const val EXTRA_PERF_LON = "com.flightalert.PERF_LON"
        const val EXTRA_PERF_ZOOM = "com.flightalert.PERF_ZOOM"
        const val EXTRA_PERF_RUN_ID = "com.flightalert.PERF_RUN_ID"
        const val EXTRA_PERF_MAP_SOURCE = "com.flightalert.PERF_MAP_SOURCE"
        const val EXTRA_PERF_MAP_LABELS_ENABLED = "com.flightalert.PERF_MAP_LABELS_ENABLED"
        const val EXTRA_PERF_MAP_ROADS_ENABLED = "com.flightalert.PERF_MAP_ROADS_ENABLED"
        const val EXTRA_PERF_MAP_BORDERS_ENABLED = "com.flightalert.PERF_MAP_BORDERS_ENABLED"
        const val EXTRA_PERF_RESTRICTED_AIRSPACES_ENABLED = "com.flightalert.PERF_RESTRICTED_AIRSPACES_ENABLED"
        const val EXTRA_PERF_CLEAR_SELECTION = "com.flightalert.PERF_CLEAR_SELECTION"
        const val EXTRA_PERF_FOCUS_OPEN_MAP = "com.flightalert.PERF_FOCUS_OPEN_MAP"
        const val EXTRA_PERF_FOCUS_X_FRACTION = "com.flightalert.PERF_FOCUS_X_FRACTION"
        const val EXTRA_PERF_FOCUS_Y_FRACTION = "com.flightalert.PERF_FOCUS_Y_FRACTION"
        const val EXTRA_PERF_SKIP_MAP = "com.flightalert.PERF_SKIP_MAP"
        const val EXTRA_PERF_SKIP_TRAFFIC = "com.flightalert.PERF_SKIP_TRAFFIC"
        const val EXTRA_PERF_SKIP_CHROME = "com.flightalert.PERF_SKIP_CHROME"
        const val EXTRA_PERF_SKIP_TOP_STATUS = "com.flightalert.PERF_SKIP_TOP_STATUS"
        const val EXTRA_PERF_SKIP_CONTROLS = "com.flightalert.PERF_SKIP_CONTROLS"
        const val EXTRA_PERF_SKIP_TRAFFIC_PANEL = "com.flightalert.PERF_SKIP_TRAFFIC_PANEL"
        const val EXTRA_PERF_TRAFFIC_DETAIL_TIMING = "com.flightalert.PERF_TRAFFIC_DETAIL_TIMING"
        const val EXTRA_PERF_FRAME_METRICS_PROBE = "com.flightalert.PERF_FRAME_METRICS_PROBE"
        const val EXTRA_PERF_MAP_DETAIL_TIMING = "com.flightalert.PERF_MAP_DETAIL_TIMING"
        const val DEFAULT_PERF_ZOOM = FlightAlertSettings.PerfLaunch.DEFAULT_ZOOM
    }
}


// Foreground watcher for drone-flight safety: live position plus live aircraft feed, no stored tracks.
class AircraftAlertService : Service(), LocationListener {
    private val executor = Executors.newSingleThreadExecutor()
    private val aircraft_feed_client = AircraftFeedClient(USER_AGENT)
    private val active_hazards = linkedMapOf<String, AlertAircraft>()

    // Settings changes immediately repoll or stop the watcher so notification state follows the configured volume.
    private val preference_listener = SharedPreferences.OnSharedPreferenceChangeListener { _, key ->
        if (key in ALERT_RELEVANT_PREF_KEYS) {
            if (!monitoring_enabled()) {
                stopSelf()
            } else {
                poll_aircraft()
            }
        }
    }
    private lateinit var location_manager: LocationManager
    private lateinit var prefs: SharedPreferences
    private var latest_location: Location? = null
    private var polling = false
    private var stopped = false
    private var foreground_active = false
    private var priority_notification_showing = false
    private var next_poll_delay_ms = POLL_MS
    @Volatile private var latest_priority_snapshot: List<AlertAircraft> = emptyList()

    // Android starts the service here; set up providers, channels, and the first poll.
    override fun onCreate() {
        super.onCreate()
        location_manager = getSystemService(LOCATION_SERVICE) as LocationManager
        prefs = FlightAlertSettings.prefs(this)
        prefs.registerOnSharedPreferenceChangeListener(preference_listener)
        ensure_channels()
        clear_legacy_notifications()
        start_location_updates()
        schedule_poll(1000L)
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (intent?.action == ACTION_PRIORITY_SNAPSHOT) {
            if (!monitoring_enabled()) {
                stopSelf()
                return START_NOT_STICKY
            }
            latest_priority_snapshot = priority_snapshot_from_intent(intent)
            update_priority_notification(latest_priority_snapshot)
            return START_STICKY
        }
        if (!monitoring_enabled()) {
            stopSelf()
            return START_NOT_STICKY
        }
        return START_STICKY
    }

    // Service teardown clears foreground state so no priority notification survives a stopped watcher.
    override fun onDestroy() {
        stopped = true
        if (::prefs.isInitialized) {
            prefs.unregisterOnSharedPreferenceChangeListener(preference_listener)
        }
        clear_legacy_notifications()
        leave_foreground()
        try {
            location_manager.removeUpdates(this)
        } catch (_: SecurityException) {
        }
        executor.shutdownNow()
        super.onDestroy()
    }

    override fun onTaskRemoved(rootIntent: Intent?) {
        stopSelf()
        super.onTaskRemoved(rootIntent)
    }

    override fun onBind(intent: Intent?): IBinder? = null

    // Keep a recent altitude briefly when Android sends a new horizontal fix without altitude.
    override fun onLocationChanged(location: Location) {
        val previous = latest_location
        latest_location = if (!location.hasAltitude() && previous?.hasAltitude() == true && location.time - previous.time < OWN_ALTITUDE_MAX_AGE_MS) {
            Location(location).apply { altitude = previous.altitude }
        } else {
            location
        }
    }


    override fun onProviderEnabled(provider: String) = start_location_updates()

    override fun onProviderDisabled(provider: String) = Unit

    // Seed from last known providers, then subscribe to GPS/network so alert math has real ownship position.
    private fun start_location_updates() {
        if (!has_location_permission()) return
        try {
            location_manager.getProviders(true).forEach { provider ->
                val last = location_manager.getLastKnownLocation(provider)
                if (last != null && should_use_location(last, latest_location)) {
                    latest_location = last
                }
            }
            if (location_manager.getProviders(true).contains(LocationManager.GPS_PROVIDER)) {
                location_manager.requestLocationUpdates(LocationManager.GPS_PROVIDER, 4000L, 10f, this)
            }
            if (location_manager.getProviders(true).contains(LocationManager.NETWORK_PROVIDER)) {
                location_manager.requestLocationUpdates(LocationManager.NETWORK_PROVIDER, 6000L, 20f, this)
            }
        } catch (_: SecurityException) {
        }
    }

    private fun should_use_location(candidate: Location, current: Location?): Boolean {
        if (current == null) return true
        if (candidate.hasAltitude() && !current.hasAltitude()) return true
        return candidate.time > current.time
    }

    private fun schedule_poll(delay_ms: Long) {
        if (stopped) return
        Handler(mainLooper).postDelayed({ poll_aircraft() }, delay_ms)
    }

    // One poll reads location, fetches real aircraft, recomputes hazards, then updates the persistent notification.
    private fun poll_aircraft() {
        if (polling || stopped) return
        if (!monitoring_enabled()) {
            stopSelf()
            return
        }
        val location = latest_location
        if (location == null) {
            start_location_updates()
            update_priority_notification(latest_priority_snapshot)
            next_poll_delay_ms = POLL_MS
            schedule_poll(next_poll_delay_ms)
            return
        }

        polling = true
        executor.execute {
            try {
                val poll = fetch_aircraft(location)
                if (!poll.feed_available) {
                    update_priority_notification(latest_priority_snapshot)
                    next_poll_delay_ms = POLL_MS
                    return@execute
                }

                latest_priority_snapshot = emptyList()
                // The extreme list comes from the classifier; notification code never invents membership.
                val current_hazards = if (alerts_enabled()) {
                    poll.aircraft.filter { it.is_hazard }.associateBy { it.icao24 }
                } else {
                    emptyMap()
                }
                active_hazards.clear()
                active_hazards.putAll(current_hazards)
                val extreme_priority = if (alerts_enabled()) poll.aircraft.filter { it.is_extreme_priority } else emptyList()
                update_priority_notification(extreme_priority)
                next_poll_delay_ms = next_poll_delay_for(
                    aircraft = poll.aircraft,
                    has_hazard = current_hazards.isNotEmpty(),
                    has_extreme_priority = extreme_priority.isNotEmpty(),
                    predictive_delay_ms = poll.next_predictive_poll_delay_ms
                )
            } catch (_: Exception) {
                update_priority_notification(latest_priority_snapshot)
                next_poll_delay_ms = POLL_MS
            } finally {
                polling = false
                schedule_poll(next_poll_delay_ms)
            }
        }
    }

    // Poll faster only while nearby or priority contacts could go stale soon.
    private fun next_poll_delay_for(
        aircraft: List<AlertAircraft>,
        has_hazard: Boolean,
        has_extreme_priority: Boolean,
        predictive_delay_ms: Long? = null
    ): Long {
        val extreme_aircraft = aircraft.filter { it.is_extreme_priority }
        val hazard_aircraft = aircraft.filter { it.is_hazard }
        val priority_aircraft = aircraft.filter { it.is_priority_range_aircraft }
        val normal_delay = when {
            has_extreme_priority -> delay_until_stale(extreme_aircraft, AlertAircraftClassifier.EXTREME_PRIORITY_CONTACT_MAX_AGE_SECONDS)
            has_hazard -> delay_until_stale(hazard_aircraft, PRIORITY_CONTACT_MAX_AGE_SECONDS)
            priority_aircraft.isNotEmpty() -> delay_until_stale(priority_aircraft, PRIORITY_CONTACT_MAX_AGE_SECONDS)
            else -> POLL_MS
        }
        return predictive_delay_ms?.let { min(normal_delay, it) } ?: normal_delay
    }

    private fun delay_until_stale(aircraft: List<AlertAircraft>, max_age_seconds: Double): Long {
        val oldest_age = aircraft.maxOfOrNull { it.contact_age_seconds } ?: return POLL_MS
        val seconds_until_stale = max_age_seconds - oldest_age
        return if (seconds_until_stale <= 0.0) {
            STALE_CONTACT_RETRY_MS
        } else {
            (seconds_until_stale * 1000.0).toLong().coerceIn(STALE_CONTACT_RETRY_MS, (max_age_seconds * 1000.0).toLong())
        }
    }

    // Safety monitoring deliberately uses API feeds only; map Web/Hybrid mode never drives notifications.
    // The query bubble is wider than the alert volume so entering aircraft are seen before they cross the boundary.
    private fun fetch_aircraft(location: Location): AlertPoll {
        val alert_distance_feet = prefs.getFloat(FlightAlertSettings.KEY_ALERT_DISTANCE_FEET, FlightAlertSettings.DEFAULT_ALERT_DISTANCE_FEET)
        val alert_altitude_feet = prefs.getFloat(FlightAlertSettings.KEY_ALERT_ALTITUDE_FEET, FlightAlertSettings.DEFAULT_ALERT_ALTITUDE_FEET)
        val priority_enabled = prefs.getBoolean(FlightAlertSettings.KEY_PRIORITY_TRACKING_ENABLED, false)
        val priority_range_feet = prefs.getFloat(FlightAlertSettings.KEY_PRIORITY_RANGE_FEET, FlightAlertSettings.DEFAULT_PRIORITY_RANGE_FEET)
        val own_altitude_feet = if (location.hasAltitude()) meters_to_feet(location.altitude) else null
        val radius_feet = api_query_radius_feet(alert_distance_feet, priority_enabled, priority_range_feet)
        val radius_meters = max(feet_to_meters(radius_feet), feet_to_meters(MIN_QUERY_RADIUS_FEET))
        val bounds = bounds_around(location, radius_meters)
        val result = aircraft_feed_client.fetch_aircraft(bounds.to_feed_bounds(), location.latitude, location.longitude)
        if (result.status != FeedStatus.OK) return AlertPoll(emptyList(), feed_available = false)
        val airborne_aircraft = result.aircraft.filter { it.on_ground != true }
        val unsupported_altitude_count = airborne_aircraft.count { it.altitude_m == null }
        val now_epoch_sec = System.currentTimeMillis() / 1000.0
        return AlertPoll(
            aircraft = airborne_aircraft
                .mapNotNull {
                    it.to_alert_aircraft(
                        own_lat = location.latitude,
                        own_lon = location.longitude,
                        alert_distance_feet = alert_distance_feet,
                        alert_altitude_feet = alert_altitude_feet,
                        own_altitude_feet = own_altitude_feet,
                        priority_enabled = priority_enabled,
                        priority_range_feet = priority_range_feet,
                        now_epoch_sec = now_epoch_sec
                    )
                }
                .sortedBy { it.distance_feet },
            feed_available = true,
            unsupported_altitude_count = unsupported_altitude_count,
            next_predictive_poll_delay_ms = next_predictive_poll_delay_ms(
                aircraft = airborne_aircraft,
                own_lat = location.latitude,
                own_lon = location.longitude,
                own_altitude_feet = own_altitude_feet,
                alert_distance_feet = alert_distance_feet,
                alert_altitude_feet = alert_altitude_feet,
                now_epoch_sec = now_epoch_sec
            )
        )
    }

    private fun api_query_radius_feet(
        alert_distance_feet: Float,
        priority_enabled: Boolean,
        priority_range_feet: Float
    ): Double {
        val alert_radius = alert_distance_feet.toDouble()
        val alert_radius_with_margin = max(
            alert_radius * ALERT_QUERY_RADIUS_MULTIPLIER,
            alert_radius + ALERT_QUERY_MIN_PADDING_FEET
        )
        val queue_radius = if (priority_enabled) priority_range_feet.toDouble() else MIN_QUERY_RADIUS_FEET
        return max(alert_radius_with_margin, queue_radius)
    }


    // The persistent notification is tied directly to the non-empty extreme-priority list.
    private fun update_priority_notification(priority_aircraft: List<AlertAircraft>) {
        val manager = getSystemService(NOTIFICATION_SERVICE) as NotificationManager
        // Defensive filtering keeps the notification contract tied to classifier output, even if a caller passes nearby queue contacts.
        val extreme_priority_aircraft = PriorityNotificationPresenter.extreme_priority_aircraft(priority_aircraft)
        if (!AlertAircraftClassifier.should_show_persistent_priority_notification(
                alerts_enabled = alerts_enabled(),
                extreme_priority_aircraft = extreme_priority_aircraft,
                has_notification_permission = has_notification_permission()
            )
        ) {
            manager.cancel(PRIORITY_NOTIFICATION_ID)
            priority_notification_showing = false
            leave_foreground()
            return
        }
        val is_update = priority_notification_showing
        val notification = build_notification(
            PRIORITY_CHANNEL_ID,
            "Extreme priority aircraft",
            PriorityNotificationPresenter.notification_body(extreme_priority_aircraft),
            ongoing = true,
            silent = is_update
        )
        try {
            if (foreground_active) {
                notify_priority_fallback(manager, notification)
            } else {
                startForeground(PRIORITY_NOTIFICATION_ID, notification)
                foreground_active = true
            }
            priority_notification_showing = true
        } catch (_: Exception) {
            notify_priority_fallback(manager, notification)
            priority_notification_showing = true
        }
    }

    private fun priority_snapshot_from_intent(intent: Intent): List<AlertAircraft> {
        val icaos = intent.getStringArrayExtra(EXTRA_PRIORITY_ICAO) ?: return emptyList()
        val callsigns = intent.getStringArrayExtra(EXTRA_PRIORITY_CALLSIGN) ?: return emptyList()
        val registrations = intent.getStringArrayExtra(EXTRA_PRIORITY_REGISTRATION) ?: return emptyList()
        val distances = intent.getDoubleArrayExtra(EXTRA_PRIORITY_DISTANCE_FEET) ?: return emptyList()
        val altitudes = intent.getDoubleArrayExtra(EXTRA_PRIORITY_ALTITUDE_FEET) ?: return emptyList()
        val verticals = intent.getDoubleArrayExtra(EXTRA_PRIORITY_VERTICAL_FEET) ?: return emptyList()
        val ages = intent.getDoubleArrayExtra(EXTRA_PRIORITY_CONTACT_AGE_SECONDS) ?: return emptyList()
        val estimated = intent.getBooleanArrayExtra(EXTRA_PRIORITY_ESTIMATED) ?: return emptyList()
        val count = listOf(
            icaos.size,
            callsigns.size,
            registrations.size,
            distances.size,
            altitudes.size,
            verticals.size,
            ages.size,
            estimated.size
        ).minOrNull() ?: return emptyList()
        val aircraft = ArrayList<AlertAircraft>(count)
        for (index in 0 until count) {
            val vertical_separation = verticals[index].takeUnless { it.isNaN() }
            aircraft += AlertAircraft(
                icao24 = icaos[index],
                callsign = callsigns[index],
                registration = registrations[index].takeIf { it.isNotBlank() },
                distance_feet = distances[index],
                altitude_feet = altitudes[index],
                vertical_separation_feet = vertical_separation,
                contact_age_seconds = ages[index],
                is_hazard = true,
                is_priority_range_aircraft = true,
                is_extreme_priority = true,
                is_estimated_position = estimated[index]
            )
        }
        return aircraft
    }

    @SuppressLint("MissingPermission")
    private fun notify_priority_fallback(manager: NotificationManager, notification: Notification) {
        if (!has_notification_permission()) return
        manager.notify(PRIORITY_NOTIFICATION_ID, notification)
    }

    @Suppress("DEPRECATION")
    private fun build_notification(
        channel_id: String,
        title: String,
        body: String,
        ongoing: Boolean,
        silent: Boolean = false
    ): Notification {
        val pending_intent = PendingIntent.getActivity(
            this,
            0,
            Intent(this, MainActivity::class.java),
            PendingIntent.FLAG_UPDATE_CURRENT or immutable_flag()
        )
        val builder = Notification.Builder(this, channel_id)
            .setSmallIcon(android.R.drawable.ic_dialog_alert)
            .setContentTitle(title)
            .setContentText(body)
            .setStyle(Notification.BigTextStyle().bigText(body))
            .setContentIntent(pending_intent)
            .setOnlyAlertOnce(ongoing)
            .setOngoing(ongoing)
            .setAutoCancel(!ongoing)
            .setVisibility(Notification.VISIBILITY_PRIVATE)
            .setPublicVersion(build_public_notification(channel_id, title, ongoing, silent))
        if (silent) {
            builder
                .setDefaults(0)
                .setSound(null)
                .setVibrate(null)
        }
        return builder.build()
    }

    @Suppress("DEPRECATION")
    private fun build_public_notification(channel_id: String, title: String, ongoing: Boolean, silent: Boolean): Notification {
        val builder = Notification.Builder(this, channel_id)
            .setSmallIcon(android.R.drawable.ic_dialog_alert)
            .setContentTitle(title)
            .setContentText("Flight Alert is monitoring live aircraft traffic.")
            .setOnlyAlertOnce(true)
            .setOngoing(ongoing)
            .setAutoCancel(!ongoing)
        if (silent) {
            builder
                .setDefaults(0)
                .setSound(null)
                .setVibrate(null)
        }
        return builder.build()
    }

    private fun ensure_channels() {
        val manager = getSystemService(NOTIFICATION_SERVICE) as NotificationManager
        manager.createNotificationChannel(
            NotificationChannel(PRIORITY_CHANNEL_ID, "Extreme priority aircraft", NotificationManager.IMPORTANCE_HIGH).apply {
                description = "Persistent list of priority-tracked aircraft inside the selected alert range"
            }
        )
    }

    // Clean old notification IDs before using the new extreme-priority foreground notification.
    private fun clear_legacy_notifications() {
        val manager = getSystemService(NOTIFICATION_SERVICE) as NotificationManager
        if (manager.activeNotifications.any { it.id == ONGOING_NOTIFICATION_ID }) {
            take_over_legacy_foreground_notification()
        }
        remove_foreground_notification()
        manager.cancel(ONGOING_NOTIFICATION_ID)
        manager.cancel(PRIORITY_NOTIFICATION_ID)
        repeat(EVENT_NOTIFICATION_ID_WINDOW) { offset ->
            manager.cancel(EVENT_NOTIFICATION_BASE_ID + offset)
        }
    }

    private fun take_over_legacy_foreground_notification() {
        if (!has_notification_permission()) return
        try {
            startForeground(
                ONGOING_NOTIFICATION_ID,
                build_notification(PRIORITY_CHANNEL_ID, "Flight Alert", "Updating alert notifications.", true)
            )
            foreground_active = true
        } catch (_: Exception) {
        }
    }

    private fun leave_foreground() {
        if (!foreground_active) return
        remove_foreground_notification()
    }

    private fun remove_foreground_notification() {
        stopForeground(STOP_FOREGROUND_REMOVE)
        foreground_active = false
        priority_notification_showing = false
    }

    private fun has_location_permission(): Boolean = has_flight_location_permission()

    private fun has_notification_permission(): Boolean {
        return Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU ||
            checkSelfPermission(Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED
    }

    private fun alerts_enabled(): Boolean {
        return prefs.getBoolean(FlightAlertSettings.KEY_ALERTS_ENABLED, true)
    }

    private fun priority_tracking_enabled(): Boolean {
        return prefs.getBoolean(FlightAlertSettings.KEY_PRIORITY_TRACKING_ENABLED, false)
    }

    private fun monitoring_enabled(): Boolean {
        return alerts_enabled() || priority_tracking_enabled()
    }

    // Turn the alert radius into a provider query box around the device location.
    private fun bounds_around(location: Location, radius_meters: Double): Bounds =
        bounds_around_location(location, radius_meters)

    private fun Bounds.to_feed_bounds(): FeedBounds {
        return FeedBounds(min_lat = min_lat, min_lon = min_lon, max_lat = max_lat, max_lon = max_lon)
    }

    // Convert provider units into classifier inputs so 3D alert math stays in one object.
    private fun FeedAircraft.to_alert_aircraft(
        own_lat: Double,
        own_lon: Double,
        alert_distance_feet: Float,
        alert_altitude_feet: Float,
        own_altitude_feet: Double?,
        priority_enabled: Boolean,
        priority_range_feet: Float,
        now_epoch_sec: Double
    ): AlertAircraft? {
        val projected = projected_alert_state(own_lat, own_lon, now_epoch_sec)
        return AlertAircraftClassifier.classify(
            icao24 = icao24,
            callsign = callsign,
            registration = registration,
            distance_meters = projected.distance_meters,
            altitude_meters = projected.altitude_meters,
            last_contact_sec = last_contact_sec,
            position_time_sec = position_time_sec,
            own_altitude_feet = own_altitude_feet,
            alerts_enabled = alerts_enabled(),
            alert_distance_feet = alert_distance_feet,
            alert_altitude_feet = alert_altitude_feet,
            priority_enabled = priority_enabled,
            priority_range_feet = priority_range_feet,
            now_epoch_sec = now_epoch_sec,
            is_estimated_position = projected.estimated
        )
    }

    private fun next_predictive_poll_delay_ms(
        aircraft: List<FeedAircraft>,
        own_lat: Double,
        own_lon: Double,
        own_altitude_feet: Double?,
        alert_distance_feet: Float,
        alert_altitude_feet: Float,
        now_epoch_sec: Double
    ): Long? {
        if (!alerts_enabled() || own_altitude_feet == null) return null
        val alert_distance_m = feet_to_meters(alert_distance_feet.toDouble())
        val alert_altitude_m = feet_to_meters(alert_altitude_feet.toDouble())
        val own_altitude_m = feet_to_meters(own_altitude_feet)
        var soonest_delay_ms: Long? = null
        for (item in aircraft) {
            if (!item.has_fresh_projectable_motion(now_epoch_sec) || item.altitude_m == null) continue
            for (seconds_ahead in 1..ALERT_ENTRY_LOOKAHEAD_SECONDS) {
                val state = item.projected_alert_state(own_lat, own_lon, now_epoch_sec + seconds_ahead)
                val altitude_m = state.altitude_meters ?: continue
                val vertical_separation_m = abs(altitude_m - own_altitude_m)
                if (state.distance_meters <= alert_distance_m && vertical_separation_m <= alert_altitude_m) {
                    val delay_ms = ((seconds_ahead * 1000L) - ALERT_ENTRY_POLL_LEAD_MS)
                        .coerceAtLeast(STALE_CONTACT_RETRY_MS)
                    soonest_delay_ms = soonest_delay_ms?.let { min(it, delay_ms) } ?: delay_ms
                    break
                }
            }
        }
        return soonest_delay_ms
    }

    private fun FeedAircraft.projected_alert_state(own_lat: Double, own_lon: Double, now_epoch_sec: Double): ProjectedAlertPosition {
        return AlertPositionProjector.projected_alert_position(
            own_lat = own_lat,
            own_lon = own_lon,
            aircraft_lat = lat,
            aircraft_lon = lon,
            reported_distance_meters = distance_m,
            altitude_meters = altitude_m,
            velocity_ms = velocity_ms,
            track_deg = track_deg,
            vertical_rate_ms = vertical_rate_ms,
            position_time_sec = position_time_sec,
            last_contact_sec = last_contact_sec,
            now_epoch_sec = now_epoch_sec
        )
    }

    private fun FeedAircraft.has_fresh_projectable_motion(now_epoch_sec: Double): Boolean {
        return AlertPositionProjector.has_fresh_projectable_motion(
            velocity_ms = velocity_ms,
            track_deg = track_deg,
            position_time_sec = position_time_sec,
            last_contact_sec = last_contact_sec,
            now_epoch_sec = now_epoch_sec,
            freshness_seconds = ALERT_ENTRY_LOOKAHEAD_SECONDS + AlertPositionProjector.ALERT_PROJECTION_MAX_SECONDS
        )
    }

    private fun feet_to_meters(feet: Double): Double = feet / 3.28084

    private fun meters_to_feet(meters: Double): Double = meters * 3.28084

    private fun immutable_flag(): Int = PendingIntent.FLAG_IMMUTABLE

    
    private data class AlertPoll(
        val aircraft: List<AlertAircraft>,
        val feed_available: Boolean,
        val unsupported_altitude_count: Int = 0,
        val next_predictive_poll_delay_ms: Long? = null
    )

    companion object {
        const val MONITORING_CHANNEL_ID = "aircraft_monitoring_status"
        const val HAZARD_CHANNEL_ID = "aircraft_range_events"
        const val PRIORITY_CHANNEL_ID = "extreme_priority_aircraft"
        const val ACTION_PRIORITY_SNAPSHOT = "com.flightalert.service.ACTION_PRIORITY_SNAPSHOT"
        const val EXTRA_PRIORITY_ICAO = "com.flightalert.service.EXTRA_PRIORITY_ICAO"
        const val EXTRA_PRIORITY_CALLSIGN = "com.flightalert.service.EXTRA_PRIORITY_CALLSIGN"
        const val EXTRA_PRIORITY_REGISTRATION = "com.flightalert.service.EXTRA_PRIORITY_REGISTRATION"
        const val EXTRA_PRIORITY_DISTANCE_FEET = "com.flightalert.service.EXTRA_PRIORITY_DISTANCE_FEET"
        const val EXTRA_PRIORITY_ALTITUDE_FEET = "com.flightalert.service.EXTRA_PRIORITY_ALTITUDE_FEET"
        const val EXTRA_PRIORITY_VERTICAL_FEET = "com.flightalert.service.EXTRA_PRIORITY_VERTICAL_FEET"
        const val EXTRA_PRIORITY_CONTACT_AGE_SECONDS = "com.flightalert.service.EXTRA_PRIORITY_CONTACT_AGE_SECONDS"
        const val EXTRA_PRIORITY_ESTIMATED = "com.flightalert.service.EXTRA_PRIORITY_ESTIMATED"
        const val ONGOING_NOTIFICATION_ID = FlightAlertSettings.AlertService.ONGOING_NOTIFICATION_ID
        const val PRIORITY_NOTIFICATION_ID = FlightAlertSettings.AlertService.PRIORITY_NOTIFICATION_ID
        const val EVENT_NOTIFICATION_BASE_ID = FlightAlertSettings.AlertService.EVENT_NOTIFICATION_BASE_ID
        const val EVENT_NOTIFICATION_ID_WINDOW = FlightAlertSettings.AlertService.EVENT_NOTIFICATION_ID_WINDOW
        const val POLL_MS = FlightAlertSettings.AlertService.POLL_MS
        const val PRIORITY_CONTACT_MAX_AGE_SECONDS = FlightAlertSettings.AlertService.PRIORITY_CONTACT_MAX_AGE_SECONDS
        const val STALE_CONTACT_RETRY_MS = FlightAlertSettings.AlertService.STALE_CONTACT_RETRY_MS
        const val ALERT_ENTRY_LOOKAHEAD_SECONDS = FlightAlertSettings.AlertService.ALERT_ENTRY_LOOKAHEAD_SECONDS
        const val ALERT_ENTRY_POLL_LEAD_MS = FlightAlertSettings.AlertService.ALERT_ENTRY_POLL_LEAD_MS
        const val MIN_QUERY_RADIUS_FEET = FlightAlertSettings.AlertService.MIN_QUERY_RADIUS_FEET
        const val ALERT_QUERY_MIN_PADDING_FEET = FlightAlertSettings.AlertService.ALERT_QUERY_MIN_PADDING_FEET
        const val ALERT_QUERY_RADIUS_MULTIPLIER = FlightAlertSettings.AlertService.ALERT_QUERY_RADIUS_MULTIPLIER
        const val OWN_ALTITUDE_MAX_AGE_MS = FlightAlertSettings.AlertService.OWN_ALTITUDE_MAX_AGE_MS
        const val USER_AGENT = FlightAlertSettings.App.USER_AGENT
        val ALERT_RELEVANT_PREF_KEYS = setOf(
            FlightAlertSettings.KEY_ALERTS_ENABLED,
            FlightAlertSettings.KEY_ALERT_DISTANCE_FEET,
            FlightAlertSettings.KEY_ALERT_ALTITUDE_FEET,
            FlightAlertSettings.KEY_PRIORITY_TRACKING_ENABLED,
            FlightAlertSettings.KEY_PRIORITY_RANGE_FEET
        )

        fun start(context: Context) {
            context.startService(Intent(context, AircraftAlertService::class.java))
        }

        fun publish_priority_snapshot(context: Context, priority_aircraft: List<AlertAircraft>) {
            val intent = Intent(context, AircraftAlertService::class.java).apply {
                action = ACTION_PRIORITY_SNAPSHOT
                putExtra(EXTRA_PRIORITY_ICAO, priority_aircraft.map { it.icao24 }.toTypedArray())
                putExtra(EXTRA_PRIORITY_CALLSIGN, priority_aircraft.map { it.callsign }.toTypedArray())
                putExtra(EXTRA_PRIORITY_REGISTRATION, priority_aircraft.map { it.registration.orEmpty() }.toTypedArray())
                putExtra(EXTRA_PRIORITY_DISTANCE_FEET, priority_aircraft.map { it.distance_feet }.toDoubleArray())
                putExtra(EXTRA_PRIORITY_ALTITUDE_FEET, priority_aircraft.map { it.altitude_feet }.toDoubleArray())
                putExtra(
                    EXTRA_PRIORITY_VERTICAL_FEET,
                    priority_aircraft.map { it.vertical_separation_feet ?: Double.NaN }.toDoubleArray()
                )
                putExtra(EXTRA_PRIORITY_CONTACT_AGE_SECONDS, priority_aircraft.map { it.contact_age_seconds }.toDoubleArray())
                putExtra(EXTRA_PRIORITY_ESTIMATED, priority_aircraft.map { it.is_estimated_position }.toBooleanArray())
            }
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O && priority_aircraft.isNotEmpty()) {
                context.startForegroundService(intent)
            } else {
                context.startService(intent)
            }
        }

        fun stop(context: Context) {
            context.stopService(Intent(context, AircraftAlertService::class.java))
        }
    }
}


data class AlertAircraft(
    val icao24: String,
    val callsign: String,
    val registration: String?,
    val distance_feet: Double,
    val altitude_feet: Double,
    val vertical_separation_feet: Double?,
    val contact_age_seconds: Double,
    val is_hazard: Boolean,
    val is_priority_range_aircraft: Boolean,
    val is_extreme_priority: Boolean,
    val is_estimated_position: Boolean = false
)

object AlertAircraftClassifier {
    // The classifier is the single place that decides whether a live contact can enter the alert volume.
    fun classify(
        icao24: String,
        callsign: String,
        registration: String?,
        distance_meters: Double,
        altitude_meters: Double?,
        last_contact_sec: Double?,
        position_time_sec: Double?,
        own_altitude_feet: Double?,
        alerts_enabled: Boolean,
        alert_distance_feet: Float,
        alert_altitude_feet: Float,
        priority_enabled: Boolean,
        priority_range_feet: Float,
        now_epoch_sec: Double,
        is_estimated_position: Boolean = false
    ): AlertAircraft? {
        val altitude_meters = altitude_meters ?: return null
        val contact_time = last_contact_sec ?: position_time_sec ?: return null
        val contact_age_seconds = max(0.0, now_epoch_sec - contact_time)
        val distance_feet = meters_to_feet(distance_meters)
        val altitude_feet = meters_to_feet(altitude_meters)
        val vertical_separation_feet = own_altitude_feet?.let { abs(altitude_feet - it) }
        val contact_is_fresh_for_alert = contact_age_seconds <= EXTREME_PRIORITY_CONTACT_MAX_AGE_SECONDS
        val is_inside_alert_range = distance_feet <= alert_distance_feet &&
            vertical_separation_feet != null &&
            vertical_separation_feet <= alert_altitude_feet
        val is_alert_aircraft = alerts_enabled && contact_is_fresh_for_alert && is_inside_alert_range
        return AlertAircraft(
            icao24 = icao24,
            callsign = callsign,
            registration = registration,
            distance_feet = distance_feet,
            altitude_feet = altitude_feet,
            vertical_separation_feet = vertical_separation_feet,
            contact_age_seconds = contact_age_seconds,
            is_hazard = is_alert_aircraft,
            is_priority_range_aircraft = priority_enabled && distance_feet <= priority_range_feet,
            is_extreme_priority = is_alert_aircraft,
            is_estimated_position = is_estimated_position
        )
    }

    fun should_show_persistent_priority_notification(
        alerts_enabled: Boolean,
        extreme_priority_aircraft: List<AlertAircraft>,
        has_notification_permission: Boolean
    ): Boolean {
        return alerts_enabled && extreme_priority_aircraft.any { it.is_extreme_priority } && has_notification_permission
    }

    private fun meters_to_feet(meters: Double): Double = meters * FEET_PER_METER

    const val EXTREME_PRIORITY_CONTACT_MAX_AGE_SECONDS = 3.0

    private const val FEET_PER_METER = 3.28084
}


data class ProjectedAlertPosition(
    val distance_meters: Double,
    val altitude_meters: Double?,
    val estimated: Boolean
)

object AlertPositionProjector {
    fun projected_alert_position(
        own_lat: Double,
        own_lon: Double,
        aircraft_lat: Double,
        aircraft_lon: Double,
        reported_distance_meters: Double,
        altitude_meters: Double?,
        velocity_ms: Double?,
        track_deg: Double?,
        vertical_rate_ms: Double?,
        position_time_sec: Double?,
        last_contact_sec: Double?,
        now_epoch_sec: Double,
        max_projection_seconds: Double = ALERT_PROJECTION_MAX_SECONDS
    ): ProjectedAlertPosition {
        val reported_distance = reported_distance(
            own_lat = own_lat,
            own_lon = own_lon,
            aircraft_lat = aircraft_lat,
            aircraft_lon = aircraft_lon,
            reported_distance_meters = reported_distance_meters
        )
        val age_seconds = projection_age_seconds(position_time_sec, last_contact_sec, now_epoch_sec, max_projection_seconds)
        if (age_seconds <= ALERT_PROJECTION_MIN_SECONDS || !has_projectable_motion(velocity_ms, track_deg)) {
            return ProjectedAlertPosition(reported_distance, altitude_meters, estimated = false)
        }
        val speed = velocity_ms ?: return ProjectedAlertPosition(reported_distance, altitude_meters, estimated = false)
        val track = normalized_degrees(track_deg) ?: return ProjectedAlertPosition(reported_distance, altitude_meters, estimated = false)
        val projected = advance_position(aircraft_lat, aircraft_lon, track, speed * age_seconds)
        return ProjectedAlertPosition(
            distance_meters = distance_meters(own_lat, own_lon, projected.lat, projected.lon),
            altitude_meters = projected_altitude_meters(altitude_meters, vertical_rate_ms, age_seconds),
            estimated = true
        )
    }

    fun contact_age_seconds(position_time_sec: Double?, last_contact_sec: Double?, now_epoch_sec: Double): Double? {
        val contact = last_contact_sec ?: position_time_sec ?: return null
        return (now_epoch_sec - contact).coerceAtLeast(0.0)
    }

    fun has_fresh_projectable_motion(
        velocity_ms: Double?,
        track_deg: Double?,
        position_time_sec: Double?,
        last_contact_sec: Double?,
        now_epoch_sec: Double,
        freshness_seconds: Double
    ): Boolean {
        val report_time = position_time_sec ?: last_contact_sec ?: return false
        if (now_epoch_sec - report_time > freshness_seconds) return false
        return has_projectable_motion(velocity_ms, track_deg)
    }

    fun distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double {
        val d_lat = Math.toRadians(lat2 - lat1)
        val d_lon = Math.toRadians(lon2 - lon1)
        val a = sin(d_lat / 2).pow(2.0) +
            cos(Math.toRadians(lat1)) * cos(Math.toRadians(lat2)) * sin(d_lon / 2).pow(2.0)
        return 2 * EARTH_RADIUS_M * atan2(sqrt(a), sqrt(1 - a))
    }

    private fun reported_distance(
        own_lat: Double,
        own_lon: Double,
        aircraft_lat: Double,
        aircraft_lon: Double,
        reported_distance_meters: Double
    ): Double {
        return if (reported_distance_meters.isFinite() && reported_distance_meters > 0.0) {
            reported_distance_meters
        } else {
            distance_meters(own_lat, own_lon, aircraft_lat, aircraft_lon)
        }
    }

    private fun projection_age_seconds(
        position_time_sec: Double?,
        last_contact_sec: Double?,
        now_epoch_sec: Double,
        max_projection_seconds: Double
    ): Double {
        val report_time = position_time_sec ?: last_contact_sec ?: return 0.0
        return (now_epoch_sec - report_time)
            .coerceAtLeast(0.0)
            .coerceAtMost(max_projection_seconds.coerceAtLeast(0.0))
    }

    private fun projected_altitude_meters(altitude_meters: Double?, vertical_rate_ms: Double?, age_seconds: Double): Double? {
        val altitude = altitude_meters ?: return null
        val vertical_rate = vertical_rate_ms
            ?.takeIf { it.isFinite() && abs(it) <= MAX_PROJECTABLE_VERTICAL_RATE_MS }
            ?: return altitude
        return altitude + vertical_rate * age_seconds
    }

    private fun has_projectable_motion(velocity_ms: Double?, track_deg: Double?): Boolean {
        val speed = velocity_ms ?: return false
        return speed.isFinite() &&
            speed in MIN_PROJECTABLE_ALERT_SPEED_MS..MAX_PROJECTABLE_ALERT_SPEED_MS &&
            normalized_degrees(track_deg) != null
    }

    private fun advance_position(lat: Double, lon: Double, track_degrees: Double, distance_meters: Double): GeoPosition {
        val angular_distance = distance_meters / EARTH_RADIUS_M
        val bearing = Math.toRadians(track_degrees)
        val lat1 = Math.toRadians(lat)
        val lon1 = Math.toRadians(lon)
        val lat2 = asin(sin(lat1) * cos(angular_distance) + cos(lat1) * sin(angular_distance) * cos(bearing))
        val lon2 = lon1 + atan2(
            sin(bearing) * sin(angular_distance) * cos(lat1),
            cos(angular_distance) - sin(lat1) * sin(lat2)
        )
        return GeoPosition(
            lat = Math.toDegrees(lat2).coerceIn(-90.0, 90.0),
            lon = normalize_lon_degrees(Math.toDegrees(lon2))
        )
    }

    private fun normalized_degrees(value: Double?): Double? {
        val degrees = value?.takeIf { it.isFinite() } ?: return null
        return ((degrees % 360.0) + 360.0) % 360.0
    }

    private fun normalize_lon_degrees(value: Double): Double {
        return ((value + 540.0) % 360.0) - 180.0
    }

    private data class GeoPosition(val lat: Double, val lon: Double)

    const val ALERT_PROJECTION_MAX_SECONDS = FlightAlertSettings.AlertProjection.MAX_SECONDS
    const val ALERT_PROJECTION_MIN_SECONDS = FlightAlertSettings.AlertProjection.MIN_SECONDS
    const val MIN_PROJECTABLE_ALERT_SPEED_MS = FlightAlertSettings.AlertProjection.MIN_PROJECTABLE_SPEED_MS
    const val MAX_PROJECTABLE_ALERT_SPEED_MS = FlightAlertSettings.AlertProjection.MAX_PROJECTABLE_SPEED_MS
    const val MAX_PROJECTABLE_VERTICAL_RATE_MS = FlightAlertSettings.AlertProjection.MAX_PROJECTABLE_VERTICAL_RATE_MS
    const val EARTH_RADIUS_M = 6371000.0
}


object PriorityNotificationPresenter {
    fun extreme_priority_aircraft(priority_aircraft: List<AlertAircraft>): List<AlertAircraft> {
        return priority_aircraft.filter { it.is_extreme_priority }
    }

    fun notification_body(extreme_priority_aircraft: List<AlertAircraft>): String {
        val body = extreme_priority_aircraft
            .sortedWith(compareBy<AlertAircraft> { it.altitude_feet }.thenBy { it.distance_feet })
            .take(MAX_LISTED_AIRCRAFT)
            .joinToString("; ") { aircraft ->
                val registration = aircraft.registration ?: "reg unavailable"
                val estimate_note = if (aircraft.is_estimated_position) " est." else ""
                String.format(Locale.US, "%s %.0f ft%s", registration, aircraft.altitude_feet, estimate_note)
            }
        val suffix = if (extreme_priority_aircraft.size > MAX_LISTED_AIRCRAFT) {
            " +${extreme_priority_aircraft.size - MAX_LISTED_AIRCRAFT} more"
        } else {
            ""
        }
        return "$body$suffix"
    }

    private const val MAX_LISTED_AIRCRAFT = FlightAlertSettings.PriorityNotification.MAX_LISTED_AIRCRAFT
}

