class AlertMonitoringController(private val context: Context) {
    fun apply(alerts_enabled: Boolean, priority_tracking_enabled: Boolean) {
        if (alerts_enabled || priority_tracking_enabled) {
            AircraftAlertService.start(context)
        } else {
            AircraftAlertService.stop(context)
        }
    }

    fun publish_priority_snapshot(priority_aircraft: List<AlertAircraft>) {
        AircraftAlertService.publish_priority_snapshot(context, priority_aircraft)
    }
}


class AviationLayerController(
    private val client: AviationLayerClient,
    private val run_in_background: (() -> Unit) -> Unit,
    private val post_to_main: (() -> Unit) -> Unit,
    private val request_redraw: () -> Unit,
    private val current_viewport: () -> Viewport?,
    private val visible_bounds: (Viewport) -> Bounds?,
    private val refresh_ms: Long,
    private val bounds_padding_fraction: Double,
    private val now_ms: () -> Long = { SystemClock.elapsedRealtime() },
    private val fetch_layers: (AviationLayerBounds, Boolean, Boolean, Boolean, Boolean) -> AviationLayerSnapshot =
        { bounds, include_atc_boundaries, include_restricted_airspaces, include_airports, include_oceanic_tracks ->
            client.fetch_layers(
                bounds = bounds,
                include_atc_boundaries = include_atc_boundaries,
                include_restricted_airspaces = include_restricted_airspaces,
                include_airports = include_airports,
                include_oceanic_tracks = include_oceanic_tracks
            )
        }
) {
    var snapshot: AviationLayerSnapshot? = null
        private set

    var fetch_in_flight: Boolean = false
        private set

    var status_text: String = "Layers off"
        private set

    private var last_fetch_ms = 0L
    private var last_bounds: Bounds? = null
    private var last_selection_key = ""
    private var latest_visibility = AviationLayerVisibility(
        restricted_airspaces_enabled = false,
        atc_boundaries_enabled = false,
        oceanic_tracks_enabled = false,
        airport_labels_enabled = false
    )

    fun request_if_needed(viewport: Viewport, visibility: AviationLayerVisibility, force: Boolean = false) {
        latest_visibility = visibility
        if (!has_enabled_layers(visibility)) {
            status_text = "Layers off"
            request_warm_aviation_layers_if_needed(viewport)
            return
        }
        val query_bounds = layer_bounds_for_viewport(viewport)
        val visible_viewport_bounds = visible_bounds(viewport) ?: query_bounds
        val selection_key = selection_key(visibility)
        val now = now_ms()
        val needs_fetch = force ||
            snapshot == null ||
            !snapshot_covers_visibility(snapshot, visibility) ||
            last_bounds?.contains(visible_viewport_bounds) != true ||
            now - last_fetch_ms >= refresh_ms
        if (!needs_fetch || fetch_in_flight) {
            if (!needs_fetch) status_text = summary(snapshot, visibility)
            return
        }

        status_text = "Loading aviation layers"
        start_fetch(
            query_bounds = query_bounds,
            visibility = visibility,
            selection_key = selection_key,
            prefetch = false,
            now = now
        )
    }

    private fun request_warm_aviation_layers_if_needed(viewport: Viewport) {
        val query_bounds = layer_bounds_for_viewport(viewport)
        val visible_viewport_bounds = visible_bounds(viewport) ?: query_bounds
        val visibility = WARM_AVIATION_LAYERS_VISIBILITY
        val selection_key = selection_key(visibility)
        val now = now_ms()
        val needs_fetch = snapshot == null ||
            !snapshot_covers_visibility(snapshot, visibility) ||
            last_bounds?.contains(visible_viewport_bounds) != true ||
            now - last_fetch_ms >= refresh_ms
        if (!needs_fetch || fetch_in_flight) return
        start_fetch(
            query_bounds = query_bounds,
            visibility = visibility,
            selection_key = selection_key,
            prefetch = true,
            now = now
        )
    }

    private fun start_fetch(
        query_bounds: Bounds,
        visibility: AviationLayerVisibility,
        selection_key: String,
        prefetch: Boolean,
        now: Long
    ) {
        val requested_kinds = active_kinds(visibility)
        fetch_in_flight = true
        last_fetch_ms = now
        run_in_background {
            val next_snapshot = try {
                fetch_layers(
                    query_bounds.to_aviation_layer_bounds(),
                    visibility.atc_boundaries_enabled,
                    visibility.restricted_airspaces_enabled,
                    visibility.airport_labels_enabled,
                    visibility.oceanic_tracks_enabled
                )
            } catch (_: Exception) {
                null
            }
            post_to_main {
                apply_fetch_result(
                    snapshot = next_snapshot,
                    requested_kinds = requested_kinds,
                    query_bounds = query_bounds,
                    selection_key = selection_key,
                    prefetch = prefetch
                )
            }
        }
    }

    fun on_visibility_changed(visibility: AviationLayerVisibility) {
        latest_visibility = visibility
        if (!has_enabled_layers(visibility)) {
            status_text = "Layers off"
            current_viewport()?.let { request_warm_aviation_layers_if_needed(it) }
            request_redraw()
            return
        }
        status_text = summary(snapshot, visibility)
        current_viewport()?.let { request_if_needed(it, visibility, force = false) }
    }

    fun clear() {
        snapshot = null
        fetch_in_flight = false
        last_bounds = null
        last_selection_key = ""
        status_text = "Layers off"
    }

    fun has_enabled_layers(visibility: AviationLayerVisibility): Boolean {
        return visibility.atc_boundaries_enabled ||
            visibility.restricted_airspaces_enabled ||
            visibility.oceanic_tracks_enabled ||
            visibility.airport_labels_enabled
    }

    private fun apply_fetch_result(
        snapshot: AviationLayerSnapshot?,
        requested_kinds: List<AviationLayerKind>,
        query_bounds: Bounds,
        selection_key: String,
        prefetch: Boolean
    ) {
        fetch_in_flight = false
        val latest_key = selection_key(latest_visibility)
        val latest_enabled = has_enabled_layers(latest_visibility)
        if (selection_key != latest_key &&
            !snapshot_covers_visibility(snapshot, latest_visibility) &&
            (!prefetch || latest_enabled)
        ) {
            last_fetch_ms = 0L
            status_text = if (latest_enabled) "Refreshing aviation layers" else "Layers off"
            current_viewport()?.let { request_if_needed(it, latest_visibility, force = true) }
            request_redraw()
            return
        }
        if (snapshot == null) {
            status_text = if (this.snapshot != null) {
                "Aviation layers unavailable; keeping previous"
            } else {
                "Aviation layers unavailable"
            }
            request_redraw()
            return
        }

        val requested_kind_set = requested_kinds.toSet()
        val all_unavailable = requested_kinds.isNotEmpty() &&
            requested_kinds.all { snapshot.statuses[it]?.state == AviationLayerState.UNAVAILABLE }
        val previous = this.snapshot
        this.snapshot = if (all_unavailable && previous != null) {
            merge_layer_snapshot(previous, snapshot, emptySet())
        } else {
            previous?.let { merge_layer_snapshot(it, snapshot, requested_kind_set) } ?: snapshot
        }
        last_bounds = query_bounds
        last_selection_key = selection_key
        status_text = if (latest_enabled) {
            summary(this.snapshot, latest_visibility, kept_last_good = all_unavailable && previous != null)
        } else {
            "Layers off"
        }
        request_redraw()
    }

    private fun layer_bounds_for_viewport(viewport: Viewport): Bounds {
        val padding = max(viewport.width, viewport.height) * bounds_padding_fraction
        val left = viewport.center_x - viewport.width / 2.0 - padding
        val right = viewport.center_x + viewport.width / 2.0 + padding
        val top = viewport.center_y - viewport.height / 2.0 - padding
        val bottom = viewport.center_y + viewport.height / 2.0 + padding
        val top_left = MapProjection.world_to_lat_lon(left, top, viewport.zoom)
        val bottom_right = MapProjection.world_to_lat_lon(right, bottom, viewport.zoom)
        val world_width = TILE_SIZE * 2.0.pow(viewport.zoom)
        val longitude_span_degrees = ((right - left) / world_width) * 360.0
        val use_world_longitude_bounds = abs(top_left.lon - bottom_right.lon) > 180.0 ||
            longitude_span_degrees >= 180.0
        return Bounds(
            min_lat = min(top_left.lat, bottom_right.lat).coerceIn(-90.0, 90.0),
            min_lon = if (use_world_longitude_bounds) -180.0 else min(top_left.lon, bottom_right.lon).coerceIn(-180.0, 180.0),
            max_lat = max(top_left.lat, bottom_right.lat).coerceIn(-90.0, 90.0),
            max_lon = if (use_world_longitude_bounds) 180.0 else max(top_left.lon, bottom_right.lon).coerceIn(-180.0, 180.0)
        )
    }

    private fun active_kinds(visibility: AviationLayerVisibility): List<AviationLayerKind> {
        val kinds = mutableListOf<AviationLayerKind>()
        if (visibility.atc_boundaries_enabled) kinds += AviationLayerKind.ATC_BOUNDARIES
        if (visibility.restricted_airspaces_enabled) kinds += AviationLayerKind.RESTRICTED_AIRSPACES
        if (visibility.oceanic_tracks_enabled) kinds += AviationLayerKind.OCEANIC_TRACKS
        if (visibility.airport_labels_enabled) kinds += AviationLayerKind.AIRPORTS
        return kinds
    }

    private fun selection_key(visibility: AviationLayerVisibility): String {
        return listOf(
            if (visibility.atc_boundaries_enabled) "atc" else "",
            if (visibility.restricted_airspaces_enabled) "restricted" else "",
            if (visibility.oceanic_tracks_enabled) "oceanic" else "",
            if (visibility.airport_labels_enabled) "airports" else ""
        ).joinToString("|")
    }

    private fun summary(
        snapshot: AviationLayerSnapshot?,
        visibility: AviationLayerVisibility,
        kept_last_good: Boolean = false
    ): String {
        if (!has_enabled_layers(visibility)) return "Layers off"
        snapshot ?: return "Waiting for aviation layers"
        val loaded = active_kinds(visibility).count { snapshot.statuses[it]?.state == AviationLayerState.LOADED }
        return when {
            kept_last_good -> "Network unavailable; showing last aviation layers"
            loaded > 0 -> "$loaded aviation layer${if (loaded == 1) "" else "s"} loaded"
            else -> "No aviation layer data in view"
        }
    }

    private fun snapshot_covers_visibility(snapshot: AviationLayerSnapshot?, visibility: AviationLayerVisibility): Boolean {
        snapshot ?: return false
        return active_kinds(visibility).all { kind ->
            snapshot.statuses[kind] != null
        }
    }

    private fun merge_layer_snapshot(
        previous: AviationLayerSnapshot,
        fetched: AviationLayerSnapshot,
        requested_kinds: Set<AviationLayerKind>
    ): AviationLayerSnapshot {
        return AviationLayerSnapshot(
            atc_boundaries = merged_layer_data(
                kind = AviationLayerKind.ATC_BOUNDARIES,
                requested_kinds = requested_kinds,
                fetched_statuses = fetched.statuses,
                previous = previous.atc_boundaries,
                fetched = fetched.atc_boundaries
            ),
            restricted_airspaces = merged_layer_data(
                kind = AviationLayerKind.RESTRICTED_AIRSPACES,
                requested_kinds = requested_kinds,
                fetched_statuses = fetched.statuses,
                previous = previous.restricted_airspaces,
                fetched = fetched.restricted_airspaces
            ),
            airports = merged_layer_data(
                kind = AviationLayerKind.AIRPORTS,
                requested_kinds = requested_kinds,
                fetched_statuses = fetched.statuses,
                previous = previous.airports,
                fetched = fetched.airports
            ),
            oceanic_tracks = merged_layer_data(
                kind = AviationLayerKind.OCEANIC_TRACKS,
                requested_kinds = requested_kinds,
                fetched_statuses = fetched.statuses,
                previous = previous.oceanic_tracks,
                fetched = fetched.oceanic_tracks
            ),
            statuses = previous.statuses + fetched.statuses,
            fetched_at_ms = fetched.fetched_at_ms
        )
    }

    private fun <T> merged_layer_data(
        kind: AviationLayerKind,
        requested_kinds: Set<AviationLayerKind>,
        fetched_statuses: Map<AviationLayerKind, AviationLayerStatus>,
        previous: List<T>,
        fetched: List<T>
    ): List<T> {
        if (kind !in requested_kinds) return previous
        if (fetched_statuses[kind]?.state == AviationLayerState.UNAVAILABLE) return previous
        return fetched
    }

    private fun Bounds.to_aviation_layer_bounds(): AviationLayerBounds {
        return AviationLayerBounds(min_lat = min_lat, min_lon = min_lon, max_lat = max_lat, max_lon = max_lon)
    }

    private fun Bounds.contains(other: Bounds): Boolean {
        return min_lat <= other.min_lat &&
            min_lon <= other.min_lon &&
            max_lat >= other.max_lat &&
            max_lon >= other.max_lon
    }

    private companion object {
        const val TILE_SIZE = FlightAlertSettings.AviationLayer.TILE_SIZE
        val WARM_AVIATION_LAYERS_VISIBILITY = AviationLayerVisibility(
            restricted_airspaces_enabled = true,
            atc_boundaries_enabled = true,
            oceanic_tracks_enabled = true,
            airport_labels_enabled = true
        )
    }
}

// endregion

// region SELECTED AIRCRAFT INTELLIGENCE

internal class AircraftDetailsContentBuilder(
    private val muted_color: () -> Int,
    private val impact_score_color: (ImpactProfile) -> Int,
    private val loading_or_unavailable: (Boolean) -> String,
    private val is_details_loading_for: (Aircraft) -> Boolean,
    private val is_flight_path_loading: (Aircraft) -> Boolean,
    private val current_impact_trace_for: (Aircraft) -> ImpactTrace?,
    private val usage_trace_for: (Aircraft) -> FlightTrace?,
    private val units: () -> UnitSystem
) {
    fun impact_panel_state(aircraft: Aircraft?, details: AircraftDetails?): AircraftImpactPanelState {
        if (aircraft == null) {
            return AircraftImpactPanelState(
                selected_aircraft_available = false,
                status = "Unavailable",
                show_trace_co2 = false,
                co2_text = "Unavailable",
                score_label = "CARBON IMPACT SCORE",
                score_text = "Unavailable",
                score_color = muted_color(),
                rows = emptyList()
            )
        }

        val details_loading = is_details_loading_for(aircraft)
        val profile = AircraftImpactPresenter.profile_for(aircraft, details)
        val trace = current_impact_trace_for(aircraft)
        val trace_loading = is_flight_path_loading(aircraft)
        val usage_trace = usage_trace_for(aircraft)
        val trace_estimate = profile?.let {
            AircraftTraceImpactAnalyzer.observed_estimate(it, usage_trace?.segments, details)
        }
        val loading = details_loading || trace_loading
        val score_value = when {
            trace_estimate != null -> AircraftImpactEstimator.score_for_kg_per_hour(trace_estimate.average_kg_per_hour_mid)
            profile != null -> AircraftImpactEstimator.score(profile)
            else -> null
        }
        val score_text = score_value?.let { "$it / 100" } ?: loading_or_unavailable(details_loading)
        val co2_text = when {
            trace_estimate != null -> AircraftImpactPresenter.carbon_range(trace_estimate.carbon)
            profile != null && trace != null -> AircraftImpactPresenter.carbon_range(profile.carbon_for_hours(trace.hours))
            trace_loading -> "Loading"
            profile != null -> AircraftImpactPresenter.kg_range(profile.low_co2_kg_per_hour(), profile.high_co2_kg_per_hour())
            else -> loading_or_unavailable(loading)
        }
        return AircraftImpactPanelState(
            selected_aircraft_available = true,
            status = AircraftImpactPresenter.status(profile, trace, details_loading, trace_loading),
            show_trace_co2 = trace != null,
            co2_text = co2_text,
            score_label = if (trace_estimate != null) "OBSERVED IMPACT SCORE" else "CLASS INTENSITY SCORE",
            score_text = score_text,
            score_color = if (profile == null) muted_color() else impact_score_color(profile),
            rows = AircraftImpactPresenter.rows(
                aircraft = aircraft,
                details = details,
                profile = profile,
                trace = trace,
                trace_estimate = trace_estimate,
                usage_trace = usage_trace,
                details_loading = details_loading,
                trace_loading = trace_loading,
                units = units()
            )
                .map { (label, value) -> AircraftDetailsRow(label, value) }
        )
    }

    fun usage_panel_state(aircraft: Aircraft?): AircraftUsagePanelState {
        if (aircraft == null) {
            return AircraftUsagePanelState(
                selected_aircraft_available = false,
                status = "Unavailable",
                unavailable_message = null,
                stat_rows = emptyList(),
                stats = null
            )
        }

        val trace = usage_trace_for(aircraft)
        val loading = trace == null && is_flight_path_loading(aircraft)
        val status = when {
            trace != null -> "Trace-derived from ${trace.source}"
            loading -> "Loading trace usage"
            else -> "Unavailable from trace source"
        }
        if (trace == null) {
            return AircraftUsagePanelState(
                selected_aircraft_available = true,
                status = status,
                unavailable_message = if (loading) "Loading" else "Unavailable: no real trace history was retrieved for this aircraft.",
                stat_rows = emptyList(),
                stats = null
            )
        }

        val stats = AircraftUsageAnalyzer.stats_for(trace)
        if (stats.flight_count == 0) {
            return AircraftUsagePanelState(
                selected_aircraft_available = true,
                status = status,
                unavailable_message = "Unavailable: trace data does not contain usable completed or current flight segments.",
                stat_rows = emptyList(),
                stats = null
            )
        }

        return AircraftUsagePanelState(
            selected_aircraft_available = true,
            status = status,
            unavailable_message = null,
            stat_rows = listOf(
                AircraftDetailsRow("Current week", "${stats.week_flight_count} flights  ${AircraftUsageAnalyzer.format_hours(stats.week_hours)}"),
                AircraftDetailsRow("Trace window total", "${stats.flight_count} flights  ${AircraftUsageAnalyzer.format_hours(stats.total_hours)}"),
                AircraftDetailsRow("Trace window", stats.window_label)
            ),
            stats = stats
        )
    }
}


private data class AircraftDetailCandidate(
    val source_name: String,
    val fetch: () -> AircraftDetails?
)

// Coordinates details, photo, and feed seed lookups so FlightMapView only reacts to finished callbacks.
class AircraftDetailsCoordinator(
    private val aircraft_details_client: AircraftDetailsClient,
    private val aircraft_photo_fetcher: AircraftPhotoFetcher,
    private val executor: Executor,
    private val post_to_main: (() -> Unit) -> Unit
) {
    // Start metadata and photo work around one selected aircraft, then post only callbacks that still match its token.
    fun request_aircraft_details(
        aircraft: Aircraft,
        request_token: Long,
        is_current_request: (String, Long) -> Boolean,
        is_photo_available: () -> Boolean,
        on_details: (String, Long, AircraftDetails, Boolean) -> Unit,
        on_details_unavailable: (String, Long) -> Unit,
        on_photo_found: (String, Long, AircraftPhotoResult.Found, Boolean) -> Unit,
        on_photo_unavailable: (String, Long) -> Unit,
        on_photo_search_done: (String, Long) -> Unit
    ) {
        val requested_id = aircraft.icao24
        val candidates = detail_candidates_for_aircraft(aircraft)
        val remaining = AtomicInteger(candidates.size)
        val photo_in_flight = AtomicInteger(0)
        val photo_found = AtomicBoolean(false)
        val photo_search_done = AtomicBoolean(false)
        val detail_lock = Any()
        val photo_keys = mutableSetOf<String>()
        var merged_details: AircraftDetails? = null

        // Wait for all real photo paths to fail before telling the UI no photo is available.
        fun maybe_post_final_photo_unavailable() {
            if (remaining.get() != 0 || photo_in_flight.get() != 0) return
            if (!photo_search_done.compareAndSet(false, true)) return
            post_to_main {
                if (!is_current_request(requested_id, request_token)) return@post_to_main
                if (!photo_found.get() && !is_photo_available()) {
                    on_photo_unavailable(requested_id, request_token)
                }
                on_photo_search_done(requested_id, request_token)
            }
        }

        // Let an honest fallback render quickly while exact exterior lookups continue in parallel.
        fun lookup_photo(details: AircraftDetails) {
            val key = photo_lookup_key(aircraft, details)
            val exact_key = "exact|$key"
            val fallback_key = "fallback|$key"
            val should_run_exact = synchronized(photo_keys) { photo_keys.add(exact_key) }
            val should_run_fallback = synchronized(photo_keys) { photo_keys.add(fallback_key) }
            if (!should_run_exact && !should_run_fallback) {
                maybe_post_final_photo_unavailable()
                return
            }
            photo_in_flight.addAndGet(listOf(should_run_exact, should_run_fallback).count { it })

            if (should_run_fallback) {
                executor.execute {
                    val photo = runCatching { aircraft_photo_fetcher.fetch_fallback_photo(aircraft, details) }
                        .getOrElse { AircraftPhotoResult.Unavailable("Exact, representative, and search photos unavailable") }
                    photo_in_flight.decrementAndGet()
                    when (photo) {
                        is AircraftPhotoResult.Found -> {
                            val first_photo = photo_found.compareAndSet(false, true)
                            if (first_photo || photo.quality == PhotoQuality.EXACT) {
                                post_to_main { on_photo_found(requested_id, request_token, photo, photo.quality == PhotoQuality.EXACT) }
                            }
                            maybe_post_final_photo_unavailable()
                        }
                        is AircraftPhotoResult.Unavailable -> maybe_post_final_photo_unavailable()
                    }
                }
            }

            if (should_run_exact) {
                executor.execute {
                    val exact = runCatching { aircraft_photo_fetcher.fetch_exact_aircraft_photo(aircraft, details) }.getOrNull()
                    photo_in_flight.decrementAndGet()
                    if (exact != null) {
                        photo_found.set(true)
                        post_to_main { on_photo_found(requested_id, request_token, exact, true) }
                        maybe_post_final_photo_unavailable()
                    } else {
                        maybe_post_final_photo_unavailable()
                    }
                }
            }
        }

        candidates.forEach { candidate ->
            executor.execute {
                val details = runCatching { candidate.fetch() }.getOrNull()
                val merged = synchronized(detail_lock) {
                    if (details != null) {
                        merged_details = merged_details?.let { merge_aircraft_details(it, details) } ?: details
                    }
                    merged_details
                }
                if (merged != null) {
                    val still_loading = remaining.get() > 1
                    post_to_main { on_details(requested_id, request_token, merged, still_loading) }
                    lookup_photo(merged)
                    remaining.decrementAndGet()
                    maybe_post_final_photo_unavailable()
                } else {
                    val still_loading = remaining.decrementAndGet() > 0
                    if (!still_loading) {
                        post_to_main { on_details_unavailable(requested_id, request_token) }
                        maybe_post_final_photo_unavailable()
                    }
                }
            }
        }
    }

    fun seeded_aircraft_details(aircraft: Aircraft): AircraftDetails? {
        val seed = aircraft.metadata_seed
        if (seed == null && aircraft.telemetry?.has_values != true) return null
        return details_from_feed_seed(aircraft, seed)
    }

    fun request_photo_gallery(
        aircraft: Aircraft,
        details: AircraftDetails,
        request_token: Long,
        is_current_request: (String, Long) -> Boolean,
        on_gallery: (String, Long, List<AircraftPhotoGalleryItem>) -> Unit
    ) {
        val requested_id = aircraft.icao24
        executor.execute {
            val items = aircraft_photo_fetcher.fetch_gallery(aircraft, details)
            post_to_main {
                if (!is_current_request(requested_id, request_token)) return@post_to_main
                on_gallery(requested_id, request_token, items)
            }
        }
    }

    // Use current feed data as seed metadata, then enrich from documented registries and routes.
    private fun detail_candidates_for_aircraft(aircraft: Aircraft): List<AircraftDetailCandidate> {
        val seed = AircraftDetailCandidate("Live feed seed") {
            seeded_aircraft_details(aircraft)
        }
        val direct = AircraftDetailCandidate("Documented sources") {
            aircraft_details_client.fetch_details(
                hex = aircraft.icao24,
                callsign = aircraft.callsign,
                registration_hint = aircraft.registration,
                metadata_seed = aircraft.metadata_seed,
                telemetry_seed = aircraft.telemetry,
                latitude = aircraft.lat,
                longitude = aircraft.lon
            )
        }
        return listOf(seed, direct)
    }

    private fun details_from_feed_seed(aircraft: Aircraft, seed: AircraftMetadataSeed?): AircraftDetails {
        return AircraftDetails(
            icao24 = aircraft.icao24.trim().trimStart('~').lowercase(Locale.US),
            registration = normalized_registration(seed?.registration ?: aircraft.registration),
            manufacturer = seed?.manufacturer?.clean_seed_value(),
            type = seed?.type?.clean_seed_value(),
            type_code = seed?.type_code?.clean_seed_value() ?: aircraft.type_code,
            owner = seed?.owner?.clean_seed_value(),
            manufactured_year = seed?.manufactured_year?.clean_seed_value()?.take(4),
            registry_source = seed?.source_name,
            operator_code = seed?.operator_code?.clean_seed_value(),
            route = null,
            route_updated_epoch_sec = null,
            route_source = null,
            origin_airport = null,
            destination_airport = null,
            telemetry = aircraft.telemetry
        )
    }

    private fun photo_lookup_key(aircraft: Aircraft, details: AircraftDetails): String {
        return listOfNotNull(
            normalized_registration(details.registration ?: aircraft.registration),
            details.manufacturer?.trim()?.uppercase(Locale.US),
            details.type?.trim()?.uppercase(Locale.US),
            details.type_code?.trim()?.uppercase(Locale.US),
            details.owner?.trim()?.uppercase(Locale.US)
        ).joinToString("|").ifBlank { aircraft.icao24.trim().lowercase(Locale.US) }
    }

    // Prefer specific documented enrichment but keep live/feed seed values when enrichment is missing.
    private fun merge_aircraft_details(seed: AircraftDetails, enrichment: AircraftDetails): AircraftDetails {
        val source = listOfNotNull(seed.registry_source, enrichment.registry_source)
            .asSequence()
            .flatMap { it.split(" + ").asSequence() }
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .distinct()
            .joinToString(" + ")
            .ifEmpty { null }
        return AircraftDetails(
            icao24 = seed.icao24,
            registration = enrichment.registration ?: seed.registration,
            manufacturer = enrichment.manufacturer ?: seed.manufacturer,
            type = enrichment.type ?: seed.type,
            type_code = enrichment.type_code ?: seed.type_code,
            owner = enrichment.owner ?: seed.owner,
            manufactured_year = enrichment.manufactured_year ?: seed.manufactured_year,
            registry_source = source,
            operator_code = enrichment.operator_code ?: seed.operator_code,
            route = enrichment.route ?: seed.route,
            route_updated_epoch_sec = enrichment.route_updated_epoch_sec ?: seed.route_updated_epoch_sec,
            route_source = enrichment.route_source ?: seed.route_source,
            origin_airport = enrichment.origin_airport ?: seed.origin_airport,
            destination_airport = enrichment.destination_airport ?: seed.destination_airport,
            telemetry = enrichment.telemetry?.with_fallback(seed.telemetry) ?: seed.telemetry
        )
    }

    private fun normalized_registration(value: String?): String? {
        return value
            ?.trim()
            ?.uppercase(Locale.US)
            ?.replace("[^A-Z0-9-]".toRegex(), "")
            ?.takeIf { it.isNotBlank() }
    }

    
    companion object {
        fun details_status(details: AircraftDetails, still_loading: Boolean): String {
            return when {
                still_loading && !has_aircraft_metadata(details) -> "Loading aircraft details from remaining feed sources"
                still_loading -> "Metadata from ${details.registry_source ?: "configured sources"}; checking remaining feed sources"
                !has_aircraft_metadata(details) && details.telemetry?.has_values == true -> "Telemetry from ${details.registry_source ?: "configured sources"}; metadata unavailable"
                !has_aircraft_metadata(details) -> "Metadata unavailable from configured sources"
                else -> "Metadata from ${details.registry_source ?: "configured sources"}"
            }
        }

        fun has_aircraft_metadata(details: AircraftDetails): Boolean {
            return details.registration != null ||
                details.manufacturer != null ||
                details.type != null ||
                details.type_code != null ||
                details.owner != null
        }
    }
}


data class AircraftDetailsPanelStyle(val visual_theme: VisualTheme)

