    // Draw a small seven-day chart from trace buckets without implying broader historical coverage.
    private fun draw_usage_graph(canvas: Canvas, rect: RectF, stats: UsageStats, style: AircraftDetailsPanelStyle) {
        if (rect.height() < dp(96) || rect.width() < dp(180)) return
        paint.style = Paint.Style.FILL
        paint.color = if (style.visual_theme.style.treatment == ThemeTreatment.PLAIN) {
            with_alpha(style.visual_theme.colors.panel, 120)
        } else {
            with_alpha(style.visual_theme.colors.panel, 150)
        }
        val radius = chrome.control_radius().coerceAtMost(dp(8))
        canvas.drawRoundRect(rect, radius, radius, paint)
        stroke_paint.color = with_alpha(style.visual_theme.colors.panel_stroke, style.visual_theme.style.divider_alpha + 44)
        stroke_paint.strokeWidth = dp(1)
        canvas.drawRoundRect(rect, radius, radius, stroke_paint)

        val chart = RectF(rect.left + dp(16), rect.top + dp(28), rect.right - dp(16), rect.bottom - dp(28))
        val max_hours = max(1.0, stats.buckets.maxOf { it.hours })
        val max_flights = max(1, stats.buckets.maxOf { it.flights })
        val step = chart.width() / max(1, stats.buckets.size - 1)
        val bar_width = min(dp(18), step * 0.38f)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(11)
        text_paint.color = style.visual_theme.colors.text
        canvas.drawText("7-day trace usage", rect.left + dp(14), rect.top + dp(18), text_paint)
        text_paint.textAlign = Paint.Align.RIGHT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(10)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText("hours line / flights bars", rect.right - dp(14), rect.top + dp(18), text_paint)

        stroke_paint.color = with_alpha(style.visual_theme.colors.muted, 90)
        stroke_paint.strokeWidth = dp(1)
        canvas.drawLine(chart.left, chart.bottom, chart.right, chart.bottom, stroke_paint)

        var previous: ScreenPoint? = null
        stats.buckets.forEachIndexed { index, bucket ->
            val x = chart.left + step * index
            val bar_height = (chart.height() * (bucket.flights.toFloat() / max_flights)).coerceAtLeast(if (bucket.flights > 0) dp(3) else 0f)
            paint.color = with_alpha(style.visual_theme.colors.accent_blue, if (bucket.flights > 0) 150 else 42)
            canvas.drawRoundRect(RectF(x - bar_width / 2f, chart.bottom - bar_height, x + bar_width / 2f, chart.bottom), dp(2), dp(2), paint)

            val point = ScreenPoint(x, chart.bottom - (chart.height() * (bucket.hours / max_hours)).toFloat())
            previous?.let { old ->
                stroke_paint.color = style.visual_theme.colors.accent_yellow
                stroke_paint.strokeWidth = dp(2)
                canvas.drawLine(old.x, old.y, point.x, point.y, stroke_paint)
            }
            paint.color = style.visual_theme.colors.accent_yellow
            canvas.drawCircle(point.x, point.y, dp(3), paint)
            previous = point

            text_paint.textAlign = Paint.Align.CENTER
            text_paint.isFakeBoldText = false
            text_paint.textSize = sp(9)
            text_paint.color = style.visual_theme.colors.muted
            canvas.drawText(bucket.label, x, rect.bottom - dp(10), text_paint)
        }
    }

    // Draw proof for search-engine photos so investigable images remain auditable to the user.
    private fun draw_photo_evidence_panel(
        canvas: Canvas,
        rect: RectF,
        style: AircraftDetailsPanelStyle,
        state: AircraftDetailsPanelState,
        content: AircraftPhotoEvidencePanelState
    ): AircraftDetailsDrawResult {
        val evidence = content.evidence
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)
        chrome.draw_choice_button(canvas, close_button_bounds(rect), "Close", false)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(21)
        text_paint.color = style.visual_theme.colors.text
        canvas.drawText("Photo verification", rect.left + dp(18), rect.top + dp(38), text_paint)

        if (evidence == null) {
            text_paint.isFakeBoldText = false
            text_paint.textSize = sp(13)
            text_paint.color = style.visual_theme.colors.muted
            canvas.drawText("No search-engine verification is attached to this photo.", rect.left + dp(18), rect.top + dp(78), text_paint)
            return AircraftDetailsDrawResult(0f, 0f)
        }

        val wide = rect.width() > rect.height()
        val image_rect = if (wide) {
            RectF(rect.left + dp(18), rect.top + dp(72), rect.left + rect.width() * 0.44f, rect.bottom - dp(80))
        } else {
            RectF(rect.left + dp(18), rect.top + dp(72), rect.right - dp(18), rect.top + dp(270))
        }
        val clip = content_bounds(rect, reserve_bottom = dp(72))
        val checkpoint = canvas.save()
        canvas.clipRect(clip)
        canvas.translate(0f, -state.scroll_y)
        draw_photo_block(canvas, image_rect, state.photo, style)

        val text_left = if (wide) image_rect.right + dp(22) else rect.left + dp(18)
        var y = if (wide) rect.top + dp(82) else image_rect.bottom + dp(32)
        val text_rect = RectF(text_left, y, rect.right - dp(18), rect.bottom - dp(82))

        y = draw_evidence_text_line(canvas, text_rect, y, "Source", evidence.source_name, style)
        y = draw_evidence_text_line(canvas, text_rect, y, "Search", evidence.search_query, style)
        y = draw_evidence_text_line(canvas, text_rect, y, "Matched", evidence.matched_terms.joinToString(", ").ifBlank { "Unavailable" }, style)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText("Verification quote", text_rect.left, y + dp(10), text_paint)
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.text
        val quote_bottom = draw_wrapped_text(canvas, evidence.quote, text_rect.left, y + dp(34), text_rect.width(), DETAILS_PROOF_QUOTE_LINES)
        val content_bottom = maxOf(image_rect.bottom, quote_bottom) + dp(14)
        canvas.restoreToCount(checkpoint)

        val result = scroll_result(content_bottom - clip.top, clip.height(), state.scroll_y)
        draw_scroll_indicator(canvas, clip, result, style)

        evidence.image_url.takeIf { it.isNotBlank() }?.let {
            chrome.draw_choice_button(canvas, photo_image_source_button_bounds(rect), "Open image", false)
        }
        evidence.page_url.takeIf { it.isNotBlank() }?.let {
            chrome.draw_choice_button(canvas, photo_page_source_button_bounds(rect), "Open source", false)
        }
        return result
    }

    private fun draw_photo_gallery_panel(
        canvas: Canvas,
        rect: RectF,
        style: AircraftDetailsPanelStyle,
        state: AircraftDetailsPanelState,
        content: AircraftPhotoGalleryPanelState
    ): AircraftDetailsDrawResult {
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)
        chrome.draw_choice_button(canvas, close_button_bounds(rect), "Back", false)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(21)
        text_paint.color = style.visual_theme.colors.text
        canvas.drawText("Photo gallery", rect.left + dp(18), rect.top + dp(38), text_paint)

        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText(chrome.ellipsize(content.status, rect.width() - dp(36)), rect.left + dp(18), rect.top + dp(62), text_paint)

        val clip = content_bounds(rect)
        if (content.items.isEmpty()) {
            val message = if (content.loading) content.status else "No real gallery photos available from checked sources."
            draw_centered_message(canvas, message, clip.inset_copy(dp(18), dp(18)), style)
            return AircraftDetailsDrawResult(0f, 0f)
        }

        canvas.withClip(clip) {
            translate(0f, -state.scroll_y)
            content.items.forEachIndexed { index, item ->
                val item_rect = gallery_item_bounds(rect, index, state.wide_layout)
                draw_gallery_item(this, item_rect, item, style)
            }
        }

        val last = gallery_item_bounds(rect, content.items.lastIndex, state.wide_layout)
        val result = scroll_result(last.bottom - clip.top + dp(18), clip.height(), state.scroll_y)
        draw_scroll_indicator(canvas, clip, result, style)
        return result
    }

    private fun draw_gallery_item(
        canvas: Canvas,
        rect: RectF,
        item: AircraftPhotoGalleryItem,
        style: AircraftDetailsPanelStyle
    ) {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(10)
        text_paint.color = style.visual_theme.colors.text
        canvas.drawText(chrome.ellipsize(item.title, rect.width()), rect.left, rect.top + dp(10), text_paint)
        val photo_rect = RectF(rect.left, rect.top + dp(16), rect.right, rect.bottom)
        draw_photo_block(canvas, photo_rect, AircraftDetailsPhotoState(item.bitmap, item.caption), style)
        if (item.evidence != null) {
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(style.visual_theme.colors.accent_blue, 176)
            canvas.drawCircle(rect.right - dp(12), rect.top + dp(28), dp(5), paint)
        }
        text_paint.isFakeBoldText = false
    }

    // Draw either the real fetched bitmap or the honest photo status message in the same reserved area.
    private fun draw_photo_block(
        canvas: Canvas,
        photo_rect: RectF,
        photo: AircraftDetailsPhotoState,
        style: AircraftDetailsPanelStyle
    ) {
        paint.color = style.visual_theme.colors.photo_surface
        val radius = chrome.control_radius().coerceAtMost(dp(10))
        canvas.drawRoundRect(photo_rect, radius, radius, paint)
        val bitmap = photo.bitmap
        paint.alpha = 255
        if (bitmap != null) {
            val previous = photo.previous_bitmap
            val progress = photo.transition_progress.coerceIn(0f, 1f)
            if (previous != null && progress < 0.999f) {
                val eased = progress * progress * (3f - 2f * progress)
                canvas.withClip(photo_rect) {
                    draw_photo_bitmap(canvas, previous, photo_rect, -photo_rect.width() * eased * 0.42f)
                    draw_photo_bitmap(canvas, bitmap, photo_rect, photo_rect.width() * (1f - eased))
                }
            } else {
                draw_photo_bitmap(canvas, bitmap, photo_rect)
            }
            draw_photo_caption(canvas, photo_rect, photo.status, style)
        } else {
            text_paint.textAlign = Paint.Align.CENTER
            text_paint.textSize = sp(11)
            text_paint.color = style.visual_theme.colors.muted
            draw_centered_wrapped_text(canvas, photo.status, photo_rect.inset_copy(dp(14), dp(8)))
        }
    }

    private fun draw_photo_bitmap(canvas: Canvas, bitmap: Bitmap, photo_rect: RectF, offset_x: Float = 0f) {
        val src = Rect(0, 0, bitmap.width, bitmap.height)
        val dest = aspect_fit_rect(bitmap.width, bitmap.height, photo_rect)
        dest.offset(offset_x, 0f)
        canvas.drawBitmap(bitmap, src, dest, paint)
    }

    // Draw one metadata row with wrapping and clipping so long values do not overlap nearby content.
    private fun draw_adaptive_detail_row(
        canvas: Canvas,
        rect: RectF,
        y: Float,
        row: AircraftDetailsRow,
        style: AircraftDetailsPanelStyle,
        visible_top: Float,
        visible_bottom: Float,
        compact: Boolean = false
    ): Float {
        if (row.section) {
            return draw_detail_section_header(canvas, rect, y, row.label, style, visible_top, visible_bottom, compact)
        }
        val label_size = if (compact) sp(9) else sp(10)
        val value_size = if (compact) sp(12) else sp(13)
        val min_value_size = if (compact) sp(8) else sp(9)
        val one_line_width = rect.width() * if (compact) 0.62f else 0.56f
        val right = rect.right - if (compact) 0f else dp(16)
        val left = rect.left + if (compact) 0f else dp(16)
        text_paint.textSize = value_size
        val row_bottom = if (text_paint.measureText(row.value) <= one_line_width) {
            y + dp(if (compact) 25 else 28)
        } else {
            val lines = wrapped_text_lines(row.value, right - left, DETAILS_ROW_MAX_LINES)
            y + dp(if (compact) 18 else 21) + lines.size * (if (compact) dp(16) else dp(18)) + dp(if (compact) 8 else 10)
        }
        if (row_bottom > visible_bottom || y < visible_top) return row_bottom

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = label_size
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText(row.label.uppercase(Locale.US), rect.left + if (compact) 0f else dp(16), y, text_paint)

        text_paint.isFakeBoldText = true
        text_paint.textSize = value_size
        text_paint.color = style.visual_theme.colors.text
        if (text_paint.measureText(row.value) <= one_line_width) {
            text_paint.textAlign = Paint.Align.RIGHT
            draw_fitted_right_text(canvas, row.value, right, y, one_line_width, value_size, min_value_size)
            stroke_paint.color = with_alpha(
                style.visual_theme.colors.panel_stroke,
                if (compact) max(36, style.visual_theme.style.divider_alpha - 10) else style.visual_theme.style.divider_alpha
            )
            stroke_paint.strokeWidth = dp(1)
            canvas.drawLine(left, y + dp(if (compact) 9 else 10), right, y + dp(if (compact) 9 else 10), stroke_paint)
            text_paint.isFakeBoldText = false
            return row_bottom
        }

        text_paint.textAlign = Paint.Align.LEFT
        val available_width = right - left
        val lines = wrapped_text_lines(row.value, available_width, DETAILS_ROW_MAX_LINES)
        var cy = y + dp(if (compact) 18 else 21)
        val line_height = if (compact) dp(16) else dp(18)
        lines.forEach { line ->
            canvas.drawText(line, left, cy, text_paint)
            cy += line_height
        }
        stroke_paint.color = with_alpha(
            style.visual_theme.colors.panel_stroke,
            if (compact) max(36, style.visual_theme.style.divider_alpha - 10) else style.visual_theme.style.divider_alpha
        )
        stroke_paint.strokeWidth = dp(1)
        canvas.drawLine(left, cy - dp(6), right, cy - dp(6), stroke_paint)
        text_paint.isFakeBoldText = false
        return row_bottom
    }

    private fun draw_detail_section_header(
        canvas: Canvas,
        rect: RectF,
        y: Float,
        label: String,
        style: AircraftDetailsPanelStyle,
        visible_top: Float,
        visible_bottom: Float,
        compact: Boolean
    ): Float {
        val top_gap = if (compact) dp(12) else dp(16)
        val row_bottom = y + top_gap + dp(if (compact) 21 else 24)
        if (row_bottom > visible_bottom || y < visible_top) return row_bottom

        val left = rect.left + if (compact) 0f else dp(16)
        val right = rect.right - if (compact) 0f else dp(16)
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = if (compact) sp(10) else sp(11)
        text_paint.color = style.visual_theme.colors.accent_blue
        canvas.drawText(label.uppercase(Locale.US), left, y + top_gap, text_paint)

        stroke_paint.color = with_alpha(style.visual_theme.colors.panel_stroke, style.visual_theme.style.divider_alpha + 42)
        stroke_paint.strokeWidth = dp(1)
        canvas.drawLine(left, y + top_gap + dp(8), right, y + top_gap + dp(8), stroke_paint)
        text_paint.isFakeBoldText = false
        return row_bottom
    }

    private fun draw_evidence_text_line(
        canvas: Canvas,
        rect: RectF,
        y: Float,
        label: String,
        value: String,
        style: AircraftDetailsPanelStyle
    ): Float {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(10)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText(label.uppercase(Locale.US), rect.left, y, text_paint)
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.text
        val lines = wrapped_text_lines(value, rect.width(), DETAILS_EVIDENCE_LINE_MAX_LINES)
        var cy = y + dp(20)
        lines.forEach { line ->
            canvas.drawText(line, rect.left, cy, text_paint)
            cy += dp(18)
        }
        text_paint.isFakeBoldText = false
        return cy + dp(10)
    }

    private fun draw_photo_caption(canvas: Canvas, photo_rect: RectF, caption: String, style: AircraftDetailsPanelStyle) {
        if (caption.isBlank()) return
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(10)
        val max_width = photo_rect.width() - dp(18)
        val line_height = dp(13)
        val max_lines = max(1, floor((photo_rect.height() - dp(12)) / line_height).toInt()).coerceAtMost(PHOTO_CAPTION_MAX_LINES)
        val lines = wrapped_text_lines(caption, max_width, max_lines)
        val caption_height = (dp(12) + lines.size * line_height).coerceAtMost(photo_rect.height() - dp(8))
        val caption_rect = RectF(photo_rect.left, photo_rect.bottom - caption_height, photo_rect.right, photo_rect.bottom)
        paint.style = Paint.Style.FILL
        paint.color = with_alpha(style.visual_theme.colors.panel, if (style.visual_theme.style.treatment == ThemeTreatment.PLAIN) 190 else 216)
        val radius = if (style.visual_theme.style.treatment == ThemeTreatment.PLAIN) dp(4) else chrome.control_radius().coerceAtMost(dp(8))
        canvas.drawRoundRect(caption_rect, radius, radius, paint)
        text_paint.color = style.visual_theme.colors.text
        val metrics = text_paint.fontMetrics
        var y = caption_rect.top + dp(6) - metrics.ascent
        lines.forEach { line ->
            canvas.drawText(line, caption_rect.centerX(), y, text_paint)
            y += line_height
        }
    }

    private fun draw_centered_message(canvas: Canvas, message: String, rect: RectF, style: AircraftDetailsPanelStyle) {
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.muted
        draw_centered_wrapped_text(canvas, message, rect)
    }

    private fun draw_centered_wrapped_text(canvas: Canvas, value: String, rect: RectF) {
        val lines = wrapped_text_lines(value, rect.width(), PHOTO_UNAVAILABLE_LINES)
        val metrics = text_paint.fontMetrics
        val line_height = text_paint.fontSpacing
        val block_height = line_height * lines.size
        var y = rect.centerY() - block_height / 2f - metrics.ascent
        lines.forEach { line ->
            canvas.drawText(line, rect.centerX(), y, text_paint)
            y += line_height
        }
    }

    private fun draw_wrapped_text(canvas: Canvas, value: String, x: Float, y: Float, width: Float, max_lines: Int): Float =
        draw_wrapped_text(canvas, text_paint, value, x, y, width, max_lines, dp(19))

    private fun draw_fitted_right_text(
        canvas: Canvas, value: String, right: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, right, y, max_width, start_size, min_size, Paint.Align.RIGHT, dp(0.5f), chrome::ellipsize
    )

    private fun draw_fitted_left_text(
        canvas: Canvas, value: String, left: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, left, y, max_width, start_size, min_size, Paint.Align.LEFT, dp(0.5f), chrome::ellipsize
    )

    // Long words are split by the shared text primitive so every panel wraps identically.
    private fun wrapped_text_lines(value: String, width: Float, max_lines: Int): List<String> =
        wrapped_text_lines(text_paint, value, width, max_lines)

    
    private fun photo_bounds(area: RectF, wide: Boolean, has_photo: Boolean): RectF {
        return if (wide) {
            val height = if (has_photo) min(area.height(), dp(280)) else min(area.height(), dp(104))
            RectF(area.left + dp(18), area.top, area.right - dp(18), area.top + height)
        } else {
            val height = if (has_photo) dp(206) else dp(86)
            RectF(area.left + dp(18), area.top + dp(78), area.right - dp(18), area.top + dp(78) + height)
        }
    }

    private fun content_bounds(panel: RectF, reserve_bottom: Float = dp(12)): RectF {
        return RectF(panel.left, panel.top + dp(70), panel.right, panel.bottom - reserve_bottom)
    }

    private fun row_bounds(panel: RectF): RectF {
        return RectF(panel.left, panel.top, panel.right, panel.bottom)
    }

    // Return corrected scroll values to FlightMapView so touch scrolling and drawing stay in sync.
    private fun scroll_result(content_height: Float, viewport_height: Float, requested_scroll_y: Float): AircraftDetailsDrawResult {
        val max_scroll_y = max(0f, content_height - viewport_height)
        return AircraftDetailsDrawResult(
            scroll_y = requested_scroll_y.coerceIn(0f, max_scroll_y),
            max_scroll_y = max_scroll_y
        )
    }

    private fun draw_scroll_indicator(
        canvas: Canvas,
        clip: RectF,
        result: AircraftDetailsDrawResult,
        style: AircraftDetailsPanelStyle
    ) {
        if (result.max_scroll_y <= dp(2)) return
        val track = RectF(clip.right - dp(6), clip.top + dp(8), clip.right - dp(3), clip.bottom - dp(8))
        paint.style = Paint.Style.FILL
        paint.color = with_alpha(style.visual_theme.colors.text, 54)
        canvas.drawRoundRect(track, dp(2), dp(2), paint)
        val thumb_height = (track.height() * (clip.height() / (clip.height() + result.max_scroll_y))).coerceIn(dp(24), track.height())
        val top = track.top + (track.height() - thumb_height) * (result.scroll_y / result.max_scroll_y)
        paint.color = with_alpha(style.visual_theme.colors.accent_blue, 170)
        canvas.drawRoundRect(RectF(track.left, top, track.right, top + thumb_height), dp(2), dp(2), paint)
    }

    private fun aspect_fit_rect(source_width: Int, source_height: Int, outer: RectF): RectF {
        if (source_width <= 0 || source_height <= 0 || outer.width() <= 0f || outer.height() <= 0f) return RectF(outer)
        val source_ratio = source_width.toFloat() / source_height
        val outer_ratio = outer.width() / outer.height()
        return if (source_ratio > outer_ratio) {
            val fitted_height = outer.width() / source_ratio
            val top = outer.centerY() - fitted_height / 2f
            RectF(outer.left, top, outer.right, top + fitted_height)
        } else {
            val fitted_width = outer.height() * source_ratio
            val left = outer.centerX() - fitted_width / 2f
            RectF(left, outer.top, left + fitted_width, outer.bottom)
        }
    }

    private fun RectF.inset_copy(dx: Float, dy: Float): RectF {
        return RectF(left + dx, top + dy, right - dx, bottom - dy)
    }

    private fun dp(value: Int): Float = dp(value.toFloat())

    private fun dp(value: Float): Float = chrome.dp(value)

    private fun sp(value: Int): Float = sp(value.toFloat())

    private fun sp(value: Float): Float = chrome.sp(value)

    
    private companion object {
        const val PHOTO_UNAVAILABLE_LINES = 4
        const val PHOTO_CAPTION_MAX_LINES = 7
        const val DETAILS_ROW_MAX_LINES = 12
        const val DETAILS_EVIDENCE_LINE_MAX_LINES = 4
        const val DETAILS_PROOF_QUOTE_LINES = 12
    }
}


// Picks likely next-tapped aircraft for warm details/photo requests while the map is idle.
internal class AircraftDetailsPrefetchPlanner(
    private val warm_requester: AircraftDetailsWarmRequester,
    private val displayed_aircraft: () -> Aircraft?,
    private val selected_aircraft_snapshot: () -> Aircraft?,
    private val cached_traffic: () -> CachedTraffic,
    private val cache_key: (Aircraft) -> String,
    private val traffic_query_padding_px: (Viewport) -> Float,
    private val screen_point_for_entry: (TrafficSpatialEntry, Viewport, Double, Double) -> ScreenPoint,
    private val screen_neighborhood_contains: (Float, Float, Boolean, Viewport) -> Boolean,
    private val now_epoch_seconds: () -> Double
) {
    fun schedule(
        state: TrafficOverlayState,
        details_open: Boolean,
        pinch_in_progress: Boolean,
        drag_started: Boolean,
        last_map_interaction_ms: Long
    ) {
        val now = SystemClock.elapsedRealtime()
        if (details_open || state.viewport.zoom < DETAILS_PREFETCH_MIN_ZOOM) return
        if (pinch_in_progress || drag_started || now - last_map_interaction_ms < DETAILS_PREFETCH_IDLE_DELAY_MS) return
        if (warm_requester.in_flight_count >= DETAILS_PREFETCH_MAX_IN_FLIGHT) return
        if (now - warm_requester.last_prefetch_elapsed_ms < DETAILS_PREFETCH_INTERVAL_MS) return

        val candidate = prefetch_candidates(state)
            .firstOrNull { warm_requester.should_prefetch(it, now) }
            ?: return
        warm_requester.last_prefetch_elapsed_ms = now
        warm_requester.start_prefetch(candidate)
    }

    private fun prefetch_candidates(state: TrafficOverlayState): List<Aircraft> {
        val preferred = listOfNotNull(
            displayed_aircraft(),
            selected_aircraft_snapshot()
        ).distinctBy(cache_key)
        val center_x = state.viewport.width / 2f
        val center_y = state.viewport.height / 2f
        if (state.aircraft.isNotEmpty()) {
            val visible = state.aircraft
                .asSequence()
                .sortedBy { item ->
                    val dx = item.screen_point.x - center_x
                    val dy = item.screen_point.y - center_y
                    dx * dx + dy * dy
                }
                .map { it.aircraft }
                .distinctBy(cache_key)
                .take(DETAILS_PREFETCH_MAX_VISIBLE_CANDIDATES)
                .toList()
            return (preferred + visible)
                .distinctBy(cache_key)
                .take(DETAILS_PREFETCH_MAX_VISIBLE_CANDIDATES)
        }

        val viewport = state.viewport
        val cache = cached_traffic()
        val scale = 2.0.pow(viewport.zoom)
        val now_epoch_sec = now_epoch_seconds()
        val candidates = ArrayList<Pair<Float, Aircraft>>(DETAILS_PREFETCH_MAX_VISIBLE_CANDIDATES)
        val seen = HashSet<String>()
        val query = cache.spatial_index.query(viewport, traffic_query_padding_px(viewport))
        for (entry in query) {
            if (candidates.size >= DETAILS_PREFETCH_SCAN_LIMIT) break
            val aircraft = entry.aircraft
            val key = cache_key(aircraft)
            if (!seen.add(key)) continue
            val screen = screen_point_for_entry(entry, viewport, scale, now_epoch_sec)
            if (!screen_neighborhood_contains(screen.x, screen.y, false, viewport)) continue
            val dx = screen.x - center_x
            val dy = screen.y - center_y
            candidates += dx * dx + dy * dy to aircraft
        }
        val visible = candidates
            .sortedBy { it.first }
            .asSequence()
            .map { it.second }
            .take(DETAILS_PREFETCH_MAX_VISIBLE_CANDIDATES)
            .toList()
        return (preferred + visible)
            .distinctBy(cache_key)
            .take(DETAILS_PREFETCH_MAX_VISIBLE_CANDIDATES)
    }
}


internal class AircraftDetailsRowsBuilder(
    private val telemetry_formatter: AircraftTelemetryFormatter,
    private val is_details_loading_for: (Aircraft) -> Boolean,
    private val details_with_trace_origin: (AircraftDetails?, Aircraft) -> AircraftDetails?,
    private val current_flight_route_details: (AircraftDetails?, Aircraft) -> AircraftDetails?,
    private val route_trace_context: (Aircraft) -> AircraftRouteTraceContext,
    private val registry_country_label: (Aircraft, AircraftDetails?, Boolean) -> String,
    private val format_origin_status: (Aircraft, AircraftDetails?) -> String,
    private val current_flight_route_loading: (Aircraft, Boolean) -> Boolean,
    private val reported_distance_meters: (Aircraft) -> Double,
    private val loading_or_unavailable: (Boolean) -> String
) {
    // Build honest detail rows from live aircraft plus documented metadata; missing data stays unavailable.
    fun aircraft_details_rows(aircraft: Aircraft, details: AircraftDetails?): List<AircraftDetailsRow> {
        val details_loading = is_details_loading_for(aircraft)
        val enriched_details = details_with_trace_origin(details, aircraft)
        val route_details = current_flight_route_details(enriched_details, aircraft)
        val route_context = route_trace_context(aircraft)
        val telemetry = enriched_details?.telemetry?.with_fallback(aircraft.telemetry) ?: aircraft.telemetry
        val rows = mutableListOf<AircraftDetailsRow>()
        rows += AircraftDetailsRow.section("Aircraft")
        rows += AircraftDetailsRow("Callsign", aircraft.callsign)
        rows += AircraftDetailsRow("ICAO hex", aircraft.icao24.uppercase(Locale.US))
        rows += AircraftDetailsRow("Registration", enriched_details?.registration ?: aircraft.registration ?: loading_or_unavailable(details_loading))
        rows += AircraftDetailsRow("Registry country", registry_country_label(aircraft, enriched_details, details_loading))
        rows += AircraftDetailsRow("Owner/Operator", AircraftRoutePresenter.details_value(enriched_details?.owner, details_loading))
        rows += AircraftDetailsRow("Aircraft", AircraftRoutePresenter.aircraft_type(enriched_details, aircraft, details_loading))
        rows += AircraftDetailsRow("MFR year", AircraftRoutePresenter.details_value(enriched_details?.manufactured_year, details_loading))
        rows += AircraftDetailsRow("Type code", enriched_details?.type_code ?: aircraft.type_code ?: loading_or_unavailable(details_loading))
        rows += AircraftDetailsRow("Squawk", telemetry_formatter.telemetry_value(telemetry?.squawk))
        rows += AircraftDetailsRow("Data source", telemetry_formatter.telemetry_value(telemetry_formatter.source_type(telemetry?.source_type)))
        rows += AircraftDetailsRow("Registry source", AircraftRoutePresenter.details_value(enriched_details?.registry_source, details_loading))
        if (aircraft.is_military) {
            rows += AircraftDetailsRow("Military", "Tagged military")
            rows += AircraftDetailsRow("Origin status", format_origin_status(aircraft, route_details))
        }
        val route_loading = current_flight_route_loading(aircraft, details_loading)
        rows += AircraftDetailsRow.section("Route")
        rows += AircraftDetailsRow("Route", AircraftRoutePresenter.value(route_details?.route, route_loading))
        rows += AircraftDetailsRow("Origin", AircraftRoutePresenter.airport(route_details?.origin_airport, route_loading))
        rows += AircraftDetailsRow("Destination", AircraftRoutePresenter.airport(route_details?.destination_airport, route_loading))
        rows += AircraftDetailsRow("Path source", AircraftRoutePresenter.trace_source(route_context))
        rows += AircraftDetailsRow("Flight time", AircraftRoutePresenter.observed_flight_time(route_context))
        rows += AircraftDetailsRow("Route complete", AircraftRoutePresenter.route_completion(route_details, aircraft, route_context, route_loading))
        rows += AircraftDetailsRow("Observed path span", AircraftRoutePresenter.observed_path_span(route_context))
        rows += spatial_rows(aircraft, telemetry)
        rows += speed_rows(aircraft, telemetry)
        rows += wind_rows(telemetry, details_loading)
        rows += altitude_rows(aircraft, telemetry)
        rows += direction_rows(aircraft, telemetry)
        return rows
    }

    private fun spatial_rows(aircraft: Aircraft, telemetry: AircraftTelemetry?): List<AircraftDetailsRow> {
        return listOf(
            AircraftDetailsRow.section("Spatial"),
            AircraftDetailsRow("Groundspeed", telemetry_formatter.aviation_speed(telemetry?.ground_speed_ms ?: aircraft.velocity_ms)),
            AircraftDetailsRow("Baro. altitude", telemetry_formatter.altitude_value(telemetry?.baro_altitude_m ?: aircraft.altitude_m)),
            AircraftDetailsRow("WGS84 altitude", telemetry_formatter.altitude_value(telemetry?.geom_altitude_m)),
            AircraftDetailsRow("Vert. Rate", telemetry_formatter.vertical_rate(telemetry?.baro_rate_ms ?: aircraft.vertical_rate_ms)),
            AircraftDetailsRow("Track", telemetry_formatter.degrees_decimal(aircraft.track_deg, decimals = 1)),
            AircraftDetailsRow("Pos.", telemetry_formatter.reported_position(aircraft)),
            AircraftDetailsRow("Distance", telemetry_formatter.distance(reported_distance_meters(aircraft)))
        )
    }

    private fun wind_rows(telemetry: AircraftTelemetry?, loading: Boolean): List<AircraftDetailsRow> {
        return listOf(
            AircraftDetailsRow.section("Wind"),
            AircraftDetailsRow("Speed", telemetry_formatter.aviation_speed(telemetry?.wind_speed_ms, loading)),
            AircraftDetailsRow("Direction (from)", telemetry_formatter.degrees_decimal(telemetry?.wind_direction_deg, loading = loading)),
            AircraftDetailsRow("TAT / OAT", telemetry_formatter.temperature_pair(telemetry?.tat_c, telemetry?.oat_c, loading))
        )
    }

    private fun speed_rows(aircraft: Aircraft, telemetry: AircraftTelemetry?): List<AircraftDetailsRow> {
        return listOf(
            AircraftDetailsRow.section("Speed"),
            AircraftDetailsRow("Ground", telemetry_formatter.aviation_speed(telemetry?.ground_speed_ms ?: aircraft.velocity_ms)),
            AircraftDetailsRow("True", telemetry_formatter.aviation_speed(telemetry?.true_speed_ms)),
            AircraftDetailsRow("Indicated", telemetry_formatter.aviation_speed(telemetry?.indicated_speed_ms)),
            AircraftDetailsRow("Mach", telemetry_formatter.mach(telemetry?.mach))
        )
    }

    private fun altitude_rows(aircraft: Aircraft, telemetry: AircraftTelemetry?): List<AircraftDetailsRow> {
        return listOf(
            AircraftDetailsRow.section("Altitude"),
            AircraftDetailsRow("Barometric", telemetry_formatter.altitude_value(telemetry?.baro_altitude_m ?: aircraft.altitude_m)),
            AircraftDetailsRow("Baro. Rate", telemetry_formatter.vertical_rate(telemetry?.baro_rate_ms ?: aircraft.vertical_rate_ms)),
            AircraftDetailsRow("Geom. WGS84", telemetry_formatter.altitude_value(telemetry?.geom_altitude_m)),
            AircraftDetailsRow("Geom. Rate", telemetry_formatter.vertical_rate(telemetry?.geom_rate_ms)),
            AircraftDetailsRow("QNH", telemetry_formatter.pressure(telemetry?.qnh_hpa)),
            AircraftDetailsRow("Sel. Alt.", telemetry_formatter.altitude_value(telemetry?.selected_altitude_m))
        )
    }

    private fun direction_rows(aircraft: Aircraft, telemetry: AircraftTelemetry?): List<AircraftDetailsRow> {
        return listOf(
            AircraftDetailsRow.section("Direction"),
            AircraftDetailsRow("Ground Track", telemetry_formatter.degrees_decimal(aircraft.track_deg, decimals = 1)),
            AircraftDetailsRow("True Heading", telemetry_formatter.degrees_decimal(telemetry?.true_heading_deg, decimals = 1)),
            AircraftDetailsRow("Magnetic Heading", telemetry_formatter.degrees_decimal(telemetry?.magnetic_heading_deg, decimals = 1)),
            AircraftDetailsRow("Magnetic Decl.", telemetry_formatter.signed_degrees(telemetry?.magnetic_declination_deg)),
            AircraftDetailsRow("Track Rate", telemetry_formatter.track_rate(telemetry?.track_rate_deg_per_sec)),
            AircraftDetailsRow("Roll", telemetry_formatter.signed_degrees(telemetry?.roll_deg)),
            AircraftDetailsRow("Sel. Head.", telemetry_formatter.degrees_decimal(telemetry?.selected_heading_deg, decimals = 1)),
            AircraftDetailsRow("Nav. Modes", telemetry?.nav_modes?.joinToString(", ")?.takeIf { it.isNotBlank() } ?: "Unavailable")
        )
    }
}


class AircraftDetailsSession(
    private val coordinator: AircraftDetailsCoordinator,
    private val warm_requester: AircraftDetailsWarmRequester,
    private val feed_mode: () -> AircraftFeedMode,
    private val selected_aircraft: () -> Aircraft?,
    private val select_aircraft: (Aircraft) -> Unit,
    private val has_selected_flight_path: () -> Boolean,
    private val is_flight_path_loading: (Aircraft) -> Boolean,
    private val request_flight_path: (String) -> Unit,
    private val request_trace_origin_airport: (Aircraft) -> Unit,
    private val reset_scroll: () -> Unit,
    private val reset_scroll_offset: () -> Unit,
    private val request_redraw: () -> Unit,
    private val request_animation_frame: () -> Unit
) {
    var details_open = false
    var usage_open = false
    var environmental_impact_open = false
    var impact_methodology_open = false
    var aircraft_details: AircraftDetails? = null
    var aircraft_details_status = "Select aircraft"
    var aircraft_details_loading = false
    var aircraft_photo: Bitmap? = null
    var aircraft_photo_previous_bitmap: Bitmap? = null
    var aircraft_photo_transition_started_elapsed_ms = 0L
    var aircraft_photo_status = "Photo unavailable"
    var aircraft_photo_evidence: PhotoEvidence? = null
    var active_photo_evidence: PhotoEvidence? = null
    var aircraft_photo_quality: PhotoQuality? = null
    var photo_evidence_open = false
    var photo_gallery_open = false
    var aircraft_photo_gallery: List<AircraftPhotoGalleryItem> = emptyList()
    var aircraft_photo_gallery_status = "Photo gallery unavailable"
    var aircraft_photo_gallery_loading = false

    private var details_request_token = 0L

    private enum class SecondaryPanel {
        USAGE,
        ENVIRONMENTAL_IMPACT
    }

    // Details open by first anchoring selection, then letting real metadata/photo sources race safely by token.
    fun open_details(aircraft: Aircraft) {
        select_aircraft(aircraft)
        details_open = true
        usage_open = false
        environmental_impact_open = false
        photo_evidence_open = false
        photo_gallery_open = false
        active_photo_evidence = null
        reset_scroll()
        clear_photo_transition()
        aircraft_photo_gallery = emptyList()
        aircraft_photo_gallery_loading = false
        aircraft_photo_gallery_status = "Photo gallery unavailable"
        val warmed = warm_requester.fresh_details_for(aircraft)
        if (warmed != null) {
            apply_warmed_details(warmed, preserve_existing = false)
        } else {
            aircraft_details = null
            aircraft_details_loading = true
            aircraft_photo = null
            aircraft_photo_evidence = null
            aircraft_photo_quality = null
            aircraft_details_status = "Loading live aircraft details"
            aircraft_photo_status = "Searching real photo sources"
            apply_seeded_details(aircraft)
        }
        request_details(aircraft)
    }

    fun open_usage(aircraft: Aircraft, selected_aircraft_id: String?) {
        open_secondary_panel(aircraft, selected_aircraft_id, SecondaryPanel.USAGE)
    }

    fun open_impact(aircraft: Aircraft, selected_aircraft_id: String?) {
        open_secondary_panel(aircraft, selected_aircraft_id, SecondaryPanel.ENVIRONMENTAL_IMPACT)
    }

    private fun open_secondary_panel(
        aircraft: Aircraft,
        selected_aircraft_id: String?,
        panel: SecondaryPanel
    ) {
        if (selected_aircraft_id != aircraft.icao24) {
            select_aircraft(aircraft)
        } else if (!has_selected_flight_path() && !is_flight_path_loading(aircraft)) {
            request_flight_path(aircraft.icao24)
        }
        usage_open = panel == SecondaryPanel.USAGE
        environmental_impact_open = panel == SecondaryPanel.ENVIRONMENTAL_IMPACT
        photo_evidence_open = false
        photo_gallery_open = false
        active_photo_evidence = null
        reset_scroll()
    }

    fun close_details_shell() {
        details_open = false
        aircraft_details_loading = false
        photo_evidence_open = false
        photo_gallery_open = false
        active_photo_evidence = null
        usage_open = false
        environmental_impact_open = false
    }

    fun open_photo_evidence(evidence: PhotoEvidence?) {
        active_photo_evidence = evidence
        photo_evidence_open = true
        reset_scroll_offset()
    }

    fun close_photo_evidence() {
        photo_evidence_open = false
        active_photo_evidence = null
    }

    fun close_photo_gallery() {
        photo_gallery_open = false
    }

    fun open_photo_gallery(aircraft: Aircraft, details: AircraftDetails) {
        val request_token = details_request_token
        photo_gallery_open = true
        photo_evidence_open = false
        active_photo_evidence = null
        reset_scroll()
        aircraft_photo_gallery = emptyList()
        aircraft_photo_gallery_loading = true
        aircraft_photo_gallery_status = when (feed_mode()) {
            AircraftFeedMode.WEB -> "Loading exact photos from direct aircraft-photo sources"
            AircraftFeedMode.API -> "Loading exterior photos from API sources"
            AircraftFeedMode.HYBRID -> "Loading exact photos, then labeled representatives"
        }
        request_redraw()
        coordinator.request_photo_gallery(
            aircraft = aircraft,
            details = details,
            request_token = request_token,
            is_current_request = ::is_current_details_request,
            on_gallery = ::post_photo_gallery
        )
    }

    fun photo_transition_progress(replacement_transition_ms: Long): Float {
        if (aircraft_photo_previous_bitmap == null) return 1f
        val elapsed = SystemClock.elapsedRealtime() - aircraft_photo_transition_started_elapsed_ms
        if (elapsed !in 0L until replacement_transition_ms) {
            clear_photo_transition()
            return 1f
        }
        request_animation_frame()
        return (elapsed.toFloat() / replacement_transition_ms).coerceIn(0f, 1f)
    }

    fun unavailable_photo_status(): String {
        return "Exact, representative, and search photos unavailable"
    }

    fun is_current_details_request(requested_id: String, request_token: Long): Boolean {
        return details_open &&
            details_request_token == request_token &&
            selected_aircraft()?.icao24 == requested_id
    }

    fun apply_warm_cache_to_current_details(key: String, entry: AircraftDetailsWarmCacheEntry, current_key: String?) {
        if (!details_open || current_key != key) return
        apply_warmed_details(entry, preserve_existing = true)
        request_redraw()
    }

    private fun request_details(aircraft: Aircraft) {
        val request_token = ++details_request_token
        coordinator.request_aircraft_details(
            aircraft = aircraft,
            request_token = request_token,
            is_current_request = ::is_current_details_request,
            is_photo_available = { aircraft_photo != null },
            on_details = ::post_aircraft_details,
            on_details_unavailable = ::post_aircraft_details_unavailable,
            on_photo_found = ::post_aircraft_photo,
            on_photo_unavailable = ::post_aircraft_photo_unavailable,
            on_photo_search_done = ::post_aircraft_photo_search_done
        )
    }

    private fun post_aircraft_details(requested_id: String, request_token: Long, details: AircraftDetails, still_loading: Boolean) {
        if (!is_current_details_request(requested_id, request_token)) return
        aircraft_details = details
        aircraft_details_loading = still_loading
        aircraft_details_status = AircraftDetailsCoordinator.details_status(details, still_loading)
        if (aircraft_photo == null) {
            aircraft_photo_status = "Searching real photo sources"
        }
        selected_aircraft()?.let { request_trace_origin_airport(it) }
        request_redraw()
    }

    private fun post_aircraft_details_unavailable(requested_id: String, request_token: Long) {
        if (!is_current_details_request(requested_id, request_token)) return
        aircraft_details_loading = false
        if (aircraft_details == null) {
            aircraft_details_status = "Metadata unavailable from configured sources"
        }
        selected_aircraft()?.let { request_trace_origin_airport(it) }
        request_redraw()
    }

    private fun post_photo_gallery(
        requested_id: String,
        request_token: Long,
        items: List<AircraftPhotoGalleryItem>
    ) {
        if (!is_current_details_request(requested_id, request_token)) return
        aircraft_photo_gallery = items
        aircraft_photo_gallery_loading = false
        aircraft_photo_gallery_status = if (items.isEmpty()) {
            "No real gallery photos available from checked sources"
        } else {
            "Tap a source-marked photo for proof and browser links"
        }
        request_redraw()
    }

    private fun apply_seeded_details(aircraft: Aircraft): Boolean {
        val details = coordinator.seeded_aircraft_details(
            aircraft = aircraft
        ) ?: return false
        warm_requester.cache_aircraft_details(aircraft, details, still_loading = true)
        aircraft_details = details
        aircraft_details_loading = true
        aircraft_details_status = AircraftDetailsCoordinator.details_status(details, still_loading = true)
        aircraft_photo_status = "Searching real photo sources"
        request_redraw()
        return true
    }

    private fun apply_warmed_details(
        entry: AircraftDetailsWarmCacheEntry,
        preserve_existing: Boolean
    ) {
        val warmed_details = entry.details
        if (warmed_details != null) {
            if (!preserve_existing || aircraft_details == null || aircraft_details_loading) {
                aircraft_details = warmed_details
                aircraft_details_loading = entry.details_loading
                aircraft_details_status = entry.details_status
            }
        } else if (!preserve_existing || aircraft_details == null) {
            aircraft_details = null
            aircraft_details_loading = entry.details_loading
            aircraft_details_status = entry.details_status
        }

        val warmed_photo = entry.photo
        if (warmed_photo != null) {
            val current_rank = aircraft_photo_quality?.rank ?: 0
            if (!preserve_existing || aircraft_photo == null || warmed_photo.quality.rank > current_rank) {
                apply_aircraft_photo(
                    warmed_photo,
                    animate_replace = preserve_existing && aircraft_photo != null && warmed_photo.quality.rank > current_rank
                )
            }
        } else if (!preserve_existing || aircraft_photo == null) {
            aircraft_photo = null
            aircraft_photo_status = entry.photo_status
            aircraft_photo_evidence = null
            aircraft_photo_quality = null
            clear_photo_transition()
        }
    }

    private fun post_aircraft_photo(
        requested_id: String,
        request_token: Long,
        photo: AircraftPhotoResult.Found,
        allow_replace: Boolean
    ) {
        if (!is_current_details_request(requested_id, request_token)) return
        val current_quality = aircraft_photo_quality
        if (!allow_replace && aircraft_photo != null) return
        if (allow_replace && current_quality != null && photo.quality.rank <= current_quality.rank) {
            request_redraw()
            return
        }
        apply_aircraft_photo(
            photo,
            animate_replace = allow_replace && aircraft_photo != null && photo.quality.rank > (current_quality?.rank ?: 0)
        )
        request_redraw()
    }

    private fun post_aircraft_photo_unavailable(requested_id: String, request_token: Long) {
        if (!is_current_details_request(requested_id, request_token)) return
        aircraft_photo = null
        aircraft_photo_status = unavailable_photo_status()
        aircraft_photo_evidence = null
        aircraft_photo_quality = null
        clear_photo_transition()
        request_redraw()
    }

    private fun post_aircraft_photo_search_done(requested_id: String, request_token: Long) {
        if (!is_current_details_request(requested_id, request_token)) return
    }

    private fun apply_aircraft_photo(photo: AircraftPhotoResult.Found, animate_replace: Boolean) {
        val previous = aircraft_photo
        if (animate_replace && previous != null && previous != photo.bitmap) {
            aircraft_photo_previous_bitmap = previous
            aircraft_photo_transition_started_elapsed_ms = SystemClock.elapsedRealtime()
            request_animation_frame()
        } else {
            clear_photo_transition()
        }
        aircraft_photo = photo.bitmap
        aircraft_photo_status = photo.note
        aircraft_photo_evidence = photo.evidence
        aircraft_photo_quality = photo.quality
    }

    private fun clear_photo_transition() {
        aircraft_photo_previous_bitmap = null
        aircraft_photo_transition_started_elapsed_ms = 0L
    }
}


data class AircraftDetailsWarmCacheEntry(
    val details: AircraftDetails? = null,
    val details_loading: Boolean = false,
    val details_status: String = "Metadata unavailable from configured sources",
    val photo: AircraftPhotoResult.Found? = null,
    val photo_status: String = "Photo unavailable",
    val updated_elapsed_ms: Long
)

class AircraftDetailsWarmCache(
    max_entries: Int,
    private val max_age_ms: Long,
    private val photo_unavailable_status: () -> String
) {
    private val entries = object : LinkedHashMap<String, AircraftDetailsWarmCacheEntry>(
        max_entries,
        0.75f,
        true
    ) {
        override fun removeEldestEntry(eldest: MutableMap.MutableEntry<String, AircraftDetailsWarmCacheEntry>): Boolean {
            return size > max_entries
        }
    }
    private val request_tokens = mutableMapOf<String, Long>()
    private var next_request_token = 0L

    var last_prefetch_elapsed_ms = 0L

    val in_flight_count: Int
        get() = request_tokens.size

    // Warm requests use monotonically increasing tokens so stale detail/photo callbacks cannot repaint a new selection.
    fun begin_request(key: String): Long {
        val token = ++next_request_token
        request_tokens[key] = token
        return token
    }

    fun has_in_flight_request(key: String): Boolean {
        return request_tokens.containsKey(key)
    }

    fun is_current_request(key: String, selected_aircraft_id: String, requested_id: String, request_token: Long): Boolean {
        return request_tokens[key] == request_token && requested_id == selected_aircraft_id
    }

    fun finish_request(key: String) {
        request_tokens.remove(key)
    }

    fun fresh_entry(key: String, now_elapsed_ms: Long): AircraftDetailsWarmCacheEntry? {
        val entry = entries[key] ?: return null
        if (now_elapsed_ms - entry.updated_elapsed_ms <= max_age_ms) return entry
        entries.remove(key)
        return null
    }

    fun needs_refresh(key: String, now_elapsed_ms: Long): Boolean {
        if (key.isBlank() || request_tokens.containsKey(key)) return false
        val cached = entries[key] ?: return true
        if (now_elapsed_ms - cached.updated_elapsed_ms > max_age_ms) {
            entries.remove(key)
            return true
        }
        return false
    }

    fun cache_details(
        key: String,
        aircraft_current_key: String,
        details: AircraftDetails,
        still_loading: Boolean,
        now_elapsed_ms: Long
    ): AircraftDetailsWarmCacheEntry {
        val previous = entries[key]
        val entry = (previous ?: AircraftDetailsWarmCacheEntry(updated_elapsed_ms = now_elapsed_ms)).copy(
            details = details,
            details_loading = still_loading,
            details_status = AircraftDetailsCoordinator.details_status(details, still_loading),
            photo_status = previous?.photo_status ?: "Searching real photo sources",
            updated_elapsed_ms = now_elapsed_ms
        )
        entries[key] = entry
        if (previous == null && aircraft_current_key != key) {
            entries.remove(key)
        }
        return entry
    }

    fun cache_details_unavailable(key: String, now_elapsed_ms: Long): AircraftDetailsWarmCacheEntry {
        val previous = entries[key]
        val entry = (previous ?: AircraftDetailsWarmCacheEntry(updated_elapsed_ms = now_elapsed_ms)).copy(
            details_loading = false,
            details_status = "Metadata unavailable from configured sources",
            updated_elapsed_ms = now_elapsed_ms
        )
        entries[key] = entry
        return entry
    }

    fun cache_photo(
        key: String,
        photo: AircraftPhotoResult.Found,
        allow_replace: Boolean,
        now_elapsed_ms: Long
    ): AircraftDetailsWarmCacheEntry {
        val previous = entries[key] ?: AircraftDetailsWarmCacheEntry(updated_elapsed_ms = now_elapsed_ms)
        val current_photo = previous.photo
        val should_replace = current_photo == null || (allow_replace && photo.quality.rank > current_photo.quality.rank)
        val entry = if (should_replace) {
            previous.copy(
                photo = photo,
                photo_status = photo.note,
                updated_elapsed_ms = now_elapsed_ms
            )
        } else {
            previous.copy(updated_elapsed_ms = now_elapsed_ms)
        }
        entries[key] = entry
        return entry
    }

    fun cache_photo_unavailable(key: String, now_elapsed_ms: Long): AircraftDetailsWarmCacheEntry {
        val previous = entries[key] ?: AircraftDetailsWarmCacheEntry(updated_elapsed_ms = now_elapsed_ms)
        val entry = previous.copy(
            photo_status = photo_unavailable_status(),
            updated_elapsed_ms = now_elapsed_ms
        )
        finish_request(key)
        entries[key] = entry
        return entry
    }
}


class AircraftDetailsWarmRequester(
    private val coordinator: AircraftDetailsCoordinator,
    private val cache_key: (Aircraft) -> String,
    private val apply_entry: (String, AircraftDetailsWarmCacheEntry) -> Unit,
    max_entries: Int,
    max_age_ms: Long,
    photo_unavailable_status: () -> String
) {
    private val warm_cache = AircraftDetailsWarmCache(
        max_entries = max_entries,
        max_age_ms = max_age_ms,
        photo_unavailable_status = photo_unavailable_status
    )

    var last_prefetch_elapsed_ms: Long
        get() = warm_cache.last_prefetch_elapsed_ms
        set(value) {
            warm_cache.last_prefetch_elapsed_ms = value
        }

    val in_flight_count: Int
        get() = warm_cache.in_flight_count

    fun fresh_details_for(aircraft: Aircraft): AircraftDetailsWarmCacheEntry? {
        return warm_cache.fresh_entry(cache_key(aircraft), SystemClock.elapsedRealtime())
    }

    fun should_prefetch(aircraft: Aircraft, now_elapsed_ms: Long): Boolean {
        return warm_cache.needs_refresh(cache_key(aircraft), now_elapsed_ms)
    }

    // Warm requests run ahead of user taps, but every callback still proves it belongs to the same aircraft key.
    fun start_prefetch(aircraft: Aircraft) {
        val key = cache_key(aircraft)
        if (key.isBlank() || warm_cache.has_in_flight_request(key)) return
        val request_token = warm_cache.begin_request(key)
        coordinator.seeded_aircraft_details(
            aircraft = aircraft
        )?.let { details ->
            cache_aircraft_details(aircraft, details, still_loading = true)
        }
        coordinator.request_aircraft_details(
            aircraft = aircraft,
            request_token = request_token,
            is_current_request = { requested_id, token ->
                is_current_warmed_request(key, aircraft, requested_id, token)
            },
            is_photo_available = { warm_cache.fresh_entry(key, SystemClock.elapsedRealtime())?.photo != null },
            on_details = { requested_id, token, details, still_loading ->
                if (is_current_warmed_request(key, aircraft, requested_id, token)) {
                    cache_aircraft_details(aircraft, details, still_loading)
                }
            },
            on_details_unavailable = { requested_id, token ->
                if (is_current_warmed_request(key, aircraft, requested_id, token)) {
                    cache_details_unavailable(key)
                }
            },
            on_photo_found = { requested_id, token, photo, allow_replace ->
                if (is_current_warmed_request(key, aircraft, requested_id, token)) {
                    cache_aircraft_photo(key, photo, allow_replace)
                }
            },
            on_photo_unavailable = { requested_id, token ->
                if (is_current_warmed_request(key, aircraft, requested_id, token)) {
                    cache_photo_unavailable(key)
                }
            },
            on_photo_search_done = { requested_id, token ->
                if (is_current_warmed_request(key, aircraft, requested_id, token)) {
                    warm_cache.finish_request(key)
                }
            }
        )
    }

    fun cache_aircraft_details(
        aircraft: Aircraft,
        details: AircraftDetails,
        still_loading: Boolean
    ) {
        val key = cache_key(aircraft)
        val entry = warm_cache.cache_details(
            key = key,
            aircraft_current_key = cache_key(aircraft),
            details = details,
            still_loading = still_loading,
            now_elapsed_ms = SystemClock.elapsedRealtime()
        )
        apply_entry(key, entry)
    }

    private fun cache_details_unavailable(key: String) {
        val entry = warm_cache.cache_details_unavailable(key, SystemClock.elapsedRealtime())
        apply_entry(key, entry)
    }

    private fun cache_aircraft_photo(
        key: String,
        photo: AircraftPhotoResult.Found,
        allow_replace: Boolean
    ) {
        val entry = warm_cache.cache_photo(
            key = key,
            photo = photo,
            allow_replace = allow_replace,
            now_elapsed_ms = SystemClock.elapsedRealtime()
        )
        apply_entry(key, entry)
    }

    private fun cache_photo_unavailable(key: String) {
        val entry = warm_cache.cache_photo_unavailable(key, SystemClock.elapsedRealtime())
        apply_entry(key, entry)
    }

    private fun is_current_warmed_request(
        key: String,
        aircraft: Aircraft,
        requested_id: String,
        request_token: Long
    ): Boolean {
        return warm_cache.is_current_request(
            key = key,
            selected_aircraft_id = aircraft.icao24,
            requested_id = requested_id,
            request_token = request_token
        )
    }
}


class AircraftOriginLookupController(
    private val military_origin_resolver: MilitaryOriginResolver,
    private val trace_origin_airport_resolver: TraceOriginAirportResolver,
    private val executor: Executor,
    private val post_to_main: (() -> Unit) -> Unit,
    private val request_redraw: () -> Unit,
    private val is_selected_key: (String) -> Boolean,
    private val selected_segments: () -> List<TraceSegment>?,
    private val aircraft_feed_mode: () -> AircraftFeedMode,
    private val aircraft_details: () -> AircraftDetails?,
    private val current_flight_route_details: (AircraftDetails, Aircraft) -> AircraftDetails?
) {
    private var military_origin_aircraft_id: String? = null
    private var military_origin_status = "Unavailable"
    private var military_origin_request_key: String? = null
    private var trace_origin_aircraft_id: String? = null
    private var trace_origin_airport: AirportDetails? = null
    private var trace_origin_request_key: String? = null
    private var trace_origin_loading = false

    fun reset_for_selection(aircraft: Aircraft) {
        military_origin_aircraft_id = aircraft.icao24
        military_origin_status = if (aircraft.is_military) "Waiting for flight path origin" else "Unavailable"
        military_origin_request_key = null
        trace_origin_aircraft_id = aircraft.icao24
        trace_origin_airport = null
        trace_origin_request_key = null
        trace_origin_loading = false
    }

    fun clear_trace_origin() {
        trace_origin_airport = null
        trace_origin_request_key = null
        trace_origin_loading = false
    }

    fun military_status_for(aircraft: Aircraft): String? {
        return military_origin_status.takeIf {
            military_origin_aircraft_id == aircraft.icao24 && it != "Unavailable"
        }
    }

    fun trace_origin_airport_for(aircraft: Aircraft): AirportDetails? {
        return trace_origin_airport?.takeIf { trace_origin_aircraft_id == aircraft.icao24 }
    }

    fun trace_origin_loading_for(aircraft: Aircraft): Boolean {
        return trace_origin_loading && trace_origin_aircraft_id == aircraft.icao24
    }

    // Military origin claims only start from the selected aircraft's real trace, never from type or registration guesses.
    fun request_military_origin_if_needed(aircraft: Aircraft) {
        val key = aircraft.icao24.lowercase(Locale.US)
        if (!aircraft.is_military || !is_selected_key(key)) return
        val first_point = first_selected_trace_point() ?: return
        val request_key = trace_request_key(key, first_point)
        if (military_origin_request_key == request_key) return

        military_origin_request_key = request_key
        military_origin_aircraft_id = aircraft.icao24
        military_origin_status = "Checking track origin"
        executor.execute {
            val status = military_origin_resolver.resolve_origin(first_point)
            post_to_main {
                if (is_selected_key(key) && military_origin_request_key == request_key) {
                    military_origin_status = status
                    request_redraw()
                }
            }
        }
    }

    // Hybrid mode can enrich route origin from the selected trace only when no provider route origin exists.
    fun request_trace_origin_airport_if_needed(aircraft: Aircraft) {
        val key = aircraft.icao24.lowercase(Locale.US)
        if (aircraft_feed_mode() != AircraftFeedMode.HYBRID) return
        if (!is_selected_key(key)) return
        if (trace_origin_airport != null && trace_origin_aircraft_id == aircraft.icao24) return
        if (trace_origin_aircraft_id == aircraft.icao24 && trace_origin_loading) return
        if (should_skip_airport_origin_fallback(aircraft)) return
        val route_with_supplied_origin = aircraft_details()
            ?.takeIf { CurrentRouteValidator.has_route_metadata(it) }
            ?.let { details -> current_flight_route_details(details, aircraft) }
        if (route_with_supplied_origin?.origin_airport != null) return
        val first_point = first_selected_trace_point() ?: return
        val request_key = trace_request_key(key, first_point)
        if (trace_origin_request_key == request_key) return

        trace_origin_aircraft_id = aircraft.icao24
        trace_origin_request_key = request_key
        trace_origin_loading = true
        executor.execute {
            val airport = trace_origin_airport_resolver.resolve_origin_airport(first_point)
            post_to_main {
                if (is_selected_key(key) && trace_origin_request_key == request_key) {
                    trace_origin_airport = airport
                    trace_origin_loading = false
                    request_redraw()
                }
            }
        }
    }

    private fun first_selected_trace_point(): TrackPoint? {
        return selected_segments()
            ?.flatMap { it.points }
            ?.minByOrNull { it.epoch_sec }
    }

    private fun should_skip_airport_origin_fallback(aircraft: Aircraft): Boolean {
        val type = aircraft.type_code?.trim()?.uppercase(Locale.US).orEmpty()
        if (type.startsWith("H") || type.startsWith("R") || type.startsWith("UAV") || type.startsWith("DRON")) return true
        return aircraft.category == 8 || aircraft.category == 14
    }

    private fun trace_request_key(key: String, first_point: TrackPoint): String {
        return "${key}:${first_point.epoch_sec}:${"%.4f".format(Locale.US, first_point.lat)}:${"%.4f".format(Locale.US, first_point.lon)}"
    }
}


internal class AircraftTelemetryFormatter(
    private val measurement_formatter: MapMeasurementFormatter,
    private val reported_distance_meters: (Aircraft) -> Double,
    private val loading_or_unavailable: (Boolean) -> String,
    private val now_epoch_seconds: () -> Double
) {
    fun aircraft_label_detail(aircraft: Aircraft): String {
        val altitude = aircraft.altitude_m?.let { altitude_value(it) } ?: "alt n/a"
        return "${distance(reported_distance_meters(aircraft))}  $altitude"
    }

    fun aircraft_detail(aircraft: Aircraft): String {
        return "${distance(reported_distance_meters(aircraft))}  ${altitude_value(aircraft.altitude_m)}"
    }

    fun distance(meters: Double): String = measurement_formatter.format_distance(meters)

    fun altitude_value(meters: Double?): String = measurement_formatter.format_altitude(meters)

    fun accuracy(meters: Double): String = measurement_formatter.format_accuracy(meters)

    fun speed_value(ms: Double?): String = measurement_formatter.format_speed(ms)

    fun aviation_speed(ms: Double?, loading: Boolean = false): String {
        ms ?: return loading_or_unavailable(loading)
        val knots = ms / KNOTS_TO_METERS_PER_SECOND
        val display = speed_value(ms)
        return String.format(Locale.US, "%.0f kt / %s", knots, display)
    }

    fun track(degrees: Double?): String = measurement_formatter.format_track(degrees)

    fun vertical_rate(ms: Double?): String = measurement_formatter.format_vertical_rate(ms)

    fun telemetry_value(value: String?): String {
        return value?.trim()?.takeIf { it.isNotBlank() } ?: "Unavailable"
    }

    fun source_type(value: String?): String? {
        val normalized = value?.trim()?.takeIf { it.isNotBlank() } ?: return null
        val compact = normalized.lowercase(Locale.US).replace("-", "_")
        return when {
            "adsb" in compact || "ads_b" in compact -> "ADS-B"
            "mlat" in compact -> "MLAT"
            "tisb" in compact || "tis_b" in compact -> "TIS-B"
            else -> normalized.uppercase(Locale.US)
        }
    }

    fun degrees_decimal(degrees: Double?, decimals: Int = 0, loading: Boolean = false): String {
        degrees ?: return loading_or_unavailable(loading)
        return String.format(Locale.US, "%.${decimals}f deg", degrees)
    }

    fun signed_degrees(degrees: Double?): String {
        degrees ?: return "Unavailable"
        return String.format(Locale.US, "%+.1f deg", degrees)
    }

    fun track_rate(degrees_per_second: Double?): String {
        degrees_per_second ?: return "Unavailable"
        return String.format(Locale.US, "%+.2f deg/s", degrees_per_second)
    }

    fun temperature_pair(tat_c: Double?, oat_c: Double?, loading: Boolean = false): String {
        return when {
            tat_c != null && oat_c != null -> String.format(Locale.US, "%.0f / %.0f C", tat_c, oat_c)
            tat_c != null -> String.format(Locale.US, "TAT %.0f C", tat_c)
            oat_c != null -> String.format(Locale.US, "OAT %.0f C", oat_c)
            else -> loading_or_unavailable(loading)
        }
    }

    fun mach(mach: Double?): String {
        mach ?: return "Unavailable"
        return String.format(Locale.US, "%.3f", mach)
    }

    fun pressure(hpa: Double?): String {
        hpa ?: return "Unavailable"
        return String.format(Locale.US, "%.1f hPa", hpa)
    }

    fun reported_position(aircraft: Aircraft): String {
        val reported = AircraftPositionProjector.reported_position(aircraft)
        return String.format(Locale.US, "%.4f, %.4f", reported.lat, reported.lon)
    }

    fun age(aircraft: Aircraft): String {
        val age = AircraftPositionProjector.contact_age_seconds(
            aircraft = aircraft,
            now_epoch_sec = now_epoch_seconds()
        ) ?: return "Age unavailable"
        return "${age.toLong()}s old"
    }

    fun feet_setting(feet: Float): String = measurement_formatter.format_feet_setting(feet)

    private companion object {
        const val KNOTS_TO_METERS_PER_SECOND = 0.514444
    }
}


internal class AircraftTraceDetailsPresenter(
    private val selected_trace_aircraft_id: () -> String?,
    private val trace: () -> FlightTrace?,
    private val selected_segments: (Boolean) -> List<TraceSegment>?,
    private val is_flight_path_loading: (Aircraft) -> Boolean,
    private val trace_origin_airport_for: (Aircraft) -> AirportDetails?,
    private val trace_origin_loading_for: (Aircraft) -> Boolean,
    private val aircraft_feed_mode: () -> AircraftFeedMode,
    private val log_route_diagnostic: (String) -> Unit
) {
    fun current_flight_route_details(details: AircraftDetails?, aircraft: Aircraft): AircraftDetails? {
        val route_details = details_with_trace_origin(details, aircraft) ?: return null
        if (!CurrentRouteValidator.has_route_metadata(route_details)) return null
        val validation = CurrentRouteValidator.evaluate(
            details = route_details,
            aircraft_icao24 = aircraft.icao24,
            aircraft_callsign = aircraft.callsign,
            selected_trace_aircraft_id = selected_trace_aircraft_id(),
            trace_segments = selected_segments(false)
        )
        log_route_diagnostic(validation.diagnostic)
        return route_details.takeIf { validation.accepted }
    }

    fun flight_trace_diagnostic(trace: FlightTrace?): String {
        if (trace == null) return "source=none points=0"
        val points = trace.all_points.sortedBy { it.epoch_sec }
        val first = points.firstOrNull()
        val last = points.lastOrNull()
        return "source=${trace.source.ifBlank { "unknown" }} points=${trace.point_count} previous=${trace.previous_point_count} " +
            "first=${first?.lat_lon_label() ?: "none"} last=${last?.lat_lon_label() ?: "none"}"
    }

    fun current_flight_route_loading(aircraft: Aircraft, details_loading: Boolean): Boolean {
        val trace_origin_pending = trace_origin_loading_for(aircraft) &&
            aircraft_feed_mode() == AircraftFeedMode.HYBRID
        return details_loading || is_flight_path_loading(aircraft) || trace_origin_pending
    }

    fun details_with_trace_origin(details: AircraftDetails?, aircraft: Aircraft): AircraftDetails? {
        val fallback_origin = trace_origin_airport_for(aircraft) ?: return details
        if (details?.origin_airport != null) return details
        val source = listOfNotNull(details?.route_source, "OSM trace-origin aerodrome")
            .distinct()
            .joinToString(" + ")
        return (details ?: AircraftDetails(
            icao24 = aircraft.icao24,
            registration = aircraft.registration,
            manufacturer = null,
            type = null,
            type_code = aircraft.type_code,
            owner = null,
            manufactured_year = null,
            registry_source = null,
            operator_code = null,
            route = null,
            route_updated_epoch_sec = null,
            route_source = source,
            origin_airport = fallback_origin,
            destination_airport = null
        )).copy(
            route_source = source,
            origin_airport = fallback_origin
        )
    }

    fun route_trace_context(aircraft: Aircraft): AircraftRouteTraceContext {
        val id = aircraft.icao24.lowercase(Locale.US)
        return AircraftRouteTraceContext(
            aircraft_id = id,
            selected_trace_aircraft_id = selected_trace_aircraft_id(),
            trace = trace(),
            segments = selected_segments(false),
            loading = is_flight_path_loading(aircraft)
        )
    }

    fun current_impact_trace_for(aircraft: Aircraft): ImpactTrace? {
        val segments = current_trace_segments_for_impact(aircraft) ?: return null
        val points = segments.flatMap { it.points }.takeIf { it.size >= 2 } ?: return null
        val start = points.minOf { it.epoch_sec }
        val end = points.maxOf { it.epoch_sec }
        val seconds = (end - start).coerceAtLeast(0L)
        val distance = AircraftRoutePresenter.trace_distance_meters(segments)
        if (seconds <= 0L || distance <= 0.0) return null
        return ImpactTrace(
            distance_m = distance,
            hours = seconds / 3600.0,
            average_speed_ms = distance / seconds,
            point_count = points.size,
            source = trace()?.source ?: "trace source"
        )
    }

    fun current_trace_segments_for_impact(aircraft: Aircraft): List<TraceSegment>? {
        val id = aircraft.icao24.lowercase(Locale.US)
        if (selected_trace_aircraft_id() != id) return null
        return selected_segments(false)?.takeIf { segments ->
            segments.sumOf { it.points.size } >= 2
        }
    }

    fun has_usage_trace_for(aircraft: Aircraft): Boolean {
        return usage_trace_for(aircraft) != null
    }

    fun usage_trace_for(aircraft: Aircraft): FlightTrace? {
        val id = aircraft.icao24.lowercase(Locale.US)
        val current_trace = trace() ?: return null
        if (selected_trace_aircraft_id() != id) return null
        if (current_trace.segments.isEmpty() && current_trace.previous_segments.isEmpty()) return null
        return current_trace
    }

    private fun TrackPoint.lat_lon_label(): String {
        return String.format(Locale.US, "%.4f,%.4f", lat, lon)
    }
}


object AircraftUsageAnalyzer {
    fun stats_for(trace: FlightTrace): UsageStats {
        val flights = (trace.previous_segments + trace.segments)
            .mapNotNull { usage_flight(it) }
            .sortedBy { it.start_epoch_sec }
        if (flights.isEmpty()) {
            return UsageStats(emptyList(), 0, 0.0, 0, 0.0, "Unavailable")
        }

        val zone = ZoneId.systemDefault()
        val today = LocalDate.now(zone)
        val week_start = today.with(TemporalAdjusters.previousOrSame(DayOfWeek.MONDAY))
            .atStartOfDay(zone)
            .toEpochSecond()
        val now = System.currentTimeMillis() / 1000L
        val week_flights = flights.filter { it.end_epoch_sec >= week_start && it.start_epoch_sec <= now }
        val week_hours = week_flights.sumOf { overlap_hours(it, week_start, now) }

        val buckets = (6 downTo 0).map { offset ->
            val day = today.minusDays(offset.toLong())
            val start = day.atStartOfDay(zone).toEpochSecond()
            val end = day.plusDays(1).atStartOfDay(zone).toEpochSecond()
            val day_flights = flights.filter { it.end_epoch_sec >= start && it.start_epoch_sec < end }
            UsageBucket(
                label = day.format(USAGE_DAY_FORMATTER),
                flights = day_flights.size,
                hours = day_flights.sumOf { overlap_hours(it, start, end) }
            )
        }

        val first = flights.first().start_epoch_sec
        val last = flights.maxOf { it.end_epoch_sec }
        return UsageStats(
            buckets = buckets,
            flight_count = flights.size,
            total_hours = flights.sumOf { it.hours },
            week_flight_count = week_flights.size,
            week_hours = week_hours,
            window_label = "${format_date(first, zone)}-${format_date(last, zone)}"
        )
    }

    fun format_hours(hours: Double): String {
        return if (hours < 10.0) {
            String.format(Locale.US, "%.1f h", hours)
        } else {
            String.format(Locale.US, "%.0f h", hours)
        }
    }

    private fun usage_flight(segment: TraceSegment): UsageFlight? {
        val points = segment.points
        if (points.size < 2) return null
        val start = points.first().epoch_sec
        val end = points.last().epoch_sec
        val duration = end - start
        if (duration < FlightAlertSettings.Usage.MIN_SEGMENT_SECONDS) return null
        val distance = trace_distance_meters(segment)
        if (distance < FlightAlertSettings.Usage.MIN_SEGMENT_DISTANCE_M) return null
        return UsageFlight(start, end, duration / 3600.0)
    }

    private fun overlap_hours(flight: UsageFlight, start_epoch_sec: Long, end_epoch_sec: Long): Double {
        val start = max(flight.start_epoch_sec, start_epoch_sec)
        val end = min(flight.end_epoch_sec, end_epoch_sec)
        return max(0L, end - start) / 3600.0
    }

    private fun format_date(epoch_sec: Long, zone: ZoneId): String {
        return Instant.ofEpochSecond(epoch_sec).atZone(zone).toLocalDate().format(USAGE_DATE_FORMATTER)
    }

    private fun trace_distance_meters(segment: TraceSegment): Double {
        var distance = 0.0
        segment.points.zipWithNext { previous, current ->
            distance += distance_meters(previous.lat, previous.lon, current.lat, current.lon)
        }
        return distance
    }

    private fun distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double =
        spherical_distance_meters(lat1, lon1, lat2, lon2)

    private val USAGE_DAY_FORMATTER: DateTimeFormatter = DateTimeFormatter.ofPattern("EEE", Locale.US)
    private val USAGE_DATE_FORMATTER: DateTimeFormatter = DateTimeFormatter.ofPattern("MMM d", Locale.US)
}

data class UsageBucket(val label: String, val flights: Int, val hours: Double)

data class UsageStats(
    val buckets: List<UsageBucket>,
    val flight_count: Int,
    val total_hours: Double,
    val week_flight_count: Int,
    val week_hours: Double,
    val window_label: String
)

private data class UsageFlight(val start_epoch_sec: Long, val end_epoch_sec: Long, val hours: Double)


private data class OriginAerodrome(
    val name: String?,
    val icao: String?,
    val distance_m: Double,
    val military: Boolean
) {
    fun label(): String = listOfNotNull(name, icao)
        .distinct()
        .joinToString(" / ")
        .ifEmpty { "Unnamed aerodrome" }
}

class MilitaryOriginResolver(private val user_agent: String) {
    fun resolve_origin(point: TrackPoint): String {
        val query = """
            [out:json][timeout:8];
            (
              node(around:${ORIGIN_AERODROME_RADIUS_M.toInt()},${point.lat},${point.lon})["aeroway"="aerodrome"];
              way(around:${ORIGIN_AERODROME_RADIUS_M.toInt()},${point.lat},${point.lon})["aeroway"="aerodrome"];
              relation(around:${ORIGIN_AERODROME_RADIUS_M.toInt()},${point.lat},${point.lon})["aeroway"="aerodrome"];
            );
            out center tags 20;
        """.trimIndent()
        val api_url = "https://overpass-api.de/api/interpreter?data=${URLEncoder.encode(query, "UTF-8")}"
        val elements = fetch_json_object(api_url)?.optJSONArray("elements") ?: return "Origin lookup unavailable"
        val candidates = mutableListOf<OriginAerodrome>()
        for (index in 0 until elements.length()) {
            val item = elements.optJSONObject(index) ?: continue
            val center = item.optJSONObject("center")
            val lat = if (item.has("lat")) item.optDouble("lat") else center?.optDouble("lat") ?: continue
            val lon = if (item.has("lon")) item.optDouble("lon") else center?.optDouble("lon") ?: continue
            val distance_m = MapProjection.distance_meters(point.lat, point.lon, lat, lon)
            if (distance_m > ORIGIN_AERODROME_RADIUS_M) continue
            val tags = item.optJSONObject("tags")
            val name = tags?.optString("name")?.trim()?.ifEmpty { null }
            val icao = tags?.optString("icao")?.trim()?.ifEmpty { null }
            candidates += OriginAerodrome(
                name = name,
                icao = icao,
                distance_m = distance_m,
                military = is_military_aerodrome(tags, name, icao)
            )
        }

        val nearest = candidates.minByOrNull { it.distance_m } ?: return "Track origin not matched to an aerodrome"
        val label = nearest.label()
        return if (nearest.military) {
            "Military base: $label"
        } else {
            "Track origin: $label (civilian/other)"
        }
    }

    private fun is_military_aerodrome(tags: JSONObject?, name: String?, icao: String?): Boolean {
        if (is_military_airport_name(name, icao)) return true
        if (tags == null) return false
        val combined = listOf(
            tags.optString("military"),
            tags.optString("aerodrome"),
            tags.optString("aerodrome:type"),
            tags.optString("operator"),
            tags.optString("operator:type"),
            tags.optString("owner")
        ).joinToString(" ").uppercase(Locale.US)
        return MILITARY_AERODROME_KEYWORDS.any { combined.contains(it) }
    }

    private fun fetch_json_object(url: String): JSONObject? =
        fetch_json_object(url, user_agent)

    
    companion object {
        fun is_military_airport_name(name: String?, icao: String?): Boolean {
            val combined = listOfNotNull(name, icao).joinToString(" ").uppercase(Locale.US)
            if (combined.isBlank()) return false
            return MILITARY_AERODROME_KEYWORDS.any { combined.contains(it) }
        }

        private const val ORIGIN_AERODROME_RADIUS_M = 9000.0

        private val MILITARY_AERODROME_KEYWORDS = listOf(
            "AIR FORCE",
            "AFB",
            "NAVAL AIR",
            "NAVAL STATION",
            "NAS ",
            "JOINT BASE",
            "ARMY AIRFIELD",
            " AAF",
            "MARINE CORPS",
            "MCAS",
            "AIR NATIONAL GUARD",
            "COAST GUARD",
            "CGAS",
            "MILITARY",
            "DEFENCE",
            "DEFENSE"
        )
    }
}


class TraceOriginAirportResolver(private val user_agent: String) {
    fun resolve_origin_airport(point: TrackPoint): AirportDetails? {
        ORIGIN_SEARCH_RADII_M.forEach { radius_m ->
            val match = aerodromes_near(point, radius_m).minByOrNull { it.distance_m }
            if (match != null) return match.airport
        }
        return null
    }

    private fun aerodromes_near(point: TrackPoint, radius_m: Double): List<TraceOriginAirportCandidate> {
        val query = """
            [out:json][timeout:8];
            (
              node(around:${radius_m.toInt()},${point.lat},${point.lon})["aeroway"="aerodrome"];
              way(around:${radius_m.toInt()},${point.lat},${point.lon})["aeroway"="aerodrome"];
              relation(around:${radius_m.toInt()},${point.lat},${point.lon})["aeroway"="aerodrome"];
            );
            out center tags 30;
        """.trimIndent()
        val api_url = "https://overpass-api.de/api/interpreter?data=${URLEncoder.encode(query, "UTF-8")}"
        val elements = fetch_json_object(api_url)?.optJSONArray("elements") ?: return emptyList()
        val candidates = mutableListOf<TraceOriginAirportCandidate>()
        for (index in 0 until elements.length()) {
            val item = elements.optJSONObject(index) ?: continue
            val tags = item.optJSONObject("tags")
            val center = item.optJSONObject("center")
            val lat = if (item.has("lat")) item.optDouble("lat") else center?.optDouble("lat") ?: continue
            val lon = if (item.has("lon")) item.optDouble("lon") else center?.optDouble("lon") ?: continue
            val distance_m = MapProjection.distance_meters(point.lat, point.lon, lat, lon)
            if (distance_m > radius_m) continue
            val airport = airport_from_tags(tags, lat, lon) ?: continue
            candidates += TraceOriginAirportCandidate(airport, distance_m)
        }
        return candidates
    }

    private fun airport_from_tags(tags: JSONObject?, lat: Double, lon: Double): AirportDetails? {
        val name = tags?.trace_origin_json_clean_string("name") ?: tags?.trace_origin_json_clean_string("official_name")
        val icao = tags?.trace_origin_json_clean_string("icao")
        val iata = tags?.trace_origin_json_clean_string("iata")
        val display_code = listOfNotNull(icao, iata, name)
            .firstOrNull { it.isNotBlank() }
            ?: return null
        return AirportDetails(
            icao = display_code.uppercase(Locale.US),
            iata = iata,
            name = name,
            country_code = tags?.trace_origin_json_clean_string("addr:country") ?: tags?.trace_origin_json_clean_string("ISO3166-1"),
            region_name = tags?.trace_origin_json_clean_string("addr:state") ?: tags?.trace_origin_json_clean_string("is_in:state"),
            latitude = lat,
            longitude = lon
        )
    }

    private fun fetch_json_object(url: String): JSONObject? =
        fetch_json_object(url, user_agent)

    
    private data class TraceOriginAirportCandidate(
        val airport: AirportDetails,
        val distance_m: Double
    )

    private companion object {
        val ORIGIN_SEARCH_RADII_M = listOf(9000.0, 18000.0, 30000.0)
    }
}

private fun JSONObject.trace_origin_json_clean_string(key: String): String? {
    if (!has(key) || isNull(key)) return null
    return optString(key)
        .trim()
        .takeIf { it.isNotBlank() && !it.equals("n/a", ignoreCase = true) }
}

