    private val ticker = object : Runnable {
        // Android's frame clock calls this before each redraw. Fetch slowly, animate every frame.
        override fun run() {
            val now = SystemClock.elapsedRealtime()
            if (now - last_ticker_fetch_ms >= AIRCRAFT_TICKER_FETCH_MS) {
                last_ticker_fetch_ms = now
                request_visible_aircraft_if_needed()
            }
            publish_priority_notification_snapshot_if_due(now)
            if (should_redraw_from_ticker(now)) {
                if (debug_perf_viewport_active) {
                    debug_record_ticker_redraw_post(debug_ticker_redraw_reason)
                }
                postInvalidateOnAnimation()
            }
            postOnAnimation(this)
        }
    }
    private val save_zoom_preference = Runnable {
        persist_zoom_preference_if_dirty()
    }

    // Init the custom View settings Android needs before it can route keys, touches, and insets here.
    init {
        isFocusable = true
        isFocusableInTouchMode = true
        setBackgroundColor(map_empty_color)
        update_host_system_bars()
        apply_theme_typeface()
        stroke_paint.style = Paint.Style.STROKE
        setup_system_insets()
        globe_bin_craft_aircraft_source?.set_enabled(globe_bin_craft_source_enabled)
        globe_bin_craft_aircraft_source?.on_snapshot_updated = {
            publish_globe_snapshot_update_if_useful()
        }
    }

    // MainActivity calls this from onResume; live location and the frame ticker start here.
    fun start() {
        start_location_updates()
        removeCallbacks(ticker)
        update_debug_frame_metrics_probe_listener()
        postOnAnimation(ticker)
    }

    // MainActivity calls this from onPause; stop listeners that only matter while the map is visible.
    fun stop() {
        removeCallbacks(ticker)
        remove_debug_frame_metrics_probe_listener()
        persist_zoom_preference_if_dirty()
        if (location_permission_granted) {
            try {
                location_manager.removeUpdates(this)
            } catch (_: SecurityException) {
                location_permission_granted = false
            }
        }
    }

    private fun update_debug_frame_metrics_probe_listener() {
        if (!debug_perf_frame_metrics_probe) {
            remove_debug_frame_metrics_probe_listener()
            return
        }
        val window = (context as? Activity)?.window ?: return
        if (debug_frame_metrics_listener_registered_window === window) return
        remove_debug_frame_metrics_probe_listener()
        window.addOnFrameMetricsAvailableListener(debug_frame_metrics_listener, Handler(Looper.getMainLooper()))
        debug_frame_metrics_listener_registered_window = window
        debug_schedule_frame_metrics_choreographer_callback()
    }

    private fun debug_schedule_frame_metrics_choreographer_callback() {
        if (!debug_perf_frame_metrics_probe || debug_frame_metrics_frame_callback_registered) return
        Choreographer.getInstance().postFrameCallback(debug_frame_metrics_frame_callback)
        debug_frame_metrics_frame_callback_registered = true
    }

    private fun remove_debug_frame_metrics_probe_listener() {
        if (debug_frame_metrics_frame_callback_registered) {
            Choreographer.getInstance().removeFrameCallback(debug_frame_metrics_frame_callback)
            debug_frame_metrics_frame_callback_registered = false
        }
        removeCallbacks(debug_frame_metrics_log_runnable)
        debug_frame_metrics_log_pending = false
        debug_frame_metrics_latest_choreographer_vsync_ns = 0L
        val window = debug_frame_metrics_listener_registered_window ?: return
        try {
            window.removeOnFrameMetricsAvailableListener(debug_frame_metrics_listener)
        } catch (_: IllegalArgumentException) {
            // The listener may already be gone after Activity/window recreation.
        }
        debug_frame_metrics_listener_registered_window = null
    }

    private fun should_redraw_from_ticker(now_elapsed_ms: Long): Boolean {
        val reason = ticker_redraw_reason(now_elapsed_ms)
        debug_ticker_redraw_reason = reason
        return reason != DEBUG_TICKER_REDRAW_NONE
    }

    private fun ticker_redraw_reason(now_elapsed_ms: Long): Int {
        if (map_touch_active || pinch_in_progress || drag_started) {
            if (!debug_perf_viewport_active) return DEBUG_TICKER_REDRAW_INTERACTION_ONLY
            return if (ticker_motion_redraw_reason(now_elapsed_ms) == DEBUG_TICKER_REDRAW_NONE) {
                DEBUG_TICKER_REDRAW_INTERACTION_ONLY
            } else {
                DEBUG_TICKER_REDRAW_INTERACTION_MOTION
            }
        }
        if (has_active_aircraft_appearance(now_elapsed_ms)) return DEBUG_TICKER_REDRAW_APPEARANCE
        if (debug_perf_viewport_active && debug_perf_skip_traffic) return DEBUG_TICKER_REDRAW_NONE
        return ticker_motion_redraw_reason(now_elapsed_ms)
    }

    private fun ticker_motion_redraw_reason(now_elapsed_ms: Long): Int {
        val last_draw = last_traffic_draw_elapsed_ms
        if (last_draw <= 0L) return DEBUG_TICKER_REDRAW_FIRST_DRAW
        val elapsed_ms = now_elapsed_ms - last_draw
        if (elapsed_ms <= 0L) return DEBUG_TICKER_REDRAW_NONE
        if (elapsed_ms >= AIRCRAFT_MOTION_REDRAW_MAX_INTERVAL_MS) return DEBUG_TICKER_REDRAW_MAX_INTERVAL
        val viewport = current_interaction_viewport() ?: return DEBUG_TICKER_REDRAW_NONE
        if (viewport.zoom >= AIRCRAFT_MOTION_ALWAYS_ANIMATE_ZOOM) return DEBUG_TICKER_REDRAW_ALWAYS_ZOOM
        val max_speed_zoom_zero = cached_traffic().max_projected_speed_zoom_zero
        if (max_speed_zoom_zero <= 0.0 || !max_speed_zoom_zero.isFinite()) return DEBUG_TICKER_REDRAW_NONE
        val max_motion_px = max_speed_zoom_zero * 2.0.pow(viewport.zoom) * elapsed_ms / 1000.0
        return if (max_motion_px >= AIRCRAFT_MOTION_REDRAW_MIN_PIXEL_DELTA) {
            DEBUG_TICKER_REDRAW_MOTION_DELTA
        } else {
            DEBUG_TICKER_REDRAW_NONE
        }
    }

    private fun has_active_aircraft_appearance(now_elapsed_ms: Long): Boolean {
        synchronized(aircraft_appearances) {
            for (appearance in aircraft_appearances.values) {
                if (now_elapsed_ms - appearance.first_seen_ms < AIRCRAFT_APPEAR_DURATION_MS) return true
            }
        }
        return false
    }

    // MainActivity owns the Android permission popup; this view owns what the map does with the answer.
    fun set_location_permission_granted(granted: Boolean) {
        if (location_permission_granted == granted) return
        location_permission_granted = granted
        if (granted) {
            start_location_updates()
        } else {
            latest_location = null
            aircraft.clear()
            mark_traffic_cache_dirty()
            aircraft_status = "Location permission required"
            map_status = "Location permission required"
        }
        invalidate()
    }

    // Close the top-most map overlay first. If nothing is open, let Android handle Back normally.
    fun handle_back_press(): Boolean {
        if (details_session.photo_evidence_open) {
            details_session.close_photo_evidence()
            invalidate()
            return true
        }
        if (details_session.photo_gallery_open) {
            details_session.close_photo_gallery()
            invalidate()
            return true
        }
        if (priority_tracker_open) {
            priority_tracker_open = false
            invalidate()
            return true
        }
        if (filters_open) {
            filters_open = false
            clear_filter_search_focus()
            invalidate()
            return true
        }
        if (map_labels_open) {
            map_labels_open = false
            invalidate()
            return true
        }
        if (aviation_layers_open) {
            aviation_layers_open = false
            invalidate()
            return true
        }
        if (details_session.details_open) {
            if (details_session.environmental_impact_open) {
                details_session.environmental_impact_open = false
                invalidate()
                return true
            }
            if (details_session.usage_open) {
                details_session.usage_open = false
                invalidate()
                return true
            }
            details_session.close_details_shell()
            invalidate()
            return true
        }
        if (settings_open) {
            if (impact_methodology_open) {
                impact_methodology_open = false
                invalidate()
                return true
            }
            if (aviation_layers_open) {
                aviation_layers_open = false
                invalidate()
                return true
            }
            settings_open = false
            impact_methodology_open = false
            aviation_layers_open = false
            invalidate()
            return true
        }
        if (selected_path_controller.close_visible_path()) {
            invalidate()
            return true
        }
        if (!following_location && latest_location != null) {
            recenter_on_location()
            return true
        }
        return false
    }

    // Android's LocationManager calls this with the device's real location fix.
    override fun onLocationChanged(location: Location) {
        latest_location = location
        mark_traffic_cache_dirty()
        map_status = "Loading map"
        apply_initial_mavic_range_zoom_if_needed()
        request_visible_aircraft_if_needed(force = true)
        invalidate()
    }

    fun apply_debug_perf_viewport(
        lat: Double,
        lon: Double,
        target_zoom: Double,
        run_id: String? = null,
        perf_map_source: TileSource? = null,
        perf_map_labels_enabled: Boolean? = null,
        perf_map_roads_enabled: Boolean? = null,
        perf_map_borders_enabled: Boolean? = null,
        perf_restricted_airspaces_enabled: Boolean? = null,
        perf_clear_selection: Boolean = false,
        perf_focus_open_map: Boolean = false,
        perf_focus_x_fraction: Double? = null,
        perf_focus_y_fraction: Double? = null,
        perf_skip_map: Boolean = false,
        perf_skip_traffic: Boolean = false,
        perf_skip_chrome: Boolean = false,
        perf_skip_top_status: Boolean = false,
        perf_skip_controls: Boolean = false,
        perf_skip_traffic_panel: Boolean = false,
        perf_traffic_detail_timing: Boolean = false,
        perf_frame_metrics_probe: Boolean = false,
        perf_map_detail_timing: Boolean = false
    ) {
        if (!lat.isFinite() || !lon.isFinite() || !target_zoom.isFinite()) return
        zoom = target_zoom.coerceIn(MIN_ZOOM.toDouble(), MAX_ZOOM.toDouble())
        perf_map_source?.let { source ->
            if (map_source != source) {
                map_source = source
                map_tile_renderer.reset_transitions()
            }
        }
        perf_map_labels_enabled?.let { enabled ->
            if (map_labels_enabled != enabled) {
                map_labels_enabled = enabled
                map_tile_renderer.reset_transitions()
            }
        }
        perf_map_roads_enabled?.let { enabled ->
            if (map_labels_enabled != enabled) {
                map_labels_enabled = enabled
                map_tile_renderer.reset_transitions()
            }
        }
        perf_map_borders_enabled?.let { enabled ->
            if (map_borders_enabled != enabled) {
                map_borders_enabled = enabled
                map_tile_renderer.reset_transitions()
            }
        }
        perf_restricted_airspaces_enabled?.let { enabled ->
            if (restricted_airspaces_layer_enabled != enabled) {
                restricted_airspaces_layer_enabled = enabled
                aviation_layer_controller.on_visibility_changed(aviation_layer_visibility())
            }
        }
        if (perf_clear_selection) {
            details_session.close_details_shell()
            selected_path_controller.clear_selection()
            selected_path_controller.clear_trace()
            selected_restricted_airspace = null
        }
        following_location = false
        debug_perf_viewport_active = true
        debug_perf_skip_map = perf_skip_map
        debug_perf_skip_traffic = perf_skip_traffic
        debug_perf_skip_chrome = perf_skip_chrome
        debug_perf_skip_top_status = perf_skip_top_status
        debug_perf_skip_controls = perf_skip_controls
        debug_perf_skip_traffic_panel = perf_skip_traffic_panel
        debug_perf_traffic_detail_timing = perf_traffic_detail_timing
        debug_perf_frame_metrics_probe = perf_frame_metrics_probe
        map_tile_renderer.debug_collect_detail_timing = perf_map_detail_timing
        reset_debug_frame_metrics_probe()
        update_debug_frame_metrics_probe_listener()
        debug_perf_focus_open_map = perf_focus_open_map
        debug_perf_focus_applied = false
        debug_perf_focus_x_fraction = perf_focus_x_fraction?.takeIf { it.isFinite() }?.coerceIn(0.0, 1.0)
        debug_perf_focus_y_fraction = perf_focus_y_fraction?.takeIf { it.isFinite() }?.coerceIn(0.0, 1.0)
        debug_perf_target_lat = lat.coerceIn(-85.0, 85.0)
        debug_perf_target_lon = normalize_longitude(lon)
        reset_debug_draw_perf()
        manual_center_lat = debug_perf_target_lat
        manual_center_lon = debug_perf_target_lon
        apply_debug_perf_target_focus_if_needed()
        Log.i(
            TAG,
            "Debug perf viewport runId=${run_id ?: "none"} lat=$manual_center_lat lon=$manual_center_lon " +
                "zoom=$zoom mapSource=$map_source mapLabels=$map_labels_enabled mapBorders=$map_borders_enabled restrictedAirspaces=$restricted_airspaces_layer_enabled " +
                "targetLat=$debug_perf_target_lat targetLon=$debug_perf_target_lon focusOpenMap=$debug_perf_focus_open_map " +
                "focusXFraction=${debug_perf_focus_x_fraction ?: "layout"} focusYFraction=${debug_perf_focus_y_fraction ?: "layout"} " +
                "clearSelection=$perf_clear_selection skipMap=$debug_perf_skip_map " +
                "skipTraffic=$debug_perf_skip_traffic skipChrome=$debug_perf_skip_chrome " +
                "skipTopStatus=$debug_perf_skip_top_status skipControls=$debug_perf_skip_controls " +
                "skipTrafficPanel=$debug_perf_skip_traffic_panel " +
                "trafficDetailTiming=$debug_perf_traffic_detail_timing frameMetricsProbe=$debug_perf_frame_metrics_probe " +
                "mapDetailTiming=$perf_map_detail_timing"
        )
        mark_traffic_cache_dirty()
        map_status = "Loading map"
        if (latest_location != null) request_visible_aircraft_if_needed(force = true)
        postInvalidateOnAnimation()
    }

    private fun debug_record_ticker_redraw_post(reason: Int) {
        if (!debug_perf_viewport_active || reason == DEBUG_TICKER_REDRAW_NONE) return
        debug_pending_ticker_redraw_reason = reason
        debug_ticker_posts++
        when (reason) {
            DEBUG_TICKER_REDRAW_INTERACTION_ONLY -> debug_ticker_interaction_only_posts++
            DEBUG_TICKER_REDRAW_INTERACTION_MOTION -> debug_ticker_interaction_motion_posts++
            DEBUG_TICKER_REDRAW_APPEARANCE -> debug_ticker_appearance_posts++
            DEBUG_TICKER_REDRAW_FIRST_DRAW -> debug_ticker_first_draw_posts++
            DEBUG_TICKER_REDRAW_MAX_INTERVAL -> debug_ticker_max_interval_posts++
            DEBUG_TICKER_REDRAW_ALWAYS_ZOOM -> debug_ticker_always_zoom_posts++
            DEBUG_TICKER_REDRAW_MOTION_DELTA -> debug_ticker_motion_delta_posts++
        }
    }

    private fun debug_note_draw_start(viewport: Viewport, now_elapsed_ms: Long) {
        if (!debug_perf_viewport_active) return
        debug_current_draw_ticker_reason = DEBUG_TICKER_REDRAW_NONE
        debug_current_draw_same_camera_traffic = false
        val signature = debug_ticker_draw_signature(viewport, now_elapsed_ms)
        val pending_reason = debug_pending_ticker_redraw_reason
        if (pending_reason != DEBUG_TICKER_REDRAW_NONE) {
            debug_pending_ticker_redraw_reason = DEBUG_TICKER_REDRAW_NONE
            debug_current_draw_ticker_reason = pending_reason
            debug_ticker_draws++
            if (debug_last_draw_signature == signature) {
                debug_current_draw_same_camera_traffic = true
                debug_ticker_same_camera_traffic_draws++
                if (pending_reason == DEBUG_TICKER_REDRAW_INTERACTION_ONLY) {
                    debug_ticker_interaction_only_same_camera_traffic_draws++
                }
            }
        }
        debug_last_draw_signature = signature
    }

    private fun debug_ticker_draw_signature(viewport: Viewport, now_elapsed_ms: Long): DebugTickerDrawSignature {
        return DebugTickerDrawSignature(
            center_x_bits = java.lang.Double.doubleToLongBits(viewport.center_x),
            center_y_bits = java.lang.Double.doubleToLongBits(viewport.center_y),
            zoom_bits = java.lang.Double.doubleToLongBits(viewport.zoom),
            width_bits = java.lang.Float.floatToIntBits(viewport.width),
            height_bits = java.lang.Float.floatToIntBits(viewport.height),
            traffic_token = traffic_cache_rebuild_token,
            active_appearance = has_active_aircraft_appearance(now_elapsed_ms)
        )
    }

    private fun debug_ticker_summary(): String {
        if (debug_ticker_posts <= 0 && debug_ticker_draws <= 0) return ""
        val same_avg = if (debug_ticker_same_camera_traffic_draws > 0) {
            debug_ticker_same_camera_traffic_ns.ms(debug_ticker_same_camera_traffic_draws)
        } else {
            "0.00ms"
        }
        val same_interaction_avg = if (debug_ticker_interaction_only_same_camera_traffic_draws > 0) {
            debug_ticker_interaction_only_same_camera_traffic_ns.ms(debug_ticker_interaction_only_same_camera_traffic_draws)
        } else {
            "0.00ms"
        }
        return "tickerPosts=$debug_ticker_posts " +
            "iOnly=$debug_ticker_interaction_only_posts iMotion=$debug_ticker_interaction_motion_posts " +
            "appearance=$debug_ticker_appearance_posts first=$debug_ticker_first_draw_posts " +
            "maxInt=$debug_ticker_max_interval_posts alwaysZoom=$debug_ticker_always_zoom_posts " +
            "motionDelta=$debug_ticker_motion_delta_posts tickerDraws=$debug_ticker_draws " +
            "sameCameraTraffic=$debug_ticker_same_camera_traffic_draws sameCameraTrafficAvg=$same_avg " +
            "iOnlySameCameraTraffic=$debug_ticker_interaction_only_same_camera_traffic_draws " +
            "iOnlySameCameraTrafficAvg=$same_interaction_avg "
    }

    private fun debug_record_draw_perf(
        total_ns: Long,
        map_ns: Long,
        layer_request_ns: Long,
        layer_draw_ns: Long,
        path_ns: Long,
        traffic_ns: Long,
        chrome_ns: Long,
        draw_seq: Long,
        draw_start_elapsed_ms: Long,
        draw_start_ns: Long,
        draw_end_ns: Long,
        location: Location?
    ) {
        if (debug_draw_perf_frames == 0) {
            debug_draw_perf_first_seq = draw_seq
        }
        debug_draw_perf_frames++
        debug_draw_perf_last_seq = draw_seq
        debug_draw_perf_last_start_elapsed_ms = draw_start_elapsed_ms
        debug_draw_perf_last_start_ns = draw_start_ns
        debug_draw_perf_last_end_ns = draw_end_ns
        debug_draw_perf_last_interval_ms = if (debug_previous_draw_start_elapsed_ms > 0L && draw_start_elapsed_ms > 0L) {
            draw_start_elapsed_ms - debug_previous_draw_start_elapsed_ms
        } else {
            0L
        }
        if (draw_start_elapsed_ms > 0L) {
            debug_previous_draw_start_elapsed_ms = draw_start_elapsed_ms
        }
        debug_draw_perf_total_ns += total_ns
        debug_draw_perf_map_ns += map_ns
        debug_draw_perf_layer_request_ns += layer_request_ns
        debug_draw_perf_layer_draw_ns += layer_draw_ns
        debug_draw_perf_path_ns += path_ns
        debug_draw_perf_traffic_ns += traffic_ns
        debug_draw_perf_chrome_ns += chrome_ns
        if (debug_current_draw_same_camera_traffic) {
            debug_ticker_same_camera_traffic_ns += traffic_ns
            if (debug_current_draw_ticker_reason == DEBUG_TICKER_REDRAW_INTERACTION_ONLY) {
                debug_ticker_interaction_only_same_camera_traffic_ns += traffic_ns
            }
        }
        if (total_ns >= debug_draw_perf_max_ns) {
            debug_draw_perf_max_ns = total_ns
            debug_draw_perf_max_detail_summary = debug_current_draw_detail_summary()
        }
        if (debug_draw_perf_frames >= DEBUG_DRAW_PERF_LOG_INTERVAL || total_ns >= DEBUG_DRAW_PERF_SLOW_NS) {
            debug_log_draw_perf(total_ns, map_ns, layer_request_ns, layer_draw_ns, path_ns, traffic_ns, chrome_ns, location)
            reset_debug_draw_perf()
        }
    }

    private fun debug_log_draw_perf(
        total_ns: Long,
        map_ns: Long,
        layer_request_ns: Long,
        layer_draw_ns: Long,
        path_ns: Long,
        traffic_ns: Long,
        chrome_ns: Long,
        location: Location?
    ) {
        val frames = debug_draw_perf_frames.coerceAtLeast(1)
        val traffic_detail_summary = traffic_overlay_renderer.debug_last_detail_timing_summary
        Log.d(
            TAG,
            "Debug draw perf frames=$frames " +
                "avg=${debug_draw_perf_total_ns.ms(frames)} max=${debug_draw_perf_max_ns.ms()} " +
                "map=${debug_draw_perf_map_ns.ms(frames)} layerReq=${debug_draw_perf_layer_request_ns.ms(frames)} " +
                "layerDraw=${debug_draw_perf_layer_draw_ns.ms(frames)} path=${debug_draw_perf_path_ns.ms(frames)} " +
                "traffic=${debug_draw_perf_traffic_ns.ms(frames)} chrome=${debug_draw_perf_chrome_ns.ms(frames)} " +
                "last=${total_ns.ms()} lastMap=${map_ns.ms()} lastLayerReq=${layer_request_ns.ms()} " +
                "lastLayerDraw=${layer_draw_ns.ms()} lastPath=${path_ns.ms()} lastTraffic=${traffic_ns.ms()} lastChrome=${chrome_ns.ms()}" +
                " drawSeqFirst=$debug_draw_perf_first_seq drawSeq=$debug_draw_perf_last_seq " +
                "drawStartMs=$debug_draw_perf_last_start_elapsed_ms drawStartNs=$debug_draw_perf_last_start_ns " +
                "drawEndNs=$debug_draw_perf_last_end_ns drawIntervalMs=$debug_draw_perf_last_interval_ms drawPasses=$frames " +
                "sameCameraLast=${if (debug_current_draw_same_camera_traffic) 1 else 0} " +
                debug_perf_camera_summary(location) +
                " symbols=$debug_last_traffic_symbol_count dots=$debug_last_traffic_dot_count " +
                debug_last_traffic_state_build_summary +
                debug_ticker_summary() +
                map_tile_renderer.debug_last_tile_summary +
                traffic_overlay_renderer.debug_last_symbol_cache_summary +
                " maxFrameDetail=${debug_draw_perf_max_detail_summary}"
        )
        if (traffic_detail_summary.isNotBlank()) {
            Log.d(
                TAG,
                "Debug draw perf detailBlock=traffic frames=$frames" +
                    traffic_detail_summary
            )
        }
    }

    private fun debug_current_draw_detail_summary(): String {
        return "symbols=$debug_last_traffic_symbol_count dots=$debug_last_traffic_dot_count " +
            debug_last_traffic_state_build_summary +
            map_tile_renderer.debug_last_tile_summary +
            traffic_overlay_renderer.debug_last_symbol_cache_summary +
            traffic_overlay_renderer.debug_last_detail_timing_summary
    }

    private fun debug_perf_camera_summary(location: Location?): String {
        val center_lat = location?.let { viewport_center_lat(it) } ?: manual_center_lat
        val center_lon = location?.let { viewport_center_lon(it) } ?: manual_center_lon
        val focus_geo = debug_perf_focus_geo(location)
        return " camera centerLat=${center_lat?.format_lat_lon() ?: "none"}" +
            " centerLon=${center_lon?.format_lat_lon() ?: "none"}" +
            " focusLat=${focus_geo?.lat?.format_lat_lon() ?: "none"}" +
            " focusLon=${focus_geo?.lon?.format_lat_lon() ?: "none"}" +
            " targetLat=${debug_perf_target_lat?.format_lat_lon() ?: "none"}" +
            " targetLon=${debug_perf_target_lon?.format_lat_lon() ?: "none"}" +
            " follow=$following_location manual=${manual_center_lat != null && manual_center_lon != null} zoom=${"%.3f".format(Locale.US, zoom)}"
    }

    private fun debug_perf_focus_geo(location: Location?): GeoPoint? {
        val focus = debug_perf_focus_point(content_width(), content_height()) ?: return null
        val viewport = location?.let { viewport_for(it, content_width(), content_height()) } ?: current_interaction_viewport() ?: return null
        return world_to_lat_lon(
            viewport.center_x - viewport.width / 2.0 + focus.x,
            viewport.center_y - viewport.height / 2.0 + focus.y,
            viewport.zoom
        )
    }

    private fun Double.format_lat_lon(): String = "%.5f".format(Locale.US, this)

    private fun reset_debug_draw_perf() {
        debug_draw_perf_frames = 0
        debug_draw_perf_total_ns = 0L
        debug_draw_perf_map_ns = 0L
        debug_draw_perf_layer_request_ns = 0L
        debug_draw_perf_layer_draw_ns = 0L
        debug_draw_perf_path_ns = 0L
        debug_draw_perf_traffic_ns = 0L
        debug_draw_perf_chrome_ns = 0L
        debug_draw_perf_max_ns = 0L
        debug_draw_perf_max_detail_summary = ""
        debug_draw_perf_first_seq = 0L
        debug_draw_perf_last_seq = 0L
        debug_draw_perf_last_start_elapsed_ms = 0L
        debug_draw_perf_last_start_ns = 0L
        debug_draw_perf_last_end_ns = 0L
        debug_draw_perf_last_interval_ms = 0L
        debug_ticker_posts = 0
        debug_ticker_interaction_only_posts = 0
        debug_ticker_interaction_motion_posts = 0
        debug_ticker_appearance_posts = 0
        debug_ticker_first_draw_posts = 0
        debug_ticker_max_interval_posts = 0
        debug_ticker_always_zoom_posts = 0
        debug_ticker_motion_delta_posts = 0
        debug_ticker_draws = 0
        debug_ticker_same_camera_traffic_draws = 0
        debug_ticker_interaction_only_same_camera_traffic_draws = 0
        debug_ticker_same_camera_traffic_ns = 0L
        debug_ticker_interaction_only_same_camera_traffic_ns = 0L
    }

    private fun debug_frame_metrics_probe_frame_time_ns(): Long {
        if (!debug_perf_frame_metrics_probe) return 0L
        return debug_frame_metrics_latest_choreographer_vsync_ns
    }

    private fun debug_record_frame_metrics_direct_sample() {
        if (!debug_perf_frame_metrics_probe || !debug_perf_traffic_detail_timing) return
        val vsync_ns = debug_current_frame_metrics_vsync_ns
        if (vsync_ns <= 0L) return
        val index = debug_frame_metrics_write_index
        debug_frame_metrics_write_index = (debug_frame_metrics_write_index + 1) % DEBUG_FRAME_METRICS_PROBE_RING_SIZE
        debug_frame_metrics_vsync_ns[index] = vsync_ns
        debug_frame_metrics_draw_seq[index] = debug_draw_sequence
        debug_frame_metrics_direct_symbols_ns[index] = traffic_overlay_renderer.debug_frame_metrics_direct_symbols_ns
        debug_frame_metrics_direct_icon_ns[index] = traffic_overlay_renderer.debug_frame_metrics_direct_icon_ns
        debug_frame_metrics_direct_drawn[index] = traffic_overlay_renderer.debug_frame_metrics_direct_drawn_count
    }

    private fun debug_record_frame_metrics_probe_frame(frame_metrics: FrameMetrics, drop_count_since_last_invocation: Int) {
        if (!debug_perf_frame_metrics_probe) return
        if (debug_frame_metrics_log_pending) return
        debug_frame_metrics_callbacks++
        debug_frame_metrics_dropped += drop_count_since_last_invocation.coerceAtLeast(0)
        val vsync_ns = frame_metrics.getMetric(FrameMetrics.VSYNC_TIMESTAMP)
        val index = debug_find_frame_metrics_sample_slot(vsync_ns)
        if (index < 0) {
            debug_frame_metrics_missed++
            return
        }
        val direct_symbols_ns = debug_frame_metrics_direct_symbols_ns[index]
        val direct_icon_ns = debug_frame_metrics_direct_icon_ns[index]
        val direct_drawn = debug_frame_metrics_direct_drawn[index]
        debug_frame_metrics_vsync_ns[index] = 0L
        debug_frame_metrics_joined++
        val draw_ns = debug_non_negative_frame_metric(frame_metrics, FrameMetrics.DRAW_DURATION)
        val sync_ns = debug_non_negative_frame_metric(frame_metrics, FrameMetrics.SYNC_DURATION)
        val command_ns = debug_non_negative_frame_metric(frame_metrics, FrameMetrics.COMMAND_ISSUE_DURATION)
        val swap_ns = debug_non_negative_frame_metric(frame_metrics, FrameMetrics.SWAP_BUFFERS_DURATION)
        val gpu_ns = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            debug_non_negative_frame_metric(frame_metrics, FrameMetrics.GPU_DURATION)
        } else {
            0L
        }
        val total_ns = debug_non_negative_frame_metric(frame_metrics, FrameMetrics.TOTAL_DURATION)
        debug_frame_metrics_sum_draw_ns += draw_ns
        debug_frame_metrics_sum_sync_ns += sync_ns
        debug_frame_metrics_sum_command_ns += command_ns
        debug_frame_metrics_sum_swap_ns += swap_ns
        debug_frame_metrics_sum_gpu_ns += gpu_ns
        debug_frame_metrics_sum_total_ns += total_ns
        debug_frame_metrics_sum_direct_symbols_ns += direct_symbols_ns
        debug_frame_metrics_sum_direct_icon_ns += direct_icon_ns
        debug_frame_metrics_sum_direct_drawn += direct_drawn.toLong()
        debug_frame_metrics_max_total_ns = max(debug_frame_metrics_max_total_ns, total_ns)
        debug_frame_metrics_max_command_ns = max(debug_frame_metrics_max_command_ns, command_ns)
        debug_frame_metrics_max_gpu_ns = max(debug_frame_metrics_max_gpu_ns, gpu_ns)
        debug_frame_metrics_max_direct_symbols_ns = max(debug_frame_metrics_max_direct_symbols_ns, direct_symbols_ns)
        debug_record_frame_metrics_correlation_sample(
            direct_symbols_ns = direct_symbols_ns,
            direct_icon_ns = direct_icon_ns,
            command_ns = command_ns,
            gpu_ns = gpu_ns
        )
        debug_schedule_frame_metrics_probe_log_if_ready()
    }

    private fun debug_find_frame_metrics_sample_slot(vsync_ns: Long): Int {
        if (vsync_ns <= 0L) return -1
        for (index in debug_frame_metrics_vsync_ns.indices) {
            if (debug_frame_metrics_vsync_ns[index] == vsync_ns) return index
        }
        return -1
    }

    private fun debug_non_negative_frame_metric(frame_metrics: FrameMetrics, metric: Int): Long {
        return frame_metrics.getMetric(metric).coerceAtLeast(0L)
    }

    private fun debug_schedule_frame_metrics_probe_log_if_ready() {
        if (debug_frame_metrics_joined < DEBUG_FRAME_METRICS_PROBE_LOG_INTERVAL || debug_frame_metrics_log_pending) {
            return
        }
        debug_frame_metrics_log_pending = true
        post(debug_frame_metrics_log_runnable)
    }

    private fun debug_record_frame_metrics_correlation_sample(
        direct_symbols_ns: Long,
        direct_icon_ns: Long,
        command_ns: Long,
        gpu_ns: Long
    ) {
        val index = debug_frame_metrics_sample_count
        if (index >= DEBUG_FRAME_METRICS_PROBE_LOG_INTERVAL) return
        debug_frame_metrics_sample_direct_symbols_ns[index] = direct_symbols_ns
        debug_frame_metrics_sample_direct_icon_ns[index] = direct_icon_ns
        debug_frame_metrics_sample_command_ns[index] = command_ns
        debug_frame_metrics_sample_gpu_ns[index] = gpu_ns
        debug_frame_metrics_sample_count = index + 1
    }

    private fun debug_log_frame_metrics_probe_if_ready() {
        val frames = debug_frame_metrics_joined
        if (frames < DEBUG_FRAME_METRICS_PROBE_LOG_INTERVAL) return
        val sample_count = debug_frame_metrics_sample_count
        val fm_direct_cmd_r = debug_frame_metrics_pearson(
            debug_frame_metrics_sample_direct_symbols_ns,
            debug_frame_metrics_sample_command_ns,
            sample_count
        )
        val fm_direct_gpu_r = debug_frame_metrics_pearson(
            debug_frame_metrics_sample_direct_symbols_ns,
            debug_frame_metrics_sample_gpu_ns,
            sample_count
        )
        val fm_icon_cmd_r = debug_frame_metrics_pearson(
            debug_frame_metrics_sample_direct_icon_ns,
            debug_frame_metrics_sample_command_ns,
            sample_count
        )
        val fm_icon_gpu_r = debug_frame_metrics_pearson(
            debug_frame_metrics_sample_direct_icon_ns,
            debug_frame_metrics_sample_gpu_ns,
            sample_count
        )
        val fm_direct_cmd_rho = debug_frame_metrics_spearman(
            debug_frame_metrics_sample_direct_symbols_ns,
            debug_frame_metrics_sample_command_ns,
            sample_count
        )
        val fm_direct_gpu_rho = debug_frame_metrics_spearman(
            debug_frame_metrics_sample_direct_symbols_ns,
            debug_frame_metrics_sample_gpu_ns,
            sample_count
        )
        val fm_icon_cmd_rho = debug_frame_metrics_spearman(
            debug_frame_metrics_sample_direct_icon_ns,
            debug_frame_metrics_sample_command_ns,
            sample_count
        )
        val fm_icon_gpu_rho = debug_frame_metrics_spearman(
            debug_frame_metrics_sample_direct_icon_ns,
            debug_frame_metrics_sample_gpu_ns,
            sample_count
        )
        val fm_cmd_slow_direct_lift_ns = debug_frame_metrics_slow_quartile_lift(
            debug_frame_metrics_sample_command_ns,
            debug_frame_metrics_sample_direct_symbols_ns,
            sample_count
        )
        val fm_gpu_slow_direct_lift_ns = debug_frame_metrics_slow_quartile_lift(
            debug_frame_metrics_sample_gpu_ns,
            debug_frame_metrics_sample_direct_symbols_ns,
            sample_count
        )
        val fm_cmd_slow_icon_lift_ns = debug_frame_metrics_slow_quartile_lift(
            debug_frame_metrics_sample_command_ns,
            debug_frame_metrics_sample_direct_icon_ns,
            sample_count
        )
        val fm_gpu_slow_icon_lift_ns = debug_frame_metrics_slow_quartile_lift(
            debug_frame_metrics_sample_gpu_ns,
            debug_frame_metrics_sample_direct_icon_ns,
            sample_count
        )
        Log.d(
            TAG,
            "Debug draw perf detailBlock=frameMetrics frames=$frames " +
                "fmCallbacks=$debug_frame_metrics_callbacks fmJoined=$debug_frame_metrics_joined " +
                "fmMissed=$debug_frame_metrics_missed fmDropped=$debug_frame_metrics_dropped " +
                "fmDraw=${debug_frame_metrics_sum_draw_ns.ms(frames)} " +
                "fmSync=${debug_frame_metrics_sum_sync_ns.ms(frames)} " +
                "fmCommandIssue=${debug_frame_metrics_sum_command_ns.ms(frames)} " +
                "fmSwapBuffers=${debug_frame_metrics_sum_swap_ns.ms(frames)} " +
                "fmGpu=${debug_frame_metrics_sum_gpu_ns.ms(frames)} " +
                "fmTotal=${debug_frame_metrics_sum_total_ns.ms(frames)} " +
                "fmMaxTotal=${debug_frame_metrics_max_total_ns.ms()} " +
                "fmMaxCommandIssue=${debug_frame_metrics_max_command_ns.ms()} " +
                "fmMaxGpu=${debug_frame_metrics_max_gpu_ns.ms()} " +
                "fmDirectSymbols=${debug_frame_metrics_sum_direct_symbols_ns.ms(frames)} " +
                "fmDirectIcon=${debug_frame_metrics_sum_direct_icon_ns.ms(frames)} " +
                "fmDirectDrawn=${debug_frame_metrics_sum_direct_drawn / frames} " +
                "fmMaxDirectSymbols=${debug_frame_metrics_max_direct_symbols_ns.ms()} " +
                "fmSamples=$sample_count " +
                "fmDirectCmdR=${fm_direct_cmd_r.fm_decimal()} " +
                "fmDirectGpuR=${fm_direct_gpu_r.fm_decimal()} " +
                "fmIconCmdR=${fm_icon_cmd_r.fm_decimal()} " +
                "fmIconGpuR=${fm_icon_gpu_r.fm_decimal()} " +
                "fmDirectCmdRho=${fm_direct_cmd_rho.fm_decimal()} " +
                "fmDirectGpuRho=${fm_direct_gpu_rho.fm_decimal()} " +
                "fmIconCmdRho=${fm_icon_cmd_rho.fm_decimal()} " +
                "fmIconGpuRho=${fm_icon_gpu_rho.fm_decimal()} " +
                "fmCmdSlowDirectLift=${fm_cmd_slow_direct_lift_ns.ms()} " +
                "fmGpuSlowDirectLift=${fm_gpu_slow_direct_lift_ns.ms()} " +
                "fmCmdSlowIconLift=${fm_cmd_slow_icon_lift_ns.ms()} " +
                "fmGpuSlowIconLift=${fm_gpu_slow_icon_lift_ns.ms()}"
        )
        reset_debug_frame_metrics_probe_counters()
    }

    private fun debug_frame_metrics_pearson(x_values: LongArray, y_values: LongArray, count: Int): Double {
        if (count < 2) return 0.0
        var sum_x = 0.0
        var sum_y = 0.0
        var sum_xx = 0.0
        var sum_yy = 0.0
        var sum_xy = 0.0
        for (index in 0 until count) {
            val x = x_values[index].toDouble()
            val y = y_values[index].toDouble()
            sum_x += x
            sum_y += y
            sum_xx += x * x
            sum_yy += y * y
            sum_xy += x * y
        }
        val n = count.toDouble()
        val denom = sqrt((n * sum_xx - sum_x * sum_x) * (n * sum_yy - sum_y * sum_y))
        if (denom <= 0.0 || !denom.isFinite()) return 0.0
        return ((n * sum_xy - sum_x * sum_y) / denom).coerceIn(-1.0, 1.0)
    }

    private fun debug_frame_metrics_spearman(x_values: LongArray, y_values: LongArray, count: Int): Double {
        if (count < 2) return 0.0
        var sum_x = 0.0
        var sum_y = 0.0
        var sum_xx = 0.0
        var sum_yy = 0.0
        var sum_xy = 0.0
        for (index in 0 until count) {
            val x_rank = debug_frame_metrics_rank(x_values, count, x_values[index])
            val y_rank = debug_frame_metrics_rank(y_values, count, y_values[index])
            sum_x += x_rank
            sum_y += y_rank
            sum_xx += x_rank * x_rank
            sum_yy += y_rank * y_rank
            sum_xy += x_rank * y_rank
        }
        val n = count.toDouble()
        val denom = sqrt((n * sum_xx - sum_x * sum_x) * (n * sum_yy - sum_y * sum_y))
        if (denom <= 0.0 || !denom.isFinite()) return 0.0
        return ((n * sum_xy - sum_x * sum_y) / denom).coerceIn(-1.0, 1.0)
    }

    private fun debug_frame_metrics_rank(values: LongArray, count: Int, value: Long): Double {
        var less = 0
        var equal = 0
        for (index in 0 until count) {
            val current = values[index]
            if (current < value) {
                less++
            } else if (current == value) {
                equal++
            }
        }
        return less + (equal + 1) / 2.0
    }

    private fun debug_frame_metrics_slow_quartile_lift(
        slow_values: LongArray,
        measured_values: LongArray,
        count: Int
    ): Long {
        if (count < 4) return 0L
        val slow_count = (count / 4).coerceAtLeast(1)
        var slow_sum = 0L
        var actual_slow_count = 0
        var rest_sum = 0L
        var rest_count = 0
        for (index in 0 until count) {
            val rank = debug_frame_metrics_descending_rank(slow_values, count, slow_values[index])
            if (rank <= slow_count) {
                slow_sum += measured_values[index]
                actual_slow_count++
            } else {
                rest_sum += measured_values[index]
                rest_count++
            }
        }
        if (actual_slow_count <= 0 || rest_count <= 0) return 0L
        return (slow_sum / actual_slow_count - rest_sum / rest_count).coerceAtLeast(0L)
    }

    private fun debug_frame_metrics_descending_rank(values: LongArray, count: Int, value: Long): Int {
        var greater = 0
        for (index in 0 until count) {
            if (values[index] > value) greater++
        }
        return greater + 1
    }

    private fun Double.fm_decimal(): String {
        return String.format(Locale.US, "%.3f", this)
    }

    private fun reset_debug_frame_metrics_probe() {
        debug_frame_metrics_vsync_ns.fill(0L)
        debug_frame_metrics_draw_seq.fill(0L)
        debug_frame_metrics_direct_symbols_ns.fill(0L)
        debug_frame_metrics_direct_icon_ns.fill(0L)
        debug_frame_metrics_direct_drawn.fill(0)
        debug_frame_metrics_sample_direct_symbols_ns.fill(0L)
        debug_frame_metrics_sample_direct_icon_ns.fill(0L)
        debug_frame_metrics_sample_command_ns.fill(0L)
        debug_frame_metrics_sample_gpu_ns.fill(0L)
        debug_frame_metrics_sample_count = 0
        removeCallbacks(debug_frame_metrics_log_runnable)
        debug_frame_metrics_log_pending = false
        debug_frame_metrics_write_index = 0
        debug_current_frame_metrics_vsync_ns = 0L
        reset_debug_frame_metrics_probe_counters()
    }

    private fun reset_debug_frame_metrics_probe_counters() {
        debug_frame_metrics_callbacks = 0
        debug_frame_metrics_joined = 0
        debug_frame_metrics_missed = 0
        debug_frame_metrics_dropped = 0
        debug_frame_metrics_sum_draw_ns = 0L
        debug_frame_metrics_sum_sync_ns = 0L
        debug_frame_metrics_sum_command_ns = 0L
        debug_frame_metrics_sum_swap_ns = 0L
        debug_frame_metrics_sum_gpu_ns = 0L
        debug_frame_metrics_sum_total_ns = 0L
        debug_frame_metrics_sum_direct_symbols_ns = 0L
        debug_frame_metrics_sum_direct_icon_ns = 0L
        debug_frame_metrics_sum_direct_drawn = 0L
        debug_frame_metrics_max_total_ns = 0L
        debug_frame_metrics_max_command_ns = 0L
        debug_frame_metrics_max_gpu_ns = 0L
        debug_frame_metrics_max_direct_symbols_ns = 0L
        debug_frame_metrics_sample_count = 0
        debug_frame_metrics_log_pending = false
    }

    private fun Long.ms(divisor: Int = 1): String {
        val value = if (divisor <= 1) this / 1_000_000.0 else this / divisor / 1_000_000.0
        return "%.2fms".format(Locale.US, value)
    }


    override fun onProviderEnabled(provider: String) = start_location_updates()

    override fun onProviderDisabled(provider: String) {
        if (latest_location == null) {
            map_status = "Enable device location"
            aircraft_status = "Enable device location"
            invalidate()
        }
    }

    // Android calls this after rotations, folds, and resizes. Refit the map to the new screen.
    override fun onSizeChanged(w: Int, h: Int, oldw: Int, oldh: Int) {
        super.onSizeChanged(w, h, oldw, oldh)
        apply_initial_mavic_range_zoom_if_needed()
        apply_debug_perf_target_focus_if_needed()
        request_deferred_aircraft_refresh()
    }

    // Android calls this whenever the View is invalidated. Draw the whole cockpit in one ordered pass.
    override fun onDraw(canvas: Canvas) {
        super.onDraw(canvas)
        paint.style = Paint.Style.FILL
        paint.color = theme_colors.system_bar
        canvas.drawRect(0f, 0f, width.toFloat(), height.toFloat(), paint)

        // Draw and hit-test inside system-bar-safe content so Android chrome never covers controls.
        val w = content_width()
        val h = content_height()
        val location = latest_location
        val modal_open = details_session.details_open || settings_open || priority_tracker_open || filters_open || selected_restricted_airspace != null
        val debug_draw_seq = if (debug_perf_viewport_active) {
            debug_draw_sequence = if (debug_draw_sequence == Long.MAX_VALUE) 1L else debug_draw_sequence + 1L
            debug_draw_sequence
        } else {
            0L
        }
        val debug_draw_trace_start_elapsed_ms = if (debug_perf_viewport_active) SystemClock.elapsedRealtime() else 0L
        val debug_draw_trace_start_ns = if (debug_perf_viewport_active) SystemClock.elapsedRealtimeNanos() else 0L
        val debug_current_vsync_ns = debug_frame_metrics_probe_frame_time_ns()
        debug_current_frame_metrics_vsync_ns = debug_current_vsync_ns

        try {
            debug_trace_frame(debug_perf_viewport_active, debug_draw_seq) {
                canvas.withTranslation(safe_inset_left, safe_inset_top) {
                clipRect(0f, 0f, w, h)
                paint.color = map_empty_color
                drawRect(0f, 0f, w, h, paint)
                var debug_draw_start_ns = 0L
                var debug_map_ns = 0L
                var debug_layer_request_ns = 0L
                var debug_layer_draw_ns = 0L
                var debug_path_ns = 0L
                var debug_traffic_ns = 0L

                if (location == null) {
                    draw_no_location_state(this, w, h)
                } else {
                    val viewport = viewport_for(location, w, h)
                    if (debug_perf_viewport_active) {
                        debug_note_draw_start(viewport, SystemClock.elapsedRealtime())
                        debug_draw_start_ns = SystemClock.elapsedRealtimeNanos()
                        var section_start_ns = debug_draw_start_ns
                        if (!debug_perf_skip_map) {
                            debug_trace_section(debug_perf_viewport_active, DEBUG_TRACE_MAP_DRAW) {
                                draw_map_tiles(this, viewport)
                            }
                        }
                        debug_map_ns = SystemClock.elapsedRealtimeNanos() - section_start_ns
                        section_start_ns = SystemClock.elapsedRealtimeNanos()
                        request_aviation_layers_if_needed(viewport)
                        debug_layer_request_ns = SystemClock.elapsedRealtimeNanos() - section_start_ns
                        section_start_ns = SystemClock.elapsedRealtimeNanos()
                        draw_aviation_layers(this, viewport)
                        debug_layer_draw_ns = SystemClock.elapsedRealtimeNanos() - section_start_ns
                        section_start_ns = SystemClock.elapsedRealtimeNanos()
                        draw_priority_range_circle(this, viewport, location)
                        draw_selected_flight_path(this, viewport)
                        debug_path_ns = SystemClock.elapsedRealtimeNanos() - section_start_ns
                        section_start_ns = SystemClock.elapsedRealtimeNanos()
                        if (!debug_perf_skip_traffic) {
                            debug_trace_section(debug_perf_viewport_active, DEBUG_TRACE_TRAFFIC_OVERLAY) {
                                draw_traffic_overlay(this, viewport)
                            }
                        }
                        debug_traffic_ns = SystemClock.elapsedRealtimeNanos() - section_start_ns
                        if (!debug_perf_skip_traffic) {
                            draw_ownship_overlay(this, viewport, location)
                        }
                    } else {
                        draw_map_tiles(this, viewport)
                        request_aviation_layers_if_needed(viewport)
                        draw_aviation_layers(this, viewport)
                        draw_priority_range_circle(this, viewport, location)
                        draw_selected_flight_path(this, viewport)
                        draw_traffic_overlay(this, viewport)
                        draw_ownship_overlay(this, viewport, location)
                    }
                }

                val chrome_start_ns = if (debug_perf_viewport_active) SystemClock.elapsedRealtimeNanos() else 0L
                if (debug_perf_viewport_active && debug_perf_skip_chrome) {
                    // Debug perf mask only; normal app launches never suppress visible chrome.
                } else if (!modal_open) {
                    if (!debug_perf_skips_top_status()) {
                        draw_top_status(this, w, h)
                    }
                    if (!debug_perf_skips_controls()) {
                        // Draw the always-available map controls after the map layers.
                        draw_recenter_button(this, w, h)
                        location?.let { draw_flight_path_buttons(this, viewport_for(it, w, h), w, h) }
                        draw_settings_button(this, w, h)
                        draw_filters_button(this, w, h)
                    }
                    if (!debug_perf_skips_traffic_panel()) {
                        draw_traffic_panel(this, w, h)
                    }
                } else {
                    draw_modal_backdrop(this, w, h)
                }
                selected_restricted_airspace?.let {
                    draw_restricted_airspace_details_panel(this, w, h, it)
                }
                if (details_session.details_open) {
                    // Draw only the open overlay branch so the visible panel matches the current state object.
                    draw_aircraft_details_panel(this, w, h)
                }
                if (settings_open) {
                    if (map_labels_open) {
                        draw_map_labels_panel(this, w, h)
                    } else if (aviation_layers_open) {
                        draw_aviation_layers_panel(this, w, h)
                    } else if (impact_methodology_open) {
                        draw_impact_methodology_panel(this, w, h)
                    } else {
                        draw_settings_panel(this, w, h)
                    }
                }
                if (priority_tracker_open) {
                    draw_priority_tracker_panel(this, w, h)
                }
                if (filters_open) {
                    draw_filters_panel(this, w, h)
                }
                if (debug_perf_viewport_active && debug_draw_start_ns > 0L) {
                    val debug_draw_end_ns = SystemClock.elapsedRealtimeNanos()
                    val chrome_ns = debug_draw_end_ns - chrome_start_ns
                    debug_record_draw_perf(
                        total_ns = debug_draw_end_ns - debug_draw_start_ns,
                        map_ns = debug_map_ns,
                        layer_request_ns = debug_layer_request_ns,
                        layer_draw_ns = debug_layer_draw_ns,
                        path_ns = debug_path_ns,
                        traffic_ns = debug_traffic_ns,
                        chrome_ns = chrome_ns,
                        draw_seq = debug_draw_seq,
                        draw_start_elapsed_ms = debug_draw_trace_start_elapsed_ms,
                        draw_start_ns = debug_draw_trace_start_ns,
                        draw_end_ns = debug_draw_end_ns,
                        location = location
                    )
                }
                }
            }
        } finally {
            if (debug_current_frame_metrics_vsync_ns == debug_current_vsync_ns) {
                debug_current_frame_metrics_vsync_ns = 0L
            }
        }
    }

    // Android sends every touch here. Convert through safe insets, then route to pinch, drag, or tap.
    override fun onTouchEvent(event: MotionEvent): Boolean {
        val x = content_x(event.x)
        val y = content_y(event.y)
        if (
            debug_perf_viewport_active &&
            (event.actionMasked == MotionEvent.ACTION_DOWN ||
                event.actionMasked == MotionEvent.ACTION_POINTER_DOWN ||
                event.actionMasked == MotionEvent.ACTION_UP ||
                event.actionMasked == MotionEvent.ACTION_POINTER_UP ||
                event.actionMasked == MotionEvent.ACTION_CANCEL)
        ) {
            Log.d(
                TAG,
                "Debug perf touch action=${event.actionMasked} x=$x y=$y pointers=${event.pointerCount} " +
                    "details=${details_session.details_open} settings=$settings_open latestLocation=${latest_location != null} " +
                    "manualCenter=${manual_center_lat != null && manual_center_lon != null}"
            )
        }
        if (!map_gesture_blocked_by_overlay() && event.pointerCount >= 2) {
            parent?.requestDisallowInterceptTouchEvent(true)
            when (event.actionMasked) {
                MotionEvent.ACTION_POINTER_DOWN -> begin_pinch(event)
                MotionEvent.ACTION_MOVE -> update_pinch(event)
                MotionEvent.ACTION_POINTER_UP,
                MotionEvent.ACTION_UP,
                MotionEvent.ACTION_CANCEL -> end_pinch()
            }
            return true
        }
        if (pinch_in_progress) {
            end_pinch()
            return true
        }
        if (priority_adjust_hold != null && event.pointerCount > 1) {
            cancel_priority_adjust_hold()
        }

        when (event.actionMasked) {
            MotionEvent.ACTION_DOWN -> {
                parent?.requestDisallowInterceptTouchEvent(true)
                val map_blocked = map_gesture_blocked_by_overlay()
                val control_hit = is_overlay_or_control_hit(x, y)
                map_touch_active = !map_blocked && !control_hit
                if (debug_perf_viewport_active) {
                    Log.d(
                        TAG,
                        "Debug perf touch down route x=$x y=$y mapBlocked=$map_blocked " +
                            "controlHit=$control_hit mapTouchActive=$map_touch_active"
                    )
                }
                if (map_touch_active) {
                    mark_map_interaction()
                    postInvalidateOnAnimation()
                }
                down_x = x
                down_y = y
                details_scroll_start_y = y
                details_scroll_start_offset = details_scroll_y
                drag_started = false
                drag_blocked = !map_touch_active
                drag_start_center = if (map_touch_active) current_interaction_viewport()?.let {
                    WorldPoint(it.center_x, it.center_y)
                } else null
                begin_priority_adjust_hold_if_needed(x, y)
                return true
            }
            MotionEvent.ACTION_MOVE -> {
                if (update_priority_adjust_hold(x, y)) return true
                if (details_session.details_open && !debug_perf_hides_chrome() && !settings_open && !priority_tracker_open && !filters_open && details_max_scroll_y > 0f) {
                    val dy = y - details_scroll_start_y
                    if (!drag_started && abs(dy) > dp(6)) drag_started = true
                    if (drag_started) {
                        details_scroll_y = (details_scroll_start_offset - dy).coerceIn(0f, details_max_scroll_y)
                        postInvalidateOnAnimation()
                    }
                    return true
                }
                if (!map_gesture_blocked_by_overlay() && !drag_blocked && drag_start_center != null) {
                    val dx = x - down_x
                    val dy = y - down_y
                    if (!drag_started && (abs(dx) > dp(8) || abs(dy) > dp(8))) {
                        drag_started = true
                    }
                    if (drag_started) {
                        mark_map_interaction()
                        val start = drag_start_center ?: return true
                        set_manual_center_from_world(start.x - dx, start.y - dy)
                        postInvalidateOnAnimation()
                    }
                }
                return true
            }
            MotionEvent.ACTION_UP -> {
                parent?.requestDisallowInterceptTouchEvent(false)
                map_touch_active = false
                val was_dragging = drag_started
                val was_dragging_map = drag_started && !drag_blocked
                drag_started = false
                drag_start_center = null
                if (finish_priority_adjust_hold(x, y)) return true
                if (was_dragging) {
                    if (was_dragging_map) {
                        mark_map_interaction()
                        request_visible_aircraft_after_map_interaction()
                    }
                    return true
                }
                if (abs(x - down_x) > dp(12) || abs(y - down_y) > dp(12)) return true
                if (event.eventTime - event.downTime >= PHOTO_LONG_PRESS_MS && handle_long_press(x, y)) return true
                performClick()
                handle_tap(x, y)
                return true
            }
            MotionEvent.ACTION_CANCEL -> {
                parent?.requestDisallowInterceptTouchEvent(false)
                map_touch_active = false
                cancel_priority_adjust_hold()
                drag_started = false
                drag_start_center = null
                return true
            }
        }
        return true
    }
    override fun performClick(): Boolean {
        super.performClick()
        return true
    }

    private fun map_gesture_blocked_by_overlay(): Boolean {
        return settings_open || details_block_map_interaction() || priority_tracker_open || filters_open
    }

    private fun details_block_map_interaction(): Boolean {
        return details_session.details_open && !debug_perf_hides_chrome()
    }

    private fun debug_perf_hides_chrome(): Boolean {
        return debug_perf_viewport_active && debug_perf_skip_chrome
    }

    private fun debug_perf_skips_top_status(): Boolean {
        return debug_perf_viewport_active && debug_perf_skip_top_status
    }

    private fun debug_perf_skips_controls(): Boolean {
        return debug_perf_viewport_active && debug_perf_skip_controls
    }

    private fun debug_perf_skips_traffic_panel(): Boolean {
        return debug_perf_viewport_active && debug_perf_skip_traffic_panel
    }

    override fun onCheckIsTextEditor(): Boolean {
        return filters_open && filter_search_focused
    }

    // Android asks for this when the filter box has focus. This small bridge turns keyboard text into filter text.
    override fun onCreateInputConnection(outAttrs: EditorInfo): InputConnection? {
        if (!filters_open || !filter_search_focused) return null
        outAttrs.inputType = InputType.TYPE_CLASS_TEXT or
            InputType.TYPE_TEXT_FLAG_CAP_CHARACTERS or
            InputType.TYPE_TEXT_FLAG_NO_SUGGESTIONS
        outAttrs.imeOptions = EditorInfo.IME_ACTION_SEARCH
        return object : BaseInputConnection(this, false) {
            override fun commitText(text: CharSequence?, newCursorPosition: Int): Boolean {
                append_filter_search_text(text?.toString().orEmpty())
                return true
            }

            override fun setComposingText(text: CharSequence?, newCursorPosition: Int): Boolean {
                return true
            }

            override fun deleteSurroundingText(beforeLength: Int, afterLength: Int): Boolean {
                delete_filter_search_character()
                return true
            }

            override fun sendKeyEvent(event: KeyEvent): Boolean {
                if (event.action != KeyEvent.ACTION_DOWN) return true
                return handle_filter_search_key(event.keyCode, event)
            }

            override fun performEditorAction(actionCode: Int): Boolean {
                if (actionCode == EditorInfo.IME_ACTION_SEARCH || actionCode == EditorInfo.IME_ACTION_DONE) {
                    submit_filter_search()
                    return true
                }
                return super.performEditorAction(actionCode)
            }
        }
    }

    override fun onGenericMotionEvent(event: MotionEvent): Boolean {
        val is_pointer_scroll = event.action == MotionEvent.ACTION_SCROLL &&
            (event.source and InputDevice.SOURCE_CLASS_POINTER) != 0
        if (!settings_open && !details_session.details_open && !priority_tracker_open && !filters_open && is_pointer_scroll && latest_location != null) {
            val scroll = event.getAxisValue(MotionEvent.AXIS_VSCROLL)
            if (scroll != 0f) {
                // Hardware wheels/trackpads zoom around the cursor, matching mouse use in the emulator.
                mark_map_interaction()
                val focus_x = content_x(event.x).coerceIn(0f, content_width())
                val focus_y = content_y(event.y).coerceIn(0f, content_height())
                val scale_factor = 2.0.pow(scroll.toDouble() * 0.22)
                zoom_and_pan_during_pinch(scale_factor, focus_x, focus_y, focus_x, focus_y)
                request_visible_aircraft_after_map_interaction()
                return true
            }
        }
        return super.onGenericMotionEvent(event)
    }

    override fun onKeyDown(keyCode: Int, event: KeyEvent): Boolean {
        if (filters_open && filter_search_focused && handle_filter_search_key(keyCode, event)) {
            return true
        }
        if (!settings_open && !details_session.details_open && !priority_tracker_open && !filters_open && latest_location != null) {
            val zoom_step = when (keyCode) {
                KeyEvent.KEYCODE_EQUALS,
                KeyEvent.KEYCODE_PLUS,
                KeyEvent.KEYCODE_NUMPAD_ADD -> 0.5
                KeyEvent.KEYCODE_MINUS,
                KeyEvent.KEYCODE_NUMPAD_SUBTRACT -> -0.5
                else -> null
            }
            if (zoom_step != null) {
                // Keyboard zoom is centered in the open map area so panels do not steal the focal point.
                mark_map_interaction()
                val focus = default_map_focus(content_width(), content_height())
                val scale_factor = 2.0.pow(zoom_step)
                zoom_and_pan_during_pinch(scale_factor, focus.x, focus.y, focus.x, focus.y)
                request_visible_aircraft_after_map_interaction()
                return true
            }
        }
        return super.onKeyDown(keyCode, event)
    }

    private fun begin_pinch(event: MotionEvent) {
        mark_map_interaction()
        pinch_in_progress = true
        map_touch_active = true
        drag_started = false
        drag_blocked = true
        drag_start_center = null
        last_pinch_span = pointer_span(event)
        last_pinch_focus_x = pointer_focus_x(event)
        last_pinch_focus_y = pointer_focus_y(event)
    }

    private fun update_pinch(event: MotionEvent) {
        mark_map_interaction()
        if (!pinch_in_progress) begin_pinch(event)

        val span = pointer_span(event)
        val focus_x = pointer_focus_x(event)
        val focus_y = pointer_focus_y(event)

        if (span <= dp(20) || last_pinch_span <= dp(20)) {
            last_pinch_span = span
            last_pinch_focus_x = focus_x
            last_pinch_focus_y = focus_y
            return
        }

        val scale_factor = (span / last_pinch_span).toDouble()
        if (!scale_factor.isFinite() || scale_factor <= 0.0) return

        val zoom_delta = ln(scale_factor) / ln(2.0)
        val moved =
            abs(focus_x - last_pinch_focus_x) > dp(0.25f) ||
                    abs(focus_y - last_pinch_focus_y) > dp(0.25f)

        // 0.001 zoom levels is roughly 0.07% scale change.
        // Or remove this threshold entirely and apply every valid MOVE.
        if (abs(zoom_delta) >= 0.001 || moved) {
            zoom_and_pan_during_pinch(
                scale_factor,
                last_pinch_focus_x,
                last_pinch_focus_y,
                focus_x,
                focus_y,
                persist_zoom = false
            )

            last_pinch_span = span
            last_pinch_focus_x = focus_x
            last_pinch_focus_y = focus_y
        }
    }

    private fun end_pinch() {
        mark_map_interaction()
        pinch_in_progress = false
        map_touch_active = false
        last_pinch_span = 0f
        last_pinch_focus_x = 0f
        last_pinch_focus_y = 0f
        drag_started = false
        drag_start_center = null
        parent?.requestDisallowInterceptTouchEvent(false)
        persist_zoom_preference_if_dirty()
        request_visible_aircraft_after_map_interaction()
    }

    private fun zoom_and_pan_during_pinch(
        scale_factor: Double,
        old_focus_x: Float,
        old_focus_y: Float,
        new_focus_x: Float,
        new_focus_y: Float,
        persist_zoom: Boolean = true
    ) {
        val old_viewport = current_interaction_viewport() ?: return
        val anchor_geo = world_to_lat_lon(
            old_viewport.center_x - old_viewport.width / 2.0 + old_focus_x,
            old_viewport.center_y - old_viewport.height / 2.0 + old_focus_y,
            old_viewport.zoom
        )
        val next_zoom = (zoom + ln(scale_factor) / ln(2.0)).coerceIn(MIN_ZOOM.toDouble(), MAX_ZOOM.toDouble())

        zoom = next_zoom
        val focus_world = lat_lon_to_world(anchor_geo.lat, anchor_geo.lon, zoom)
        set_manual_center_from_world(
            focus_world.x + content_width() / 2.0 - new_focus_x,
            focus_world.y + content_height() / 2.0 - new_focus_y
        )
        zoom_preference_dirty = true
        if (persist_zoom) schedule_zoom_preference_save()
        postInvalidateOnAnimation()
    }

    private fun current_interaction_viewport(): Viewport? {
        val w = content_width()
        val h = content_height()
        if (w <= 0f || h <= 0f) return null
        latest_location?.let { location -> return viewport_for(location, w, h) }
        val center_lat = manual_center_lat ?: return null
        val center_lon = manual_center_lon ?: return null
        val center = lat_lon_to_world(center_lat, center_lon, zoom)
        return Viewport(
            zoom = zoom,
            center_x = center.x,
            center_y = center.y,
            width = w,
            height = h
        )
    }

    private fun schedule_zoom_preference_save() {
        removeCallbacks(save_zoom_preference)
        postDelayed(save_zoom_preference, ZOOM_PREFERENCE_SAVE_DELAY_MS)
    }

    private fun persist_zoom_preference_if_dirty() {
        if (!zoom_preference_dirty) return
        removeCallbacks(save_zoom_preference)
        zoom_preference_dirty = false
        prefs.edit { putFloat(FlightAlertSettings.KEY_ZOOM, zoom.toFloat()) }
    }

    private fun pointer_span(event: MotionEvent): Float {
        if (event.pointerCount < 2) return 0f
        val dx = event.getX(1) - event.getX(0)
        val dy = event.getY(1) - event.getY(0)
        return sqrt(dx * dx + dy * dy)
    }

    private fun pointer_focus_x(event: MotionEvent): Float {
        return content_x(if (event.pointerCount >= 2) (event.getX(0) + event.getX(1)) / 2f else event.x)
    }

    private fun pointer_focus_y(event: MotionEvent): Float {
        return content_y(if (event.pointerCount >= 2) (event.getY(0) + event.getY(1)) / 2f else event.y)
    }

    private fun setup_system_insets() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            setOnApplyWindowInsetsListener { _, insets ->
                val bars = insets.getInsets(WindowInsets.Type.systemBars())
                val cutout = insets.displayCutout
                val cutout_insets = if (cutout != null && has_non_hole_punch_cutout(cutout.boundingRects)) cutout else null
                update_safe_insets(
                    max(bars.left, cutout_insets?.safeInsetLeft ?: 0),
                    max(bars.top, cutout_insets?.safeInsetTop ?: 0),
                    max(bars.right, cutout_insets?.safeInsetRight ?: 0),
                    max(bars.bottom, cutout_insets?.safeInsetBottom ?: 0)
                )
                insets
            }
        } else {
            @Suppress("DEPRECATION")
            setOnApplyWindowInsetsListener { _, insets ->
                update_safe_insets(
                    insets.systemWindowInsetLeft,
                    insets.systemWindowInsetTop,
                    insets.systemWindowInsetRight,
                    insets.systemWindowInsetBottom
                )
                insets
            }
        }
        post { requestApplyInsets() }
    }

    private fun has_non_hole_punch_cutout(cutouts: List<Rect>): Boolean {
        if (cutouts.isEmpty()) return false
        return cutouts.any { !is_hole_punch_cutout(it) }
    }

    private fun is_hole_punch_cutout(cutout: Rect): Boolean {
        val max_size = max(cutout.width(), cutout.height()).toFloat()
        val min_size = min(cutout.width(), cutout.height()).toFloat()
        // Small, roughly round/square cutouts are hole-punch cameras; wide edge cutouts still get avoided.
        return max_size <= dp(HOLE_PUNCH_MAX_SIZE_DP) && min_size >= max_size * 0.55f
    }

    private fun update_safe_insets(left: Int, top: Int, right: Int, bottom: Int) {
        val next_left = left.toFloat()
        val next_top = top.toFloat()
        val next_right = right.toFloat()
        val next_bottom = bottom.toFloat()
        if (safe_inset_left == next_left && safe_inset_top == next_top && safe_inset_right == next_right && safe_inset_bottom == next_bottom) return
        safe_inset_left = next_left
        safe_inset_top = next_top
        safe_inset_right = next_right
        safe_inset_bottom = next_bottom
        request_deferred_aircraft_refresh()
        invalidate()
    }

    private fun content_width(): Float = max(1f, width.toFloat() - safe_inset_left - safe_inset_right)

    private fun content_height(): Float = max(1f, height.toFloat() - safe_inset_top - safe_inset_bottom)

    private fun content_x(screen_x: Float): Float = screen_x - safe_inset_left

    private fun content_y(screen_y: Float): Float = screen_y - safe_inset_top

    // Ask Android for available providers, seed from last known fixes, then subscribe to live fixes.
    private fun start_location_updates() {
        if (!has_location_permission()) {
            location_permission_granted = false
            return
        }
        location_permission_granted = true
        try {
            val providers = location_manager.getProviders(true)
            for (provider in providers) {
                val last = location_manager.getLastKnownLocation(provider)
                if (last != null && is_better_location(last, latest_location)) latest_location = last
            }
            if (latest_location != null) request_visible_aircraft_if_needed(force = true)
            if (latest_location == null) {
                map_status = "Waiting for device location"
                aircraft_status = "Waiting for device location"
            }
            if (providers.contains(LocationManager.GPS_PROVIDER)) {
                location_manager.requestLocationUpdates(LocationManager.GPS_PROVIDER, 2000L, 5f, this)
            }
            if (providers.contains(LocationManager.NETWORK_PROVIDER)) {
                location_manager.requestLocationUpdates(LocationManager.NETWORK_PROVIDER, 3000L, 10f, this)
            }
        } catch (_: SecurityException) {
            location_permission_granted = false
            map_status = "Location permission required"
            aircraft_status = "Location permission required"
        }
    }

    private fun has_location_permission(): Boolean = context.has_flight_location_permission()

    private fun is_better_location(candidate: Location, current: Location?): Boolean {
        if (current == null) return true
        return candidate.time > current.time || candidate.accuracy < current.accuracy
    }

    // Make the camera: follow mode keeps the user under the focus point, manual mode keeps the dragged map centered.
    private fun viewport_for(location: Location, w: Float, h: Float): Viewport {
        val center_lat = if (following_location) location.latitude else manual_center_lat ?: location.latitude
        val center_lon = if (following_location) location.longitude else manual_center_lon ?: location.longitude
        val center = lat_lon_to_world(center_lat, center_lon, zoom)
        val focus = if (following_location) default_map_focus(w, h) else ScreenPoint(w / 2f, h / 2f)
        return Viewport(
            zoom = zoom,
            center_x = center.x + w / 2.0 - focus.x,
            center_y = center.y + h / 2.0 - focus.y,
            width = w,
            height = h
        )
    }

    private fun viewport_center_lat(location: Location): Double {
        return if (following_location) location.latitude else manual_center_lat ?: location.latitude
    }

    private fun viewport_center_lon(location: Location): Double {
        return if (following_location) location.longitude else manual_center_lon ?: location.longitude
    }

    // Ask the tile renderer to draw real map imagery and return the honest map status.
    private fun draw_map_tiles(canvas: Canvas, viewport: Viewport) {
        map_status = map_tile_renderer.draw_tiles(
            canvas = canvas,
            viewport = viewport,
            state = map_tile_state(),
            style = map_tile_style()
        )
    }

    private fun map_tile_state(): MapTileRenderState {
        return MapTileRenderState(
            map_source = map_source,
            map_labels_enabled = map_labels_enabled,
            map_borders_enabled = map_borders_enabled,
            user_agent = USER_AGENT,
            interaction_active = map_tile_interaction_active(SystemClock.elapsedRealtime())
        )
    }

    private fun map_tile_interaction_active(now: Long): Boolean {
        return pinch_in_progress ||
            drag_started ||
            map_touch_active ||
            now - last_map_interaction_ms <= MAP_TILE_INTERACTION_SETTLE_MS
    }

    private fun map_tile_style(): MapTileRenderStyle {
        return MapTileRenderStyle(
            map_empty = map_empty_color,
            panel_alt = panel_alt_color,
            text = text_color
        )
    }
    private fun should_draw_priority_range_circle(): Boolean {
        return priority_tracker_open || (alerts_enabled && priority_range_circle_visible)
    }

    // Draw the configured horizontal alert radius; vertical separation stays in the alert math, not this flat ring.
    private fun draw_priority_range_circle(canvas: Canvas, viewport: Viewport, location: Location, outline_only: Boolean = false) {
        if (!should_draw_priority_range_circle()) return
        val ownship = lat_lon_to_world(location.latitude, location.longitude, viewport.zoom)
        val cx = (ownship.x - viewport.center_x + viewport.width / 2.0).toFloat()
        val cy = (ownship.y - viewport.center_y + viewport.height / 2.0).toFloat()
        val meters_per_pixel = meters_per_pixel_at(location.latitude, viewport.zoom).coerceAtLeast(0.01)
        val radius_px = (feet_to_meters(alert_distance_feet.toDouble()) / meters_per_pixel).toFloat()
        if (radius_px <= 1f) return

        val preview_only = !alerts_enabled || !priority_range_circle_visible
        if (!outline_only) {
            paint.style = Paint.Style.FILL
            paint.color = Color.argb(if (preview_only) 18 else 26, Color.red(accent_green_color), Color.green(accent_green_color), Color.blue(accent_green_color))
            canvas.drawCircle(cx, cy, radius_px, paint)
        }
        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeWidth = dp(if (outline_only) 2.2f else 1.8f)
        val stroke_alpha = when {
            outline_only && preview_only -> 155
            outline_only -> 230
            preview_only -> 130
            else -> 185
        }
        stroke_paint.color = Color.argb(stroke_alpha, Color.red(accent_green_color), Color.green(accent_green_color), Color.blue(accent_green_color))
        canvas.drawCircle(cx, cy, radius_px, stroke_paint)
    }

    // Draw cached real aviation layers only after the viewport request has produced source data.
    private fun draw_aviation_layers(canvas: Canvas, viewport: Viewport) {
        val visibility = aviation_layer_visibility()
        if (!aviation_layer_controller.has_enabled_layers(visibility) && selected_restricted_airspace == null) return
        val snapshot = aviation_layer_controller.snapshot ?: return
        val visible_bounds = aviation_bounds_for_viewport(viewport).to_aviation_geo_bounds()
        aviation_layer_renderer.draw_layers(
            canvas = canvas,
            viewport = viewport,
            snapshot = snapshot,
            visible_bounds = visible_bounds,
            visibility = visibility,
            style = aviation_layer_style(),
            selected_restricted_airspace = selected_restricted_airspace,
            interaction_active = aviation_layer_interacting(SystemClock.elapsedRealtime())
        )
    }

    private fun aviation_layer_interacting(now: Long): Boolean {
        return pinch_in_progress ||
            drag_started ||
            now - last_map_interaction_ms <= AVIATION_LAYER_INTERACTION_SETTLE_MS
    }

    private fun aviation_layer_visibility(): AviationLayerVisibility {
        return AviationLayerVisibility(
            restricted_airspaces_enabled = restricted_airspaces_layer_enabled,
            atc_boundaries_enabled = atc_boundaries_layer_enabled,
            oceanic_tracks_enabled = oceanic_tracks_layer_enabled,
            airport_labels_enabled = airport_labels_layer_enabled
        )
    }

    private fun aviation_layer_style(): AviationLayerStyle {
        return AviationLayerStyle(
            accent_orange = accent_orange_color,
            danger = danger_color,
            accent_blue = accent_blue_color,
            accent_green = accent_green_color,
            accent_pink = accent_pink_color,
            accent_yellow = accent_yellow_color,
            military_gray = military_gray_color,
            panel = panel_color,
            text = text_color,
            treatment = visual_theme.style.treatment
        )
    }

    // Draw a selected aircraft's real trace; the controller decides whether previous legs are visible.
    private fun draw_selected_flight_path(canvas: Canvas, viewport: Viewport) {
        val state = selected_flight_path_render_state() ?: return
        flight_path_renderer.draw_selected_path(canvas, viewport, state, flight_path_render_style())
    }

    private fun selected_flight_path_render_state(): FlightPathRenderState? {
        val selected_segments = selected_path_controller.selected_segments(visible_only = true) ?: return null
        return FlightPathRenderState(
            selected_segments = selected_segments,
            previous_segments = selected_path_controller.previous_segments(visible_only = true).orEmpty(),
            projection = selected_flight_path_projection()
        )
    }

    private fun selected_flight_path_projection(): FlightPathProjection? {
        val last = selected_path_controller.selected_segments(visible_only = true)
            ?.flatMap { it.points }
            ?.maxByOrNull { it.epoch_sec }
            ?: return null
        val projected = selected_path_controller.projected_endpoint() ?: return null
        return FlightPathProjection(last_trace_point = last, projected_endpoint = projected)
    }

    private fun flight_path_render_style(): FlightPathRenderStyle {
        return FlightPathRenderStyle(
            path_shadow = theme_colors.path_shadow,
            accent_yellow = accent_yellow_color,
            accent_blue = accent_blue_color
        )
    }
    private fun has_aviation_layers_enabled(): Boolean {
        return aviation_layer_controller.has_enabled_layers(aviation_layer_visibility())
    }

    private fun request_aviation_layers_if_needed(viewport: Viewport, force: Boolean = false) {
        aviation_layer_controller.request_if_needed(viewport, aviation_layer_visibility(), force)
    }

    // Build one real feed request for the current viewport, then let AircraftTrafficFeed merge enabled sources.
    private fun request_visible_aircraft_if_needed(force: Boolean = false) {
        visible_aircraft_feed_controller.request_if_needed(force)
    }

    private fun request_visible_aircraft_after_map_interaction() {
        visible_aircraft_feed_controller.request_after_map_interaction()
    }

    private fun should_defer_aircraft_refresh_for_interaction(now: Long): Boolean {
        if (traffic_cache_controller.total < BINCRAFT_FEED_READY_AIRCRAFT_MIN) return false
        return pinch_in_progress ||
            drag_started ||
            now - last_map_interaction_ms < MAP_INTERACTION_AIRCRAFT_REFRESH_DELAY_MS
    }

    private fun aircraft_refresh_delay_after_interaction(now: Long): Long {
        if (pinch_in_progress || drag_started) return MAP_INTERACTION_AIRCRAFT_REFRESH_DELAY_MS
        val elapsed = now - last_map_interaction_ms
        return (MAP_INTERACTION_AIRCRAFT_REFRESH_DELAY_MS - elapsed).coerceAtLeast(AIRCRAFT_IN_FLIGHT_RETRY_MS)
    }

    private fun publish_globe_snapshot_update_if_useful() {
        visible_aircraft_feed_controller.publish_globe_snapshot_update_if_useful(aircraft_feed_mode)
    }

    private fun visible_aircraft_request(): VisibleAircraftRequest {
        val location = latest_location ?: error("visible aircraft request requires a location")
        val bounds = aircraft_bounds_for_current_viewport(location)
        val feed_bounds = bounds.to_feed_bounds()
        return VisibleAircraftRequest(
            feed_bounds = feed_bounds,
            safety_api_bounds = safety_api_bounds_for(location),
            own_lat = location.latitude,
            own_lon = location.longitude,
            center_lat = viewport_center_lat(location),
            center_lon = viewport_center_lon(location),
            zoom = zoom,
            feed_mode = aircraft_feed_mode,
            exact_search = aircraft_filter_controller.search_query.takeIf { it.isNotBlank() }
        )
    }

    // Convert the feed result into display aircraft, preserve selected state, and publish one map update.
    private fun apply_aircraft_feed_result(result: FeedResult, fetch_token: Long, fetch_signature: String): Boolean {
        if (!is_current_aircraft_fetch(fetch_token, fetch_signature)) return false
        if (result.status == FeedStatus.OK) {
            val parsed = preserve_existing_aircraft_metadata(
                result = result,
                parsed = aircraft_traffic_feed.map_aircraft(result)
            )
            val parsed_cache = traffic_cache_controller.build_cached_traffic(parsed)
            post {
                publish_aircraft_feed_result(
                    result = result,
                    fetch_token = fetch_token,
                    fetch_signature = fetch_signature,
                    parsed = parsed,
                    parsed_cache = parsed_cache
                )
            }
            return true
        }

        post {
            publish_aircraft_feed_failure(result, fetch_token)
        }
        return false
    }

    private fun publish_aircraft_feed_result(
        result: FeedResult,
        fetch_token: Long,
        fetch_signature: String,
        parsed: List<Aircraft>,
        parsed_cache: CachedTraffic
    ) {
        if (!is_current_aircraft_fetch(fetch_token, fetch_signature)) return
        if (should_keep_current_aircraft_for_partial_result(result, parsed_cache)) {
            val coverage = aircraft_traffic_feed.coverage_label(result)
            Log.d(
                TAG,
                "Aircraft feed ${result.source.display_name}: ${parsed.size} aircraft$coverage; keeping ${traffic_cache_controller.total} displayed aircraft"
            )
            aircraft_status = "Live aircraft updating via ${result.source.display_name}$coverage"
            visible_aircraft_feed_controller.schedule_hybrid_supplement_refresh()
            postInvalidateOnAnimation()
            return
        }
        if (should_defer_aircraft_feed_publish_for_interaction()) {
            defer_aircraft_feed_publish(result, fetch_token, fetch_signature, parsed, parsed_cache)
            return
        }
        publish_aircraft_feed_result_now(result, fetch_token, fetch_signature, parsed, parsed_cache)
    }

    private fun publish_aircraft_feed_result_now(
        result: FeedResult,
        fetch_token: Long,
        fetch_signature: String,
        parsed: List<Aircraft>,
        parsed_cache: CachedTraffic
    ) {
        if (!is_current_aircraft_fetch(fetch_token, fetch_signature)) return
        update_aircraft_appearances(parsed)
        selected_path_controller.selected_aircraft_id?.let { selected_id ->
            parsed.firstOrNull { it.icao24 == selected_id }?.let { selected_path_controller.update_selected_aircraft(it) }
        }
        prune_selection_for_filters()
        val coverage = aircraft_traffic_feed.coverage_label(result)
        Log.d(TAG, "Aircraft feed ${result.source.display_name}: ${parsed.size} aircraft$coverage")
        synchronized(aircraft) {
            aircraft.clear()
            aircraft.addAll(parsed)
        }
        publish_prepared_traffic_cache(parsed_cache)
        publish_priority_notification_snapshot(force = true)
        last_aircraft_data_epoch_sec = result.epoch_sec
        aircraft_status = if (parsed.isEmpty()) {
            "No aircraft reported in current map area (${result.source.display_name}$coverage)"
        } else {
            "Live aircraft updated via ${result.source.display_name}$coverage"
        }
        if (result.source == FeedSource.HYBRID && result.partial_coverage) {
            visible_aircraft_feed_controller.schedule_hybrid_supplement_refresh()
        }
        postInvalidateOnAnimation()
    }

    private fun should_defer_aircraft_feed_publish_for_interaction(): Boolean {
        if (traffic_cache_controller.total < BINCRAFT_FEED_READY_AIRCRAFT_MIN) return false
        return should_defer_aircraft_refresh_for_interaction(SystemClock.elapsedRealtime())
    }

    private fun defer_aircraft_feed_publish(
        result: FeedResult,
        fetch_token: Long,
        fetch_signature: String,
        parsed: List<Aircraft>,
        parsed_cache: CachedTraffic
    ) {
        deferred_aircraft_feed_publish = DeferredAircraftFeedPublish(
            result = result,
            fetch_token = fetch_token,
            fetch_signature = fetch_signature,
            parsed = parsed,
            parsed_cache = parsed_cache
        )
        schedule_deferred_aircraft_feed_publish()
    }

    private fun schedule_deferred_aircraft_feed_publish() {
        if (deferred_aircraft_feed_publish_scheduled) return
        deferred_aircraft_feed_publish_scheduled = true
        val now = SystemClock.elapsedRealtime()
        postDelayed({
            deferred_aircraft_feed_publish_scheduled = false
            flush_deferred_aircraft_feed_publish()
        }, aircraft_refresh_delay_after_interaction(now))
    }

    private fun flush_deferred_aircraft_feed_publish() {
        val pending = deferred_aircraft_feed_publish ?: return
        if (should_defer_aircraft_feed_publish_for_interaction()) {
            schedule_deferred_aircraft_feed_publish()
            return
        }
        deferred_aircraft_feed_publish = null
        publish_aircraft_feed_result_now(
            result = pending.result,
            fetch_token = pending.fetch_token,
            fetch_signature = pending.fetch_signature,
            parsed = pending.parsed,
            parsed_cache = pending.parsed_cache
        )
    }

    private fun should_keep_current_aircraft_for_partial_result(result: FeedResult, parsed_cache: CachedTraffic): Boolean {
        if (result.source != FeedSource.HYBRID) return false
        if (aircraft_filter_controller.search_query.isNotBlank()) return false
        if (traffic_cache_controller.total < BINCRAFT_FEED_READY_AIRCRAFT_MIN) return false
        if (parsed_cache.total >= BINCRAFT_FEED_READY_AIRCRAFT_MIN) return false
        return parsed_cache.total < traffic_cache_controller.total * PARTIAL_FEED_REGRESSION_RATIO
    }

    private fun is_current_aircraft_fetch(fetch_token: Long, fetch_signature: String): Boolean {
        return visible_aircraft_feed_controller.is_current_fetch(fetch_token, fetch_signature)
    }

    private fun preserve_existing_aircraft_metadata(result: FeedResult, parsed: List<Aircraft>): List<Aircraft> {
        if (result.source != FeedSource.AIRPLANES_LIVE_GLOBE) return parsed
        val existing_by_key = all_aircraft_snapshot().associateBy { it.aircraft_metadata_merge_key() }
        var changed = false
        val merged = parsed.map { fresh_aircraft ->
            val existing = existing_by_key[fresh_aircraft.aircraft_metadata_merge_key()]
                ?: return@map fresh_aircraft
            val merged_aircraft = fresh_aircraft.with_metadata_fallback(existing)
            changed = changed || merged_aircraft !== fresh_aircraft
            merged_aircraft
        }
        return if (changed) merged else parsed
    }

    private fun Aircraft.aircraft_metadata_merge_key(): String =
        aircraft_identity_key(icao24, registration, callsign, lat, lon)

    private fun Aircraft.with_metadata_fallback(fallback: Aircraft): Aircraft {
        val merged_callsign = callsign.takeUnless { it.isBlank() || it.equals("Unknown", ignoreCase = true) }
            ?: fallback.callsign
        val merged = copy(
            callsign = merged_callsign,
            registration = registration ?: fallback.registration,
            type_code = type_code ?: fallback.type_code,
            metadata_seed = metadata_seed ?: fallback.metadata_seed,
            is_military = is_military || fallback.is_military,
            on_ground = on_ground ?: fallback.on_ground,
            altitude_m = altitude_m ?: fallback.altitude_m,
            velocity_ms = velocity_ms ?: fallback.velocity_ms,
            track_deg = track_deg ?: fallback.track_deg,
            vertical_rate_ms = vertical_rate_ms ?: fallback.vertical_rate_ms,
            category = category ?: fallback.category,
            telemetry = telemetry?.with_fallback(fallback.telemetry) ?: fallback.telemetry
        )
        return if (merged == this) this else merged
    }

    private fun publish_aircraft_feed_failure(result: FeedResult, fetch_token: Long) {
        if (!visible_aircraft_feed_controller.is_current_token(fetch_token)) return
        aircraft_status = when {
            result.source == FeedSource.AIRPLANES_LIVE_GLOBE && result.partial_coverage -> "binCraft aircraft feed loading"
            result.http_code != null -> "Aircraft feed unavailable: HTTP ${result.http_code}"
            result.status == FeedStatus.RATE_LIMITED -> "Aircraft feed rate limited"
            else -> "Aircraft feed unavailable"
        }
        if (result.source == FeedSource.AIRPLANES_LIVE_GLOBE && result.partial_coverage) {
            visible_aircraft_feed_controller.schedule_hybrid_supplement_refresh()
        }
        Log.d(TAG, "Aircraft feed ${result.source.display_name}: ${result.status} http=${result.http_code ?: "none"}")
        postInvalidateOnAnimation()
    }


    private fun request_deferred_aircraft_refresh() {
        visible_aircraft_feed_controller.request_deferred_refresh()
    }

    private fun update_aircraft_appearances(next_aircraft: List<Aircraft>) {
        val now = SystemClock.elapsedRealtime()
        synchronized(aircraft_appearances) {
            if (aircraft_appearances.isNotEmpty()) {
                val active_keys = next_aircraft.mapTo(HashSet(next_aircraft.size)) { it.appearance_key() }
                aircraft_appearances.entries.removeAll { entry ->
                    entry.key !in active_keys && now - entry.value.last_seen_ms > AIRCRAFT_APPEARANCE_RETENTION_MS
                }
            }
            next_aircraft.forEach { item ->
                val key = item.appearance_key()
                val existing = aircraft_appearances[key]
                aircraft_appearances[key] = existing?.copy(last_seen_ms = now) ?:
                    AircraftAppearance(
                        first_seen_ms = now,
                        delay_ms = 0L,
                        last_seen_ms = now
                    )
            }
            aircraft_appearance_snapshot = HashMap(aircraft_appearances)
        }
    }

    private fun aircraft_appearance_progress_for_key(key: String, aircraft: Aircraft): Float {
        val appearance = aircraft_appearance_snapshot[key] ?: return 1f
        val elapsed = SystemClock.elapsedRealtime() - appearance.first_seen_ms - appearance.delay_ms
        return smooth_step(0f, AIRCRAFT_APPEAR_DURATION_MS.toFloat(), elapsed.toFloat())
    }

    private fun aircraft_appearance_for_key(key: String, aircraft: Aircraft): AircraftAppearance? {
        return aircraft_appearance_snapshot[key]
    }

    private fun has_usable_viewport(): Boolean {
        return width > 0 &&
            height > 0 &&
            width.toFloat() - safe_inset_left - safe_inset_right >= dp(180) &&
            height.toFloat() - safe_inset_top - safe_inset_bottom >= dp(180)
    }

    // Fetch the selected aircraft's trace only after selection, then ignore stale responses if selection changed.
    private fun request_flight_path(icao24: String, force: Boolean = false) {
        val key = selected_path_controller.trace_request_key(icao24) ?: return
        if (!force && selected_path_controller.selected_trace_aircraft_id == key && selected_path_controller.trace != null) return
        synchronized(flight_path_requests) {
            if (flight_path_requests.contains(key)) return
            flight_path_requests += key
        }

        executor.execute {
            try {
                val selected_aircraft = selected_path_controller.selected_snapshot_for_key(key)
                val live_point = selected_aircraft?.let { AircraftPositionProjector.to_track_point(it) }
                val trace = flight_trace_client.fetch_flight_trace(
                    icao24 = key,
                    live_point = live_point,
                    type_code = selected_aircraft?.type_code
                )
                post {
                    if (selected_path_controller.is_selected_key(key)) {
                        selected_path_controller.apply_trace_result(key, trace)
                        Log.d(TAG, "Flight trace icao=$key ${flight_trace_diagnostic(trace)}")
                        displayed_traffic().aircraft?.let { aircraft ->
                            origin_lookup_controller.request_military_origin_if_needed(aircraft)
                            origin_lookup_controller.request_trace_origin_airport_if_needed(aircraft)
                        }
                        invalidate()
                    }
                }
            } catch (_: Exception) {
                post {
                    if (selected_path_controller.is_selected_key(key)) {
                        selected_path_controller.clear_trace_for_key(key)
                        invalidate()
                    }
                }
            } finally {
                synchronized(flight_path_requests) { flight_path_requests -= key }
            }
        }
    }

    private fun aircraft_bounds_for_current_viewport(location: Location): Bounds {
        if (!has_usable_viewport()) return aircraft_bounds_around_location(location).with_priority_bounds(location)
        val viewport = viewport_for(location, content_width(), content_height())
        val bounds = bounds_for_viewport(viewport, aircraft_bounds_padding_px(viewport))
        return (bounds ?: aircraft_bounds_around_location(location)).with_priority_bounds(location)
    }

    private fun bounds_for_viewport(viewport: Viewport, padding: Double = AIRCRAFT_BOUNDS_PADDING_PX): Bounds? {
        val left = viewport.center_x - viewport.width / 2.0 - padding
        val right = viewport.center_x + viewport.width / 2.0 + padding
        val top = viewport.center_y - viewport.height / 2.0 - padding
        val bottom = viewport.center_y + viewport.height / 2.0 + padding
        val top_left = world_to_lat_lon(left, top, viewport.zoom)
        val bottom_right = world_to_lat_lon(right, bottom, viewport.zoom)
        if (abs(top_left.lon - bottom_right.lon) > 180.0) return null
        return Bounds(
            min_lat = min(top_left.lat, bottom_right.lat).coerceIn(-90.0, 90.0),
            min_lon = min(top_left.lon, bottom_right.lon).coerceIn(-180.0, 180.0),
            max_lat = max(top_left.lat, bottom_right.lat).coerceIn(-90.0, 90.0),
            max_lon = max(top_left.lon, bottom_right.lon).coerceIn(-180.0, 180.0)
        )
    }

    private fun aviation_bounds_for_viewport(viewport: Viewport, padding: Double = AIRCRAFT_BOUNDS_PADDING_PX): Bounds {
        return bounds_for_viewport(viewport, padding) ?: world_longitude_bounds_for_viewport(viewport, padding)
    }

    private fun world_longitude_bounds_for_viewport(viewport: Viewport, padding: Double): Bounds {
        val left = viewport.center_x - viewport.width / 2.0 - padding
        val right = viewport.center_x + viewport.width / 2.0 + padding
        val top = viewport.center_y - viewport.height / 2.0 - padding
        val bottom = viewport.center_y + viewport.height / 2.0 + padding
        val top_left = world_to_lat_lon(left, top, viewport.zoom)
        val bottom_right = world_to_lat_lon(right, bottom, viewport.zoom)
        return Bounds(
            min_lat = min(top_left.lat, bottom_right.lat).coerceIn(-90.0, 90.0),
            min_lon = -180.0,
            max_lat = max(top_left.lat, bottom_right.lat).coerceIn(-90.0, 90.0),
            max_lon = 180.0
        )
    }

    private fun aircraft_bounds_padding_px(viewport: Viewport): Double {
        if (!aircraft_feed_mode.uses_globe) return AIRCRAFT_BOUNDS_PADDING_PX
        val screen_span = max(viewport.width, viewport.height).toDouble()
        val screen_fraction = when {
            viewport.zoom < 6.0 -> 1.35
            viewport.zoom < 8.0 -> 1.05
            viewport.zoom < 10.0 -> 0.75
            else -> 0.45
        }
        return max(AIRCRAFT_BOUNDS_PADDING_PX, screen_span * screen_fraction)
    }

    private fun aircraft_bounds_around_location(location: Location): Bounds {
        val radius_km = when (zoom) {
            in 0.0..8.999 -> 90.0
            in 9.0..9.999 -> 65.0
            in 10.0..10.999 -> 45.0
            in 11.0..11.999 -> 28.0
            in 12.0..12.999 -> 16.0
            else -> 10.0
        }
        return aircraft_bounds_around_location(location, radius_km * 1000.0)
    }

    private fun aircraft_bounds_around_location(location: Location, radius_meters: Double): Bounds =
        bounds_around_location(location, radius_meters)

    private fun safety_api_bounds_for(location: Location): FeedBounds? {
        if (!alerts_enabled && !priority_tracking_enabled) return null
        return aircraft_bounds_around_location(location, feet_to_meters(safety_api_radius_feet())).to_feed_bounds()
    }

    private fun safety_api_radius_feet(): Double {
        val alert_radius_with_margin = if (alerts_enabled) {
            max(
                alert_distance_feet.toDouble() * SAFETY_API_RADIUS_MULTIPLIER,
                alert_distance_feet.toDouble() + SAFETY_API_MIN_PADDING_FEET
            )
        } else {
            SAFETY_API_MIN_RADIUS_FEET
        }
        val queue_radius = if (priority_tracking_enabled) priority_range_feet.toDouble() else SAFETY_API_MIN_RADIUS_FEET
        return max(alert_radius_with_margin, queue_radius).coerceAtLeast(SAFETY_API_MIN_RADIUS_FEET)
    }

    // Expand fetch bounds to include alert and priority volumes even when the map is panned away.
    private fun Bounds.with_priority_bounds(location: Location): Bounds {
        var combined = this
        if (alerts_enabled) {
            combined = combined.union(aircraft_bounds_around_location(location, feet_to_meters(alert_distance_feet.toDouble())))
        }
        if (priority_tracking_enabled) {
            combined = combined.union(aircraft_bounds_around_location(location, feet_to_meters(priority_range_feet.toDouble())))
        }
        return combined
    }

    private fun Bounds.union(other: Bounds): Bounds {
        return Bounds(
            min_lat = min(min_lat, other.min_lat),
            min_lon = min(min_lon, other.min_lon),
            max_lat = max(max_lat, other.max_lat),
            max_lon = max(max_lon, other.max_lon)
        )
    }

    private fun draw_traffic_overlay(canvas: Canvas, viewport: Viewport) {
        val collect_traffic_detail_timing = debug_perf_viewport_active && debug_perf_traffic_detail_timing
        traffic_overlay_renderer.debug_collect_detail_timing = collect_traffic_detail_timing
        traffic_overlay_state_builder.debug_collect_detail_timing = collect_traffic_detail_timing
        val state_start_ns = if (collect_traffic_detail_timing) {
            SystemClock.elapsedRealtimeNanos()
        } else {
            0L
        }
        val state = debug_trace_result(collect_traffic_detail_timing, DEBUG_TRACE_TRAFFIC_STATE) {
            traffic_overlay_state(viewport)
        }
        debug_last_traffic_state_build_summary = if (state_start_ns > 0L) {
            "stateBuild=${(SystemClock.elapsedRealtimeNanos() - state_start_ns).ms()} " +
                traffic_overlay_state_builder.debug_last_detail_timing_summary + " "
        } else {
            ""
        }
        if (debug_perf_viewport_active) {
            debug_last_traffic_symbol_count = state.aircraft.size
            debug_last_traffic_dot_count = state.dot_batch?.visible_count ?: state.aircraft.size
        }
        debug_trace_section(collect_traffic_detail_timing, DEBUG_TRACE_AIRCRAFT_DRAW) {
            traffic_overlay_renderer.draw_aircraft(
                canvas = canvas,
                state = state,
                style = TrafficOverlayStyle(visual_theme)
            )
        }
        debug_record_frame_metrics_direct_sample()
        last_traffic_draw_elapsed_ms = SystemClock.elapsedRealtime()
        aircraft_details_prefetch_planner.schedule(
            state = state,
            details_open = details_session.details_open,
            pinch_in_progress = pinch_in_progress,
            drag_started = drag_started,
            last_map_interaction_ms = last_map_interaction_ms
        )
    }

