    private fun set_manual_center_from_world(center_x: Double, center_y: Double) {
        val scale = TILE_SIZE * 2.0.pow(zoom)
        val wrapped_x = ((center_x % scale) + scale) % scale
        val half_visible_world = (content_height() / 2.0).coerceAtMost(scale / 2.0)
        val clamped_y = center_y.coerceIn(half_visible_world, scale - half_visible_world)
        val center = world_to_lat_lon(wrapped_x, clamped_y, zoom)
        manual_center_lat = center.lat
        manual_center_lon = center.lon
        following_location = false
    }

    private fun apply_debug_perf_target_focus_if_needed() {
        if (!debug_perf_viewport_active || !debug_perf_focus_open_map || debug_perf_focus_applied) return
        val target_lat = debug_perf_target_lat ?: return
        val target_lon = debug_perf_target_lon ?: return
        val w = content_width()
        val h = content_height()
        if (w <= 1f || h <= 1f) return
        val target_world = lat_lon_to_world(target_lat, target_lon, zoom)
        val focus = debug_perf_focus_point(w, h) ?: default_map_focus(w, h)
        set_manual_center_from_world(
            target_world.x + w / 2.0 - focus.x,
            target_world.y + h / 2.0 - focus.y
        )
        debug_perf_focus_applied = true
        Log.i(
            TAG,
            "Debug perf focus anchored targetLat=$target_lat targetLon=$target_lon " +
                "focusX=${focus.x} focusY=${focus.y} manualLat=$manual_center_lat manualLon=$manual_center_lon"
        )
    }

    private fun debug_perf_focus_point(w: Float, h: Float): ScreenPoint? {
        if (!debug_perf_viewport_active) return null
        val focus_x_fraction = debug_perf_focus_x_fraction
        val focus_y_fraction = debug_perf_focus_y_fraction
        if (focus_x_fraction != null && focus_y_fraction != null) {
            return ScreenPoint(
                (w * focus_x_fraction).toFloat().coerceIn(0f, w),
                (h * focus_y_fraction).toFloat().coerceIn(0f, h)
            )
        }
        return if (debug_perf_focus_open_map) default_map_focus(w, h) else null
    }

    private fun is_overlay_or_control_hit(x: Float, y: Float): Boolean {
        if (settings_open || details_block_map_interaction() || priority_tracker_open || filters_open) return true
        if (debug_perf_hides_chrome()) return false
        val w = content_width()
        val h = content_height()
        return (!following_location && recenter_button_bounds(w, h).contains(x, y)) ||
            (should_show_path_button(viewport_for(latest_location ?: return true, w, h)) && flight_path_button_bounds(w, h).contains(x, y)) ||
            (should_show_previous_flights_button() && previous_flights_button_bounds(w, h).contains(x, y)) ||
            (should_show_clear_path_button() && clear_flight_path_button_bounds(w, h).contains(x, y)) ||
            settings_button_bounds(w, h).contains(x, y) ||
            filters_button_bounds(w, h).contains(x, y) ||
            info_panel_bounds(w, h).contains(x, y) ||
            top_status_bounds(w, h).contains(x, y)
    }

