object MapProjection {
    fun distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double {
        val result = FloatArray(1)
        Location.distanceBetween(lat1, lon1, lat2, lon2, result)
        return result[0].toDouble()
    }

    fun meters_per_pixel_at(latitude: Double, zoom: Double): Double {
        return cos(Math.toRadians(latitude.coerceIn(-85.0, 85.0))) *
            EARTH_CIRCUMFERENCE_M /
            (TILE_SIZE * 2.0.pow(zoom))
    }

    fun lat_lon_to_world(lat: Double, lon: Double, zoom: Double): WorldPoint {
        val scale = TILE_SIZE * 2.0.pow(zoom)
        val sin_lat = sin(Math.toRadians(lat.coerceIn(MERCATOR_MIN_LAT, MERCATOR_MAX_LAT)))
        val x = (lon + 180.0) / 360.0 * scale
        val y = (0.5 - ln((1.0 + sin_lat) / (1.0 - sin_lat)) / (4.0 * Math.PI)) * scale
        return WorldPoint(x, y)
    }

    fun world_to_lat_lon(x: Double, y: Double, zoom: Double): GeoPoint {
        val scale = TILE_SIZE * 2.0.pow(zoom)
        val lon = x / scale * 360.0 - 180.0
        val n = Math.PI - 2.0 * Math.PI * y / scale
        val lat = Math.toDegrees(atan(sinh(n)))
        return GeoPoint(lat.coerceIn(MERCATOR_MIN_LAT, MERCATOR_MAX_LAT), normalize_longitude(lon))
    }

    fun destination_point(lat: Double, lon: Double, bearing_deg: Double, distance_m: Double): GeoPoint {
        val angular_distance = distance_m / EARTH_RADIUS_M
        val bearing = Math.toRadians(bearing_deg)
        val lat1 = Math.toRadians(lat)
        val lon1 = Math.toRadians(lon)
        val lat2 = asin(sin(lat1) * cos(angular_distance) + cos(lat1) * sin(angular_distance) * cos(bearing))
        val lon2 = lon1 + atan2(
            sin(bearing) * sin(angular_distance) * cos(lat1),
            cos(angular_distance) - sin(lat1) * sin(lat2)
        )
        return GeoPoint(Math.toDegrees(lat2), normalize_longitude(Math.toDegrees(lon2)))
    }

    fun normalize_longitude(lon: Double): Double {
        return ((lon + 180.0) % 360.0 + 360.0) % 360.0 - 180.0
    }

    const val EARTH_CIRCUMFERENCE_M = 40075016.686

    private const val EARTH_RADIUS_M = 6371000.0
    private const val TILE_SIZE = 256.0
    private const val MERCATOR_MIN_LAT = -85.05112878
    private const val MERCATOR_MAX_LAT = 85.05112878
}

// endregion

// region LAYOUT, PANELS, AND MEDIA

data class FlightMapLayoutState(
    val following_location: Boolean,
    val has_location: Boolean,
    val has_selected_flight_path: Boolean,
    val show_previous_flights: Boolean
)

// Owns map and panel geometry so FlightMapView can ask where things go without doing rectangle math inline.
class FlightMapLayout(private val scale_dp: (Float) -> Float) {
    // Keep the top status clear of the traffic card on wide screens and full-width on narrow screens.
    fun top_status_bounds(w: Float, h: Float): RectF {
        val left = dp(12)
        val top = dp(12)
        val right = if (is_wide_layout(w, h)) {
            min(info_panel_bounds(w, h).left - dp(12), left + dp(620))
        } else {
            w - dp(12)
        }
        return RectF(left, top, right, top + dp(66))
    }

    // Context controls share one row or stack above the toolbar when width gets tight.
    fun recenter_button_bounds(w: Float, h: Float, state: FlightMapLayoutState): RectF {
        val slot = if (state.has_selected_flight_path) 1 else 0
        return context_button_bounds(w, h, slot)
    }

    fun flight_path_button_bounds(w: Float, h: Float): RectF {
        return context_button_bounds(w, h, 0)
    }

    fun previous_flights_button_bounds(w: Float, h: Float, state: FlightMapLayoutState): RectF {
        var slot = 0
        if (state.has_selected_flight_path) slot++
        if (!state.following_location && state.has_location) slot++
        return context_button_bounds(w, h, slot)
    }

    fun clear_flight_path_button_bounds(w: Float, h: Float, state: FlightMapLayoutState): RectF {
        var slot = 0
        if (state.has_selected_flight_path) slot++
        if (!state.following_location && state.has_location) slot++
        if (state.show_previous_flights) slot++
        return context_button_bounds(w, h, slot)
    }

    // Slot-based context buttons let recenter/path/history/clear appear without overlapping filters.
    fun context_button_bounds(w: Float, h: Float, slot: Int): RectF {
        val anchor = filters_button_bounds(w, h)
        val size = dp(44)
        val gap = dp(10)
        val left = anchor.right + gap + slot * (size + gap)
        return if (left + size <= w - dp(12)) {
            RectF(left, anchor.top, left + size, anchor.top + size)
        } else {
            val stacked_left = anchor.left + slot * (size + gap)
            val top = anchor.top - size - gap
            RectF(stacked_left, top, stacked_left + size, top + size)
        }
    }

    fun settings_button_bounds(w: Float, h: Float): RectF {
        val info = info_panel_bounds(w, h)
        val width = dp(84)
        val height = dp(44)
        val x = dp(12)
        val y = if (is_wide_layout(w, h)) h - height - dp(14) else info.top - height - dp(12)
        return RectF(x, y, x + width, y + height)
    }

    fun filters_button_bounds(w: Float, h: Float): RectF {
        val settings = settings_button_bounds(w, h)
        val gap = dp(10)
        val width = dp(84)
        return RectF(settings.right + gap, settings.top, settings.right + gap + width, settings.bottom)
    }

    // Settings panel changes shape for landscape-short devices before it starts clipping.
    fun settings_panel_bounds(w: Float, h: Float): RectF {
        val compact = w > h && h < dp(500)
        val narrow_portrait = !compact && w < dp(430)
        val width = if (compact) min(w - dp(24), dp(860)) else min(w - dp(32), dp(430))
        val height = when {
            compact -> min(h - dp(16), dp(320))
            narrow_portrait -> h - dp(32)
            else -> min(h - dp(32), dp(660))
        }
        val top = max(if (compact) dp(8) else dp(16), (h - height) / 2f)
        return RectF((w - width) / 2f, top, (w + width) / 2f, top + height)
    }

    private fun display_setting_button_bounds(panel: RectF, compact_top_dp: Int, portrait_top_dp: Int): RectF {
        if (is_compact_settings_panel(panel)) {
            val column = compact_settings_display_column(panel)
            val top = panel.top + dp(compact_top_dp)
            return RectF(column.left, top, column.right, top + dp(30))
        }
        val top = panel.top + dp(portrait_top_dp)
        return RectF(panel.left + dp(18), top, panel.right - dp(18), top + dp(34))
    }

    private fun map_setting_button_bounds(
        panel: RectF,
        wide_compact_top_dp: Int,
        narrow_compact_top_dp: Int,
        portrait_top_dp: Int
    ): RectF {
        if (is_compact_settings_panel(panel)) {
            val column = compact_settings_map_column(panel)
            val top_dp = if (is_wide_settings_hub_panel(panel)) wide_compact_top_dp else narrow_compact_top_dp
            val top = panel.top + dp(top_dp)
            return RectF(column.left, top, column.right, top + dp(30))
        }
        val top = panel.top + dp(portrait_top_dp)
        return RectF(panel.left + dp(18), top, panel.right - dp(18), top + dp(34))
    }

    private fun safety_setting_button_bounds(panel: RectF, compact_top_dp: Int, portrait_top_dp: Int): RectF {
        if (is_compact_settings_panel(panel)) {
            val column = compact_settings_safety_column(panel)
            val top = panel.top + dp(compact_top_dp)
            return RectF(column.left, top, column.right, top + dp(30))
        }
        val top = panel.top + dp(portrait_top_dp)
        return RectF(panel.left + dp(18), top, panel.right - dp(18), top + dp(34))
    }

    fun imperial_button_bounds(panel: RectF): RectF =
        display_setting_button_bounds(panel, compact_top_dp = 66, portrait_top_dp = 88)

    fun metric_button_bounds(panel: RectF): RectF =
        display_setting_button_bounds(panel, compact_top_dp = 102, portrait_top_dp = 130)

    fun close_button_bounds(panel: RectF): RectF {
        return RectF(panel.right - dp(112), panel.top + dp(14), panel.right - dp(18), panel.top + dp(48))
    }

    fun map_source_button_bounds(panel: RectF): RectF =
        map_setting_button_bounds(panel, wide_compact_top_dp = 66, narrow_compact_top_dp = 190, portrait_top_dp = 244)

    fun map_labels_button_bounds(panel: RectF): RectF =
        map_setting_button_bounds(panel, wide_compact_top_dp = 102, narrow_compact_top_dp = 220, portrait_top_dp = 284)

    fun globe_bin_craft_source_button_bounds(panel: RectF): RectF =
        map_setting_button_bounds(panel, wide_compact_top_dp = 138, narrow_compact_top_dp = 250, portrait_top_dp = 324)

    fun aviation_layers_button_bounds(panel: RectF): RectF =
        map_setting_button_bounds(panel, wide_compact_top_dp = 174, narrow_compact_top_dp = 280, portrait_top_dp = 364)

    fun theme_button_bounds(panel: RectF): RectF =
        display_setting_button_bounds(panel, compact_top_dp = 138, portrait_top_dp = 168)

    fun alerts_toggle_bounds(panel: RectF): RectF =
        safety_setting_button_bounds(panel, compact_top_dp = 66, portrait_top_dp = 452)

    fun alert_distance_minus_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            adjuster_minus_bounds(priority_alert_control_area(panel), panel.top + dp(132))
        } else {
            adjuster_minus_bounds(panel, panel.top + dp(178))
        }
    }

    fun alert_distance_plus_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            adjuster_plus_bounds(priority_alert_control_area(panel), panel.top + dp(132))
        } else {
            adjuster_plus_bounds(panel, panel.top + dp(178))
        }
    }

    fun alert_altitude_minus_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            adjuster_minus_bounds(priority_alert_control_area(panel), panel.top + dp(200))
        } else {
            adjuster_minus_bounds(panel, panel.top + dp(266))
        }
    }

    fun alert_altitude_plus_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            adjuster_plus_bounds(priority_alert_control_area(panel), panel.top + dp(200))
        } else {
            adjuster_plus_bounds(panel, panel.top + dp(266))
        }
    }

    fun priority_tracker_button_bounds(panel: RectF): RectF =
        safety_setting_button_bounds(panel, compact_top_dp = 102, portrait_top_dp = 492)

    fun impact_methodology_button_bounds(panel: RectF): RectF =
        safety_setting_button_bounds(panel, compact_top_dp = 166, portrait_top_dp = 580)

    fun impact_source_button_bounds(panel: RectF, index: Int, source_count: Int): RectF {
        val gap = dp(8)
        val safe_index = index.coerceIn(0, source_count - 1)
        return if (is_compact_settings_panel(panel)) {
            val left = panel.left + dp(18)
            val button_width = (panel.width() - dp(36) - gap * (source_count - 1)) / source_count
            val x = left + safe_index * (button_width + gap)
            RectF(x, panel.bottom - dp(46), x + button_width, panel.bottom - dp(16))
        } else {
            val columns = 3
            val row = safe_index / columns
            val column = safe_index % columns
            val left = panel.left + dp(18)
            val button_width = (panel.width() - dp(36) - gap * (columns - 1)) / columns
            val x = left + column * (button_width + gap)
            val y = panel.bottom - dp(92) + row * (dp(34) + gap)
            RectF(x, y, x + button_width, y + dp(34))
        }
    }

    fun map_street_labels_button_bounds(panel: RectF): RectF {
        if (is_compact_settings_panel(panel)) {
            val left = panel.left + dp(18)
            val right = panel.centerX() - dp(5)
            return RectF(left, panel.top + dp(92), right, panel.top + dp(126))
        }
        return RectF(panel.left + dp(18), panel.top + dp(102), panel.right - dp(18), panel.top + dp(138))
    }

    fun map_borders_button_bounds(panel: RectF): RectF {
        if (is_compact_settings_panel(panel)) {
            val left = panel.centerX() + dp(5)
            val right = panel.right - dp(18)
            return RectF(left, panel.top + dp(92), right, panel.top + dp(126))
        }
        return RectF(panel.left + dp(18), panel.top + dp(148), panel.right - dp(18), panel.top + dp(184))
    }

    fun aviation_layer_status_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            RectF(panel.left + dp(18), panel.top + dp(64), panel.right - dp(18), panel.top + dp(86))
        } else {
            RectF(panel.left + dp(18), panel.top + dp(72), panel.right - dp(18), panel.top + dp(116))
        }
    }

    fun layer_atc_button_bounds(panel: RectF): RectF {
        return layer_toggle_bounds(panel, row = 0, right_column = false)
    }

    fun layer_restricted_button_bounds(panel: RectF): RectF {
        return layer_toggle_bounds(panel, row = if (is_compact_settings_panel(panel)) 0 else 1, right_column = is_compact_settings_panel(panel))
    }

    fun layer_oceanic_button_bounds(panel: RectF): RectF {
        return layer_toggle_bounds(panel, row = if (is_compact_settings_panel(panel)) 1 else 2, right_column = false)
    }

    fun layer_airport_labels_button_bounds(panel: RectF): RectF {
        return layer_toggle_bounds(panel, row = if (is_compact_settings_panel(panel)) 1 else 3, right_column = is_compact_settings_panel(panel))
    }

    // Aviation layer toggles use the same row/column math in compact and portrait panels.
    fun layer_toggle_bounds(panel: RectF, row: Int, right_column: Boolean): RectF {
        return if (is_compact_settings_panel(panel)) {
            val column = if (right_column) compact_settings_right_column(panel) else compact_settings_left_column(panel)
            val top = panel.top + dp(104 + row * 44)
            RectF(column.left, top, column.right, top + dp(32))
        } else {
            val top = panel.top + dp(126 + row * 46)
            RectF(panel.left + dp(18), top, panel.right - dp(18), top + dp(36))
        }
    }

    fun filter_search_box_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            RectF(panel.left + dp(18), panel.top + dp(62), panel.right - dp(210), panel.top + dp(96))
        } else {
            RectF(panel.left + dp(18), panel.top + dp(74), panel.right - dp(18), panel.top + dp(112))
        }
    }

    fun filter_search_find_button_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            RectF(panel.right - dp(200), panel.top + dp(62), panel.right - dp(112), panel.top + dp(96))
        } else {
            RectF(panel.left + dp(18), panel.top + dp(122), panel.centerX() - dp(5), panel.top + dp(156))
        }
    }

    fun filter_search_clear_button_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            RectF(panel.right - dp(102), panel.top + dp(62), panel.right - dp(18), panel.top + dp(96))
        } else {
            RectF(panel.centerX() + dp(5), panel.top + dp(122), panel.right - dp(18), panel.top + dp(156))
        }
    }

    fun filter_aircraft_type_button_bounds(panel: RectF): RectF {
        return filter_button_bounds(panel, row = 0, right_column = false)
    }

    fun filter_altitude_button_bounds(panel: RectF): RectF {
        return filter_button_bounds(panel, row = 1, right_column = false)
    }

    fun filter_distance_button_bounds(panel: RectF): RectF {
        return filter_button_bounds(panel, row = 2, right_column = false)
    }

    fun filter_status_button_bounds(panel: RectF): RectF {
        return filter_button_bounds(panel, row = if (is_compact_settings_panel(panel)) 0 else 3, right_column = is_compact_settings_panel(panel))
    }

    fun filter_age_button_bounds(panel: RectF): RectF {
        return filter_button_bounds(panel, row = if (is_compact_settings_panel(panel)) 1 else 4, right_column = is_compact_settings_panel(panel))
    }

    fun filter_alert_button_bounds(panel: RectF): RectF {
        return filter_button_bounds(panel, row = if (is_compact_settings_panel(panel)) 2 else 5, right_column = is_compact_settings_panel(panel))
    }

    fun filter_reset_button_bounds(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            RectF(panel.right - dp(126), panel.bottom - dp(52), panel.right - dp(18), panel.bottom - dp(22))
        } else {
            RectF(panel.left + dp(18), panel.bottom - dp(74), panel.right - dp(18), panel.bottom - dp(38))
        }
    }

    // Filter rows share spacing math so search, reset, and every toggle stay visible together.
    fun filter_button_bounds(panel: RectF, row: Int, right_column: Boolean): RectF {
        return if (is_compact_settings_panel(panel)) {
            val column = if (right_column) compact_settings_right_column(panel) else compact_settings_left_column(panel)
            val top = panel.top + dp(120 + row * 46)
            RectF(column.left, top, column.right, top + dp(32))
        } else {
            val row_height = dp(36)
            val start = filter_search_clear_button_bounds(panel).bottom + dp(20)
            val reset_top = filter_reset_button_bounds(panel).top
            val available = (reset_top - start - row_height * 6).coerceAtLeast(dp(30))
            val gap = (available / 5f).coerceIn(dp(6), dp(16))
            val top = start + row * (row_height + gap)
            RectF(panel.left + dp(18), top, panel.right - dp(18), top + row_height)
        }
    }

    // Priority tracker reuses the settings modal size so safety controls do not introduce another layout mode.
    fun priority_tracker_panel_bounds(w: Float, h: Float): RectF {
        return settings_panel_bounds(w, h)
    }

    fun priority_close_button_bounds(panel: RectF): RectF {
        return RectF(panel.right - dp(112), panel.top + dp(14), panel.right - dp(18), panel.top + dp(48))
    }

    fun priority_tracking_toggle_bounds(panel: RectF): RectF {
        val gap = dp(10)
        if (is_compact_settings_panel(panel)) {
            val left = compact_settings_left_column(panel)
            val right = left.left + (left.width() - gap) / 2f
            return RectF(left.left, panel.top + dp(66), right, panel.top + dp(96))
        }
        val left = panel.left + dp(18)
        val right = panel.centerX() - gap / 2f
        return RectF(left, panel.top + dp(72), right, panel.top + dp(110))
    }

    fun priority_ring_toggle_bounds(panel: RectF): RectF {
        val gap = dp(10)
        if (is_compact_settings_panel(panel)) {
            val left = compact_settings_left_column(panel)
            val button_left = left.left + (left.width() + gap) / 2f
            return RectF(button_left, panel.top + dp(66), left.right, panel.top + dp(96))
        }
        val button_left = panel.centerX() + gap / 2f
        return RectF(button_left, panel.top + dp(72), panel.right - dp(18), panel.top + dp(110))
    }

    // Compact settings means short landscape: use columns before shrinking text or clipping controls.
    fun is_compact_settings_panel(panel: RectF): Boolean {
        return panel.width() >= dp(520) && panel.height() < dp(380)
    }

    fun is_wide_settings_hub_panel(panel: RectF): Boolean {
        return is_compact_settings_panel(panel) && panel.width() >= dp(760)
    }

    fun compact_settings_display_column(panel: RectF): RectF {
        return if (is_wide_settings_hub_panel(panel)) compact_settings_hub_column(panel, 0) else compact_settings_left_column(panel)
    }

    fun compact_settings_map_column(panel: RectF): RectF {
        return if (is_wide_settings_hub_panel(panel)) compact_settings_hub_column(panel, 1) else compact_settings_left_column(panel)
    }

    fun compact_settings_safety_column(panel: RectF): RectF {
        return if (is_wide_settings_hub_panel(panel)) compact_settings_hub_column(panel, 2) else compact_settings_right_column(panel)
    }

    private fun compact_settings_hub_column(panel: RectF, index: Int): RectF {
        val gap = dp(14)
        val left = panel.left + dp(18)
        val width = (panel.width() - dp(36) - gap * 2f) / 3f
        val x = left + index.coerceIn(0, 2) * (width + gap)
        return RectF(x, panel.top, x + width, panel.bottom)
    }

    fun compact_settings_left_column(panel: RectF): RectF {
        return RectF(panel.left + dp(18), panel.top, panel.left + panel.width() * 0.49f, panel.bottom)
    }

    fun compact_settings_right_column(panel: RectF): RectF {
        return RectF(panel.left + panel.width() * 0.54f, panel.top, panel.right - dp(18), panel.bottom)
    }

    // Priority alert steppers live in the left column when the modal is split into compact columns.
    fun priority_alert_control_area(panel: RectF): RectF {
        return if (is_compact_settings_panel(panel)) {
            RectF(panel.left, panel.top, panel.left + panel.width() * 0.49f, panel.bottom)
        } else {
            panel
        }
    }

    fun adjuster_minus_bounds(panel: RectF, top: Float): RectF {
        return RectF(panel.left + dp(18), top, panel.left + dp(72), top + dp(38))
    }

    fun adjuster_plus_bounds(panel: RectF, top: Float): RectF {
        return RectF(panel.right - dp(72), top, panel.right - dp(18), top + dp(38))
    }

    // The traffic panel anchors opposite the top/status controls and becomes a bottom card in portrait.
    fun info_panel_bounds(w: Float, h: Float): RectF {
        val margin = dp(12)
        return if (is_wide_layout(w, h)) {
            val panel_width = min(dp(360), max(dp(300), w * 0.32f))
            RectF(w - margin - panel_width, margin, w - margin, h - margin)
        } else {
            val panel_height = min(dp(176), max(dp(152), h * 0.24f))
            RectF(margin, h - margin - panel_height, w - margin, h - margin)
        }
    }

    // Following mode centers the user in the largest open map area, not necessarily the physical screen center.
    fun default_map_focus(w: Float, h: Float, state: FlightMapLayoutState): ScreenPoint {
        val open = largest_unblocked_map_rect(w, h, state)
        return ScreenPoint(open.centerX(), open.centerY())
    }

    // Find the largest rectangle not covered by cockpit UI so map fitting avoids panels and controls.
    fun largest_unblocked_map_rect(w: Float, h: Float, state: FlightMapLayoutState): RectF {
        val obstacles = map_obstacles(w, h, state)
        val xs = mutableListOf(0f, w)
        val ys = mutableListOf(0f, h)
        obstacles.forEach {
            xs += it.left.coerceIn(0f, w)
            xs += it.right.coerceIn(0f, w)
            ys += it.top.coerceIn(0f, h)
            ys += it.bottom.coerceIn(0f, h)
        }
        val sorted_x = xs.distinct().sorted()
        val sorted_y = ys.distinct().sorted()
        var best = RectF(0f, 0f, w, h)
        var best_area = -1f
        for (left_index in sorted_x.indices) {
            for (right_index in left_index + 1 until sorted_x.size) {
                for (top_index in sorted_y.indices) {
                    for (bottom_index in top_index + 1 until sorted_y.size) {
                        val candidate = RectF(sorted_x[left_index], sorted_y[top_index], sorted_x[right_index], sorted_y[bottom_index])
                        val area = candidate.width() * candidate.height()
                        if (area <= best_area) continue
                        if (obstacles.none { RectF.intersects(candidate, it) }) {
                            best = candidate
                            best_area = area
                        }
                    }
                }
            }
        }
        return best
    }

    // Obstacles are the UI rectangles that map focus, labels, and path fitting should avoid.
    fun map_obstacles(w: Float, h: Float, state: FlightMapLayoutState): List<RectF> {
        val items = mutableListOf(
            top_status_bounds(w, h),
            info_panel_bounds(w, h),
            settings_button_bounds(w, h),
            filters_button_bounds(w, h)
        )
        if (!state.following_location && state.has_location) items += recenter_button_bounds(w, h, state)
        return items
    }

    fun is_wide_layout(w: Float, h: Float): Boolean = w > h * 1.15f

    private fun dp(value: Int): Float = dp(value.toFloat())

    private fun dp(value: Float): Float = scale_dp(value)
}


data class FlightMapPanelStyle(val visual_theme: VisualTheme)

data class SettingsPanelState(
    val units: UnitSystem,
    val map_source: TileSource,
    val map_labels_enabled: Boolean,
    val map_borders_enabled: Boolean,
    val aircraft_feed_mode: AircraftFeedMode,
    val aviation_layers_enabled: Boolean,
    val alerts_enabled: Boolean,
    val priority_tracking_enabled: Boolean,
    val map_attribution: String,
    val aircraft_source_label: String
)

data class MapLabelsPanelState(
    val street_labels_enabled: Boolean,
    val borders_enabled: Boolean
)

data class AviationLayersPanelState(
    val status_text: String,
    val snapshot: AviationLayerSnapshot?,
    val fetch_in_flight: Boolean,
    val atc_boundaries_enabled: Boolean,
    val restricted_airspaces_enabled: Boolean,
    val oceanic_tracks_enabled: Boolean,
    val airport_labels_enabled: Boolean
)

data class ImpactMethodologyPanelState(
    val source_labels: List<String>
)

data class FiltersPanelState(
    val filter_search_query: String,
    val filter_search_focused: Boolean,
    val aircraft_type_filter: AircraftTypeFilter,
    val altitude_filter: AltitudeFilter,
    val distance_filter: DistanceFilter,
    val flight_status_filter: FlightStatusFilter,
    val report_age_filter: ReportAgeFilter,
    val alert_volume_filter: Boolean,
    val filters_active: Boolean,
    val stats_summary: String
)

data class PriorityAircraftPanelRow(
    val title: String,
    val altitude: String,
    val detail: String,
    val is_extreme: Boolean
)

data class PriorityTrackerPanelState(
    val priority_tracking_enabled: Boolean,
    val priority_range_circle_visible: Boolean,
    val alert_distance_label: String,
    val alert_altitude_label: String,
    val aircraft_rows: List<PriorityAircraftPanelRow>,
    val long_press_fill: PriorityRangeButtonFillState? = null
)

enum class PriorityRangeAdjustButton {
    DISTANCE_MINUS,
    DISTANCE_PLUS,
    ALTITUDE_MINUS,
    ALTITUDE_PLUS
}

data class PriorityRangeButtonFillState(
    val button: PriorityRangeAdjustButton,
    val press_x: Float,
    val press_y: Float,
    val started_ms: Long,
    val duration_ms: Long
)

interface FlightMapPanelChrome {
    val layout: FlightMapLayout

    fun dp(value: Float): Float
    fun sp(value: Float): Float
    fun ellipsize(value: String, max_width: Float): String
    fun control_radius(): Float
    fun draw_panel_surface(canvas: Canvas, rect: RectF, fill: Int, alpha: Int)
    fun draw_choice_button(canvas: Canvas, rect: RectF, label: String, selected: Boolean)
    fun draw_control_surface(canvas: Canvas, rect: RectF, fill: Int, stroke: Int, selected: Boolean)
    fun draw_wrapped_text(canvas: Canvas, value: String, x: Float, y: Float, width: Float, max_lines: Int): Float
    fun request_animation_frame()
}

// Draws settings, filters, layers, methodology, and priority panels from prepared state snapshots.
class FlightMapPanelRenderer(
    private val paint: Paint,
    private val stroke_paint: Paint,
    private val text_paint: Paint,
    private val chrome: FlightMapPanelChrome
) {
    private val long_press_fill_clip = Path()

    // Draw the main settings hub; subpanels own detailed choices but share this modal shell.
    fun draw_settings_panel(canvas: Canvas, w: Float, h: Float, style: FlightMapPanelStyle, state: SettingsPanelState) {
        paint.style = Paint.Style.FILL
        val rect = chrome.layout.settings_panel_bounds(w, h)
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)

        draw_panel_title(canvas, rect, "Settings", style)
        chrome.draw_choice_button(canvas, chrome.layout.close_button_bounds(rect), "Close", false)

        if (chrome.layout.is_compact_settings_panel(rect)) {
            draw_compact_settings_panel_contents(canvas, rect, style, state)
            return
        }

        draw_settings_section_label(canvas, rect.left + dp(18), rect.top + dp(74), "Display", style)
        chrome.draw_choice_button(canvas, chrome.layout.imperial_button_bounds(rect), "Miles / feet", state.units == UnitSystem.IMPERIAL)
        chrome.draw_choice_button(canvas, chrome.layout.metric_button_bounds(rect), "Kilometers / meters", state.units == UnitSystem.METRIC)
        chrome.draw_choice_button(canvas, chrome.layout.theme_button_bounds(rect), "Theme: ${style.visual_theme.display_name}", true)

        draw_settings_section_label(canvas, rect.left + dp(18), rect.top + dp(230), "Map", style)
        chrome.draw_choice_button(
            canvas,
            chrome.layout.map_source_button_bounds(rect),
            if (state.map_source == TileSource.SATELLITE) "Satellite map" else "Street map",
            state.map_source == TileSource.SATELLITE
        )
        chrome.draw_choice_button(canvas, chrome.layout.map_labels_button_bounds(rect), map_labels_button_label(state, compact = false), state.map_labels_enabled || state.map_borders_enabled)
        chrome.draw_choice_button(canvas, chrome.layout.globe_bin_craft_source_button_bounds(rect), state.aircraft_feed_mode.display_name, true)
        chrome.draw_choice_button(canvas, chrome.layout.aviation_layers_button_bounds(rect), "Aviation layers", state.aviation_layers_enabled)

        draw_settings_section_label(canvas, rect.left + dp(18), rect.top + dp(438), "Safety", style)
        chrome.draw_choice_button(canvas, chrome.layout.alerts_toggle_bounds(rect), if (state.alerts_enabled) "Hazard alerts on" else "Hazard alerts off", state.alerts_enabled)
        chrome.draw_choice_button(canvas, chrome.layout.priority_tracker_button_bounds(rect), "Notification range and tracker", state.priority_tracking_enabled)

        draw_settings_section_label(canvas, rect.left + dp(18), rect.top + dp(566), "Reference", style)
        chrome.draw_choice_button(canvas, chrome.layout.impact_methodology_button_bounds(rect), "Impact methodology", false)

        val footer_top = rect.bottom - dp(38)
        if (chrome.layout.impact_methodology_button_bounds(rect).bottom + dp(24) <= footer_top) {
            text_paint.textAlign = Paint.Align.LEFT
            text_paint.isFakeBoldText = false
            text_paint.textSize = sp(11)
            text_paint.color = style.visual_theme.colors.muted
            draw_fitted_left_text(canvas, "Map: ${state.map_attribution}", rect.left + dp(18), rect.bottom - dp(38), rect.width() - dp(36), sp(11), sp(9))
            val source_label = "Aircraft: ${state.aircraft_source_label}; paths: live trace sources"
            canvas.drawText(chrome.ellipsize(source_label, rect.width() - dp(36)), rect.left + dp(18), rect.bottom - dp(18), text_paint)
        }
    }

    // Draw map-label provider choices without implying label tiles are available for every map source.
    fun draw_map_labels_panel(canvas: Canvas, w: Float, h: Float, style: FlightMapPanelStyle, state: MapLabelsPanelState) {
        val rect = chrome.layout.settings_panel_bounds(w, h)
        val compact = chrome.layout.is_compact_settings_panel(rect)
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)

        draw_panel_title(canvas, rect, "Map labels", style)
        chrome.draw_choice_button(canvas, chrome.layout.close_button_bounds(rect), "Back", false)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = if (compact) sp(11) else sp(12)
        text_paint.color = style.visual_theme.colors.muted
        val label_y = if (compact) rect.top + dp(74) else rect.top + dp(82)
        canvas.drawText("Label layers", rect.left + dp(18), label_y, text_paint)

        chrome.draw_choice_button(canvas, chrome.layout.map_street_labels_button_bounds(rect), "Street labels", state.street_labels_enabled)
        chrome.draw_choice_button(canvas, chrome.layout.map_borders_button_bounds(rect), if (compact) "Borders" else "Countries + borders", state.borders_enabled)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = if (compact) sp(10) else sp(11)
        text_paint.color = style.visual_theme.colors.muted
        val source_y = if (compact) rect.top + dp(154) else rect.top + dp(216)
        val source_text = when {
            state.street_labels_enabled && state.borders_enabled -> "Current: street labels plus countries and borders"
            state.street_labels_enabled -> "Current: street labels only"
            state.borders_enabled -> "Current: countries and borders only"
            else -> "Current: no-label base where available"
        }
        draw_fitted_left_text(canvas, source_text, rect.left + dp(18), source_y, rect.width() - dp(36), text_paint.textSize, sp(8))
    }

    // Draw aviation layer toggles with source status visible before any layer is treated as available.
    fun draw_aviation_layers_panel(canvas: Canvas, w: Float, h: Float, style: FlightMapPanelStyle, state: AviationLayersPanelState) {
        val rect = chrome.layout.settings_panel_bounds(w, h)
        val compact = chrome.layout.is_compact_settings_panel(rect)
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)

        draw_panel_title(canvas, rect, "Layers", style)
        chrome.draw_choice_button(canvas, chrome.layout.close_button_bounds(rect), "Back", false)

        val status_rect = chrome.layout.aviation_layer_status_bounds(rect)
        text_paint.isFakeBoldText = false
        text_paint.textSize = if (compact) sp(10) else sp(11)
        text_paint.color = style.visual_theme.colors.muted
        chrome.draw_wrapped_text(canvas, state.status_text, status_rect.left, status_rect.top, status_rect.width(), max_lines = if (compact) 1 else 2)

        draw_layer_toggle_button(canvas, chrome.layout.layer_atc_button_bounds(rect), "ATC boundaries", state.atc_boundaries_enabled, AviationLayerKind.ATC_BOUNDARIES, state)
        draw_layer_toggle_button(canvas, chrome.layout.layer_restricted_button_bounds(rect), "Restricted airspace", state.restricted_airspaces_enabled, AviationLayerKind.RESTRICTED_AIRSPACES, state)
        draw_layer_toggle_button(canvas, chrome.layout.layer_oceanic_button_bounds(rect), "Oceanic tracks", state.oceanic_tracks_enabled, AviationLayerKind.OCEANIC_TRACKS, state)
        draw_layer_toggle_button(canvas, chrome.layout.layer_airport_labels_button_bounds(rect), "Airport labels", state.airport_labels_enabled, AviationLayerKind.AIRPORTS, state)
    }

    // Draw methodology text and source buttons so impact numbers remain explained and auditable.
    fun draw_impact_methodology_panel(canvas: Canvas, w: Float, h: Float, style: FlightMapPanelStyle, state: ImpactMethodologyPanelState) {
        val rect = chrome.layout.settings_panel_bounds(w, h)
        val compact = chrome.layout.is_compact_settings_panel(rect)
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)

        draw_panel_title(canvas, rect, "Impact methodology", style)
        chrome.draw_choice_button(canvas, chrome.layout.close_button_bounds(rect), "Back", false)

        val items = impact_methodology_items()
        if (compact) {
            val left = RectF(rect.left + dp(18), rect.top + dp(64), rect.centerX() - dp(10), rect.bottom - dp(62))
            val right = RectF(rect.centerX() + dp(10), left.top, rect.right - dp(18), left.bottom)
            draw_methodology_column(canvas, left, items.take(3), style)
            draw_methodology_column(canvas, right, items.drop(3), style)
        } else {
            var y = rect.top + dp(72)
            val text_rect = RectF(rect.left + dp(18), y, rect.right - dp(18), rect.bottom - dp(104))
            items.forEach { item ->
                y = draw_methodology_item(canvas, text_rect, y, item.first, item.second, max_lines = 3, style)
            }
        }

        state.source_labels.forEachIndexed { index, label ->
            chrome.draw_choice_button(canvas, chrome.layout.impact_source_button_bounds(rect, index, state.source_labels.size), label, false)
        }
    }

    // Draw filters as explicit live-traffic filters, including search focus and current match summary.
    fun draw_filters_panel(canvas: Canvas, w: Float, h: Float, style: FlightMapPanelStyle, state: FiltersPanelState) {
        paint.style = Paint.Style.FILL
        val rect = chrome.layout.settings_panel_bounds(w, h)
        val compact = chrome.layout.is_compact_settings_panel(rect)
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)

        draw_panel_title(canvas, rect, "Filters", style)
        chrome.draw_choice_button(canvas, chrome.layout.close_button_bounds(rect), "Close", false)

        draw_filter_search_control(canvas, rect, style, state)

        if (compact) {
            draw_compact_filters_panel_contents(canvas, rect, state)
        } else {
            draw_portrait_filters_panel_contents(canvas, rect, state)
        }

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(if (compact) 10 else 11)
        text_paint.color = style.visual_theme.colors.muted
        val stats_y = if (compact) rect.bottom - dp(18) else rect.bottom - dp(22)
        draw_fitted_left_text(canvas, state.stats_summary, rect.left + dp(18), stats_y, rect.width() - dp(36), text_paint.textSize, sp(8))
    }

    // Draw alert-volume controls and the current priority queue without inventing aircraft status.
    fun draw_priority_tracker_panel(canvas: Canvas, w: Float, h: Float, style: FlightMapPanelStyle, state: PriorityTrackerPanelState) {
        paint.style = Paint.Style.FILL
        val rect = chrome.layout.priority_tracker_panel_bounds(w, h)
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel_alt, style.visual_theme.style.modal_panel_alpha)

        draw_panel_title(canvas, rect, "Notification range", style)
        chrome.draw_choice_button(canvas, chrome.layout.priority_close_button_bounds(rect), "Close", false)

        if (chrome.layout.is_compact_settings_panel(rect)) {
            draw_compact_priority_tracker_contents(canvas, rect, style, state)
            return
        }

        chrome.draw_choice_button(
            canvas,
            chrome.layout.priority_tracking_toggle_bounds(rect),
            if (state.priority_tracking_enabled) "Queue on" else "Queue off",
            state.priority_tracking_enabled
        )
        chrome.draw_choice_button(
            canvas,
            chrome.layout.priority_ring_toggle_bounds(rect),
            if (state.priority_range_circle_visible) "Alert ring on" else "Alert ring off",
            state.priority_range_circle_visible
        )

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText("Notification range", rect.left + dp(18), rect.top + dp(136), text_paint)
        draw_adjuster_row(
            canvas,
            rect,
            rect.top + dp(162),
            "Horizontal",
            state.alert_distance_label,
            chrome.layout.alert_distance_minus_bounds(rect),
            chrome.layout.alert_distance_plus_bounds(rect),
            style,
            state.long_press_fill,
            PriorityRangeAdjustButton.DISTANCE_MINUS,
            PriorityRangeAdjustButton.DISTANCE_PLUS
        )
        draw_adjuster_row(
            canvas,
            rect,
            rect.top + dp(250),
            "Vertical",
            state.alert_altitude_label,
            chrome.layout.alert_altitude_minus_bounds(rect),
            chrome.layout.alert_altitude_plus_bounds(rect),
            style,
            state.long_press_fill,
            PriorityRangeAdjustButton.ALTITUDE_MINUS,
            PriorityRangeAdjustButton.ALTITUDE_PLUS
        )

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText("Aircraft in queue", rect.left + dp(18), rect.top + dp(344), text_paint)

        if (state.aircraft_rows.isEmpty()) {
            text_paint.isFakeBoldText = true
            text_paint.textSize = sp(17)
            text_paint.color = style.visual_theme.colors.text
            draw_fitted_left_text(
                canvas,
                if (state.priority_tracking_enabled) "No aircraft in queue" else "Queue is off",
                rect.left + dp(18),
                rect.top + dp(386),
                rect.width() - dp(36),
                sp(17),
                sp(10)
            )
            text_paint.isFakeBoldText = false
            return
        }

        var y = rect.top + dp(382)
        state.aircraft_rows.take(PRIORITY_PANEL_ROWS).forEach { item ->
            y = draw_priority_aircraft_row(canvas, rect, y, item, style)
        }
        if (state.aircraft_rows.size > PRIORITY_PANEL_ROWS) {
            text_paint.textAlign = Paint.Align.LEFT
            text_paint.isFakeBoldText = false
            text_paint.textSize = sp(11)
            text_paint.color = style.visual_theme.colors.muted
            draw_fitted_left_text(canvas, "+${state.aircraft_rows.size - PRIORITY_PANEL_ROWS} more", rect.left + dp(18), y + dp(8), rect.width() - dp(36), sp(11), sp(8))
        }
    }

    // Compact settings splits display/map and safety/reference into columns instead of clipping controls.
    private fun draw_compact_settings_panel_contents(canvas: Canvas, rect: RectF, style: FlightMapPanelStyle, state: SettingsPanelState) {
        val display = chrome.layout.compact_settings_display_column(rect)
        val map = chrome.layout.compact_settings_map_column(rect)
        val safety = chrome.layout.compact_settings_safety_column(rect)
        val wide = chrome.layout.is_wide_settings_hub_panel(rect)

        draw_settings_section_label(canvas, display.left, rect.top + dp(58), "Display", style)
        chrome.draw_choice_button(canvas, chrome.layout.imperial_button_bounds(rect), "Miles / feet", state.units == UnitSystem.IMPERIAL)
        chrome.draw_choice_button(canvas, chrome.layout.metric_button_bounds(rect), "Kilometers / meters", state.units == UnitSystem.METRIC)
        chrome.draw_choice_button(canvas, chrome.layout.theme_button_bounds(rect), "Theme: ${style.visual_theme.short_name}", true)

        draw_settings_section_label(canvas, map.left, rect.top + dp(if (wide) 58 else 184), "Map", style)
        chrome.draw_choice_button(
            canvas,
            chrome.layout.map_source_button_bounds(rect),
            if (state.map_source == TileSource.SATELLITE) "Satellite" else "Street",
            state.map_source == TileSource.SATELLITE
        )
        chrome.draw_choice_button(canvas, chrome.layout.map_labels_button_bounds(rect), map_labels_button_label(state, compact = true), state.map_labels_enabled || state.map_borders_enabled)
        chrome.draw_choice_button(canvas, chrome.layout.globe_bin_craft_source_button_bounds(rect), state.aircraft_feed_mode.compact_name, true)
        chrome.draw_choice_button(canvas, chrome.layout.aviation_layers_button_bounds(rect), "Layers", state.aviation_layers_enabled)

        draw_settings_section_label(canvas, safety.left, rect.top + dp(58), "Safety", style)
        chrome.draw_choice_button(canvas, chrome.layout.alerts_toggle_bounds(rect), if (state.alerts_enabled) "Hazard alerts on" else "Hazard alerts off", state.alerts_enabled)
        chrome.draw_choice_button(canvas, chrome.layout.priority_tracker_button_bounds(rect), "Notification range", state.priority_tracking_enabled)

        draw_settings_section_label(canvas, safety.left, rect.top + dp(158), "Reference", style)
        chrome.draw_choice_button(canvas, chrome.layout.impact_methodology_button_bounds(rect), "Impact method", false)
    }

    private fun map_labels_button_label(state: SettingsPanelState, compact: Boolean): String {
        val prefix = if (compact) "Labels" else "Map labels"
        return when {
            state.map_labels_enabled && state.map_borders_enabled -> "$prefix on"
            state.map_labels_enabled || state.map_borders_enabled -> "$prefix mixed"
            else -> "$prefix off"
        }
    }

    private fun draw_settings_section_label(canvas: Canvas, x: Float, y: Float, label: String, style: FlightMapPanelStyle) {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText(label, x, y, text_paint)
    }

    // Layer buttons include source state suffixes so unavailable or empty real layers are labeled honestly.
    private fun draw_layer_toggle_button(
        canvas: Canvas,
        rect: RectF,
        label: String,
        enabled: Boolean,
        kind: AviationLayerKind,
        state: AviationLayersPanelState
    ) {
        val status = state.snapshot?.statuses?.get(kind)
        val suffix = when {
            !enabled -> "off"
            status?.state == AviationLayerState.LOADED -> "on"
            status?.state == AviationLayerState.EMPTY -> "empty"
            status?.state == AviationLayerState.UNAVAILABLE -> "retry"
            state.fetch_in_flight -> "loading"
            else -> "on"
        }
        chrome.draw_choice_button(canvas, rect, "$label $suffix", enabled)
    }

    private fun impact_methodology_items(): List<Pair<String, String>> {
        return listOf(
            "Trace first" to "Only real trace points from the aircraft source are used. App-session dots are never stored as a path.",
            "Aircraft profile" to "Live web/feed type is tried first, then registry/API metadata. Known ICAO types use a type benchmark; otherwise class benchmarks are used.",
            "Phase model" to "Observed legs are split into ground, climb, cruise, descent, low-level, or time-only using trace altitude, speed, and timestamps.",
            "Carbon math" to "CO2 range = profile gal/hr x phase multiplier x trace hours x EIA kg CO2/gal. Jet fuel uses 9.75; avgas uses 8.31.",
            "Score" to "0-100 is log-scaled kg CO2/hr. When a phase trace exists it scores observed intensity; otherwise it scores the profile rate.",
            "Full flight" to "Shown only when real origin, destination, and trace progress are credible enough to route-scale the observed estimate.",
            "Not claimed" to "No exact fuel flow, payload, passenger count, SAF blend, contrails, NOx, noise, or per-passenger allocation is inferred."
        )
    }

    private fun draw_methodology_column(
        canvas: Canvas,
        rect: RectF,
        items: List<Pair<String, String>>,
        style: FlightMapPanelStyle
    ) {
        var y = rect.top
        items.forEach { item ->
            y = draw_methodology_item(canvas, rect, y, item.first, item.second, max_lines = 2, style)
        }
    }

    private fun draw_methodology_item(
        canvas: Canvas,
        rect: RectF,
        y: Float,
        label: String,
        body: String,
        max_lines: Int,
        style: FlightMapPanelStyle
    ): Float {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(11)
        text_paint.color = style.visual_theme.colors.text
        canvas.drawText(label, rect.left, y, text_paint)

        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(11)
        text_paint.color = style.visual_theme.colors.muted
        val bottom = chrome.draw_wrapped_text(canvas, body, rect.left, y + dp(18), rect.width(), max_lines)
        return bottom + dp(12)
    }

    // Search control owns the caret animation while FlightMapView owns actual text input.
    private fun draw_filter_search_control(canvas: Canvas, panel: RectF, style: FlightMapPanelStyle, state: FiltersPanelState) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val search = chrome.layout.filter_search_box_bounds(panel)
        val stroke = if (state.filter_search_focused) colors.accent_green else colors.button_stroke
        val fill = if (theme_style.treatment == ThemeTreatment.PLAIN) colors.button_fill else with_alpha(colors.button_fill, theme_style.control_alpha)
        chrome.draw_control_surface(canvas, search, fill, stroke, state.filter_search_focused)

        val display = state.filter_search_query.ifBlank { "Callsign, reg, ICAO hex" }
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = state.filter_search_query.isNotBlank()
        text_paint.textSize = sp(13)
        text_paint.color = if (state.filter_search_query.isBlank()) colors.muted else colors.text
        val max_width = search.width() - dp(24)
        canvas.drawText(chrome.ellipsize(display, max_width), search.left + dp(12), search.centerY() + dp(5), text_paint)
        if (state.filter_search_focused && SystemClock.elapsedRealtime() % 1000L < 560L) {
            val visible_text = if (state.filter_search_query.isBlank()) "" else chrome.ellipsize(state.filter_search_query, max_width)
            val caret_x = (search.left + dp(12) + text_paint.measureText(visible_text)).coerceAtMost(search.right - dp(12))
            stroke_paint.color = colors.accent_green
            stroke_paint.strokeWidth = dp(1.2f)
            canvas.drawLine(caret_x, search.top + dp(9), caret_x, search.bottom - dp(9), stroke_paint)
            chrome.request_animation_frame()
        }
        text_paint.isFakeBoldText = false

        chrome.draw_choice_button(canvas, chrome.layout.filter_search_find_button_bounds(panel), "Find live", false)
        chrome.draw_choice_button(canvas, chrome.layout.filter_search_clear_button_bounds(panel), "Clear", false)
    }

    // Portrait filters use one vertical list so long labels stay physically consistent.
    private fun draw_portrait_filters_panel_contents(canvas: Canvas, rect: RectF, state: FiltersPanelState) {
        draw_filters_panel_contents(canvas, rect, state, reset_label = "Reset filters")
    }

    // Compact filters use two columns and shorter reset text to fit landscape-short devices.
    private fun draw_compact_filters_panel_contents(canvas: Canvas, rect: RectF, state: FiltersPanelState) {
        draw_filters_panel_contents(canvas, rect, state, reset_label = "Reset")
    }

    private fun draw_filters_panel_contents(
        canvas: Canvas,
        rect: RectF,
        state: FiltersPanelState,
        reset_label: String
    ) {
        draw_filter_cycle_row(
            canvas,
            chrome.layout.filter_aircraft_type_button_bounds(rect),
            "Type: ${state.aircraft_type_filter.short_label}",
            state.aircraft_type_filter != AircraftTypeFilter.ALL
        )
        draw_filter_cycle_row(
            canvas,
            chrome.layout.filter_altitude_button_bounds(rect),
            "Alt: ${state.altitude_filter.short_label}",
            state.altitude_filter != AltitudeFilter.ANY
        )
        draw_filter_cycle_row(
            canvas,
            chrome.layout.filter_distance_button_bounds(rect),
            "Range: ${state.distance_filter.short_label}",
            state.distance_filter != DistanceFilter.ANY
        )
        draw_filter_cycle_row(
            canvas,
            chrome.layout.filter_status_button_bounds(rect),
            "Status: ${state.flight_status_filter.short_label}",
            state.flight_status_filter != FlightStatusFilter.AIRBORNE
        )
        draw_filter_cycle_row(
            canvas,
            chrome.layout.filter_age_button_bounds(rect),
            "Age: ${state.report_age_filter.short_label}",
            state.report_age_filter != ReportAgeFilter.ANY
        )
        draw_filter_cycle_row(
            canvas,
            chrome.layout.filter_alert_button_bounds(rect),
            if (state.alert_volume_filter) "Alert volume only" else "Alert volume: off",
            state.alert_volume_filter
        )
        chrome.draw_choice_button(canvas, chrome.layout.filter_reset_button_bounds(rect), reset_label, state.filters_active)
    }

    private fun draw_filter_cycle_row(canvas: Canvas, bounds: RectF, label: String, selected: Boolean) {
        chrome.draw_choice_button(canvas, bounds, label, selected)
    }

    // Compact priority tracker keeps alert controls left and queue rows right.
    private fun draw_compact_priority_tracker_contents(canvas: Canvas, rect: RectF, style: FlightMapPanelStyle, state: PriorityTrackerPanelState) {
        val left_area = chrome.layout.priority_alert_control_area(rect)
        val right = chrome.layout.compact_settings_right_column(rect)

        chrome.draw_choice_button(
            canvas,
            chrome.layout.priority_tracking_toggle_bounds(rect),
            if (state.priority_tracking_enabled) "Queue on" else "Queue off",
            state.priority_tracking_enabled
        )
        chrome.draw_choice_button(
            canvas,
            chrome.layout.priority_ring_toggle_bounds(rect),
            if (state.priority_range_circle_visible) "Alert ring on" else "Alert ring off",
            state.priority_range_circle_visible
        )
        draw_adjuster_row(
            canvas,
            left_area,
            rect.top + dp(118),
            "Horizontal",
            state.alert_distance_label,
            chrome.layout.alert_distance_minus_bounds(rect),
            chrome.layout.alert_distance_plus_bounds(rect),
            style,
            state.long_press_fill,
            PriorityRangeAdjustButton.DISTANCE_MINUS,
            PriorityRangeAdjustButton.DISTANCE_PLUS
        )
        draw_adjuster_row(
            canvas,
            left_area,
            rect.top + dp(186),
            "Vertical",
            state.alert_altitude_label,
            chrome.layout.alert_altitude_minus_bounds(rect),
            chrome.layout.alert_altitude_plus_bounds(rect),
            style,
            state.long_press_fill,
            PriorityRangeAdjustButton.ALTITUDE_MINUS,
            PriorityRangeAdjustButton.ALTITUDE_PLUS
        )

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(11)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText("Aircraft in queue", right.left, rect.top + dp(58), text_paint)

        if (state.aircraft_rows.isEmpty()) {
            text_paint.isFakeBoldText = true
            text_paint.textSize = sp(16)
            text_paint.color = style.visual_theme.colors.text
            canvas.drawText(if (state.priority_tracking_enabled) "No aircraft in queue" else "Queue is off", right.left, rect.top + dp(94), text_paint)
            text_paint.isFakeBoldText = false
            return
        }

        var y = rect.top + dp(94)
        state.aircraft_rows.take(3).forEach { item ->
            y = draw_priority_aircraft_row(canvas, RectF(right.left - dp(18), rect.top, rect.right, rect.bottom), y, item, style)
        }
        if (state.aircraft_rows.size > 3) {
            text_paint.isFakeBoldText = false
            text_paint.textSize = sp(11)
            text_paint.color = style.visual_theme.colors.muted
            draw_fitted_left_text(canvas, "+${state.aircraft_rows.size - 3} more", right.left, y + dp(4), right.width(), sp(11), sp(8))
        }
    }

    private fun draw_priority_aircraft_row(
        canvas: Canvas,
        panel: RectF,
        y: Float,
        row_state: PriorityAircraftPanelRow,
        style: FlightMapPanelStyle
    ): Float {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val row = RectF(panel.left + dp(18), y - dp(22), panel.right - dp(18), y + dp(34))
        paint.style = Paint.Style.FILL
        paint.color = if (row_state.is_extreme) with_alpha(colors.danger, 60) else with_alpha(colors.text, colors.row_fill_alpha)
        val row_radius = if (theme_style.treatment == ThemeTreatment.PLAIN) dp(6) else chrome.control_radius().coerceAtLeast(dp(1))
        canvas.drawRoundRect(row, row_radius, row_radius, paint)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(15)
        text_paint.color = if (row_state.is_extreme) colors.danger else colors.text
        val altitude_width = (row.width() * 0.34f).coerceAtLeast(dp(58))
        val title_width = (row.width() - altitude_width - dp(28)).coerceAtLeast(dp(48))
        draw_fitted_left_text(canvas, row_state.title, row.left + dp(10), y, title_width, sp(15), sp(9))

        text_paint.textAlign = Paint.Align.RIGHT
        text_paint.textSize = sp(13)
        text_paint.color = colors.text
        draw_fitted_right_text(canvas, row_state.altitude, row.right - dp(10), y, altitude_width, sp(13), sp(8))

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(11)
        text_paint.color = colors.muted
        draw_fitted_left_text(canvas, row_state.detail, row.left + dp(10), y + dp(20), row.width() - dp(20), sp(11), sp(8))
        return y + dp(64)
    }

    private fun draw_adjuster_row(
        canvas: Canvas,
        panel: RectF,
        y: Float,
        label: String,
        value: String,
        minus: RectF,
        plus: RectF,
        style: FlightMapPanelStyle,
        long_press_fill: PriorityRangeButtonFillState?,
        minus_button: PriorityRangeAdjustButton,
        plus_button: PriorityRangeAdjustButton
    ) {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText(label, panel.left + dp(18), y, text_paint)

        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.text
        draw_fitted_center_text(canvas, value, minus.right + dp(8), plus.left - dp(8), y + dp(32), sp(13), sp(8))
        chrome.draw_choice_button(canvas, minus, "-", false)
        chrome.draw_choice_button(canvas, plus, "+", false)
        draw_long_press_fill(canvas, minus, "-", minus_button, long_press_fill, style)
        draw_long_press_fill(canvas, plus, "+", plus_button, long_press_fill, style)
    }

    private fun draw_long_press_fill(
        canvas: Canvas,
        rect: RectF,
        label: String,
        button: PriorityRangeAdjustButton,
        fill: PriorityRangeButtonFillState?,
        style: FlightMapPanelStyle
    ) {
        if (fill?.button != button) return
        val elapsed = SystemClock.elapsedRealtime() - fill.started_ms
        val progress = (elapsed.toFloat() / fill.duration_ms.coerceAtLeast(1L)).coerceIn(0f, 1f)
        val eased = progress * progress * (3f - 2f * progress)
        val max_radius = max_distance_to_corner(fill.press_x, fill.press_y, rect)
        canvas.withSave {
            long_press_fill_clip.reset()
            long_press_fill_clip.addRoundRect(rect, chrome.control_radius(), chrome.control_radius(), Path.Direction.CW)
            clipPath(long_press_fill_clip)
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(style.visual_theme.colors.accent_green, 92)
            drawCircle(fill.press_x, fill.press_y, max_radius * eased, paint)
        }

        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.text
        val metrics = text_paint.fontMetrics
        canvas.drawText(label, rect.centerX(), rect.centerY() - (metrics.ascent + metrics.descent) / 2f, text_paint)
        text_paint.isFakeBoldText = false
        if (progress < 1f) chrome.request_animation_frame()
    }

    private fun max_distance_to_corner(x: Float, y: Float, rect: RectF): Float {
        var max_squared = 0f
        val xs = floatArrayOf(rect.left, rect.right)
        val ys = floatArrayOf(rect.top, rect.bottom)
        for (corner_x in xs) {
            for (corner_y in ys) {
                val dx = corner_x - x
                val dy = corner_y - y
                val squared = dx * dx + dy * dy
                if (squared > max_squared) max_squared = squared
            }
        }
        return sqrt(max_squared)
    }

    private fun draw_panel_title(canvas: Canvas, rect: RectF, title: String, style: FlightMapPanelStyle) {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(20)
        text_paint.color = style.visual_theme.colors.text
        val left = rect.left + dp(18)
        val close_left = chrome.layout.close_button_bounds(rect).left
        draw_fitted_left_text(canvas, title, left, rect.top + dp(34), close_left - left - dp(8), sp(20), sp(11))
    }

    private fun draw_fitted_left_text(
        canvas: Canvas, value: String, left: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, left, y, max_width, start_size, min_size, Paint.Align.LEFT, dp(0.5f), chrome::ellipsize, dp(8)
    )

    private fun draw_fitted_right_text(
        canvas: Canvas, value: String, right: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, right, y, max_width, start_size, min_size, Paint.Align.RIGHT, dp(0.5f), chrome::ellipsize, dp(8)
    )

    private fun draw_fitted_center_text(
        canvas: Canvas,
        value: String,
        left: Float,
        right: Float,
        y: Float,
        start_size: Float,
        min_size: Float
    ) {
        val width = (right - left).coerceAtLeast(dp(8))
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.textSize = start_size
        while (text_paint.textSize > min_size && text_paint.measureText(value) > width) {
            text_paint.textSize -= dp(0.5f)
        }
        val display = if (text_paint.measureText(value) <= width) value else chrome.ellipsize(value, width)
        canvas.drawText(display, (left + right) / 2f, y, text_paint)
    }

    private fun dp(value: Int): Float = dp(value.toFloat())

    private fun dp(value: Float): Float = chrome.dp(value)

    private fun sp(value: Int): Float = sp(value.toFloat())

    private fun sp(value: Float): Float = chrome.sp(value)

    
    private companion object {
        const val PRIORITY_PANEL_ROWS = 5
    }
}


data class TrafficPanelStyle(val visual_theme: VisualTheme)

data class TrafficPanelState(
    val title: String,
    val title_color: Int,
    val content: TrafficPanelContent
)

sealed interface TrafficPanelContent

data class TrafficPanelAircraftState(
    val callsign: String,
    val distance_label: String,
    val distance_color: Int,
    val wide_rows: List<TrafficPanelRow>,
    val compact_primary_values: List<String>,
    val compact_secondary_values: List<String>,
    val military_label: String?
) : TrafficPanelContent

data class TrafficPanelEmptyState(
    val headline: String,
    val message: String,
    val data_time_label: String?
) : TrafficPanelContent

data class TrafficPanelRow(val label: String, val value: String)

interface TrafficPanelChrome {
    fun dp(value: Float): Float
    fun sp(value: Float): Float
    fun ellipsize(value: String, max_width: Float): String
    fun draw_panel_surface(canvas: Canvas, rect: RectF, fill: Int, alpha: Int)
}

class TrafficPanelRenderer(
    private val text_paint: Paint,
    private val stroke_paint: Paint,
    private val chrome: TrafficPanelChrome,
    private val with_alpha: (Int, Int) -> Int
) {
    fun draw_panel(canvas: Canvas, rect: RectF, wide: Boolean, style: TrafficPanelStyle, state: TrafficPanelState) {
        chrome.draw_panel_surface(canvas, rect, style.visual_theme.colors.panel, style.visual_theme.style.info_panel_alpha)

        val y = rect.top + if (wide) dp(32) else dp(27)
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(13)
        text_paint.color = state.title_color
        draw_fitted_left_text(canvas, state.title, rect.left + dp(16), y, rect.width() - dp(32), sp(13), sp(9))

        when (val content = state.content) {
            is TrafficPanelEmptyState -> draw_empty_panel(canvas, rect, y + if (wide) dp(60) else dp(38), style, content)
            is TrafficPanelAircraftState -> draw_aircraft_panel(canvas, rect, wide, y, style, content)
        }
    }

    private fun draw_aircraft_panel(
        canvas: Canvas,
        rect: RectF,
        wide: Boolean,
        start_y: Float,
        style: TrafficPanelStyle,
        content: TrafficPanelAircraftState
    ) {
        var y = start_y + if (wide) dp(44) else dp(32)
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = if (wide) sp(29) else sp(24)
        text_paint.color = style.visual_theme.colors.text
        val distance_width = (rect.width() * 0.38f).coerceAtLeast(dp(58))
        val callsign_width = (rect.width() - distance_width - dp(44)).coerceAtLeast(dp(54))
        draw_fitted_left_text(
            canvas = canvas,
            value = content.callsign,
            left = rect.left + dp(16),
            y = y,
            max_width = callsign_width,
            start_size = if (wide) sp(29) else sp(24),
            min_size = sp(12)
        )

        text_paint.textAlign = Paint.Align.RIGHT
        text_paint.textSize = if (wide) sp(29) else sp(24)
        text_paint.color = content.distance_color
        draw_fitted_right_text(
            canvas = canvas,
            value = content.distance_label,
            right = rect.right - dp(16),
            y = y,
            max_width = distance_width,
            start_size = if (wide) sp(29) else sp(24),
            min_size = sp(12)
        )

        if (wide) {
            y += dp(38)
            val row_height = row_height(rect, y, content.wide_rows.size)
            content.wide_rows.forEach { row ->
                if (y + row_height <= rect.bottom - dp(8)) {
                    y = draw_detail_row(canvas, rect, y, row, row_height, style)
                }
            }
            return
        }

        y += dp(28)
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.muted
        content.compact_primary_values.forEachIndexed { index, value ->
            draw_compact_value(
                canvas = canvas,
                rect = rect,
                index = index,
                item_count = content.compact_primary_values.size,
                primary = true,
                y = y,
                value = value
            )
        }

        y += dp(24)
        content.compact_secondary_values.forEachIndexed { index, value ->
            draw_compact_value(
                canvas = canvas,
                rect = rect,
                index = index,
                item_count = content.compact_secondary_values.size,
                primary = false,
                y = y,
                value = value
            )
        }
        content.military_label?.let { label ->
            y += dp(22)
            text_paint.isFakeBoldText = true
            text_paint.color = style.visual_theme.colors.military
            draw_fitted_left_text(canvas, label, rect.left + dp(16), y, rect.width() - dp(32), sp(13), sp(9))
            text_paint.isFakeBoldText = false
        }
    }

    private fun draw_empty_panel(
        canvas: Canvas,
        rect: RectF,
        y: Float,
        style: TrafficPanelStyle,
        content: TrafficPanelEmptyState
    ) {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(20)
        text_paint.color = style.visual_theme.colors.text
        draw_fitted_left_text(canvas, content.headline, rect.left + dp(16), y, rect.width() - dp(32), sp(20), sp(12))
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(12)
        text_paint.color = style.visual_theme.colors.muted
        draw_fitted_left_text(canvas, content.message, rect.left + dp(16), y + dp(24), rect.width() - dp(32), sp(12), sp(9))
        content.data_time_label?.let {
            draw_fitted_left_text(canvas, it, rect.left + dp(16), y + dp(44), rect.width() - dp(32), sp(12), sp(9))
        }
    }

    private fun row_height(rect: RectF, start_y: Float, row_count: Int): Float {
        if (row_count <= 0) return dp(28)
        val available = (rect.bottom - dp(14) - start_y).coerceAtLeast(dp(21))
        return (available / row_count).coerceIn(dp(21), dp(28))
    }

    private fun draw_detail_row(
        canvas: Canvas,
        rect: RectF,
        y: Float,
        row: TrafficPanelRow,
        row_height: Float,
        style: TrafficPanelStyle
    ): Float {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(10)
        text_paint.color = style.visual_theme.colors.muted
        canvas.drawText(row.label.uppercase(Locale.US), rect.left + dp(16), y, text_paint)

        text_paint.textAlign = Paint.Align.RIGHT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(13)
        text_paint.color = style.visual_theme.colors.text
        draw_fitted_right_text(canvas, row.value, rect.right - dp(16), y, rect.width() * 0.56f, sp(13), sp(9))

        stroke_paint.color = with_alpha(style.visual_theme.colors.panel_stroke, style.visual_theme.style.divider_alpha)
        stroke_paint.strokeWidth = dp(1)
        val divider_y = y + min(dp(10), row_height - dp(7))
        canvas.drawLine(rect.left + dp(16), divider_y, rect.right - dp(16), divider_y, stroke_paint)
        text_paint.isFakeBoldText = false
        return y + row_height
    }

    private fun draw_fitted_right_text(
        canvas: Canvas, value: String, right: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, right, y, max_width, start_size, min_size, Paint.Align.RIGHT, dp(0.5f), chrome::ellipsize
    )

    private fun draw_fitted_left_text(
        canvas: Canvas, value: String, left: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, left, y, max_width, start_size, min_size, Paint.Align.LEFT, dp(0.5f), chrome::ellipsize
    )

    private fun draw_compact_value(
        canvas: Canvas,
        rect: RectF,
        index: Int,
        item_count: Int,
        primary: Boolean,
        y: Float,
        value: String
    ) {
        val left = compact_column_x(rect, index, primary)
        draw_fitted_left_text(canvas, value, left, y, compact_column_width(rect, index, item_count, primary), sp(13), sp(8))
    }

    private fun compact_column_x(rect: RectF, index: Int, primary: Boolean): Float {
        return when (index) {
            0 -> rect.left + dp(16)
            1 -> rect.left + rect.width() * if (primary) 0.34f else 0.46f
            else -> rect.left + rect.width() * 0.60f
        }
    }

    private fun compact_column_width(rect: RectF, index: Int, item_count: Int, primary: Boolean): Float {
        val left = compact_column_x(rect, index, primary)
        val next = when (index) {
            0 -> compact_column_x(rect, 1, primary)
            1 -> if (item_count <= 2) rect.right - dp(16) else compact_column_x(rect, 2, primary)
            else -> rect.right - dp(16)
        }
        return (next - left - dp(8)).coerceAtLeast(dp(24))
    }

    private fun dp(value: Int): Float = dp(value.toFloat())

    private fun dp(value: Float): Float = chrome.dp(value)

    private fun sp(value: Int): Float = sp(value.toFloat())

    private fun sp(value: Float): Float = chrome.sp(value)
}


internal class TrafficPanelStateBuilder(
    private val telemetry_formatter: AircraftTelemetryFormatter,
    private val reported_distance_meters: (Aircraft) -> Double,
    private val traffic_distance_color: (Aircraft) -> Int,
    private val registry_country_label: (Aircraft) -> String,
    private val current_route_details_for_panel: (Aircraft) -> AircraftDetails?,
    private val format_origin_status: (Aircraft, AircraftDetails?) -> String
) {
    // Choose one aircraft summary; renderers only receive prepared text and colors.
    fun panel_state(
        display: TrafficDisplay,
        muted_color: Int,
        accent_blue_color: Int,
        danger_color: Int,
        filters_active: Boolean,
        filter_stats: FilterStats,
        aircraft_status: String,
        last_aircraft_data_epoch_sec: Double?
    ): TrafficPanelState {
        val target = display.aircraft
        return TrafficPanelState(
            title = panel_title(display, filters_active),
            title_color = when {
                target == null -> muted_color
                display.selected -> accent_blue_color
                else -> danger_color
            },
            content = target?.let { aircraft_panel_state(it) } ?: empty_panel_state(
                filter_stats = filter_stats,
                filters_active = filters_active,
                aircraft_status = aircraft_status,
                last_aircraft_data_epoch_sec = last_aircraft_data_epoch_sec
            )
        )
    }

    private fun panel_title(display: TrafficDisplay, filters_active: Boolean): String {
        return when {
            display.aircraft == null -> "AIRCRAFT FEED"
            display.selected -> "SELECTED TRAFFIC"
            filters_active -> "FILTERED TRAFFIC"
            else -> "NEAREST TRAFFIC"
        }
    }

    private fun aircraft_panel_state(target: Aircraft): TrafficPanelAircraftState {
        return TrafficPanelAircraftState(
            callsign = target.callsign,
            distance_label = telemetry_formatter.distance(reported_distance_meters(target)),
            distance_color = traffic_distance_color(target),
            wide_rows = panel_rows(target),
            compact_primary_values = listOf(
                telemetry_formatter.altitude_value(target.altitude_m),
                telemetry_formatter.speed_value(target.velocity_ms),
                telemetry_formatter.age(target)
            ),
            compact_secondary_values = listOf(
                telemetry_formatter.track(target.track_deg),
                telemetry_formatter.vertical_rate(target.vertical_rate_ms)
            ),
            military_label = if (target.is_military) "Tagged military" else null
        )
    }

    private fun panel_rows(target: Aircraft): List<TrafficPanelRow> {
        val rows = mutableListOf(
            TrafficPanelRow("Altitude", telemetry_formatter.altitude_value(target.altitude_m)),
            TrafficPanelRow("Speed", telemetry_formatter.speed_value(target.velocity_ms)),
            TrafficPanelRow("Track", telemetry_formatter.track(target.track_deg)),
            TrafficPanelRow("Vertical rate", telemetry_formatter.vertical_rate(target.vertical_rate_ms)),
            TrafficPanelRow("Last contact", telemetry_formatter.age(target)),
            TrafficPanelRow("Registration", target.registration ?: "Unavailable"),
            TrafficPanelRow("Registry country", registry_country_label(target)),
            TrafficPanelRow("Type", target.type_code ?: "Unavailable")
        )
        if (target.is_military) {
            rows += TrafficPanelRow("Military", "Tagged military")
            rows += TrafficPanelRow("Origin status", format_origin_status(target, current_route_details_for_panel(target)))
        }
        rows += TrafficPanelRow("ICAO", target.icao24.uppercase(Locale.US))
        rows += TrafficPanelRow("Reported position", telemetry_formatter.reported_position(target))
        return rows
    }

    private fun empty_panel_state(
        filter_stats: FilterStats,
        filters_active: Boolean,
        aircraft_status: String,
        last_aircraft_data_epoch_sec: Double?
    ): TrafficPanelEmptyState {
        val filtered_to_none = filters_active && filter_stats.total > 0 && filter_stats.matched == 0
        return TrafficPanelEmptyState(
            headline = when {
                filtered_to_none -> "No filter matches"
                aircraft_status.startsWith("No aircraft reported") -> "No reported aircraft"
                else -> "No aircraft data"
            },
            message = if (filtered_to_none) filter_stats.summary else aircraft_status,
            data_time_label = last_aircraft_data_epoch_sec?.let { "Data time ${it.toLong()}" }
        )
    }
}


object AircraftPhotoCatalog {
    fun representative_model_names(details: AircraftDetails): List<String> {
        val base = representative_model_name(details)
        val type = details.type?.trim()
        val manufacturer = details.manufacturer?.trim()
        val aliases = mutableListOf<String>()
        if (base != null) aliases += base
        if (manufacturer != null && type != null) {
            aliases += "$manufacturer $type"
            manufacturer_aliases(manufacturer).forEach { alias -> aliases += "$alias $type" }
            type_model_aliases(type).forEach { alias_type ->
                aliases += "$manufacturer $alias_type"
                manufacturer_aliases(manufacturer).forEach { alias -> aliases += "$alias $alias_type" }
            }
        }
        type?.let { aliases += it }
        return aliases
            .map { normalize_aircraft_search_name(it) }
            .filter { it.length >= 3 }
            .distinct()
    }

    fun representative_photo_queries(details: AircraftDetails, model: String): List<String> {
        return listOfNotNull(
            "\"$model\" aircraft exterior",
            "$model aircraft exterior",
            "\"$model\" exterior photo",
            "\"$model\" aircraft",
            "$model aircraft",
            "\"$model\" aircraft photo",
            "$model aircraft photo",
            "\"$model\" airplane",
            "$model airplane",
            "\"$model\" airliner",
            "\"$model\" in flight",
            details.type?.let { "\"$it\" aircraft" },
            details.type_code?.let { "${details.manufacturer.orEmpty()} $it aircraft".trim() },
            details.type_code?.let { "$it aircraft" }
        ).filter { it.isNotBlank() }.distinct()
    }

    fun exact_photo_queries(registration: String?, icao24: String): List<String> {
        return listOfNotNull(
            registration?.let { "\"$it\" aircraft exterior" },
            registration?.let { "\"$it\" exterior photo" },
            registration?.let { "\"$it\" aircraft photo" },
            registration?.let { "$it aircraft" },
            icao24.takeIf { it.isNotBlank() }?.let { "\"${it.uppercase(Locale.US)}\" aircraft" }
        ).distinct()
    }

    fun photo_verification_terms(details: AircraftDetails, model: String): List<String> {
        val family_terms = listOfNotNull(
            Regex("""Airbus A\d{3}""").find(model)?.value,
            Regex("""Boeing \d{3}""").find(model)?.value,
            Regex("""Cessna \d{3}""").find(model)?.value,
            Regex("""Piper PA-\d{2}""").find(model)?.value,
            Regex("""Embraer \d{3}""").find(model)?.value
        )
        return listOfNotNull(
            model,
            model.substringAfterLast(" ").takeIf { it.length >= 3 && it.any(Char::isDigit) },
            details.type,
            details.type_code
        ).plus(family_terms)
            .map { it.trim() }
            .filter { it.length >= 3 }
            .distinct()
    }

