    private fun manufacturer_aliases(manufacturer: String): List<String> {
        val normalized = manufacturer.uppercase(Locale.US)
        return when {
            "GRUMMAN" in normalized -> listOf("Grumman American", "Grumman")
            "AMERICAN" in normalized && "GENERAL" in normalized -> listOf("American General", "Grumman American")
            "CESSNA" in normalized -> listOf("Cessna")
            "PIPER" in normalized -> listOf("Piper")
            "BEECH" in normalized -> listOf("Beechcraft", "Beech")
            "CIRRUS" in normalized -> listOf("Cirrus")
            "DIAMOND" in normalized -> listOf("Diamond")
            "MOONEY" in normalized -> listOf("Mooney")
            "ROBINSON" in normalized -> listOf("Robinson")
            "VANS" in normalized || "VAN'S" in normalized -> listOf("Van's", "Vans")
            "PILATUS" in normalized -> listOf("Pilatus")
            else -> emptyList()
        }
    }

    private fun type_model_aliases(type: String): List<String> {
        val normalized = type.uppercase(Locale.US).replace(Regex("[^A-Z0-9]+"), " ").trim()
        val compact = normalized.replace(" ", "")
        return when {
            compact == "AA1" || compact.startsWith("AA1") -> listOf("AA-1", "AA1", "American Yankee")
            compact.startsWith("AA5") -> listOf("AA-5", "AA5", "Cheetah", "Tiger")
            compact.startsWith("GA7") -> listOf("GA-7", "GA7", "Cougar")
            compact.startsWith("C120") -> listOf("120")
            compact.startsWith("C140") -> listOf("140")
            compact.startsWith("C150") -> listOf("150")
            compact.startsWith("C152") -> listOf("152")
            compact.startsWith("C172") -> listOf("172 Skyhawk", "172")
            compact.startsWith("C177") -> listOf("177 Cardinal", "177")
            compact.startsWith("C182") -> listOf("182 Skylane", "182")
            compact.startsWith("C185") -> listOf("185 Skywagon", "185")
            compact.startsWith("C206") -> listOf("206 Stationair", "206")
            compact.startsWith("C210") -> listOf("210 Centurion", "210")
            compact.startsWith("C337") -> listOf("337 Skymaster", "337")
            compact.startsWith("BE33") -> listOf("Bonanza")
            compact.startsWith("BE35") -> listOf("Bonanza")
            compact.startsWith("BE36") -> listOf("Bonanza")
            compact.startsWith("BE55") -> listOf("Baron")
            compact.startsWith("BE58") -> listOf("Baron")
            compact.startsWith("BE20") -> listOf("King Air 200", "King Air")
            compact.startsWith("B350") -> listOf("King Air 350", "King Air")
            compact.startsWith("PA28") -> listOf("PA-28 Cherokee", "PA-28")
            compact.startsWith("PA32") -> listOf("PA-32 Cherokee Six", "PA-32")
            compact.startsWith("PA34") -> listOf("PA-34 Seneca", "PA-34")
            compact.startsWith("PA44") -> listOf("PA-44 Seminole", "PA-44")
            compact.startsWith("PA46") || compact.startsWith("P46T") -> listOf("PA-46 Malibu", "PA-46 Mirage", "PA-46 Meridian", "PA-46")
            compact.startsWith("SR20") -> listOf("SR20")
            compact.startsWith("SR22") || compact.startsWith("S22T") -> listOf("SR22", "SR22T")
            compact.startsWith("DA40") -> listOf("DA40")
            compact.startsWith("DA42") -> listOf("DA42")
            compact.startsWith("M20") -> listOf("M20")
            compact.startsWith("RV6") -> listOf("RV-6", "RV6")
            compact.startsWith("RV7") -> listOf("RV-7", "RV7")
            compact.startsWith("RV8") -> listOf("RV-8", "RV8")
            compact.startsWith("RV9") -> listOf("RV-9", "RV9")
            compact.startsWith("R44") -> listOf("R44 Raven", "R44")
            compact.startsWith("R66") -> listOf("R66")
            compact.startsWith("PC12") -> listOf("PC-12", "PC12")
            else -> emptyList()
        }
    }

    private fun normalize_aircraft_search_name(value: String): String {
        return value
            .replace(Regex("\\bINC\\.?\\b", RegexOption.IGNORE_CASE), " ")
            .replace(Regex("\\bCORP\\.?\\b", RegexOption.IGNORE_CASE), " ")
            .replace(Regex("\\bAVN\\.?\\b", RegexOption.IGNORE_CASE), " Aviation ")
            .replace(Regex("\\s+"), " ")
            .trim()
    }
}


// Finds aircraft photos in an honesty ladder: exact first, labeled representative next, investigable last.
class AircraftPhotoFetcher(private val user_agent: String) {
    private val photo_cache = object : LinkedHashMap<String, CachedPhotoResult>(
        PHOTO_CACHE_MAX_ENTRIES,
        0.75f,
        true
    ) {
        override fun removeEldestEntry(eldest: MutableMap.MutableEntry<String, CachedPhotoResult>): Boolean {
            return size > PHOTO_CACHE_MAX_ENTRIES
        }
    }

    // Public photo lookup tries exact aircraft sources before any labeled fallback.
    fun fetch(aircraft: Aircraft, details: AircraftDetails): AircraftPhotoResult {
        fetch_exact_aircraft_photo(aircraft, details)?.let { return it }
        return fetch_fallback_photo(aircraft, details)
    }

    // Exact photos require an aircraft identifier or matching registration from documented photo sources.
    fun fetch_exact_aircraft_photo(aircraft: Aircraft, details: AircraftDetails): AircraftPhotoResult.Found? {
        val registration = normalized_registration(details.registration ?: aircraft.registration)
        val cache_key = exact_photo_cache_key(aircraft, details, registration)
        cached_photo(cache_key)?.let { return it }

        fun found(photo: AircraftPhotoResult.Found): AircraftPhotoResult.Found {
            cache_photo(cache_key, photo)
            return photo
        }

        fetch_adsb_db_photo_candidates(aircraft.icao24, registration).forEach { candidate ->
            fetch_bitmap(candidate.image_url, candidate.page_url)?.let { bitmap ->
                return found(found_exact_photo(bitmap, candidate))
            }
        }
        fetch_planespotters_selected_candidates(aircraft.icao24, registration, details.type_code ?: aircraft.type_code).forEach { candidate ->
            fetch_bitmap(candidate.image_url, candidate.page_url)?.let { bitmap ->
                return found(found_exact_photo(bitmap, candidate))
            }
        }
        val exact_sources = listOfNotNull(
            "https://api.planespotters.net/pub/photos/hex/${aircraft.icao24.trim()}",
            (details.registration ?: aircraft.registration)?.let { "https://api.planespotters.net/pub/photos/reg/${it.trim()}" }
        )
        exact_sources.forEach { api_url ->
            fetch_planespotters_photo_candidate(api_url)?.let { candidate ->
                fetch_bitmap(candidate.image_url, candidate.page_url)?.let { bitmap ->
                    return found(found_exact_photo(bitmap, candidate))
                }
            }
        }
        if (registration != null) {
            fetch_jet_photos_exact_candidates(registration).forEach { candidate ->
                fetch_bitmap(candidate.image_url, candidate.page_url)?.let { bitmap ->
                    return found(found_exact_photo(bitmap, candidate))
                }
            }
        }
        val hex_image_url = "https://hexdb.io/hex-image-thumb?hex=${aircraft.icao24.trim()}"
        fetch_bitmap(hex_image_url)?.let { bitmap ->
            return found(
                found_exact_photo(
                    bitmap,
                    ExactPhotoCandidate(
                        image_url = hex_image_url,
                        source_name = "HexDB",
                        page_url = hex_image_url,
                        note = "Exact aircraft photo from HexDB"
                    )
                )
            )
        }
        return null
    }

    // Fallback photos must stay labeled as representative, verified search, or investigable search.
    fun fetch_fallback_photo(aircraft: Aircraft, details: AircraftDetails): AircraftPhotoResult {
        val cache_key = fallback_photo_cache_key(aircraft, details)
        cached_photo(cache_key)?.let { return it }
        val photo = fetch_representative_photo(details)
            ?: fetch_verified_generic_search_photo(aircraft, details)
            ?: fetch_investigable_search_photo(aircraft, details)
            ?: AircraftPhotoResult.Unavailable("Exact, representative, and search photos unavailable")
        if (photo is AircraftPhotoResult.Found) cache_photo(cache_key, photo)
        return photo
    }

    fun fetch_gallery(
        aircraft: Aircraft,
        details: AircraftDetails
    ): List<AircraftPhotoGalleryItem> {
        val items = mutableListOf<AircraftPhotoGalleryItem>()
        fetch_exact_aircraft_photo(aircraft, details)?.let {
            items += it.to_gallery_item("Exact exterior", AircraftPhotoViewType.EXTERIOR)
        }
        items += fetch_representative_gallery_items(aircraft, details)
        return items.distinctBy { it.evidence?.image_url ?: "${it.title}:${it.caption}" }.take(MAX_GALLERY_ITEMS)
    }

    // ADSBdb can return direct exact-photo URLs keyed by ICAO or registration.
    private fun fetch_adsb_db_photo_candidates(icao24: String, registration: String?): List<ExactPhotoCandidate> {
        val keys = listOfNotNull(icao24.trim().takeIf { it.isNotBlank() }, registration).distinct()
        return keys.flatMap { key ->
            val encoded = URLEncoder.encode(key, "UTF-8")
            val api_url = "https://api.adsbdb.com/v0/aircraft/$encoded"
            val json = fetch_json_object(api_url) ?: return@flatMap emptyList()
            val aircraft = json.optJSONObject("response")?.optJSONObject("aircraft") ?: return@flatMap emptyList()
            listOfNotNull(
                aircraft.optString("url_photo").takeIf { it.startsWith("https://", ignoreCase = true) },
                aircraft.optString("url_photo_thumbnail").takeIf { it.startsWith("https://", ignoreCase = true) }
            ).filter { url -> is_exterior_candidate_text(url) }
                .map { url ->
                    ExactPhotoCandidate(
                        image_url = url,
                        source_name = "ADSBdb",
                        page_url = api_url,
                        note = "Exact aircraft photo from ADSBdb"
                    )
                }
        }.distinct()
    }

    // JetPhotos results are accepted only when the returned registration matches exactly.
    private fun fetch_jet_photos_exact_candidates(registration: String): List<ExactPhotoCandidate> {
        val encoded = URLEncoder.encode(registration, "UTF-8")
        val api_url = "https://jp.rewis.workers.dev/?page=1&sort-order=1&keywords=$encoded&keywords-type=registration&keywords-contain=0"
        val photos = fetch_json_object(api_url)?.optJSONArray("photos") ?: return emptyList()
        val candidates = mutableListOf<ExactPhotoCandidate>()
        for (index in 0 until photos.length()) {
            val item = photos.optJSONObject(index) ?: continue
            val found_registration = normalized_registration(item.optString("registration"))
            if (found_registration != registration) continue
            if (!is_exterior_candidate_text(item.toString())) continue
            listOf(item.optString("imageUrl"), item.optString("thumbnailUrl")).forEach { url ->
                if (url.startsWith("https://", ignoreCase = true) && IMAGE_URL_PATTERN.containsMatchIn(url)) {
                    candidates += ExactPhotoCandidate(
                        image_url = url,
                        source_name = "JetPhotos",
                        page_url = item.optString("link").takeIf { it.startsWith("https://", ignoreCase = true) } ?: api_url,
                        note = "Exact aircraft photo from JetPhotos; registration verified"
                    )
                }
            }
        }
        return candidates.distinctBy { it.image_url }
    }

    // PlaneSpotters APIs return nested JSON, so this walks the response for the first allowed image URL.
    private fun fetch_planespotters_photo_candidate(api_url: String): ExactPhotoCandidate? {
        val safe_url = https_url(api_url) ?: return null
        var connection: HttpURLConnection? = null
        return try {
            connection = (safe_url.openConnection() as HttpURLConnection).apply {
                connectTimeout = 5000
                readTimeout = 8000
                requestMethod = "GET"
                setRequestProperty("User-Agent", user_agent)
            }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                return null
            }
            exterior_image_urls(JSONObject(connection.inputStream.bufferedReader().use { it.readText() }))
                .firstOrNull()
                ?.let { image_url ->
                    ExactPhotoCandidate(
                        image_url = image_url,
                        source_name = "PlaneSpotters",
                        page_url = api_url,
                        note = "Exact aircraft photo from PlaneSpotters"
                    )
                }
        } catch (_: Exception) {
            null
        } finally {
            connection?.disconnect()
        }
    }

    // This mirrors tar1090's selected-aircraft photo query using direct HTTP.
    private fun fetch_planespotters_selected_candidates(
        icao24: String,
        registration: String?,
        type_code: String?
    ): List<ExactPhotoCandidate> {
        val hex = icao24.trim().trimStart('~').uppercase(Locale.US).takeIf { MODE_S_HEX.matches(it) } ?: return emptyList()
        val url = StringBuilder("https://api.planespotters.net/pub/photos/hex/$hex")
        val params = mutableListOf<String>()
        registration?.takeIf { it.isNotBlank() }?.let { params += "reg=${URLEncoder.encode(it, "UTF-8")}" }
        type_code?.trim()?.takeIf { it.isNotBlank() }?.let { params += "icaoType=${URLEncoder.encode(it, "UTF-8")}" }
        if (params.isNotEmpty()) url.append("?").append(params.joinToString("&"))
        val json = fetch_json_object(url.toString()) ?: return emptyList()
        val photos = json.optJSONArray("photos") ?: json.optJSONArray("images") ?: return emptyList()
        val candidates = mutableListOf<ExactPhotoCandidate>()
            for (index in 0 until photos.length()) {
                val photo = photos.optJSONObject(index) ?: continue
                if (!is_exterior_candidate_text(photo.toString())) continue
                val image_url = photo.optJSONObject("thumbnail")?.optString("src")?.takeIf { it.startsWith("https://", ignoreCase = true) }
                    ?: photo.optString("thumbnail").takeIf { it.startsWith("https://", ignoreCase = true) }
                    ?: photo.optString("image").takeIf { it.startsWith("https://", ignoreCase = true) }
                ?: photo.optString("imageUrl").takeIf { it.startsWith("https://", ignoreCase = true) }
                ?: continue
            if (!is_allowed_https_image_url(image_url)) continue
            val page_url = photo.optString("link").takeIf { it.startsWith("https://", ignoreCase = true) }
                ?: photo.optString("url").takeIf { it.startsWith("https://", ignoreCase = true) }
                ?: url.toString()
            val photographer = photo.optString("photographer").trim().ifEmpty { photo.optString("user").trim() }
            candidates += ExactPhotoCandidate(
                image_url = image_url,
                source_name = "PlaneSpotters",
                page_url = page_url,
                note = listOfNotNull(
                    "Exact aircraft photo from PlaneSpotters",
                    photographer.takeIf { it.isNotBlank() }?.let { "image credit $it" }
                ).joinToString("; ")
            )
        }
        return candidates.distinctBy { it.image_url }
    }

    // Representative photos are only same make/model examples and are labeled as not this exact aircraft.
    private fun fetch_representative_photo(details: AircraftDetails): AircraftPhotoResult.Found? {
        AircraftPhotoCatalog.representative_model_names(details).forEach { model ->
            val queries = AircraftPhotoCatalog.representative_photo_queries(details, model)
            queries.forEach { query ->
                val candidates = fetch_wikimedia_search_image_candidates(query) +
                    fetch_openverse_image_candidates(query).take(MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY)
                candidates
                    .as_exterior_candidates()
                    .take(MAX_REPRESENTATIVE_PHOTO_CANDIDATES_PER_QUERY)
                    .forEach { candidate ->
                        fetch_bitmap(candidate.image_url, candidate.page_url)?.let { bitmap ->
                            return AircraftPhotoResult.Found(
                                bitmap,
                                "Representative exterior $model photo from ${candidate.source_name}; not this exact aircraft",
                                candidate.gallery_evidence(query),
                                PhotoQuality.REPRESENTATIVE
                            )
                        }
                    }
            }
        }
        return null
    }

    // Generic search results must contain proof terms before they can be shown as verified.
    private fun fetch_verified_generic_search_photo(aircraft: Aircraft, details: AircraftDetails): AircraftPhotoResult.Found? {
        val registration = normalized_registration(details.registration ?: aircraft.registration)
        val exact_terms = listOfNotNull(registration, aircraft.icao24.takeIf { it.isNotBlank() })
        AircraftPhotoCatalog.exact_photo_queries(registration, aircraft.icao24).forEach { query ->
            val candidates = fetch_wikimedia_search_image_candidates(query) +
                fetch_openverse_image_candidates(query).take(MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY)
            candidates.as_exterior_candidates().forEach { candidate ->
                verified_search_photo(
                    candidate = candidate,
                    query = query,
                    note = "Verified exact-aircraft search result for ${registration ?: aircraft.icao24.uppercase(Locale.US)}",
                    verification_terms = exact_terms,
                    quality = PhotoQuality.EXACT
                )?.let { return it }
            }
        }

        AircraftPhotoCatalog.representative_model_names(details).forEach { model ->
            val verification_terms = AircraftPhotoCatalog.photo_verification_terms(details, model)
            AircraftPhotoCatalog.representative_photo_queries(details, model).forEach { query ->
                val candidates = fetch_wikimedia_search_image_candidates(query) +
                    fetch_openverse_image_candidates(query).take(MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY)
                candidates.as_exterior_candidates().forEach { candidate ->
                    verified_search_photo(
                        candidate = candidate,
                        query = query,
                        note = "Verified search result for $model; not this exact aircraft",
                        verification_terms = verification_terms,
                        quality = PhotoQuality.REPRESENTATIVE
                    )?.let { return it }
                }
            }
        }
        return null
    }

    // Investigable photos are a last resort and always carry source evidence for the user to inspect.
    private fun fetch_investigable_search_photo(aircraft: Aircraft, details: AircraftDetails): AircraftPhotoResult.Found? {
        val registration = normalized_registration(details.registration ?: aircraft.registration)
        val exact_queries = AircraftPhotoCatalog.exact_photo_queries(registration, aircraft.icao24)
        val representative_queries = AircraftPhotoCatalog.representative_model_names(details)
            .flatMap { AircraftPhotoCatalog.representative_photo_queries(details, it) }
        (exact_queries + representative_queries).distinct().forEach { query ->
            val candidates = fetch_wikimedia_search_image_candidates(query) +
                fetch_openverse_image_candidates(query).take(MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY)
            candidates.as_exterior_candidates().forEach { candidate ->
                val bitmap = fetch_bitmap(candidate.image_url, candidate.page_url) ?: return@forEach
                val evidence = PhotoEvidence(
                    source_name = candidate.source_name,
                    image_url = candidate.image_url,
                    page_url = candidate.page_url,
                    search_query = query,
                    quote = candidate.investigation_text(),
                    matched_terms = emptyList()
                )
                return AircraftPhotoResult.Found(
                    bitmap,
                    "Unverified search result; tap photo to inspect source",
                    evidence,
                    PhotoQuality.INVESTIGABLE
                )
            }
        }
        return null
    }

    private fun fetch_representative_gallery_items(
        aircraft: Aircraft,
        details: AircraftDetails
    ): List<AircraftPhotoGalleryItem> {
        val items = mutableListOf<AircraftPhotoGalleryItem>()
        val models = AircraftPhotoCatalog.representative_model_names(details)
        models.take(3).forEach { model ->
            items += fetch_gallery_item_for_queries(
                queries = AircraftPhotoCatalog.representative_photo_queries(details, model),
                title = "Representative exterior",
                caption = "Same make/model family: $model; not this exact aircraft",
                view_type = AircraftPhotoViewType.EXTERIOR
            )
            items += fetch_gallery_item_for_queries(
                queries = listOf("\"$model\" cockpit", "$model cockpit"),
                title = "Representative cockpit",
                caption = "Representative cockpit view for $model; not this exact aircraft",
                view_type = AircraftPhotoViewType.COCKPIT
            )
            items += fetch_gallery_item_for_queries(
                queries = listOf("\"$model\" cabin interior", "$model cabin interior", "$model interior"),
                title = "Representative interior",
                caption = "Representative interior/cabin view for $model; not this exact aircraft",
                view_type = AircraftPhotoViewType.INTERIOR
            )
        }
        if (items.isEmpty() && aircraft.icao24.isNotBlank()) {
            fetch_investigable_search_photo(aircraft, details)?.let {
                items += it.to_gallery_item("Investigable photo", AircraftPhotoViewType.EXTERIOR)
            }
        }
        return items
    }

    private fun fetch_gallery_item_for_queries(
        queries: List<String>,
        title: String,
        caption: String,
        view_type: AircraftPhotoViewType
    ): List<AircraftPhotoGalleryItem> {
        queries.distinct().forEach { query ->
            val candidates = fetch_wikimedia_search_image_candidates(query) +
                fetch_openverse_image_candidates(query).take(MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY)
            candidates
                .filter { candidate -> candidate.matches_gallery_view_type(view_type) }
                .distinctBy { it.image_url }
                .take(MAX_GALLERY_CANDIDATES_PER_QUERY)
                .forEach { candidate ->
                    val bitmap = fetch_bitmap(candidate.image_url, candidate.page_url) ?: return@forEach
                    return listOf(
                        AircraftPhotoGalleryItem(
                            bitmap = bitmap,
                            title = title,
                            caption = caption,
                            evidence = candidate.gallery_evidence(query),
                            quality = PhotoQuality.REPRESENTATIVE,
                            view_type = view_type
                        )
                    )
                }
        }
        return emptyList()
    }

    // A search candidate becomes usable only after the source page or metadata actually mentions the verification terms.
    private fun verified_search_photo(
        candidate: SearchImageCandidate,
        query: String,
        note: String,
        verification_terms: List<String>,
        quality: PhotoQuality
    ): AircraftPhotoResult.Found? {
        val quote = fetch_verification_quote(candidate.page_url, verification_terms)
            ?: candidate.verification_text?.let { quote_from_text(it, verification_terms) }
            ?: return null
        val bitmap = fetch_bitmap(candidate.image_url, candidate.page_url) ?: return null
        val evidence = PhotoEvidence(
            source_name = candidate.source_name,
            image_url = candidate.image_url,
            page_url = candidate.page_url,
            search_query = query,
            quote = quote.text,
            matched_terms = quote.matched_terms
        )
        return AircraftPhotoResult.Found(
            bitmap,
            note,
            evidence,
            quality
        )
    }

    // Build the short proof text shown for user-investigable images.
    private fun SearchImageCandidate.investigation_text(): String {
        val title_text = title.takeIf { it.isNotBlank() }?.let { "Title: $it" }
        val metadata_text = verification_text?.takeIf { it.isNotBlank() }?.let { "Metadata: $it" }
        return listOfNotNull(title_text, metadata_text, "Source page: $page_url")
            .joinToString("  ")
    }

    private fun found_exact_photo(
        bitmap: Bitmap,
        candidate: ExactPhotoCandidate
    ): AircraftPhotoResult.Found {
        return AircraftPhotoResult.Found(
            bitmap = bitmap,
            note = candidate.note,
            evidence = PhotoEvidence(
                source_name = candidate.source_name,
                image_url = candidate.image_url,
                page_url = candidate.page_url,
                search_query = "Exact aircraft photo lookup",
                quote = candidate.note,
                matched_terms = emptyList()
            ),
            quality = PhotoQuality.EXACT
        )
    }

    private fun AircraftPhotoResult.Found.to_gallery_item(
        title: String,
        view_type: AircraftPhotoViewType
    ): AircraftPhotoGalleryItem {
        return AircraftPhotoGalleryItem(
            bitmap = bitmap,
            title = title,
            caption = note,
            evidence = evidence,
            quality = quality,
            view_type = view_type
        )
    }

    private fun SearchImageCandidate.gallery_evidence(query: String): PhotoEvidence {
        return PhotoEvidence(
            source_name = source_name,
            image_url = image_url,
            page_url = page_url,
            search_query = query,
            quote = investigation_text(),
            matched_terms = emptyList()
        )
    }

    private fun SearchImageCandidate.is_main_exterior_candidate(): Boolean {
        val text = "$title ${verification_text.orEmpty()}"
        return is_exterior_candidate_text(text)
    }

    private fun List<SearchImageCandidate>.as_exterior_candidates(): List<SearchImageCandidate> {
        return distinctBy { it.image_url }
            .filter { it.is_main_exterior_candidate() }
            .sortedByDescending { it.exterior_score() }
    }

    private fun SearchImageCandidate.exterior_score(): Int {
        val text = "$title ${verification_text.orEmpty()} $image_url".lowercase(Locale.US)
        var score = 0
        EXTERIOR_PREFERRED_TEXT.findAll(text).forEach { _ -> score += 4 }
        if (AIRCRAFT_TEXT.containsMatchIn(text)) score += 2
        if (DISALLOWED_MAIN_PHOTO_TEXT.containsMatchIn(text)) score -= 100
        return score
    }

    private fun SearchImageCandidate.matches_gallery_view_type(view_type: AircraftPhotoViewType): Boolean {
        val text = "$title ${verification_text.orEmpty()}"
        return when (view_type) {
            AircraftPhotoViewType.EXTERIOR -> !DISALLOWED_MAIN_PHOTO_TEXT.containsMatchIn(text)
            AircraftPhotoViewType.COCKPIT -> COCKPIT_TEXT.containsMatchIn(text)
            AircraftPhotoViewType.CABIN,
            AircraftPhotoViewType.INTERIOR -> INTERIOR_TEXT.containsMatchIn(text)
        }
    }

    // Openverse candidates stay candidates until proof terms are found elsewhere.
    private fun fetch_openverse_image_candidates(query: String): List<SearchImageCandidate> {
        var connection: HttpURLConnection? = null
        return try {
            val encoded = URLEncoder.encode(query, "UTF-8")
            val api_url = "https://api.openverse.org/v1/images/?format=json&page_size=12&mature=false&q=$encoded"
            connection = (URL(api_url).openConnection() as HttpURLConnection).apply {
                connectTimeout = 5000
                readTimeout = 9000
                requestMethod = "GET"
                setRequestProperty("User-Agent", user_agent)
            }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                return emptyList()
            }
            val results = JSONObject(connection.inputStream.bufferedReader().use { it.readText() })
                .optJSONArray("results")
                ?: return emptyList()
            val candidates = mutableListOf<SearchImageCandidate>()
            for (index in 0 until results.length()) {
                val item = results.optJSONObject(index) ?: continue
                val image_url = item.optString("url").trim()
                val page_url = item.optString("foreign_landing_url").trim()
                val title = item.optString("title").trim()
                val lower_title = title.lowercase(Locale.US)
                if (
                    is_allowed_https_image_url(image_url) &&
                    page_url.startsWith("https://", ignoreCase = true) &&
                    !lower_title.contains("logo") &&
                    !lower_title.contains("diagram")
                ) {
                    val tags = item.optJSONArray("tags")?.let { tag_array ->
                        (0 until tag_array.length()).mapNotNull { tag_index ->
                            tag_array.optJSONObject(tag_index)?.optString("name")?.trim()?.takeIf { it.isNotBlank() }
                        }
                    }.orEmpty()
                    candidates += SearchImageCandidate(
                        image_url = image_url,
                        page_url = page_url,
                        source_name = item.optString("provider").trim().ifEmpty { "Openverse source" },
                        title = title,
                        verification_text = listOf(
                            title,
                            item.optString("creator").trim(),
                            tags.take(8).joinToString(" ")
                        ).filter { it.isNotBlank() }.joinToString(" ")
                    )
                }
            }
            candidates.distinctBy { it.image_url }
        } catch (_: Exception) {
            emptyList()
        } finally {
            connection?.disconnect()
        }
    }

    // Wikimedia Commons candidates include structured metadata for exact or representative proof.
    private fun fetch_wikimedia_search_image_candidates(query: String): List<SearchImageCandidate> {
        val encoded = URLEncoder.encode(query, "UTF-8")
        val api_url = "https://commons.wikimedia.org/w/api.php" +
            "?action=query&format=json&generator=search&gsrnamespace=6&gsrlimit=10" +
            "&gsrsearch=$encoded&prop=imageinfo&iiprop=url|mime|extmetadata"
        val pages = fetch_json_object(api_url)
            ?.optJSONObject("query")
            ?.optJSONObject("pages")
            ?: return emptyList()
        val candidates = mutableListOf<SearchImageCandidate>()
        val keys = pages.keys()
        while (keys.hasNext()) {
            val page = pages.optJSONObject(keys.next()) ?: continue
            val title = page.optString("title").removePrefix("File:").trim()
            val info = page.optJSONArray("imageinfo")?.optJSONObject(0) ?: continue
            val mime = info.optString("mime")
            val image_url = info.optString("url").trim()
            val page_url = info.optString("descriptionurl").trim()
            if (!mime.startsWith("image/") || !is_allowed_https_image_url(image_url)) continue
            if (!page_url.startsWith("https://", ignoreCase = true)) continue
            val metadata = info.optJSONObject("extmetadata")
            val metadata_text = listOfNotNull(
                title,
                metadata?.optJSONObject("ObjectName")?.optString("value"),
                metadata?.optJSONObject("ImageDescription")?.optString("value"),
                metadata?.optJSONObject("Categories")?.optString("value")
            ).joinToString(" ")
            candidates += SearchImageCandidate(
                image_url = image_url,
                page_url = page_url,
                source_name = "Wikimedia Commons",
                title = title,
                verification_text = plain_text_from_html(metadata_text)
            )
        }
        return candidates.distinctBy { it.image_url }.take(MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY)
    }

    // Pull a small proof quote from the source page when it mentions the aircraft or model terms.
    private fun fetch_verification_quote(page_url: String, terms: List<String>): VerificationQuote? {
        val html = fetch_text(page_url) ?: return null
        return quote_from_text(plain_text_from_html(html), terms)
    }

    // Keep only enough quoted text to justify the match without treating the source page as app data.
    private fun quote_from_text(text: String, terms: List<String>): VerificationQuote? {
        val upper = text.uppercase(Locale.US)
        val matched = terms.filter { term -> upper.contains(term.uppercase(Locale.US)) }.distinct()
        if (matched.isEmpty()) return null
        val first_index = matched.mapNotNull { term ->
            val index = upper.indexOf(term.uppercase(Locale.US))
            if (index >= 0) index else null
        }.minOrNull() ?: return null
        val start = max(0, first_index - 120)
        val end = min(text.length, first_index + 180)
        return VerificationQuote(
            text = text.substring(start, end).trim(),
            matched_terms = matched.take(4)
        )
    }

    // Strip page markup before proof matching so verification looks at readable source text.

    // JSON helpers reject non-HTTPS URLs before any request leaves the app.
    private fun fetch_json_object(url: String): JSONObject? =
        fetch_json_object(url, user_agent)

    // Text helpers are used only for proof snippets, not to manufacture aircraft facts.
    private fun fetch_text(url: String): String? {
        val safe_url = https_url(url) ?: return null
        var connection: HttpURLConnection? = null
        return try {
            connection = (safe_url.openConnection() as HttpURLConnection).apply {
                connectTimeout = 5000
                readTimeout = PHOTO_TEXT_READ_TIMEOUT_MS
                requestMethod = "GET"
                setRequestProperty("User-Agent", user_agent)
            }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                return null
            }
            connection.inputStream.bufferedReader().use { it.readText() }
        } catch (_: Exception) {
            null
        } finally {
            connection?.disconnect()
        }
    }

    // Image download accepts only allowed HTTPS image URLs and returns null on any uncertainty.
    private fun fetch_bitmap(url: String, referer: String? = null): Bitmap? {
        val safe_url = https_url(url) ?: return null
        var connection: HttpURLConnection? = null
        return try {
            connection = (safe_url.openConnection() as HttpURLConnection).apply {
                connectTimeout = 5000
                readTimeout = 8000
                requestMethod = "GET"
                setRequestProperty("User-Agent", AirplanesLiveHttp.browser_user_agent(user_agent))
                setRequestProperty("Accept", "image/avif,image/webp,image/apng,image/*,*/*;q=0.8")
                referer?.takeIf { it.startsWith("https://", ignoreCase = true) }?.let {
                    setRequestProperty("Referer", it)
                }
            }
            if (connection.responseCode != HttpURLConnection.HTTP_OK) {
                connection.errorStream?.close()
                return null
            }
            val content_type = connection.contentType.orEmpty()
            if (!content_type.startsWith("image/", ignoreCase = true) && !IMAGE_URL_PATTERN.containsMatchIn(url)) {
                return null
            }
            val bytes = read_image_bytes(connection.inputStream) ?: return null
            decode_display_photo(bytes)
        } catch (_: Exception) {
            null
        } finally {
            connection?.disconnect()
        }
    }

    private fun read_image_bytes(input: InputStream): ByteArray? {
        val output = ByteArrayOutputStream()
        val buffer = ByteArray(16 * 1024)
        var total = 0
        input.use { stream ->
            while (true) {
                val read = stream.read(buffer)
                if (read < 0) break
                total += read
                if (total > MAX_PHOTO_IMAGE_BYTES) return null
                output.write(buffer, 0, read)
            }
        }
        return output.toByteArray().takeIf { it.isNotEmpty() }
    }

    private fun decode_display_photo(bytes: ByteArray): Bitmap? {
        val bounds = BitmapFactory.Options().apply { inJustDecodeBounds = true }
        BitmapFactory.decodeByteArray(bytes, 0, bytes.size, bounds)
        if (bounds.outWidth <= 0 || bounds.outHeight <= 0) return null
        val options = BitmapFactory.Options().apply {
            inSampleSize = photo_sample_size(bounds.outWidth, bounds.outHeight)
            inPreferredConfig = Bitmap.Config.ARGB_8888
        }
        return BitmapFactory.decodeByteArray(bytes, 0, bytes.size, options)
    }

    private fun photo_sample_size(width: Int, height: Int): Int {
        var sample_size = 1
        var sampled_width = width
        var sampled_height = height
        while (max(sampled_width, sampled_height) > PHOTO_DECODE_MAX_EDGE_PX) {
            sample_size *= 2
            sampled_width /= 2
            sampled_height /= 2
        }
        return sample_size
    }

    // Walk nested photo API responses without assuming a specific field name for the first image.
    private fun exterior_image_urls(value: Any?): List<String> {
        val urls = mutableListOf<String>()
        collect_exterior_image_urls(value, context_text = "", output = urls)
        return urls.distinct()
    }

    private fun collect_exterior_image_urls(value: Any?, context_text: String, output: MutableList<String>) {
        when (value) {
            is JSONObject -> {
                val next_context = listOf(
                    context_text,
                    value.optString("caption"),
                    value.optString("description"),
                    value.optString("title"),
                    value.optString("category"),
                    value.optString("type")
                ).filter { it.isNotBlank() }.joinToString(" ")
                val keys = value.keys()
                while (keys.hasNext()) {
                    collect_exterior_image_urls(value.opt(keys.next()), next_context, output)
                }
            }
            is JSONArray -> {
                for (index in 0 until value.length()) {
                    collect_exterior_image_urls(value.opt(index), context_text, output)
                }
            }
            is String -> {
                if (is_allowed_https_image_url(value) && is_exterior_candidate_text("$context_text $value")) output += value
            }
        }
    }

    private fun is_exterior_candidate_text(text: String): Boolean {
        return !DISALLOWED_MAIN_PHOTO_TEXT.containsMatchIn(text)
    }

    private fun is_allowed_https_image_url(value: String?): Boolean {
        val url = value?.trim() ?: return false
        return url.startsWith("https://", ignoreCase = true) && IMAGE_URL_PATTERN.containsMatchIn(url)
    }

    
    private fun normalized_registration(value: String?): String? =
        normalized_photo_registration(value)

    private fun exact_photo_cache_key(
        aircraft: Aircraft,
        details: AircraftDetails,
        registration: String?
    ): String {
        return listOf(
            "exact",
            aircraft.icao24.trim().trimStart('~').uppercase(Locale.US),
            registration.orEmpty(),
            (details.type_code ?: aircraft.type_code).orEmpty().uppercase(Locale.US)
        ).joinToString("|")
    }

    private fun fallback_photo_cache_key(aircraft: Aircraft, details: AircraftDetails): String {
        return listOf(
            "fallback",
            aircraft.icao24.trim().trimStart('~').uppercase(Locale.US),
            normalized_registration(details.registration ?: aircraft.registration).orEmpty(),
            details.manufacturer.orEmpty().uppercase(Locale.US),
            details.type.orEmpty().uppercase(Locale.US),
            (details.type_code ?: aircraft.type_code).orEmpty().uppercase(Locale.US)
        ).joinToString("|")
    }

    private fun cached_photo(key: String): AircraftPhotoResult.Found? {
        val now = System.currentTimeMillis()
        return synchronized(photo_cache) {
            val cached = photo_cache[key] ?: return@synchronized null
            if (now - cached.stored_at_ms > PHOTO_CACHE_MAX_AGE_MS) {
                photo_cache.remove(key)
                null
            } else {
                cached.photo
            }
        }
    }

    private fun cache_photo(key: String, photo: AircraftPhotoResult.Found) {
        synchronized(photo_cache) {
            photo_cache[key] = CachedPhotoResult(photo, System.currentTimeMillis())
        }
    }

    private companion object {
        const val PHOTO_CACHE_MAX_ENTRIES = 32
        const val PHOTO_CACHE_MAX_AGE_MS = 15L * 60L * 1000L
        const val PHOTO_DECODE_MAX_EDGE_PX = 1200
        const val MAX_PHOTO_IMAGE_BYTES = 8 * 1024 * 1024
        const val MAX_REPRESENTATIVE_PHOTO_CANDIDATES_PER_QUERY = 4
        const val MAX_SEARCH_PHOTO_CANDIDATES_PER_QUERY = 5
        const val MAX_GALLERY_CANDIDATES_PER_QUERY = 4
        const val MAX_GALLERY_ITEMS = 8
        const val PHOTO_TEXT_READ_TIMEOUT_MS = 9000
        val IMAGE_URL_PATTERN = Regex("\\.(jpg|jpeg|png|webp)(\\?|$)", RegexOption.IGNORE_CASE)
        val DISALLOWED_MAIN_PHOTO_TEXT = Regex(
            "\\b(interior|cockpit|cabin|seat|seats|seating|lavatory|blueprint|diagram|schematic|floor\\s*plan|seat\\s*map)\\b",
            RegexOption.IGNORE_CASE
        )
        val EXTERIOR_PREFERRED_TEXT = Regex(
            "\\b(exterior|side\\s*view|ramp|apron|taxi|taxiing|takeoff|landing|in\\s*flight|airborne|livery)\\b",
            RegexOption.IGNORE_CASE
        )
        val AIRCRAFT_TEXT = Regex("\\b(aircraft|airplane|aeroplane|airliner|jet|helicopter|rotorcraft)\\b", RegexOption.IGNORE_CASE)
        val COCKPIT_TEXT = Regex("\\b(cockpit|flight\\s*deck)\\b", RegexOption.IGNORE_CASE)
        val INTERIOR_TEXT = Regex("\\b(interior|cabin|seat|seats|seating|lavatory)\\b", RegexOption.IGNORE_CASE)
        val MODE_S_HEX = Regex("^[0-9A-F]{6}$")
    }
}

private data class ExactPhotoCandidate(
    val image_url: String,
    val source_name: String,
    val page_url: String,
    val note: String
)

private data class CachedPhotoResult(
    val photo: AircraftPhotoResult.Found,
    val stored_at_ms: Long
)


sealed class AircraftPhotoResult {
    data class Found(
        val bitmap: Bitmap,
        val note: String,
        val evidence: PhotoEvidence? = null,
        val quality: PhotoQuality
    ) : AircraftPhotoResult()

    data class Unavailable(val reason: String) : AircraftPhotoResult()
}

enum class PhotoQuality(val rank: Int) {
    INVESTIGABLE(1),
    REPRESENTATIVE(2),
    EXACT(3)
}

data class PhotoEvidence(
    val source_name: String,
    val image_url: String,
    val page_url: String,
    val search_query: String,
    val quote: String,
    val matched_terms: List<String>
)

data class SearchImageCandidate(
    val image_url: String,
    val page_url: String,
    val source_name: String,
    val title: String = "",
    val verification_text: String? = null
)

data class AircraftPhotoGalleryItem(
    val bitmap: Bitmap,
    val title: String,
    val caption: String,
    val evidence: PhotoEvidence?,
    val quality: PhotoQuality,
    val view_type: AircraftPhotoViewType
)

enum class AircraftPhotoViewType {
    EXTERIOR,
    INTERIOR,
    COCKPIT,
    CABIN
}

data class VerificationQuote(
    val text: String,
    val matched_terms: List<String>
)


enum class PriorityRangeValue {
    HORIZONTAL,
    VERTICAL
}

object PriorityRangeAdjuster {
    fun adjusted_feet(
        current_feet: Float,
        value: PriorityRangeValue,
        direction: Float,
        long_press: Boolean,
        units: UnitSystem
    ): Float {
        return if (units == UnitSystem.METRIC) {
            adjusted_metric_feet(current_feet, value, direction, long_press)
        } else {
            adjusted_imperial_feet(current_feet, value, direction, long_press)
        }
    }

    private fun adjusted_metric_feet(
        current_feet: Float,
        value: PriorityRangeValue,
        direction: Float,
        long_press: Boolean
    ): Float {
        val current_meters = feet_to_meters(current_feet.toDouble())
        val normal_step_meters = when (value) {
            PriorityRangeValue.HORIZONTAL -> 250.0
            PriorityRangeValue.VERTICAL -> 100.0
        }
        val action_step_meters = if (long_press) 3000.0 else normal_step_meters
        val min_meters = when (value) {
            PriorityRangeValue.HORIZONTAL -> 200.0
            PriorityRangeValue.VERTICAL -> 30.0
        }
        val max_meters = when (value) {
            PriorityRangeValue.HORIZONTAL -> 18_000.0
            PriorityRangeValue.VERTICAL -> 3_000.0
        }
        return meters_to_feet(
            stepped_display_value(
                current = current_meters,
                direction = direction.toDouble(),
                normal_step = normal_step_meters,
                action_step = action_step_meters,
                min_value = min_meters,
                max_value = max_meters
            )
        ).toFloat()
    }

    private fun adjusted_imperial_feet(
        current_feet: Float,
        value: PriorityRangeValue,
        direction: Float,
        long_press: Boolean
    ): Float {
        val normal_step_feet = when (value) {
            PriorityRangeValue.HORIZONTAL -> 1000.0
            PriorityRangeValue.VERTICAL -> 500.0
        }
        val action_step_feet = if (long_press) 10_000.0 else normal_step_feet
        val min_feet = when (value) {
            PriorityRangeValue.HORIZONTAL -> 500.0
            PriorityRangeValue.VERTICAL -> 100.0
        }
        val max_feet = when (value) {
            PriorityRangeValue.HORIZONTAL -> 60_000.0
            PriorityRangeValue.VERTICAL -> 10_000.0
        }
        return stepped_display_value(
            current = current_feet.toDouble(),
            direction = direction.toDouble(),
            normal_step = normal_step_feet,
            action_step = action_step_feet,
            min_value = min_feet,
            max_value = max_feet
        ).toFloat()
    }

    private fun stepped_display_value(
        current: Double,
        direction: Double,
        normal_step: Double,
        action_step: Double,
        min_value: Double,
        max_value: Double
    ): Double {
        val current_on_grid = grid_aligned_value(current, normal_step)
        val aligned = if (direction > 0.0) {
            floor(current_on_grid / normal_step) * normal_step
        } else {
            ceil(current_on_grid / normal_step) * normal_step
        }
        return (aligned + direction * action_step).coerceIn(min_value, max_value)
    }

    private fun grid_aligned_value(current: Double, step: Double): Double {
        val nearest = round(current / step) * step
        return if (abs(current - nearest) < GRID_EPSILON) nearest else current
    }

    private fun feet_to_meters(feet: Double): Double = feet / FEET_PER_METER

    private fun meters_to_feet(meters: Double): Double = meters * FEET_PER_METER

    private const val FEET_PER_METER = 3.28084

    private const val GRID_EPSILON = 0.05
}

// endregion

// region RENDERING PIPELINE

object AircraftMarkerMorph {
    fun marker_dot_blend(viewport: Viewport): Float {
        return zoom_marker_dot_blend(viewport.zoom)
    }

    fun zoom_marker_dot_blend(zoom: Double): Float {
        val zoom_dot_blend = 1f - smooth_step(DOT_ZOOM_FULL, DOT_ZOOM_SYMBOL, zoom.toFloat())
        return smooth_step(0f, 1f, zoom_dot_blend)
    }

    fun symbol_progress(dot_blend: Float): Float {
        return smooth_step(SYMBOL_BLEND_START, SYMBOL_BLEND_FULL, 1f - dot_blend)
    }

    fun symbol_visibility(dot_blend: Float): Float {
        return smooth_step(SYMBOL_VISIBILITY_START, SYMBOL_VISIBILITY_FULL, symbol_progress(dot_blend))
    }

    fun dot_progress(dot_blend: Float): Float {
        return smooth_step(DOT_FADE_OUT_START, DOT_FADE_OUT_FULL, dot_blend)
    }

    fun shape_progress(dot_blend: Float): Float {
        return smooth_step(0f, 1f, 1f - dot_blend)
    }

    fun aircraft_icon_scale(zoom: Double): Float {
        val zoom_progress = smooth_step(SCALE_ZOOM_MIN, SCALE_ZOOM_MAX, zoom.toFloat())
        return SCALE_MIN + (SCALE_MAX - SCALE_MIN) * zoom_progress
    }

    fun aircraft_dot_scale(zoom: Double): Float {
        val far_progress = smooth_step(DOT_SCALE_FLOOR_ZOOM_MIN, DOT_SCALE_FLOOR_ZOOM_MAX, zoom.toFloat())
        val far_scale = lerp(DOT_SCALE_FLOOR_MIN, DOT_SCALE_FLOOR_MAX, far_progress)
        val transition_progress = smooth_step(
            DOT_SCALE_TRANSITION_ZOOM_START,
            DOT_SCALE_TRANSITION_ZOOM_END,
            zoom.toFloat()
        )
        return max(READABLE_DOT_SCALE_MIN, lerp(far_scale, DOT_SCALE_TRANSITION_MAX, transition_progress))
    }

    fun blended_icon_scale(zoom: Double, dot_blend: Float): Float {
        return lerp(aircraft_icon_scale(zoom), aircraft_dot_scale(zoom), dot_blend)
    }

    fun dense_batch_dot_alpha(dot_blend: Float): Float {
        return 0.38f + 0.62f * smooth_step(0.12f, 0.92f, dot_blend)
    }

    fun batch_dot_outline_scale(dot_scale: Float): Float {
        return (dot_scale / DOT_SCALE_TRANSITION_MAX).coerceIn(BATCH_DOT_OUTLINE_MIN_SCALE, 1f)
    }

    fun smooth_step(edge0: Float, edge1: Float, value: Float): Float =
        safe_smooth_step(edge0, edge1, value)

    
    const val SYMBOL_ACTIVE_MIN_PROGRESS = 0.03f
    const val SYMBOL_IDLE_MIN_PROGRESS = 0.03f
    const val READABLE_DOT_SCALE_MIN = 0.24f

    private const val SCALE_ZOOM_MIN = 5.6f
    private const val SCALE_ZOOM_MAX = 13.2f
    private const val SCALE_MIN = 0.30f
    private const val SCALE_MAX = 1.0f
    private const val DOT_SCALE_FLOOR_MIN = 0.06f
    private const val DOT_SCALE_FLOOR_MAX = 0.34f
    private const val DOT_SCALE_TRANSITION_MAX = 1.08f
    private const val DOT_SCALE_FLOOR_ZOOM_MIN = 3.0f
    private const val DOT_SCALE_FLOOR_ZOOM_MAX = 6.4f
    private const val DOT_SCALE_TRANSITION_ZOOM_START = 3.8f
    private const val DOT_SCALE_TRANSITION_ZOOM_END = 13.6f
    private const val DOT_ZOOM_FULL = 2.0f
    private const val DOT_ZOOM_SYMBOL = 13.6f
    private const val SYMBOL_BLEND_START = 0.0f
    private const val SYMBOL_BLEND_FULL = 0.78f
    private const val SYMBOL_VISIBILITY_START = 0.0f
    private const val SYMBOL_VISIBILITY_FULL = 0.26f
    private const val DOT_FADE_OUT_START = 0.0f
    private const val DOT_FADE_OUT_FULL = 0.86f
    private const val BATCH_DOT_OUTLINE_MIN_SCALE = 0.22f
}


object AircraftSymbolRenderer {
    private val path = Path()
    private val body_path_cache = object : LinkedHashMap<SymbolBodyPathKey, Path>(64, 0.75f, true) {
        override fun removeEldestEntry(eldest: MutableMap.MutableEntry<SymbolBodyPathKey, Path>): Boolean {
            return size > SYMBOL_BODY_PATH_CACHE_MAX_ENTRIES
        }
    }
    private val body_point_cache = object : LinkedHashMap<SymbolBodyPathKey, FloatArray>(64, 0.75f, true) {
        override fun removeEldestEntry(eldest: MutableMap.MutableEntry<SymbolBodyPathKey, FloatArray>): Boolean {
            return size > SYMBOL_BODY_PATH_CACHE_MAX_ENTRIES
        }
    }

    fun draw(
        canvas: Canvas,
        symbol: AircraftSymbol,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        when (symbol) {
            AircraftSymbol.ROTORCRAFT -> draw_rotorcraft(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.GLIDER -> draw_glider(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.UAV -> draw_uav(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.SURFACE -> draw_surface(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.AIRLINER -> draw_airliner(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.GENERAL_AVIATION -> draw_general_aviation(canvas, progress, paint, stroke_paint, dp)
        }
    }

    fun draw_cached_morph(
        canvas: Canvas,
        symbol: AircraftSymbol,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        when (symbol) {
            AircraftSymbol.GENERAL_AVIATION -> draw_cached_morphed_polygon(canvas, symbol, GENERAL_AVIATION_POINTS, progress, paint, stroke_paint, dp)
            AircraftSymbol.GLIDER -> draw_cached_morphed_polygon(canvas, symbol, GLIDER_POINTS, progress, paint, stroke_paint, dp)
            AircraftSymbol.AIRLINER -> draw_cached_airliner(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.SURFACE -> draw_cached_surface(canvas, progress, paint, stroke_paint, dp)
            AircraftSymbol.ROTORCRAFT,
            AircraftSymbol.UAV -> draw(canvas, symbol, progress, paint, stroke_paint, dp)
        }
    }

    private fun draw_general_aviation(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        draw_morphed_polygon(
            canvas = canvas,
            target = GENERAL_AVIATION_POINTS,
            progress = progress,
            paint = paint,
            stroke_paint = stroke_paint,
            dp = dp
        )
    }

    private fun draw_airliner(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        draw_morphed_polygon(
            canvas = canvas,
            target = AIRLINER_POINTS,
            progress = p,
            paint = paint,
            stroke_paint = stroke_paint,
            dp = dp
        )

        val engine = smooth_step(0.48f, 1f, p)
        if (engine > 0f) {
            canvas.drawCircle(-dp(11.8f * engine), dp(5.6f * engine), dp(2.2f * engine), stroke_paint)
            canvas.drawCircle(dp(11.8f * engine), dp(5.6f * engine), dp(2.2f * engine), stroke_paint)
        }
    }

    private fun draw_rotorcraft(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        val body = smooth_step(0f, 0.55f, p)
        val rotor = smooth_step(0.25f, 1f, p)
        val tail = smooth_step(0.45f, 1f, p)
        val body_rect = RectF(-dp(4f + 4f * body), -dp(4f + 3f * body), dp(4f + 5f * body), dp(4f + 4f * body))
        canvas.drawOval(body_rect, paint)
        canvas.drawOval(body_rect, stroke_paint)
        stroke_paint.strokeWidth = dp(2.5f)
        canvas.drawLine(-dp(5f + 19f * rotor), 0f, dp(5f + 19f * rotor), 0f, stroke_paint)
        canvas.drawLine(0f, -dp(5f + 17f * rotor), 0f, dp(5f + 17f * rotor), stroke_paint)
        stroke_paint.strokeWidth = dp(2f)
        canvas.drawLine(dp(5f + 4f * body), dp(1f), dp(7f + 16f * tail), dp(4f + 5f * tail), stroke_paint)
        canvas.drawLine(dp(8f + 13f * tail), dp(3f + 2f * tail), dp(9f + 16f * tail), dp(5f + 8f * tail), stroke_paint)
        stroke_paint.strokeWidth = dp(1.2f)
    }

    private fun draw_glider(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        draw_morphed_polygon(
            canvas = canvas,
            target = GLIDER_POINTS,
            progress = progress,
            paint = paint,
            stroke_paint = stroke_paint,
            dp = dp
        )
    }

    private fun draw_uav(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        path.reset()
        val p = progress.coerceIn(0f, 1f)
        val body = smooth_step(0f, 0.55f, p)
        val arms = smooth_step(0.2f, 1f, p)
        val rotors = smooth_step(0.55f, 1f, p)
        path.moveTo(0f, -dp(5f + 8f * body))
        path.lineTo(dp(3f + 5f * body), 0f)
        path.lineTo(0f, dp(5f + 8f * body))
        path.lineTo(-dp(3f + 5f * body), 0f)
        path.close()
        canvas.drawPath(path, paint)
        canvas.drawPath(path, stroke_paint)
        stroke_paint.strokeWidth = dp(2f)
        val arm_inner = dp(4f + 2f * body)
        val arm_outer = dp(7f + 11f * arms)
        canvas.drawLine(-arm_inner, -arm_inner, -arm_outer, -arm_outer, stroke_paint)
        canvas.drawLine(arm_inner, -arm_inner, arm_outer, -arm_outer, stroke_paint)
        canvas.drawLine(-arm_inner, arm_inner, -arm_outer, arm_outer, stroke_paint)
        canvas.drawLine(arm_inner, arm_inner, arm_outer, arm_outer, stroke_paint)
        val rotor_offset = dp(8f + 12f * arms)
        val rotor_radius = dp(1.5f + 3.5f * rotors)
        val rotor_blade = dp(5f * rotors)
        draw_uav_rotor(canvas, -rotor_offset, -rotor_offset, rotor_radius, rotor_blade, paint, stroke_paint)
        draw_uav_rotor(canvas, rotor_offset, -rotor_offset, rotor_radius, rotor_blade, paint, stroke_paint)
        draw_uav_rotor(canvas, -rotor_offset, rotor_offset, rotor_radius, rotor_blade, paint, stroke_paint)
        draw_uav_rotor(canvas, rotor_offset, rotor_offset, rotor_radius, rotor_blade, paint, stroke_paint)
        stroke_paint.strokeWidth = dp(1.2f)
    }

    private fun draw_surface(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        val body = smooth_step(0f, 0.6f, p)
        val gear = smooth_step(0.55f, 1f, p)
        draw_morphed_polygon(
            canvas = canvas,
            target = SURFACE_POINTS,
            progress = p,
            paint = paint,
            stroke_paint = stroke_paint,
            dp = dp
        )
        stroke_paint.strokeWidth = dp(2f)
        canvas.drawLine(-dp(5f + 9f * gear), dp(8f + 10f * body), dp(5f + 9f * gear), dp(8f + 10f * body), stroke_paint)
        canvas.drawCircle(-dp(3f + 5f * gear), dp(8f + 10f * body), dp(2.2f * gear), stroke_paint)
        canvas.drawCircle(dp(3f + 5f * gear), dp(8f + 10f * body), dp(2.2f * gear), stroke_paint)
        stroke_paint.strokeWidth = dp(1.2f)
    }

    private fun draw_cached_airliner(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        draw_cached_morphed_polygon(canvas, AircraftSymbol.AIRLINER, AIRLINER_POINTS, p, paint, stroke_paint, dp)
        draw_airliner_details(canvas, p, stroke_paint, dp)
    }

    private fun draw_airliner_details(
        canvas: Canvas,
        progress: Float,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        val engine = smooth_step(0.48f, 1f, p)
        if (engine > 0f) {
            canvas.drawCircle(-dp(11.8f * engine), dp(5.6f * engine), dp(2.2f * engine), stroke_paint)
            canvas.drawCircle(dp(11.8f * engine), dp(5.6f * engine), dp(2.2f * engine), stroke_paint)
        }
    }

    private fun draw_cached_surface(
        canvas: Canvas,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        draw_cached_morphed_polygon(canvas, AircraftSymbol.SURFACE, SURFACE_POINTS, p, paint, stroke_paint, dp)
        draw_surface_details(canvas, p, stroke_paint, dp)
    }

    private fun draw_surface_details(
        canvas: Canvas,
        progress: Float,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val p = progress.coerceIn(0f, 1f)
        val body = smooth_step(0f, 0.6f, p)
        val gear = smooth_step(0.55f, 1f, p)
        stroke_paint.strokeWidth = dp(2f)
        canvas.drawLine(-dp(5f + 9f * gear), dp(8f + 10f * body), dp(5f + 9f * gear), dp(8f + 10f * body), stroke_paint)
        canvas.drawCircle(-dp(3f + 5f * gear), dp(8f + 10f * body), dp(2.2f * gear), stroke_paint)
        canvas.drawCircle(dp(3f + 5f * gear), dp(8f + 10f * body), dp(2.2f * gear), stroke_paint)
        stroke_paint.strokeWidth = dp(1.2f)
    }

    private fun draw_cached_morphed_polygon(
        canvas: Canvas,
        symbol: AircraftSymbol,
        target: FloatArray,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        val body = cached_morphed_polygon(symbol, target, progress, dp)
        canvas.drawPath(body, paint)
        canvas.drawPath(body, stroke_paint)
    }

    private fun draw_morphed_polygon(
        canvas: Canvas,
        target: FloatArray,
        progress: Float,
        paint: Paint,
        stroke_paint: Paint,
        dp: (Float) -> Float
    ) {
        path.reset()
        val p = smooth_step(0f, 1f, progress.coerceIn(0f, 1f))
        var target_index = 0
        var point_index = 0
        while (target_index + 1 < target.size) {
            val point_x = target[target_index]
            val point_y = target[target_index + 1]
            val angle = atan2(point_y.toDouble(), point_x.toDouble())
            val start_x = (cos(angle) * AIRCRAFT_MORPH_SEED_RADIUS_DP).toFloat()
            val start_y = (sin(angle) * AIRCRAFT_MORPH_SEED_RADIUS_DP).toFloat()
            val x = lerp(start_x, point_x, p)
            val y = lerp(start_y, point_y, p)
            if (point_index == 0) {
                path.moveTo(dp(x), dp(y))
            } else {
                path.lineTo(dp(x), dp(y))
            }
            target_index += 2
            point_index++
        }
        path.close()
        canvas.drawPath(path, paint)
        canvas.drawPath(path, stroke_paint)
    }

    private fun cached_morphed_polygon(
        symbol: AircraftSymbol,
        target: FloatArray,
        progress: Float,
        dp: (Float) -> Float
    ): Path {
        val key = symbol_body_key(symbol, progress, dp)
        body_path_cache[key]?.let { return it }
        val body = Path()
        val points = cached_morphed_points(symbol, target, progress, dp)
        var index = 0
        var point_index = 0
        while (index + 1 < points.size) {
            if (point_index == 0) {
                body.moveTo(points[index], points[index + 1])
            } else {
                body.lineTo(points[index], points[index + 1])
            }
            index += 2
            point_index++
        }
        body.close()
        body_path_cache[key] = body
        return body
    }

    private fun cached_morphed_points(
        symbol: AircraftSymbol,
        target: FloatArray,
        progress: Float,
        dp: (Float) -> Float
    ): FloatArray {
        val key = symbol_body_key(symbol, progress, dp)
        body_point_cache[key]?.let { return it }
        val p = smooth_step(0f, 1f, key.progress_bucket / SYMBOL_VECTOR_PROGRESS_STEPS.toFloat())
        val points = FloatArray(target.size)
        var target_index = 0
        while (target_index + 1 < target.size) {
            val point_x = target[target_index]
            val point_y = target[target_index + 1]
            val angle = atan2(point_y.toDouble(), point_x.toDouble())
            val start_x = (cos(angle) * AIRCRAFT_MORPH_SEED_RADIUS_DP).toFloat()
            val start_y = (sin(angle) * AIRCRAFT_MORPH_SEED_RADIUS_DP).toFloat()
            points[target_index] = dp(lerp(start_x, point_x, p))
            points[target_index + 1] = dp(lerp(start_y, point_y, p))
            target_index += 2
        }
        body_point_cache[key] = points
        return points
    }

    private fun symbol_body_key(
        symbol: AircraftSymbol,
        progress: Float,
        dp: (Float) -> Float
    ): SymbolBodyPathKey {
        val progress_bucket = (progress.coerceIn(0f, 1f) * SYMBOL_VECTOR_PROGRESS_STEPS)
            .roundToInt()
            .coerceIn(0, SYMBOL_VECTOR_PROGRESS_STEPS)
        val dp_unit_bucket = (dp(1f) * 1000f).roundToInt()
        return SymbolBodyPathKey(symbol, progress_bucket, dp_unit_bucket)
    }

    private fun draw_uav_rotor(
        canvas: Canvas,
        x: Float,
        y: Float,
        radius: Float,
        blade: Float,
        paint: Paint,
        stroke_paint: Paint
    ) {
        canvas.drawCircle(x, y, radius, paint)
        canvas.drawCircle(x, y, radius, stroke_paint)
        canvas.drawLine(x - blade, y, x + blade, y, stroke_paint)
    }

    
    
    private data class SymbolBodyPathKey(
        val symbol: AircraftSymbol,
        val progress_bucket: Int,
        val dp_unit_bucket: Int
    )

    private const val AIRCRAFT_MORPH_SEED_RADIUS_DP = 4f
    private const val SYMBOL_VECTOR_PROGRESS_STEPS = 96
    private const val SYMBOL_BODY_PATH_CACHE_MAX_ENTRIES = 768

    private val GENERAL_AVIATION_POINTS = floatArrayOf(
        0f, -17f,
        3.2f, -4.2f,
        17f, 0.8f,
        15.2f, 4.4f,
        3.3f, 3.4f,
        2.2f, 13.8f,
        8.4f, 17.2f,
        0f, 12.7f,
        -8.4f, 17.2f,
        -2.2f, 13.8f,
        -3.3f, 3.4f,
        -15.2f, 4.4f,
        -17f, 0.8f,
        -3.2f, -4.2f
    )

    private val AIRLINER_POINTS = floatArrayOf(
        0f, -21f,
        5.5f, -4.8f,
        23.5f, 0.8f,
        21.5f, 5.8f,
        7.2f, 6.2f,
        5.1f, 16.5f,
        13.5f, 21f,
        2.8f, 17.2f,
        0f, 13.5f,
        -2.8f, 17.2f,
        -13.5f, 21f,
        -5.1f, 16.5f,
        -7.2f, 6.2f,
        -21.5f, 5.8f,
        -23.5f, 0.8f,
        -5.5f, -4.8f
    )

    private val GLIDER_POINTS = floatArrayOf(
        0f, -16f,
        3f, 2f,
        27f, 5f,
        4f, 8f,
        1.8f, 17f,
        -1.8f, 17f,
        -4f, 8f,
        -27f, 5f,
        -3f, 2f
    )

    private val SURFACE_POINTS = floatArrayOf(
        0f, -15f,
        5f, -4f,
        18f, 1f,
        15f, 6f,
        4f, 4f,
        2f, 13f,
        -2f, 13f,
        -4f, 4f,
        -15f, 6f,
        -18f, 1f,
        -5f, -4f
    )
}


data class AviationLayerVisibility(
    val restricted_airspaces_enabled: Boolean,
    val atc_boundaries_enabled: Boolean,
    val oceanic_tracks_enabled: Boolean,
    val airport_labels_enabled: Boolean
)

data class AviationLayerStyle(
    val accent_orange: Int,
    val danger: Int,
    val accent_blue: Int,
    val accent_green: Int,
    val accent_pink: Int,
    val accent_yellow: Int,
    val military_gray: Int,
    val panel: Int,
    val text: Int,
    val treatment: ThemeTreatment
)

class AviationLayerRenderer(
    private val paint: Paint,
    private val stroke_paint: Paint,
    private val text_paint: Paint,
    private val path: Path,
    private val dp: (Float) -> Float,
    private val sp: (Float) -> Float,
    private val ellipsize: (String, Float) -> String
) {
    private var prepared_snapshot: AviationLayerSnapshot? = null
    private var prepared_restricted_airspaces: List<PreparedAirspaceFeature> = emptyList()
    private var prepared_atc_boundaries: List<PreparedAirspaceFeature> = emptyList()
    private val layer_label_rects = ArrayList<RectF>(16)
    private var settled_cache_bitmap: Bitmap? = null
    private var settled_cache_canvas: Canvas? = null
    private var settled_cache_key: SettledLayerCacheKey? = null
    private val settled_cache_matrix = Matrix()

    fun draw_layers(
        canvas: Canvas,
        viewport: Viewport,
        snapshot: AviationLayerSnapshot,
        visible_bounds: AviationGeoBounds,
        visibility: AviationLayerVisibility,
        style: AviationLayerStyle,
        selected_restricted_airspace: AviationAirspaceFeature? = null,
        interaction_active: Boolean = false
    ) {
        prepare_snapshot_if_needed(snapshot)
        if (interaction_active && draw_transformed_settled_cache(canvas, viewport, snapshot, visibility, style, selected_restricted_airspace)) {
            return
        }
        if (!interaction_active && draw_settled_cache_if_current(canvas, viewport, snapshot, visible_bounds, visibility, style, selected_restricted_airspace)) {
            return
        }
        if (!interaction_active && draw_into_settled_cache(canvas, viewport, snapshot, visible_bounds, visibility, style, selected_restricted_airspace)) {
            return
        }
        draw_layers_direct(
            canvas = canvas,
            viewport = viewport,
            snapshot = snapshot,
            visible_bounds = visible_bounds,
            visibility = visibility,
            style = style,
            selected_restricted_airspace = selected_restricted_airspace,
            interaction_active = interaction_active
        )
    }

    private fun draw_settled_cache_if_current(
        canvas: Canvas,
        viewport: Viewport,
        snapshot: AviationLayerSnapshot,
        visible_bounds: AviationGeoBounds,
        visibility: AviationLayerVisibility,
        style: AviationLayerStyle,
        selected_restricted_airspace: AviationAirspaceFeature?
    ): Boolean {
        val bitmap = settled_cache_bitmap ?: return false
        val key = settled_cache_key ?: return false
        if (key != settled_layer_cache_key(viewport, snapshot, visible_bounds, visibility, style, selected_restricted_airspace)) return false
        canvas.drawBitmap(bitmap, 0f, 0f, null)
        return true
    }

    private fun draw_transformed_settled_cache(
        canvas: Canvas,
        viewport: Viewport,
        snapshot: AviationLayerSnapshot,
        visibility: AviationLayerVisibility,
        style: AviationLayerStyle,
        selected_restricted_airspace: AviationAirspaceFeature?
    ): Boolean {
        val bitmap = settled_cache_bitmap ?: return false
        val key = settled_cache_key ?: return false
        if (bitmap.isRecycled) return false
        if (key.snapshot_identity != System.identityHashCode(snapshot) ||
            key.width != viewport.width.toInt() ||
            key.height != viewport.height.toInt() ||
            key.visibility != visibility ||
            key.style != style ||
            key.selected_restricted_airspace_identity != selected_restricted_airspace?.let(System::identityHashCode)
        ) {
            return false
        }
        val zoom_delta = viewport.zoom - key.zoom
        if (abs(zoom_delta) > MAX_TRANSFORMED_CACHE_ZOOM_DELTA) return false
        val scale = 2.0.pow(zoom_delta).toFloat()
        if (scale <= 0f || !scale.isFinite()) return false
        val translation_x = (key.center_x * scale - viewport.center_x + viewport.width / 2.0 - key.width * scale / 2.0).toFloat()
        val translation_y = (key.center_y * scale - viewport.center_y + viewport.height / 2.0 - key.height * scale / 2.0).toFloat()
        if (abs(translation_x) > viewport.width * MAX_TRANSFORMED_CACHE_TRANSLATION_FRACTION ||
            abs(translation_y) > viewport.height * MAX_TRANSFORMED_CACHE_TRANSLATION_FRACTION
        ) {
            return false
        }
        settled_cache_matrix.reset()
        settled_cache_matrix.setScale(scale, scale)
        settled_cache_matrix.postTranslate(translation_x, translation_y)
        canvas.drawBitmap(bitmap, settled_cache_matrix, null)
        return true
    }

    private fun draw_into_settled_cache(
        canvas: Canvas,
        viewport: Viewport,
        snapshot: AviationLayerSnapshot,
        visible_bounds: AviationGeoBounds,
        visibility: AviationLayerVisibility,
        style: AviationLayerStyle,
        selected_restricted_airspace: AviationAirspaceFeature?
    ): Boolean {
        val layer_canvas = settled_cache_canvas_for(viewport) ?: return false
        val bitmap = settled_cache_bitmap ?: return false
        layer_canvas.drawColor(Color.TRANSPARENT, PorterDuff.Mode.CLEAR)
        draw_layers_direct(
            canvas = layer_canvas,
            viewport = viewport,
            snapshot = snapshot,
            visible_bounds = visible_bounds,
            visibility = visibility,
            style = style,
            selected_restricted_airspace = selected_restricted_airspace,
            interaction_active = false
        )
        settled_cache_key = settled_layer_cache_key(viewport, snapshot, visible_bounds, visibility, style, selected_restricted_airspace)
        canvas.drawBitmap(bitmap, 0f, 0f, null)
        return true
    }

    private fun settled_cache_canvas_for(viewport: Viewport): Canvas? {
        val width = viewport.width.toInt().coerceAtLeast(1)
        val height = viewport.height.toInt().coerceAtLeast(1)
        val current = settled_cache_bitmap
        if (current != null && current.width == width && current.height == height && !current.isRecycled) {
            return settled_cache_canvas
        }
        current?.recycle()
        return try {
            val bitmap = createBitmap(width, height, Bitmap.Config.ARGB_8888)
            settled_cache_bitmap = bitmap
            settled_cache_canvas = Canvas(bitmap)
            settled_cache_key = null
            settled_cache_canvas
        } catch (_: OutOfMemoryError) {
            settled_cache_bitmap = null
            settled_cache_canvas = null
            settled_cache_key = null
            null
        }
    }

    private fun settled_layer_cache_key(
        viewport: Viewport,
        snapshot: AviationLayerSnapshot,
        visible_bounds: AviationGeoBounds,
        visibility: AviationLayerVisibility,
        style: AviationLayerStyle,
        selected_restricted_airspace: AviationAirspaceFeature?
    ): SettledLayerCacheKey {
        return SettledLayerCacheKey(
            snapshot_identity = System.identityHashCode(snapshot),
            width = viewport.width.toInt(),
            height = viewport.height.toInt(),
            zoom = viewport.zoom,
            center_x = viewport.center_x,
            center_y = viewport.center_y,
            visible_bounds = visible_bounds,
            visibility = visibility,
            style = style,
            selected_restricted_airspace_identity = selected_restricted_airspace?.let(System::identityHashCode)
        )
    }

    private fun draw_layers_direct(
        canvas: Canvas,
        viewport: Viewport,
        snapshot: AviationLayerSnapshot,
        visible_bounds: AviationGeoBounds,
        visibility: AviationLayerVisibility,
        style: AviationLayerStyle,
        selected_restricted_airspace: AviationAirspaceFeature?,
        interaction_active: Boolean
    ) {
        layer_label_rects.clear()
        if (visibility.restricted_airspaces_enabled) {
            draw_airspace_layer(
                canvas = canvas,
                viewport = viewport,
                features = prepared_restricted_airspaces,
                visible_bounds = visible_bounds,
                excluded_feature = selected_restricted_airspace,
                stroke = restricted_airspace_stroke(style),
                fill = restricted_airspace_fill(style),
                label_limit = if (viewport.zoom >= 8.0) 6 else 3,
                label_rects = layer_label_rects,
                style = style,
                restricted = true,
                interaction_active = interaction_active
            )
            selected_restricted_airspace
                ?.takeIf { it.bounds.intersects(visible_bounds) }
                ?.let { selected ->
                    val selected_prepared = prepared_restricted_airspaces.firstOrNull { it.source == selected }
                        ?: prepare_airspace_feature(selected)
                        ?: return@let
                    draw_selected_airspace(canvas, viewport, selected, style)
                    if (viewport.zoom >= AIRSPACE_LABEL_MIN_ZOOM) {
                        draw_airspace_label(canvas, viewport, selected_prepared, layer_label_rects, style)
                    }
                }
        }
        if (visibility.atc_boundaries_enabled) {
            val focused_atc_feature = focused_airspace_feature(
                viewport = viewport,
                features = prepared_atc_boundaries,
                visible_bounds = visible_bounds
            )
            draw_airspace_layer(
                canvas = canvas,
                viewport = viewport,
                features = prepared_atc_boundaries,
                visible_bounds = visible_bounds,
                excluded_feature = null,
                stroke = style.accent_blue,
                fill = style.accent_blue,
                label_limit = 4,
                label_rects = layer_label_rects,
                style = style,
                restricted = false,
                focused_feature = focused_atc_feature,
                interaction_active = interaction_active
            )
        }
        if (visibility.oceanic_tracks_enabled) {
            draw_oceanic_tracks(
                canvas = canvas,
                viewport = viewport,
                tracks = snapshot.oceanic_tracks.filter { it.bounds.intersects(visible_bounds) },
                label_rects = layer_label_rects,
                style = style
            )
        }
        if (visibility.airport_labels_enabled) {
            draw_airport_labels(
                canvas = canvas,
                viewport = viewport,
                airports = snapshot.airports,
                label_rects = layer_label_rects,
                style = style
            )
        }
    }

    private fun prepare_snapshot_if_needed(snapshot: AviationLayerSnapshot) {
        if (prepared_snapshot === snapshot) return
        prepared_snapshot = snapshot
        prepared_restricted_airspaces = prepare_airspace_features(snapshot.restricted_airspaces)
        prepared_atc_boundaries = prepare_airspace_features(snapshot.atc_boundaries)
    }

    private fun prepare_airspace_features(features: List<AviationAirspaceFeature>): List<PreparedAirspaceFeature> {
        return features
            .mapNotNull(::prepare_airspace_feature)
            .sortedBy { it.point_count }
    }

    private fun prepare_airspace_feature(feature: AviationAirspaceFeature): PreparedAirspaceFeature? {
        val rings = feature.rings
            .take(MAX_DRAWN_RINGS_PER_FEATURE)
            .mapNotNull { ring -> prepare_airspace_ring(ring, MAX_DRAWN_AIRSPACE_POINTS_PER_RING) }
        val interaction_rings = feature.rings
            .take(MAX_DRAWN_RINGS_PER_FEATURE)
            .mapNotNull { ring -> prepare_airspace_ring(ring, MAX_DRAWN_AIRSPACE_POINTS_PER_RING_INTERACTION) }
        if (rings.isEmpty()) return null
        val label = airspace_label(feature)
        return PreparedAirspaceFeature(
            source = feature,
            label = label,
            center = feature.bounds.center_point(),
            point_count = rings.sumOf { it.point_count },
            rings = rings,
            interaction_rings = interaction_rings.ifEmpty { rings }
        )
    }

    private fun airspace_label(feature: AviationAirspaceFeature): String {
        val type = feature.type.trim()
        if (type.isBlank() || type.equals(feature.name, ignoreCase = true)) return feature.name
        val type_already_in_name = Regex("\\b${Regex.escape(type)}\\b", RegexOption.IGNORE_CASE).containsMatchIn(feature.name)
        return if (type_already_in_name) feature.name else "${feature.name} $type"
    }

    private fun prepare_airspace_ring(ring: List<AviationLayerPoint>, max_points: Int): PreparedAirspaceRing? {
        if (ring.size < 3) return null
        val step = max(1, ring.size / max_points)
        val sampled_count = ring.indices.count { index -> index % step == 0 || index == ring.lastIndex }
        if (sampled_count < 3) return null
        val world_path = Path()
        var point_index = 0
        var min_x = Float.POSITIVE_INFINITY
        var max_x = Float.NEGATIVE_INFINITY
        var min_y = Float.POSITIVE_INFINITY
        var max_y = Float.NEGATIVE_INFINITY
        ring.forEachIndexed { index, point ->
            if (index % step == 0 || index == ring.lastIndex) {
                val world = MapProjection.lat_lon_to_world(point.lat, point.lon, 0.0)
                val x = world.x.toFloat()
                val y = world.y.toFloat()
                if (point_index == 0) world_path.moveTo(x, y) else world_path.lineTo(x, y)
                min_x = min(min_x, x)
                max_x = max(max_x, x)
                min_y = min(min_y, y)
                max_y = max(max_y, y)
                point_index++
            }
        }
        world_path.close()
        return PreparedAirspaceRing(
            point_count = sampled_count,
            path = world_path,
            min_x = min_x,
            max_x = max_x,
            min_y = min_y,
            max_y = max_y
        )
    }

    private fun draw_airspace_layer(
        canvas: Canvas,
        viewport: Viewport,
        features: List<PreparedAirspaceFeature>,
        visible_bounds: AviationGeoBounds,
        excluded_feature: AviationAirspaceFeature?,
        stroke: Int,
        fill: Int,
        label_limit: Int,
        label_rects: MutableList<RectF>,
        style: AviationLayerStyle,
        restricted: Boolean,
        focused_feature: PreparedAirspaceFeature? = null,
        interaction_active: Boolean
    ) {
        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeCap = Paint.Cap.ROUND
        stroke_paint.strokeJoin = Paint.Join.ROUND
        val low_zoom_emphasis = layer_low_zoom_emphasis(viewport.zoom, restricted)
        val base_stroke_width_dp = when {
            interaction_active && restricted -> 1.25f
            interaction_active -> 1.0f
            restricted && viewport.zoom >= 8.0 -> 2.0f
            viewport.zoom >= 8.0 -> 1.6f
            restricted -> 1.35f
            else -> 1.1f
        }
        val min_stroke_width_dp = if (restricted) 0.55f else 0.42f
        stroke_paint.strokeWidth = dp(lerp(min_stroke_width_dp, base_stroke_width_dp, low_zoom_emphasis))
        val raw_stroke_alpha = when {
            interaction_active && viewport.zoom >= 8.0 -> 190
            interaction_active -> 150
            viewport.zoom >= 8.0 -> 220
            else -> 170
        }
        val min_stroke_alpha_scale = if (restricted) 0.40f else 0.26f
        val stroke_alpha_scale = lerp(min_stroke_alpha_scale, 1f, low_zoom_emphasis)
        val base_stroke_alpha = (raw_stroke_alpha * stroke_alpha_scale).toInt().coerceIn(24, 235)
        paint.style = Paint.Style.FILL
        val fill_zoom_emphasis = smooth_step(5.3f, 8.5f, viewport.zoom.toFloat())
        val raw_fill_alpha = if (restricted && viewport.zoom >= 8.5) 28 else if (viewport.zoom >= 8.5) 18 else 10
        val base_fill_alpha = (raw_fill_alpha * fill_zoom_emphasis).toInt()

        var labels_drawn = 0
        var drawn_features = 0
        for (feature in features) {
            if (feature.source == excluded_feature || !feature.source.bounds.intersects(visible_bounds)) continue
            if (drawn_features >= MAX_DRAWN_AIRSPACE_FEATURES) break
            val is_focused = focused_feature == null || focused_feature === feature
            val fill_alpha = when {
                interaction_active -> 0
                restricted -> base_fill_alpha
                focused_feature == null -> 0
                is_focused -> base_fill_alpha
                else -> 0
            }
            val stroke_alpha = when {
                restricted -> base_stroke_alpha
                focused_feature == null -> (base_stroke_alpha * 0.72f).toInt()
                is_focused -> base_stroke_alpha
                else -> (base_stroke_alpha * 0.58f).toInt()
            }
            paint.color = with_alpha(fill, fill_alpha)
            stroke_paint.color = with_alpha(stroke, stroke_alpha)
            val rings = if (interaction_active) feature.interaction_rings else feature.rings
            rings.forEach { ring ->
                draw_prepared_airspace_ring(
                    canvas = canvas,
                    viewport = viewport,
                    ring = ring,
                    fill_paint = paint.takeIf { fill_alpha > 0 },
                    outline_paint = stroke_paint
                )
            }
            if (!interaction_active && labels_drawn < label_limit && viewport.zoom >= AIRSPACE_LABEL_MIN_ZOOM) {
                if (draw_airspace_label(canvas, viewport, feature, label_rects, style)) {
                    labels_drawn++
                }
            }
            drawn_features++
        }
        stroke_paint.strokeCap = Paint.Cap.BUTT
        stroke_paint.strokeJoin = Paint.Join.MITER
    }

    private fun layer_low_zoom_emphasis(zoom: Double, restricted: Boolean): Float {
        val start = if (restricted) 3.2f else 3.7f
        val end = if (restricted) 7.0f else 7.4f
        return smooth_step(start, end, zoom.toFloat())
    }

    
    
    private fun focused_airspace_feature(
        viewport: Viewport,
        features: List<PreparedAirspaceFeature>,
        visible_bounds: AviationGeoBounds
    ): PreparedAirspaceFeature? {
        val center = MapProjection.world_to_lat_lon(viewport.center_x, viewport.center_y, viewport.zoom)
        val point = AviationLayerPoint(center.lat, center.lon)
        return features.firstOrNull { feature ->
            feature.source.bounds.intersects(visible_bounds) &&
                feature.source.bounds.contains(point) &&
                point_inside_airspace(point, feature.source)
        }
    }

    private fun AviationGeoBounds.contains(point: AviationLayerPoint): Boolean {
        return point.lat in min_lat..max_lat && point.lon in min_lon..max_lon
    }

    private fun point_inside_airspace(point: AviationLayerPoint, feature: AviationAirspaceFeature): Boolean {
        var crossings = 0
        feature.rings.forEach { ring ->
            if (point_inside_ring(point, ring)) crossings++
        }
        return crossings % 2 == 1
    }

    private fun point_inside_ring(point: AviationLayerPoint, ring: List<AviationLayerPoint>): Boolean {
        if (ring.size < 3) return false
        var inside = false
        var j = ring.lastIndex
        for (i in ring.indices) {
            val pi = ring[i]
            val pj = ring[j]
            val intersects = (pi.lat > point.lat) != (pj.lat > point.lat) &&
                point.lon < (pj.lon - pi.lon) * (point.lat - pi.lat) / ((pj.lat - pi.lat).takeIf { abs(it) > 1e-9 } ?: 1e-9) + pi.lon
            if (intersects) inside = !inside
            j = i
        }
        return inside
    }

    private fun draw_selected_airspace(
        canvas: Canvas,
        viewport: Viewport,
        feature: AviationAirspaceFeature,
        style: AviationLayerStyle
    ) {
        val prepared = prepared_restricted_airspaces.firstOrNull { it.source == feature }
            ?: prepare_airspace_feature(feature)
            ?: return
        paint.style = Paint.Style.FILL
        paint.color = with_alpha(restricted_airspace_fill(style), selected_restricted_airspace_fill_alpha(style))
        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeCap = Paint.Cap.ROUND
        stroke_paint.strokeJoin = Paint.Join.ROUND
        stroke_paint.strokeWidth = dp(3.0f)
        stroke_paint.color = with_alpha(selected_restricted_airspace_stroke(style), 235)
        prepared.rings.forEach { ring ->
            draw_prepared_airspace_ring(canvas, viewport, ring, paint, stroke_paint)
        }
        stroke_paint.strokeCap = Paint.Cap.BUTT
        stroke_paint.strokeJoin = Paint.Join.MITER
    }

    private fun draw_prepared_airspace_ring(
        canvas: Canvas,
        viewport: Viewport,
        ring: PreparedAirspaceRing,
        fill_paint: Paint?,
        outline_paint: Paint
    ) {
        val scale = 2.0.pow(viewport.zoom).toFloat()
        if (scale <= 0f || !scale.isFinite()) return
        val world_span = TILE_SIZE * scale
        val screen_offset_x = (-viewport.center_x + viewport.width / 2.0).toFloat()
        val screen_offset_y = (-viewport.center_y + viewport.height / 2.0).toFloat()
        draw_prepared_airspace_ring_path(
            canvas = canvas,
            viewport = viewport,
            ring = ring,
            scale = scale,
            world_span = world_span,
            screen_offset_x = screen_offset_x,
            screen_offset_y = screen_offset_y,
            fill_paint = fill_paint,
            outline_paint = outline_paint
        )
    }

    private fun draw_prepared_airspace_ring_path(
        canvas: Canvas,
        viewport: Viewport,
        ring: PreparedAirspaceRing,
        scale: Float,
        world_span: Float,
        screen_offset_x: Float,
        screen_offset_y: Float,
        fill_paint: Paint?,
        outline_paint: Paint
    ) {
        if (ring.point_count < 3 || scale <= 0f || !scale.isFinite()) return
        val extended_left = -viewport.width * 0.5f
        val extended_right = viewport.width * 1.5f
        val extended_top = -viewport.height * 0.5f
        val extended_bottom = viewport.height * 1.5f
        val screen_top = ring.min_y * scale + screen_offset_y
        val screen_bottom = ring.max_y * scale + screen_offset_y
        if (screen_bottom < extended_top || screen_top > extended_bottom) return

        val base_left = ring.min_x * scale + screen_offset_x
        val base_right = ring.max_x * scale + screen_offset_x
        var shift_x = 0f
        var guard = 0
        while (base_right + shift_x < extended_left && guard++ < MAX_WRAPPED_RING_COPIES) {
            shift_x += world_span
        }
        guard = 0
        val original_stroke_width = outline_paint.strokeWidth
        outline_paint.strokeWidth = original_stroke_width / scale
        try {
            while (base_left + shift_x <= extended_right && guard++ < MAX_WRAPPED_RING_COPIES) {
                if (base_right + shift_x >= extended_left) {
                    canvas.withTranslation(screen_offset_x + shift_x, screen_offset_y) {
                        scale(scale, scale)
                        if (fill_paint != null) drawPath(ring.path, fill_paint)
                        drawPath(ring.path, outline_paint)
                    }
                }
                shift_x += world_span
            }
        } finally {
            outline_paint.strokeWidth = original_stroke_width
        }
    }

    private fun draw_airspace_label(
        canvas: Canvas,
        viewport: Viewport,
        feature: PreparedAirspaceFeature,
        label_rects: MutableList<RectF>,
        style: AviationLayerStyle
    ): Boolean {
        val screen = project_aviation_point_to_screen(feature.center, viewport, MapProjection::lat_lon_to_world) ?: return false
        if (screen.x !in 0f..viewport.width || screen.y !in 0f..viewport.height) return false
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(if (feature.source.type.equals("R", ignoreCase = true)) 11f else 10f)
        text_paint.color = with_alpha(style.text, 224)
        val display = ellipsize(feature.label, dp(142f))
        val width = text_paint.measureText(display) + dp(14f)
        val rect = RectF(screen.x - width / 2f, screen.y - dp(20f), screen.x + width / 2f, screen.y + dp(3f))
        if (!rect.intersects(0f, 0f, viewport.width, viewport.height)) return false
        val padded = rect.padded_copy(dp(3f))
        if (label_rects.any { RectF.intersects(padded, it) }) return false
        label_rects += padded
        paint.style = Paint.Style.FILL
        paint.color = with_alpha(style.panel, 184)
        canvas.drawRoundRect(rect, dp(4f), dp(4f), paint)
        canvas.drawText(display, rect.centerX(), rect.bottom - dp(7f), text_paint)
        text_paint.isFakeBoldText = false
        return true
    }

    private fun draw_oceanic_tracks(
        canvas: Canvas,
        viewport: Viewport,
        tracks: List<AviationOceanicTrack>,
        label_rects: MutableList<RectF>,
        style: AviationLayerStyle
    ) {
        if (viewport.zoom < OCEANIC_TRACK_MIN_ZOOM) return
        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeCap = Paint.Cap.ROUND
        stroke_paint.strokeJoin = Paint.Join.ROUND
        stroke_paint.strokeWidth = dp(2.2f)
        stroke_paint.color = with_alpha(style.accent_pink, 215)
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(11f)
        text_paint.color = style.accent_pink

        tracks.take(MAX_DRAWN_OCEANIC_TRACKS).forEach { track ->
            val points = ring_to_screen_points(track.points, viewport)
            if (points.size < 2) return@forEach
            path.reset()
            points.forEachIndexed { index, point ->
                if (index == 0) path.moveTo(point.x, point.y) else path.lineTo(point.x, point.y)
            }
            canvas.drawPath(path, stroke_paint)
            val label_point = points.getOrNull(points.size / 2) ?: return@forEach
            canvas.drawCircle(label_point.x, label_point.y, dp(3f), paint.apply {
                this.style = Paint.Style.FILL
                color = style.accent_pink
            })
            val label_width = text_paint.measureText(track.name)
            val label_rect = RectF(
                label_point.x - label_width / 2f,
                label_point.y - dp(24f),
                label_point.x + label_width / 2f,
                label_point.y - dp(8f)
            )
            val padded = label_rect.padded_copy(dp(4f))
            if (!label_rect.intersects(0f, 0f, viewport.width, viewport.height) ||
                label_rects.any { RectF.intersects(padded, it) }
            ) {
                return@forEach
            }
            label_rects += padded
            canvas.drawText(track.name, label_point.x, label_point.y - dp(8f), text_paint)
        }
        text_paint.isFakeBoldText = false
        stroke_paint.strokeCap = Paint.Cap.BUTT
        stroke_paint.strokeJoin = Paint.Join.MITER
    }

    private fun draw_airport_labels(
        canvas: Canvas,
        viewport: Viewport,
        airports: List<AviationAirportFeature>,
        label_rects: MutableList<RectF>,
        style: AviationLayerStyle
    ) {
        if (viewport.zoom < AIRPORT_LABEL_MIN_ZOOM) return
        val visible = airports
            .mapNotNull { airport -> project_aviation_point_to_screen(
                    AviationLayerPoint(airport.lat, airport.lon),
                    viewport,
                    MapProjection::lat_lon_to_world
                )?.let { airport to it } }
            .filter { (_, point) -> point.x in 0f..viewport.width && point.y in 0f..viewport.height }
            .sortedBy { (_, point) -> distance_from_screen_center(point, viewport) }
            .take(if (viewport.zoom >= 10.0) MAX_DRAWN_AIRPORT_LABELS else MAX_DRAWN_AIRPORT_LABELS_LOW_ZOOM)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(10f)
        visible.forEach { (airport, point) ->
            val label = airport.ident.ifBlank { airport.name }
            val color = if (airport.military) style.military_gray else style.accent_yellow
            val max_width = dp(if (viewport.zoom >= 10.0) 98f else 62f)
            text_paint.color = color
            val display = ellipsize(label, max_width)
            val width = text_paint.measureText(display) + dp(10f)
            val preferred_left = if (point.x + dp(5f) + width <= viewport.width - dp(2f)) {
                point.x + dp(5f)
            } else {
                point.x - dp(5f) - width
            }
            val left = preferred_left.coerceIn(dp(2f), (viewport.width - width - dp(2f)).coerceAtLeast(dp(2f)))
            val top = (point.y - dp(16f)).coerceIn(dp(2f), viewport.height - dp(22f))
            val rect = RectF(left, top, left + width, top + dp(20f))
            if (!rect.intersects(0f, 0f, viewport.width, viewport.height)) return@forEach
            val padded = rect.padded_copy(dp(3f))
            if (label_rects.any { RectF.intersects(padded, it) }) return@forEach
            label_rects += padded
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(style.panel, 165)
            canvas.drawRoundRect(rect, dp(4f), dp(4f), paint)
            paint.color = color
            canvas.drawCircle(point.x, point.y, dp(3f), paint)
            canvas.drawText(display, rect.left + dp(5f), rect.bottom - dp(6f), text_paint)
        }
        text_paint.isFakeBoldText = false
    }

    private fun ring_to_screen_points(points: List<AviationLayerPoint>, viewport: Viewport): List<ScreenPoint> {
        if (points.isEmpty()) return emptyList()
        val step = max(1, points.size / MAX_DRAWN_OCEANIC_POINTS)
        val result = mutableListOf<ScreenPoint>()
        points.forEachIndexed { index, point ->
            if (index % step == 0 || index == points.lastIndex) {
                project_aviation_point_to_screen(point, viewport, MapProjection::lat_lon_to_world)?.let { result += it }
            }
        }
        return result
    }

    private fun distance_from_screen_center(point: ScreenPoint, viewport: Viewport): Float {
        val dx = point.x - viewport.width / 2f
        val dy = point.y - viewport.height / 2f
        return dx * dx + dy * dy
    }

    private fun AviationGeoBounds.center_point(): AviationLayerPoint {
        return AviationLayerPoint((min_lat + max_lat) / 2.0, (min_lon + max_lon) / 2.0)
    }

    private fun RectF.padded_copy(padding: Float): RectF {
        return RectF(left - padding, top - padding, right + padding, bottom + padding)
    }

    
    private fun restricted_airspace_stroke(style: AviationLayerStyle): Int {
        return when (style.treatment) {
            ThemeTreatment.PLAIN -> style.accent_orange
            ThemeTreatment.GLASS -> style.accent_pink
            ThemeTreatment.RADAR_GRID -> style.accent_yellow
            ThemeTreatment.DAYLIGHT_CARD -> style.accent_pink
            ThemeTreatment.STORM_BAND -> style.accent_orange
            ThemeTreatment.CRT_SCANLINE -> style.accent_green
        }
    }

    private fun restricted_airspace_fill(style: AviationLayerStyle): Int {
        return when (style.treatment) {
            ThemeTreatment.PLAIN -> style.danger
            ThemeTreatment.GLASS -> style.accent_blue
            ThemeTreatment.RADAR_GRID -> style.danger
            ThemeTreatment.DAYLIGHT_CARD -> style.danger
            ThemeTreatment.STORM_BAND -> style.accent_pink
            ThemeTreatment.CRT_SCANLINE -> style.danger
        }
    }

    private fun selected_restricted_airspace_stroke(style: AviationLayerStyle): Int {
        return when (style.treatment) {
            ThemeTreatment.PLAIN -> style.accent_yellow
            ThemeTreatment.GLASS -> style.accent_yellow
            ThemeTreatment.RADAR_GRID -> style.accent_green
            ThemeTreatment.DAYLIGHT_CARD -> style.accent_orange
            ThemeTreatment.STORM_BAND -> style.accent_yellow
            ThemeTreatment.CRT_SCANLINE -> style.accent_yellow
        }
    }

    private fun selected_restricted_airspace_fill_alpha(style: AviationLayerStyle): Int {
        return when (style.treatment) {
            ThemeTreatment.DAYLIGHT_CARD -> 34
            ThemeTreatment.GLASS -> 36
            else -> 42
        }
    }

    private data class PreparedAirspaceFeature(
        val source: AviationAirspaceFeature,
        val label: String,
        val center: AviationLayerPoint,
        val point_count: Int,
        val rings: List<PreparedAirspaceRing>,
        val interaction_rings: List<PreparedAirspaceRing>
    )

    private data class PreparedAirspaceRing(
        val point_count: Int,
        val path: Path,
        val min_x: Float,
        val max_x: Float,
        val min_y: Float,
        val max_y: Float
    )

    private data class SettledLayerCacheKey(
        val snapshot_identity: Int,
        val width: Int,
        val height: Int,
        val zoom: Double,
        val center_x: Double,
        val center_y: Double,
        val visible_bounds: AviationGeoBounds,
        val visibility: AviationLayerVisibility,
        val style: AviationLayerStyle,
        val selected_restricted_airspace_identity: Int?
    )

    private companion object {
        const val TILE_SIZE = 256
        const val MAX_DRAWN_AIRSPACE_FEATURES = 80
        const val MAX_DRAWN_RINGS_PER_FEATURE = 4
        const val MAX_DRAWN_AIRSPACE_POINTS_PER_RING = 180
        const val MAX_DRAWN_AIRSPACE_POINTS_PER_RING_INTERACTION = 42
        const val MAX_WRAPPED_RING_COPIES = 8
        const val MAX_TRANSFORMED_CACHE_ZOOM_DELTA = 1.6
        const val MAX_TRANSFORMED_CACHE_TRANSLATION_FRACTION = 0.65f
        const val MAX_DRAWN_AIRPORT_LABELS = 36
        const val MAX_DRAWN_AIRPORT_LABELS_LOW_ZOOM = 16
        const val MAX_DRAWN_OCEANIC_TRACKS = 16
        const val MAX_DRAWN_OCEANIC_POINTS = 24
        const val AIRSPACE_LABEL_MIN_ZOOM = 7.2
        const val AIRPORT_LABEL_MIN_ZOOM = 8.4
        const val OCEANIC_TRACK_MIN_ZOOM = 3.0
    }
}


class FlightMapChromeBridge(
    override val layout: FlightMapLayout,
    private val dp_value: (Float) -> Float,
    private val sp_value: (Float) -> Float,
    private val fit_text: (String, Float) -> String,
    private val control_radius_value: () -> Float,
    private val panel_surface: (Canvas, RectF, Int, Int) -> Unit,
    private val choice_button: (Canvas, RectF, String, Boolean) -> Unit,
    private val control_surface: (Canvas, RectF, Int, Int, Boolean) -> Unit,
    private val wrapped_text: (Canvas, String, Float, Float, Float, Int) -> Float,
    private val aircraft_label: (Aircraft) -> String,
    private val animation_frame: () -> Unit
) : FlightMapChromeHost,
    FlightMapPanelChrome,
    AircraftDetailsPanelChrome,
    TrafficPanelChrome,
    TrafficOverlayChrome {

    override fun dp(value: Float): Float = dp_value(value)

    override fun sp(value: Float): Float = sp_value(value)

    override fun ellipsize(value: String, max_width: Float): String = fit_text(value, max_width)

    override fun control_radius(): Float = control_radius_value()

    override fun draw_panel_surface(canvas: Canvas, rect: RectF, fill: Int, alpha: Int) {
        panel_surface(canvas, rect, fill, alpha)
    }

    override fun draw_choice_button(canvas: Canvas, rect: RectF, label: String, selected: Boolean) {
        choice_button(canvas, rect, label, selected)
    }

    override fun draw_control_surface(canvas: Canvas, rect: RectF, fill: Int, stroke: Int, selected: Boolean) {
        control_surface(canvas, rect, fill, stroke, selected)
    }

    override fun draw_wrapped_text(
        canvas: Canvas,
        value: String,
        x: Float,
        y: Float,
        width: Float,
        max_lines: Int
    ): Float {
        return wrapped_text(canvas, value, x, y, width, max_lines)
    }

    override fun aircraft_label_detail(aircraft: Aircraft): String = aircraft_label(aircraft)

    override fun request_animation_frame() {
        animation_frame()
    }
}


data class FlightMapChromeStyle(val visual_theme: VisualTheme)

private enum class ChromeSurfaceKind {
    CONTROL,
    PANEL
}

private data class ChromeSurfaceKey(
    val kind: ChromeSurfaceKind,
    val width: Int,
    val height: Int,
    val radius: Int,
    val fill: Int,
    val stroke: Int,
    val stroke_width: Int,
    val selected: Boolean,
    val visual_theme: VisualTheme
)

interface FlightMapChromeHost {
    fun dp(value: Float): Float
    fun sp(value: Float): Float
    fun ellipsize(value: String, max_width: Float): String
}

// Draws shared map chrome: panels, controls, status labels, and theme treatments.
class FlightMapChromeRenderer(
    private val paint: Paint,
    private val stroke_paint: Paint,
    private val text_paint: Paint,
    private val path: Path,
    private val host: FlightMapChromeHost
) {
    private val surface_cache_paint = Paint(Paint.DITHER_FLAG)
    private val surface_cache_rect = RectF()
    private val surface_cache = object : LinkedHashMap<ChromeSurfaceKey, Bitmap>(CHROME_SURFACE_CACHE_LIMIT, 0.75f, true) {
        override fun removeEldestEntry(eldest: MutableMap.MutableEntry<ChromeSurfaceKey, Bitmap>): Boolean {
            val remove = size > CHROME_SURFACE_CACHE_LIMIT
            if (remove && !eldest.value.isRecycled) eldest.value.recycle()
            return remove
        }
    }

    fun panel_radius(style: FlightMapChromeStyle): Float {
        return host.dp(style.visual_theme.style.panel_corner_dp)
    }

    fun control_radius(style: FlightMapChromeStyle): Float {
        return host.dp(style.visual_theme.style.control_corner_dp)
    }

    // Choice buttons shrink text before ellipsizing so labels stay inside compact controls.
    fun draw_choice_button(
        canvas: Canvas,
        rect: RectF,
        label: String,
        selected: Boolean,
        style: FlightMapChromeStyle
    ) {
        val theme_style = style.visual_theme.style
        val colors = style.visual_theme.colors
        val previous_align = text_paint.textAlign
        val color = if (selected) colors.accent_green else colors.button_stroke
        paint.style = Paint.Style.FILL
        val fill = if (selected) {
            with_alpha(color, colors.selected_fill_alpha)
        } else if (theme_style.treatment == ThemeTreatment.PLAIN) {
            colors.button_fill
        } else {
            with_alpha(colors.button_fill, theme_style.control_alpha)
        }
        draw_control_surface(canvas, rect, fill, color, selected, null, style)
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = host.sp(12f)
        val available_width = (rect.width() - host.dp(12f)).coerceAtLeast(host.dp(4f))
        val available_height = (rect.height() - host.dp(8f)).coerceAtLeast(host.dp(4f))
        while (text_paint.textSize > host.sp(8f) &&
            (text_paint.measureText(label) > available_width ||
                text_paint.fontMetrics.let { it.descent - it.ascent } > available_height)
        ) {
            text_paint.textSize -= host.dp(0.5f)
        }
        val display = if (text_paint.measureText(label) <= available_width) {
            label
        } else {
            host.ellipsize(label, available_width)
        }
        text_paint.color = if (selected) colors.accent_green else colors.text
        val metrics = text_paint.fontMetrics
        canvas.drawText(display, rect.centerX(), rect.centerY() - (metrics.ascent + metrics.descent) / 2f, text_paint)
        text_paint.isFakeBoldText = false
        text_paint.textAlign = previous_align
    }

    // Context controls are icon-only map actions that share one cockpit surface treatment.
    fun draw_context_control(
        canvas: Canvas,
        rect: RectF,
        stroke: Int,
        style: FlightMapChromeStyle
    ) {
        val theme_style = style.visual_theme.style
        val colors = style.visual_theme.colors
        val alpha = if (theme_style.treatment == ThemeTreatment.PLAIN) 235 else theme_style.control_alpha
        val stroke_width = if (theme_style.treatment == ThemeTreatment.PLAIN) 1.4f else theme_style.control_stroke_dp
        draw_control_surface(canvas, rect, with_alpha(colors.control_fill, alpha), stroke, false, stroke_width, style)
    }

    // Draw the reusable control surface before icons or text are placed on top.
    fun draw_control_surface(
        canvas: Canvas,
        rect: RectF,
        fill: Int,
        stroke: Int,
        selected: Boolean = false,
        stroke_width_dp: Float? = null,
        style: FlightMapChromeStyle
    ) {
        val theme_style = style.visual_theme.style
        val radius = control_radius(style)
        val stroke_width_px = host.dp(stroke_width_dp ?: theme_style.control_stroke_dp)
        if (
            theme_style.treatment != ThemeTreatment.DAYLIGHT_CARD &&
            draw_cached_surface(
                canvas = canvas,
                rect = rect,
                key = ChromeSurfaceKey(
                    kind = ChromeSurfaceKind.CONTROL,
                    width = rect.width().roundToInt(),
                    height = rect.height().roundToInt(),
                    radius = radius.roundToInt(),
                    fill = fill,
                    stroke = stroke,
                    stroke_width = stroke_width_px.roundToInt(),
                    selected = selected,
                    visual_theme = style.visual_theme
                )
            ) { cache_canvas, cache_rect ->
                draw_control_surface_direct(
                    canvas = cache_canvas,
                    rect = cache_rect,
                    fill = fill,
                    stroke = stroke,
                    selected = selected,
                    stroke_width_px = stroke_width_px,
                    style = style
                )
            }
        ) {
            return
        }
        draw_control_surface_direct(canvas, rect, fill, stroke, selected, stroke_width_px, style)
    }

    private fun draw_control_surface_direct(
        canvas: Canvas,
        rect: RectF,
        fill: Int,
        stroke: Int,
        selected: Boolean,
        stroke_width_px: Float,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val radius = control_radius(style)
        if (theme_style.treatment == ThemeTreatment.DAYLIGHT_CARD) {
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(colors.scrim, 28)
            canvas.drawRoundRect(
                RectF(rect.left + host.dp(1f), rect.top + host.dp(2f), rect.right + host.dp(1f), rect.bottom + host.dp(2f)),
                radius,
                radius,
                paint
            )
        }

        paint.style = Paint.Style.FILL
        paint.color = fill
        canvas.drawRoundRect(rect, radius, radius, paint)
        draw_control_treatment(canvas, rect, radius, stroke, selected, style)

        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeWidth = stroke_width_px
        stroke_paint.color = stroke
        canvas.drawRoundRect(rect, radius, radius, stroke_paint)
    }

    // Draw the reusable panel surface with theme texture and border applied consistently.
    fun draw_panel_surface(
        canvas: Canvas,
        rect: RectF,
        fill: Int? = null,
        alpha: Int? = null,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val radius = panel_radius(style)
        val fill_color = with_alpha(fill ?: colors.panel, alpha ?: theme_style.info_panel_alpha)
        val stroke_width_px = host.dp(theme_style.panel_stroke_dp)
        if (
            theme_style.treatment != ThemeTreatment.DAYLIGHT_CARD &&
            draw_cached_surface(
                canvas = canvas,
                rect = rect,
                key = ChromeSurfaceKey(
                    kind = ChromeSurfaceKind.PANEL,
                    width = rect.width().roundToInt(),
                    height = rect.height().roundToInt(),
                    radius = radius.roundToInt(),
                    fill = fill_color,
                    stroke = colors.panel_stroke,
                    stroke_width = stroke_width_px.roundToInt(),
                    selected = false,
                    visual_theme = style.visual_theme
                )
            ) { cache_canvas, cache_rect ->
                draw_panel_surface_direct(
                    canvas = cache_canvas,
                    rect = cache_rect,
                    fill_color = fill_color,
                    stroke_width_px = stroke_width_px,
                    style = style
                )
            }
        ) {
            return
        }
        draw_panel_surface_direct(canvas, rect, fill_color, stroke_width_px, style)
    }

    private fun draw_panel_surface_direct(
        canvas: Canvas,
        rect: RectF,
        fill_color: Int,
        stroke_width_px: Float,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val radius = panel_radius(style)
        if (theme_style.treatment == ThemeTreatment.DAYLIGHT_CARD) {
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(colors.scrim, 42)
            canvas.drawRoundRect(
                RectF(rect.left + host.dp(2f), rect.top + host.dp(3f), rect.right + host.dp(2f), rect.bottom + host.dp(3f)),
                radius,
                radius,
                paint
            )
        }

        paint.style = Paint.Style.FILL
        paint.color = fill_color
        canvas.drawRoundRect(rect, radius, radius, paint)
        draw_panel_treatment(canvas, rect, radius, style)

        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeWidth = stroke_width_px
        stroke_paint.color = colors.panel_stroke
        canvas.drawRoundRect(rect, radius, radius, stroke_paint)
    }

    private fun draw_cached_surface(
        canvas: Canvas,
        rect: RectF,
        key: ChromeSurfaceKey,
        create_surface: (Canvas, RectF) -> Unit
    ): Boolean {
        if (key.width <= 0 || key.height <= 0) return false
        val bitmap = synchronized(surface_cache) {
            surface_cache[key]?.takeIf { !it.isRecycled } ?: create_surface_bitmap(key, create_surface)?.also {
                surface_cache[key] = it
            }
        } ?: return false
        surface_cache_rect.set(rect.left, rect.top, rect.right, rect.bottom)
        canvas.drawBitmap(bitmap, null, surface_cache_rect, surface_cache_paint)
        return true
    }

    private fun create_surface_bitmap(
        key: ChromeSurfaceKey,
        create_surface: (Canvas, RectF) -> Unit
    ): Bitmap? {
        val bitmap = try {
            createBitmap(key.width, key.height, Bitmap.Config.ARGB_8888)
        } catch (_: OutOfMemoryError) {
            return null
        }
        val cache_canvas = Canvas(bitmap)
        val local_rect = RectF(0f, 0f, key.width.toFloat(), key.height.toFloat())
        create_surface(cache_canvas, local_rect)
        return bitmap
    }

        // Modal backdrop dims the map while keeping the active panel visually attached to the cockpit.
    fun draw_modal_backdrop(canvas: Canvas, w: Float, h: Float, style: FlightMapChromeStyle) {
        val colors = style.visual_theme.colors
        val alpha = when (style.visual_theme.style.treatment) {
            ThemeTreatment.DAYLIGHT_CARD -> 96
            ThemeTreatment.GLASS -> 120
            ThemeTreatment.CRT_SCANLINE -> 148
            else -> 132
        }
        paint.style = Paint.Style.FILL
        paint.color = with_alpha(colors.scrim, alpha)
        canvas.drawRect(0f, 0f, w, h, paint)
    }

    // No-location state is intentionally plain: without real ownship location, the map and traffic stay unavailable.
    fun draw_no_location_state(
        canvas: Canvas,
        w: Float,
        h: Float,
        location_permission_granted: Boolean,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        paint.style = Paint.Style.FILL
        paint.color = colors.map_empty
        canvas.drawRect(0f, 0f, w, h, paint)
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = host.sp(18f)
        text_paint.color = colors.text
        val message = if (location_permission_granted) "Waiting for device location" else "Location permission required"
        canvas.drawText(message, w / 2f, h * 0.45f, text_paint)
        text_paint.isFakeBoldText = false
        text_paint.textSize = host.sp(12f)
        text_paint.color = colors.muted
        canvas.drawText("No map or aircraft will be shown until real location data is available.", w / 2f, h * 0.45f + host.dp(24f), text_paint)
    }

    // Top status combines source truth, alert status, and scale into one quick-read card.
    fun draw_top_status(
        canvas: Canvas,
        rect: RectF,
        subtitle: String,
        traffic_status: Pair<String, Int>,
        scale_label: ScaleLabel,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        draw_panel_surface(canvas, rect, colors.panel, theme_style.top_panel_alpha, style)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        val right_status_left = rect.right - host.dp(132f)
        val title_left = rect.left + host.dp(16f)
        text_paint.textSize = host.sp(19f * theme_style.heading_scale)
        text_paint.color = colors.text
        draw_fitted_left_text(
            canvas = canvas,
            value = "Flight Alert",
            left = title_left,
            y = rect.top + host.dp(27f),
            max_width = (right_status_left - host.dp(12f) - title_left).coerceAtLeast(host.dp(36f)),
            start_size = host.sp(19f * theme_style.heading_scale),
            min_size = host.sp(11f)
        )
        text_paint.isFakeBoldText = false
        text_paint.textSize = host.sp(12f)
        text_paint.color = colors.muted

        val subtitle_left = rect.left + host.dp(16f)
        draw_fitted_left_text(
            canvas = canvas,
            value = subtitle,
            left = subtitle_left,
            y = rect.top + host.dp(49f),
            max_width = (right_status_left - host.dp(12f) - subtitle_left).coerceAtLeast(host.dp(36f)),
            start_size = host.sp(12f),
            min_size = host.sp(9f)
        )
        draw_status_label(canvas, right_status_left, rect.top + host.dp(14f), host.dp(116f), host.dp(26f), traffic_status.first, traffic_status.second)
        draw_scale_label(canvas, right_status_left, rect.top + host.dp(45f), host.dp(116f), host.dp(17f), scale_label, style)
    }

    // Recenter uses the same context-control surface as path controls so the top toolbar stays predictable.
    fun draw_recenter_button(canvas: Canvas, rect: RectF, style: FlightMapChromeStyle) {
        val color = style.visual_theme.colors.accent_green
        draw_context_control(canvas, rect, color, style)
        draw_locate_icon(canvas, rect.centerX(), rect.centerY(), color)
    }

    // Path buttons choose their icon from the command label while keeping the styling caller-controlled.
    fun draw_flight_path_button(
        canvas: Canvas,
        rect: RectF,
        label: String,
        color: Int,
        style: FlightMapChromeStyle
    ) {
        draw_context_control(canvas, rect, color, style)
        when (label) {
            "Clear" -> draw_clear_icon(canvas, rect.centerX(), rect.centerY(), color)
            "History" -> draw_history_icon(canvas, rect.centerX(), rect.centerY(), color)
            else -> draw_path_fit_icon(canvas, rect.centerX(), rect.centerY(), color)
        }
    }

    // Settings button keeps text plus icon because it is a top-level panel opener.
    fun draw_settings_button(canvas: Canvas, bounds: RectF, style: FlightMapChromeStyle) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val stroke = if (theme_style.treatment == ThemeTreatment.PLAIN) with_alpha(colors.control_stroke, 155) else colors.control_stroke
        val fill_alpha = if (theme_style.treatment == ThemeTreatment.PLAIN) 228 else theme_style.control_alpha
        val stroke_width = if (theme_style.treatment == ThemeTreatment.PLAIN) 1f else theme_style.control_stroke_dp
        draw_control_surface(canvas, bounds, with_alpha(colors.control_fill, fill_alpha), stroke, false, stroke_width, style)
        draw_gear_icon(canvas, bounds.centerX(), bounds.centerY() - host.dp(4f), colors.accent_blue)
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.textSize = host.sp(8f)
        text_paint.color = colors.text
        canvas.drawText("Settings", bounds.centerX(), bounds.bottom - host.dp(6f), text_paint)
    }

    // Filters button changes label and accent only when a filter is actively changing visible traffic.
    fun draw_filters_button(canvas: Canvas, bounds: RectF, active: Boolean, style: FlightMapChromeStyle) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        val stroke = when {
            active -> colors.accent_orange
            theme_style.treatment == ThemeTreatment.PLAIN -> with_alpha(colors.control_stroke, 155)
            else -> colors.control_stroke
        }
        val fill_alpha = if (theme_style.treatment == ThemeTreatment.PLAIN) 228 else theme_style.control_alpha
        val fill = if (active) {
            with_alpha(colors.accent_orange, colors.selected_fill_alpha)
        } else {
            with_alpha(colors.control_fill, fill_alpha)
        }
        val stroke_width = if (theme_style.treatment == ThemeTreatment.PLAIN) 1f else theme_style.control_stroke_dp
        draw_control_surface(canvas, bounds, fill, stroke, active, stroke_width, style)
        draw_filter_icon(canvas, bounds.centerX(), bounds.centerY() - host.dp(4f), if (active) colors.accent_orange else colors.accent_blue)
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.textSize = host.sp(8f)
        text_paint.color = if (active) colors.accent_orange else colors.text
        canvas.drawText(if (active) "Filtered" else "Filters", bounds.centerX(), bounds.bottom - host.dp(6f), text_paint)
    }

    fun draw_gear_icon(canvas: Canvas, cx: Float, cy: Float, color: Int) {
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = host.dp(2f)
        paint.color = color
        canvas.drawCircle(cx, cy, host.dp(8f), paint)
        canvas.drawCircle(cx, cy, host.dp(3f), paint)
        for (i in 0 until 8) {
            val angle = Math.toRadians((i * 45).toDouble())
            canvas.drawLine(
                cx + cos(angle).toFloat() * host.dp(10f),
                cy + sin(angle).toFloat() * host.dp(10f),
                cx + cos(angle).toFloat() * host.dp(13f),
                cy + sin(angle).toFloat() * host.dp(13f),
                paint
            )
        }
    }

    fun draw_filter_icon(canvas: Canvas, cx: Float, cy: Float, color: Int) {
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = host.dp(2.2f)
        paint.color = color
        path.reset()
        path.moveTo(cx - host.dp(13f), cy - host.dp(10f))
        path.lineTo(cx + host.dp(13f), cy - host.dp(10f))
        path.lineTo(cx + host.dp(4f), cy)
        path.lineTo(cx + host.dp(4f), cy + host.dp(10f))
        path.lineTo(cx - host.dp(4f), cy + host.dp(14f))
        path.lineTo(cx - host.dp(4f), cy)
        path.close()
        canvas.drawPath(path, paint)
    }

    fun draw_locate_icon(canvas: Canvas, cx: Float, cy: Float, color: Int) {
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = host.dp(2f)
        paint.color = color
        canvas.drawCircle(cx, cy, host.dp(12f), paint)
        canvas.drawLine(cx, cy - host.dp(18f), cx, cy - host.dp(13f), paint)
        canvas.drawLine(cx, cy + host.dp(13f), cx, cy + host.dp(18f), paint)
        canvas.drawLine(cx - host.dp(18f), cy, cx - host.dp(13f), cy, paint)
        canvas.drawLine(cx + host.dp(13f), cy, cx + host.dp(18f), cy, paint)
        paint.style = Paint.Style.FILL
        paint.color = color
        canvas.drawCircle(cx, cy, host.dp(4f), paint)
    }

    fun draw_path_fit_icon(canvas: Canvas, cx: Float, cy: Float, color: Int) {
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = host.dp(2f)
        paint.color = color
        val size = host.dp(15f)
        canvas.drawRect(cx - size / 2f, cy - size / 2f, cx + size / 2f, cy + size / 2f, paint)
        canvas.drawLine(cx - host.dp(12f), cy - host.dp(12f), cx - host.dp(6f), cy - host.dp(12f), paint)
        canvas.drawLine(cx - host.dp(12f), cy - host.dp(12f), cx - host.dp(12f), cy - host.dp(6f), paint)
        canvas.drawLine(cx + host.dp(12f), cy + host.dp(12f), cx + host.dp(6f), cy + host.dp(12f), paint)
        canvas.drawLine(cx + host.dp(12f), cy + host.dp(12f), cx + host.dp(12f), cy + host.dp(6f), paint)
    }

    fun draw_history_icon(canvas: Canvas, cx: Float, cy: Float, color: Int) {
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = host.dp(2.1f)
        paint.strokeCap = Paint.Cap.ROUND
        paint.strokeJoin = Paint.Join.ROUND
        paint.color = color
        path.reset()
        path.moveTo(cx - host.dp(12f), cy + host.dp(8f))
        path.cubicTo(cx - host.dp(5f), cy - host.dp(11f), cx + host.dp(6f), cy + host.dp(12f), cx + host.dp(12f), cy - host.dp(8f))
        canvas.drawPath(path, paint)
        paint.style = Paint.Style.FILL
        canvas.drawCircle(cx - host.dp(12f), cy + host.dp(8f), host.dp(3f), paint)
        canvas.drawCircle(cx, cy, host.dp(2.6f), paint)
        canvas.drawCircle(cx + host.dp(12f), cy - host.dp(8f), host.dp(3f), paint)
        paint.strokeCap = Paint.Cap.BUTT
        paint.strokeJoin = Paint.Join.MITER
    }

    fun draw_clear_icon(canvas: Canvas, cx: Float, cy: Float, color: Int) {
        paint.style = Paint.Style.STROKE
        paint.strokeWidth = host.dp(2.4f)
        paint.color = color
        canvas.drawCircle(cx, cy, host.dp(12f), paint)
        canvas.drawLine(cx - host.dp(6f), cy - host.dp(6f), cx + host.dp(6f), cy + host.dp(6f), paint)
        canvas.drawLine(cx + host.dp(6f), cy - host.dp(6f), cx - host.dp(6f), cy + host.dp(6f), paint)
    }

    private fun draw_fitted_left_text(
        canvas: Canvas, value: String, left: Float, y: Float, max_width: Float, start_size: Float, min_size: Float
    ) = draw_fitted_text(
        canvas, text_paint, value, left, y, max_width, start_size, min_size, Paint.Align.LEFT, host.dp(0.5f), host::ellipsize
    )

    private fun draw_status_label(
        canvas: Canvas,
        x: Float,
        y: Float,
        width: Float,
        height: Float,
        label: String,
        color: Int
    ) {
        val rect = RectF(x, y, x + width, y + height)
        paint.style = Paint.Style.FILL
        paint.color = Color.argb(34, Color.red(color), Color.green(color), Color.blue(color))
        canvas.drawRoundRect(rect, height / 2f, height / 2f, paint)
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = true
        text_paint.textSize = if (height > host.dp(20f)) host.sp(10f) else host.sp(9f)
        text_paint.color = color
        val max_width = (rect.width() - host.dp(12f)).coerceAtLeast(host.dp(8f))
        while (text_paint.textSize > host.sp(7f) && text_paint.measureText(label) > max_width) {
            text_paint.textSize -= host.dp(0.5f)
        }
        val display = if (text_paint.measureText(label) <= max_width) label else host.ellipsize(label, max_width)
        val metrics = text_paint.fontMetrics
        canvas.drawText(display, rect.centerX(), rect.centerY() - (metrics.ascent + metrics.descent) / 2f, text_paint)
        text_paint.isFakeBoldText = false
    }

    private fun draw_scale_label(
        canvas: Canvas,
        x: Float,
        y: Float,
        width: Float,
        height: Float,
        scale: ScaleLabel,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        val rect = RectF(x, y, x + width, y + height)
        paint.style = Paint.Style.FILL
        paint.color = Color.argb(34, Color.red(colors.accent_yellow), Color.green(colors.accent_yellow), Color.blue(colors.accent_yellow))
        canvas.drawRoundRect(rect, height / 2f, height / 2f, paint)

        val line_left = rect.left + host.dp(9f)
        val line_width = scale.pixels.coerceIn(host.dp(18f), width * 0.44f)
        val line_right = line_left + line_width
        val line_y = rect.centerY()
        stroke_paint.color = colors.accent_yellow
        stroke_paint.strokeWidth = host.dp(1.2f)
        canvas.drawLine(line_left, line_y, line_right, line_y, stroke_paint)
        canvas.drawLine(line_left, line_y - host.dp(3f), line_left, line_y + host.dp(3f), stroke_paint)
        canvas.drawLine(line_right, line_y - host.dp(3f), line_right, line_y + host.dp(3f), stroke_paint)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = host.sp(9f)
        text_paint.color = colors.accent_yellow
        draw_fitted_left_text(
            canvas = canvas,
            value = scale.label,
            left = line_right + host.dp(7f),
            y = rect.centerY() - (text_paint.fontMetrics.ascent + text_paint.fontMetrics.descent) / 2f,
            max_width = (rect.right - line_right - host.dp(13f)).coerceAtLeast(host.dp(16f)),
            start_size = host.sp(9f),
            min_size = host.sp(7f)
        )
        text_paint.isFakeBoldText = false
    }

    // Control treatments add theme texture without changing the control's hit rectangle or label contract.
    private fun draw_control_treatment(
        canvas: Canvas,
        rect: RectF,
        radius: Float,
        stroke: Int,
        selected: Boolean,
        style: FlightMapChromeStyle
    ) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        if (theme_style.texture_alpha <= 0) return
        val alpha = if (selected) max(theme_style.texture_alpha, 46) else theme_style.texture_alpha
        when (theme_style.treatment) {
            ThemeTreatment.PLAIN -> Unit
            ThemeTreatment.GLASS -> {
                val glass_accent = if (selected) stroke else colors.accent_blue
                val clip = Path()
                clip.addRoundRect(rect, radius, radius, Path.Direction.CW)
                val save = canvas.save()
                canvas.clipPath(clip)

                paint.style = Paint.Style.FILL
                paint.shader = LinearGradient(
                    rect.left,
                    rect.top,
                    rect.left,
                    rect.bottom,
                    intArrayOf(
                        with_alpha(Color.WHITE, (alpha * 0.78f).roundToInt()),
                        with_alpha(glass_accent, (alpha * 0.24f).roundToInt()),
                        with_alpha(Color.WHITE, (alpha * 0.18f).roundToInt())
                    ),
                    floatArrayOf(0f, 0.56f, 1f),
                    Shader.TileMode.CLAMP
                )
                canvas.drawRect(rect, paint)
                paint.shader = null

                val shine_height = min(rect.height() * 0.42f, host.dp(18f)).coerceAtLeast(host.dp(7f))
                paint.shader = LinearGradient(
                    rect.left,
                    rect.top,
                    rect.left,
                    rect.top + shine_height,
                    with_alpha(Color.WHITE, (alpha * 0.64f).roundToInt()),
                    with_alpha(Color.WHITE, 0),
                    Shader.TileMode.CLAMP
                )
                canvas.drawRect(rect.left, rect.top, rect.right, rect.top + shine_height, paint)
                paint.shader = null

                paint.color = with_alpha(glass_accent, (alpha * 0.40f).roundToInt())
                canvas.drawRect(rect.left, rect.top + host.dp(2f), rect.left + host.dp(2f), rect.bottom - host.dp(2f), paint)
                paint.color = with_alpha(Color.WHITE, (alpha * 0.18f).roundToInt())
                canvas.drawRect(rect.right - host.dp(1.2f), rect.top + radius * 0.44f, rect.right, rect.bottom - radius * 0.44f, paint)

                val inset = host.dp(1.1f)
                val inner = RectF(rect.left + inset, rect.top + inset, rect.right - inset, rect.bottom - inset)
                val inner_radius = max(0f, radius - inset)
                stroke_paint.style = Paint.Style.STROKE
                stroke_paint.strokeWidth = host.dp(0.75f)
                stroke_paint.color = with_alpha(Color.WHITE, (alpha * 0.78f).roundToInt())
                canvas.drawRoundRect(inner, inner_radius, inner_radius, stroke_paint)

                stroke_paint.strokeWidth = host.dp(0.9f)
                val line_inset = min(radius * 0.86f, rect.width() * 0.22f).coerceAtLeast(host.dp(7f))
                stroke_paint.color = with_alpha(glass_accent, (alpha * 0.95f).roundToInt())
                canvas.drawLine(rect.left + line_inset, rect.top + host.dp(4f), rect.right - line_inset, rect.top + host.dp(4f), stroke_paint)
                stroke_paint.strokeWidth = host.dp(0.7f)
                stroke_paint.color = with_alpha(Color.WHITE, (alpha * 0.34f).roundToInt())
                canvas.drawLine(rect.left + line_inset, rect.bottom - host.dp(4f), rect.right - line_inset, rect.bottom - host.dp(4f), stroke_paint)
                canvas.restoreToCount(save)
            }
            ThemeTreatment.RADAR_GRID -> {
                stroke_paint.strokeWidth = host.dp(1f)
                stroke_paint.color = with_alpha(stroke, alpha)
                val inset = host.dp(5f)
                val tick = min(rect.width(), rect.height()) * 0.22f
                canvas.drawLine(rect.left + inset, rect.top + inset, rect.left + inset + tick, rect.top + inset, stroke_paint)
                canvas.drawLine(rect.left + inset, rect.top + inset, rect.left + inset, rect.top + inset + tick, stroke_paint)
                canvas.drawLine(rect.right - inset - tick, rect.top + inset, rect.right - inset, rect.top + inset, stroke_paint)
                canvas.drawLine(rect.right - inset, rect.top + inset, rect.right - inset, rect.top + inset + tick, stroke_paint)
                canvas.drawLine(rect.left + inset, rect.bottom - inset, rect.left + inset + tick, rect.bottom - inset, stroke_paint)
                canvas.drawLine(rect.left + inset, rect.bottom - inset - tick, rect.left + inset, rect.bottom - inset, stroke_paint)
                canvas.drawLine(rect.right - inset - tick, rect.bottom - inset, rect.right - inset, rect.bottom - inset, stroke_paint)
                canvas.drawLine(rect.right - inset, rect.bottom - inset - tick, rect.right - inset, rect.bottom - inset, stroke_paint)
            }
            ThemeTreatment.DAYLIGHT_CARD -> {
                paint.style = Paint.Style.FILL
                paint.color = with_alpha(stroke, alpha)
                canvas.drawRect(rect.left, rect.top, rect.right, rect.top + host.dp(3f), paint)
                paint.color = with_alpha(colors.accent_pink, (alpha * 0.65f).roundToInt())
                canvas.drawRect(rect.left, rect.bottom - host.dp(2f), rect.right, rect.bottom, paint)
            }
            ThemeTreatment.STORM_BAND -> {
                paint.style = Paint.Style.FILL
                paint.color = with_alpha(stroke, alpha)
                canvas.drawRect(rect.left, rect.top, rect.left + host.dp(4f), rect.bottom, paint)
                stroke_paint.strokeWidth = host.dp(1.2f)
                stroke_paint.color = with_alpha(colors.accent_orange, (alpha * 0.85f).roundToInt())
                canvas.drawLine(rect.right - host.dp(15f), rect.top + host.dp(7f), rect.right - host.dp(7f), rect.bottom - host.dp(7f), stroke_paint)
            }
            ThemeTreatment.CRT_SCANLINE -> {
                stroke_paint.strokeWidth = host.dp(0.7f)
                stroke_paint.color = with_alpha(colors.accent_green, (alpha * 0.9f).roundToInt())
                var y = rect.top + host.dp(5f)
                while (y < rect.bottom - host.dp(2f)) {
                    canvas.drawLine(rect.left + host.dp(3f), y, rect.right - host.dp(3f), y, stroke_paint)
                    y += host.dp(10f)
                }
                stroke_paint.strokeWidth = host.dp(0.8f)
                stroke_paint.color = with_alpha(colors.text, (alpha * 0.55f).roundToInt())
                canvas.drawRect(rect.left + host.dp(3f), rect.top + host.dp(3f), rect.right - host.dp(3f), rect.bottom - host.dp(3f), stroke_paint)
            }
        }
    }

    // Panel treatments are visual-only layers that keep map/provider attribution and data states untouched.
    private fun draw_panel_treatment(canvas: Canvas, rect: RectF, radius: Float, style: FlightMapChromeStyle) {
        val colors = style.visual_theme.colors
        val theme_style = style.visual_theme.style
        if (theme_style.texture_alpha <= 0) return
        when (theme_style.treatment) {
            ThemeTreatment.PLAIN -> Unit
            ThemeTreatment.GLASS -> {
                val clip = Path()
                clip.addRoundRect(rect, radius, radius, Path.Direction.CW)
                val save = canvas.save()
                canvas.clipPath(clip)

                paint.style = Paint.Style.FILL
                paint.shader = LinearGradient(
                    rect.left,
                    rect.top,
                    rect.left,
                    rect.bottom,
                    intArrayOf(
                        with_alpha(Color.WHITE, (theme_style.texture_alpha * 0.58f).roundToInt()),
                        with_alpha(colors.accent_blue, (theme_style.texture_alpha * 0.16f).roundToInt()),
                        with_alpha(Color.WHITE, (theme_style.texture_alpha * 0.10f).roundToInt())
                    ),
                    floatArrayOf(0f, 0.56f, 1f),
                    Shader.TileMode.CLAMP
                )
                canvas.drawRect(rect, paint)
                paint.shader = null

                val shine_height = min(host.dp(78f), max(host.dp(28f), rect.height() * 0.16f))
                paint.shader = LinearGradient(
                    rect.left,
                    rect.top,
                    rect.left,
                    rect.top + shine_height,
                    with_alpha(Color.WHITE, (theme_style.texture_alpha * 0.42f).roundToInt()),
                    with_alpha(Color.WHITE, 0),
                    Shader.TileMode.CLAMP
                )
                canvas.drawRect(rect.left, rect.top, rect.right, rect.top + shine_height, paint)
                paint.shader = null

                paint.color = with_alpha(colors.accent_blue, (theme_style.texture_alpha * 0.34f).roundToInt())
                canvas.drawRect(rect.left, rect.top + host.dp(4f), rect.left + host.dp(3f), rect.bottom - host.dp(4f), paint)
                paint.color = with_alpha(Color.WHITE, (theme_style.texture_alpha * 0.13f).roundToInt())
                canvas.drawRect(rect.right - host.dp(2f), rect.top + radius * 0.5f, rect.right, rect.bottom - radius * 0.5f, paint)

                val inset = host.dp(1.4f)
                val inner = RectF(rect.left + inset, rect.top + inset, rect.right - inset, rect.bottom - inset)
                val inner_radius = max(0f, radius - inset)
                stroke_paint.style = Paint.Style.STROKE
                stroke_paint.strokeWidth = host.dp(0.8f)
                stroke_paint.color = with_alpha(Color.WHITE, (theme_style.texture_alpha * 0.58f).roundToInt())
                canvas.drawRoundRect(inner, inner_radius, inner_radius, stroke_paint)

                val line_inset = max(host.dp(16f), min(rect.width(), rect.height()) * 0.1f)
                stroke_paint.strokeWidth = host.dp(0.9f)
                stroke_paint.color = with_alpha(colors.accent_blue, (theme_style.texture_alpha * 1.05f).roundToInt())
                canvas.drawLine(rect.left + line_inset, rect.top + host.dp(8f), rect.right - line_inset, rect.top + host.dp(8f), stroke_paint)
                stroke_paint.strokeWidth = host.dp(0.75f)
                stroke_paint.color = with_alpha(Color.WHITE, (theme_style.texture_alpha * 0.38f).roundToInt())
                canvas.drawLine(rect.left + line_inset, rect.bottom - host.dp(9f), rect.right - line_inset, rect.bottom - host.dp(9f), stroke_paint)
                canvas.restoreToCount(save)
            }
            ThemeTreatment.RADAR_GRID -> {
                stroke_paint.strokeWidth = host.dp(0.6f)
                stroke_paint.color = with_alpha(colors.accent_yellow, theme_style.texture_alpha)
                draw_even_radar_grid(canvas, rect)
            }
            ThemeTreatment.DAYLIGHT_CARD -> {
                paint.style = Paint.Style.FILL
                paint.color = with_alpha(colors.accent_blue, theme_style.texture_alpha)
                canvas.drawRect(rect.left, rect.top, rect.right, rect.top + host.dp(3f), paint)
            }
            ThemeTreatment.STORM_BAND -> {
                paint.style = Paint.Style.FILL
                paint.color = with_alpha(colors.accent_blue, theme_style.texture_alpha)
                canvas.drawRect(rect.left, rect.top, rect.left + host.dp(5f), rect.bottom, paint)
                paint.color = with_alpha(colors.text, (theme_style.texture_alpha * 0.5f).toInt())
                canvas.drawRect(rect.left, rect.top, rect.right, rect.top + host.dp(2f), paint)
            }
            ThemeTreatment.CRT_SCANLINE -> {
                stroke_paint.strokeWidth = host.dp(0.7f)
                stroke_paint.color = with_alpha(colors.accent_green, theme_style.texture_alpha)
                var y = rect.top + host.dp(6f)
                while (y < rect.bottom) {
                    canvas.drawLine(rect.left + host.dp(2f), y, rect.right - host.dp(2f), y, stroke_paint)
                    y += host.dp(12f)
                }
            }
        }
    }

    // Radar-grid texture is centered evenly so decorative lines do not bunch up on resized panels.
    private fun draw_even_radar_grid(canvas: Canvas, rect: RectF) {
        val inset = host.dp(2f)
        val step = host.dp(RADAR_GRID_SPACING_DP)
        val left = rect.left + inset
        val top = rect.top + inset
        val right = rect.right - inset
        val bottom = rect.bottom - inset
        val width = right - left
        val height = bottom - top
        if (width < step || height < step) return

        val columns = max(1, floor(width / step).toInt())
        val rows = max(1, floor(height / step).toInt())
        val grid_width = columns * step
        val grid_height = rows * step
        val start_x = left + (width - grid_width) / 2f
        val start_y = top + (height - grid_height) / 2f

        for (index in 0..columns) {
            val x = start_x + index * step
            if (x > left + 0.5f && x < right - 0.5f) {
                canvas.drawLine(x, top, x, bottom, stroke_paint)
            }
        }
        for (index in 0..rows) {
            val y = start_y + index * step
            if (y > top + 0.5f && y < bottom - 0.5f) {
                canvas.drawLine(left, y, right, y, stroke_paint)
            }
        }
    }

    
    private companion object {
        const val CHROME_SURFACE_CACHE_LIMIT = 48
        const val RADAR_GRID_SPACING_DP = 36f
    }
}


data class FlightPathProjection(
    val last_trace_point: TrackPoint,
    val projected_endpoint: GeoPoint
)

data class FlightPathRenderState(
    val selected_segments: List<TraceSegment>,
    val previous_segments: List<TraceSegment>,
    val projection: FlightPathProjection?
)

data class FlightPathRenderStyle(
    val path_shadow: Int,
    val accent_yellow: Int,
    val accent_blue: Int
)

class FlightPathRenderer(
    private val stroke_paint: Paint,
    private val path: Path,
    private val dp: (Float) -> Float,
    private val with_alpha: (Int, Int) -> Int
) {
    fun draw_selected_path(canvas: Canvas, viewport: Viewport, state: FlightPathRenderState, style: FlightPathRenderStyle) {
        if (state.selected_segments.isEmpty()) return
        if (state.previous_segments.isNotEmpty()) {
            draw_previous_paths(canvas, viewport, state.previous_segments, style)
        }

        path.reset()
        val has_drawable_segment = add_segments_to_path(viewport, state.selected_segments)
        if (!has_drawable_segment) return

        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeCap = Paint.Cap.ROUND
        stroke_paint.strokeJoin = Paint.Join.ROUND
        stroke_paint.strokeWidth = dp(5f)
        stroke_paint.color = with_alpha(style.path_shadow, 90)
        canvas.drawPath(path, stroke_paint)
        stroke_paint.strokeWidth = dp(2.4f)
        stroke_paint.color = style.accent_yellow
        canvas.drawPath(path, stroke_paint)
        draw_projection(canvas, viewport, state.projection, style)
        reset_stroke()
    }

    private fun draw_previous_paths(
        canvas: Canvas,
        viewport: Viewport,
        previous_segments: List<TraceSegment>,
        style: FlightPathRenderStyle
    ) {
        path.reset()
        val has_drawable_segment = add_segments_to_path(viewport, previous_segments)
        if (!has_drawable_segment) return

        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeCap = Paint.Cap.ROUND
        stroke_paint.strokeJoin = Paint.Join.ROUND
        stroke_paint.pathEffect = DashPathEffect(floatArrayOf(dp(8f), dp(8f)), 0f)
        stroke_paint.strokeWidth = dp(4.2f)
        stroke_paint.color = with_alpha(style.path_shadow, 72)
        canvas.drawPath(path, stroke_paint)
        stroke_paint.strokeWidth = dp(1.9f)
        stroke_paint.color = with_alpha(style.accent_blue, 190)
        canvas.drawPath(path, stroke_paint)
        reset_stroke()
    }

    private fun draw_projection(
        canvas: Canvas,
        viewport: Viewport,
        projection: FlightPathProjection?,
        style: FlightPathRenderStyle
    ) {
        if (projection == null) return
        val distance = MapProjection.distance_meters(
            projection.last_trace_point.lat,
            projection.last_trace_point.lon,
            projection.projected_endpoint.lat,
            projection.projected_endpoint.lon
        )
        if (distance < MIN_PROJECTED_PATH_CONNECTOR_M) return

        val start = MapProjection.lat_lon_to_world(projection.last_trace_point.lat, projection.last_trace_point.lon, viewport.zoom)
        val end = MapProjection.lat_lon_to_world(projection.projected_endpoint.lat, projection.projected_endpoint.lon, viewport.zoom)
        val world_span = TILE_SIZE * 2.0.pow(viewport.zoom)
        val start_x = (start.x - viewport.center_x + viewport.width / 2.0).toFloat()
        var end_x = (end.x - viewport.center_x + viewport.width / 2.0).toFloat()
        while (end_x - start_x > world_span / 2.0) end_x -= world_span.toFloat()
        while (start_x - end_x > world_span / 2.0) end_x += world_span.toFloat()
        val start_y = (start.y - viewport.center_y + viewport.height / 2.0).toFloat()
        val end_y = (end.y - viewport.center_y + viewport.height / 2.0).toFloat()

        path.reset()
        path.moveTo(start_x, start_y)
        path.lineTo(end_x, end_y)
        stroke_paint.style = Paint.Style.STROKE
        stroke_paint.strokeCap = Paint.Cap.ROUND
        stroke_paint.strokeJoin = Paint.Join.ROUND
        stroke_paint.pathEffect = DashPathEffect(floatArrayOf(dp(9f), dp(7f)), 0f)
        stroke_paint.strokeWidth = dp(2.2f)
        stroke_paint.color = with_alpha(style.accent_yellow, 185)
        canvas.drawPath(path, stroke_paint)
        stroke_paint.pathEffect = null
    }

    private fun add_segments_to_path(viewport: Viewport, segments: List<TraceSegment>): Boolean {
        val world_span = TILE_SIZE * 2.0.pow(viewport.zoom)
        var has_drawable_segment = false
        segments.forEach { segment ->
            var previous_screen_x: Float? = null
            segment.points.forEachIndexed { index, point ->
                val world = MapProjection.lat_lon_to_world(point.lat, point.lon, viewport.zoom)
                var sx = (world.x - viewport.center_x + viewport.width / 2.0).toFloat()
                val sy = (world.y - viewport.center_y + viewport.height / 2.0).toFloat()
                previous_screen_x?.let { last_x ->
                    val span = world_span.toFloat()
                    while (sx - last_x > span / 2f) sx -= span
                    while (last_x - sx > span / 2f) sx += span
                }
                if (index == 0) {
                    path.moveTo(sx, sy)
                } else {
                    path.lineTo(sx, sy)
                    has_drawable_segment = true
                }
                previous_screen_x = sx
            }
        }
        return has_drawable_segment
    }

    private fun reset_stroke() {
        stroke_paint.strokeCap = Paint.Cap.BUTT
        stroke_paint.strokeJoin = Paint.Join.MITER
        stroke_paint.pathEffect = null
    }

    private companion object {
        const val TILE_SIZE = 256
        const val MIN_PROJECTED_PATH_CONNECTOR_M = 60.0
    }
}


data class LocalReferenceOverlayStats(
    val status: LocalReferenceOverlayStatus,
    val lines_drawn: Int,
    val labels_drawn: Int,
    val cached: Boolean = false
) {
    fun summary(): String {
        return when (status) {
            LocalReferenceOverlayStatus.LOADED -> {
                val cache_note = if (cached) " cached" else ""
                " localRef=lines:$lines_drawn labels:$labels_drawn$cache_note"
            }
            LocalReferenceOverlayStatus.LOADING -> " localRef=loading"
            LocalReferenceOverlayStatus.FAILED -> " localRef=failed"
        }
    }
}

enum class LocalReferenceOverlayStatus {
    LOADING,
    LOADED,
    FAILED
}

private data class LocalReferenceDataset(
    val lines: List<LocalReferenceLine>,
    val labels: List<LocalReferenceLabel>
)

private data class LocalReferenceOverlayCacheKey(
    val zoom: Int,
    val center_x: Int,
    val center_y: Int,
    val width: Int,
    val height: Int
)

private data class LocalReferenceOverlayCache(
    val key: LocalReferenceOverlayCacheKey,
    val bitmap: Bitmap,
    val lines_drawn: Int,
    val labels_drawn: Int
)

@Suppress("ArrayInDataClass")
private data class LocalReferenceLine(
    val kind: LocalReferenceKind,
    val min_zoom: Double,
    val min_lon: Double,
    val min_lat: Double,
    val max_lon: Double,
    val max_lat: Double,
    val points: DoubleArray
)

private data class LocalReferenceLabel(
    val kind: LocalReferenceKind,
    val text: String,
    val lat: Double,
    val lon: Double,
    val min_zoom: Double,
    val max_zoom: Double,
    val rank: Int,
    val population: Int,
    val capital: Boolean
)

private data class LocalGeoBounds(
    val min_lat: Double,
    val min_lon: Double,
    val max_lat: Double,
    val max_lon: Double,
    val wraps: Boolean
)

private enum class LocalReferenceKind {
    COUNTRY,
    REGION,
    PLACE
}

private enum class LocalReferenceDetail {
    INTERACTION,
    SETTLED
}

internal class LocalReferenceOverlayRenderer(
    private val context: Context,
    private val paint: Paint,
    private val text_paint: Paint,
    private val path: Path,
    private val dp: (Float) -> Float,
    private val sp: (Float) -> Float,
    private val with_alpha: (Int, Int) -> Int,
    private val request_redraw: () -> Unit
) {
    @Volatile private var dataset: LocalReferenceDataset? = null
    @Volatile private var load_failed = false
    @Volatile private var load_error: String? = null
    private val load_started = AtomicBoolean(false)
    private val label_bounds = ArrayList<RectF>(128)
    private var overlay_cache: LocalReferenceOverlayCache? = null
    private var overlay_cache_canvas: Canvas? = null

    init {
        request_load_if_needed()
    }

    fun draw(
        canvas: Canvas,
        viewport: Viewport,
        enabled: Boolean,
        interaction_active: Boolean
    ): LocalReferenceOverlayStats {
        if (!enabled) {
            return LocalReferenceOverlayStats(
                status = LocalReferenceOverlayStatus.LOADED,
                lines_drawn = 0,
                labels_drawn = 0
            )
        }
        if (load_failed) {
            return LocalReferenceOverlayStats(
                status = LocalReferenceOverlayStatus.FAILED,
                lines_drawn = 0,
                labels_drawn = 0
            )
        }
        val local_dataset = dataset ?: run {
            request_load_if_needed()
            return LocalReferenceOverlayStats(
                status = LocalReferenceOverlayStatus.LOADING,
                lines_drawn = 0,
                labels_drawn = 0
            )
        }
        if (!interaction_active) {
            val cache_key = cache_key_for(viewport)
            val cache = overlay_cache
            if (cache != null && cache.key == cache_key && !cache.bitmap.isRecycled) {
                canvas.drawBitmap(cache.bitmap, 0f, 0f, null)
                return LocalReferenceOverlayStats(
                    status = LocalReferenceOverlayStatus.LOADED,
                    lines_drawn = cache.lines_drawn,
                    labels_drawn = cache.labels_drawn,
                    cached = true
                )
            }
            val bitmap = obtain_cache_bitmap(viewport)
            bitmap.eraseColor(Color.TRANSPARENT)
            val cache_canvas = overlay_cache_canvas ?: Canvas(bitmap).also { overlay_cache_canvas = it }
            if (cache_canvas.width != bitmap.width || cache_canvas.height != bitmap.height) {
                cache_canvas.setBitmap(bitmap)
            }
            val lines = draw_lines(cache_canvas, viewport, local_dataset.lines, LocalReferenceDetail.SETTLED)
            val labels = draw_labels(cache_canvas, viewport, local_dataset.labels, LocalReferenceDetail.SETTLED)
            overlay_cache = LocalReferenceOverlayCache(
                key = cache_key,
                bitmap = bitmap,
                lines_drawn = lines,
                labels_drawn = labels
            )
            canvas.drawBitmap(bitmap, 0f, 0f, null)
            return LocalReferenceOverlayStats(
                status = LocalReferenceOverlayStatus.LOADED,
                lines_drawn = lines,
                labels_drawn = labels
            )
        }
        val lines = draw_lines(canvas, viewport, local_dataset.lines, LocalReferenceDetail.INTERACTION)
        val labels = draw_labels(canvas, viewport, local_dataset.labels, LocalReferenceDetail.INTERACTION)
        return LocalReferenceOverlayStats(
            status = LocalReferenceOverlayStatus.LOADED,
            lines_drawn = lines,
            labels_drawn = labels
        )
    }

    fun clear() {
        label_bounds.clear()
        overlay_cache?.bitmap?.takeIf { !it.isRecycled }?.recycle()
        overlay_cache = null
        overlay_cache_canvas = null
    }

    private fun cache_key_for(viewport: Viewport): LocalReferenceOverlayCacheKey {
        return LocalReferenceOverlayCacheKey(
            zoom = (viewport.zoom * 1000.0).roundToInt(),
            center_x = viewport.center_x.roundToInt(),
            center_y = viewport.center_y.roundToInt(),
            width = viewport.width.roundToInt(),
            height = viewport.height.roundToInt()
        )
    }

    private fun obtain_cache_bitmap(viewport: Viewport): Bitmap {
        val width = viewport.width.roundToInt().coerceAtLeast(1)
        val height = viewport.height.roundToInt().coerceAtLeast(1)
        val current = overlay_cache?.bitmap
        if (current != null && !current.isRecycled && current.width == width && current.height == height) {
            return current
        }
        current?.takeIf { !it.isRecycled }?.recycle()
        overlay_cache = null
        overlay_cache_canvas = null
        return createBitmap(width, height, Bitmap.Config.ARGB_8888)
    }

    private fun request_load_if_needed() {
        if (load_failed || !load_started.compareAndSet(false, true)) return
        Thread({
            try {
                android.os.Process.setThreadPriority(android.os.Process.THREAD_PRIORITY_BACKGROUND)
                val loaded_dataset = load_dataset()
                dataset = loaded_dataset
                Log.i(
                    FlightAlertSettings.App.TAG,
                    "Local reference overlay loaded lines=${loaded_dataset.lines.size} labels=${loaded_dataset.labels.size}"
                )
            } catch (error: Exception) {
                load_error = error.javaClass.simpleName + ": " + (error.message ?: "unknown")
                load_failed = true
                Log.w(FlightAlertSettings.App.TAG, "Local reference overlay failed to load: $load_error", error)
            } finally {
                request_redraw()
            }
        }, "flightalert-local-reference-labels").start()
    }

    private fun load_dataset(): LocalReferenceDataset {
        val root = load_root_json()
        val lines = parse_lines(root.getJSONArray("lines"))
        val labels = parse_labels(root.getJSONArray("labels")).sortedWith(
            compareBy<LocalReferenceLabel> { label_priority_bucket(it) }
                .thenBy { it.rank }
                .thenByDescending { it.population }
                .thenBy { it.text }
        )
        return LocalReferenceDataset(lines = lines, labels = labels)
    }

    private fun load_root_json(): JSONObject {
        var missing_error: FileNotFoundException? = null
        for (asset_path in ASSET_PATHS) {
            try {
                return context.assets.open(asset_path).use { raw ->
                    val text = if (asset_path.endsWith(".gz")) {
                        GZIPInputStream(raw).bufferedReader(Charsets.UTF_8).use { it.readText() }
                    } else {
                        raw.bufferedReader(Charsets.UTF_8).use { it.readText() }
                    }
                    JSONObject(text)
                }
            } catch (error: FileNotFoundException) {
                missing_error = error
            }
        }
        throw missing_error ?: FileNotFoundException(ASSET_PATHS.joinToString())
    }

    private fun parse_lines(items: JSONArray): List<LocalReferenceLine> {
        val result = ArrayList<LocalReferenceLine>(items.length())
        for (index in 0 until items.length()) {
            val item = items.getJSONObject(index)
            val point_array = item.getJSONArray("points")
            val points = DoubleArray(point_array.length() * 2)
            var out = 0
            for (point_index in 0 until point_array.length()) {
                val point = point_array.getJSONArray(point_index)
                points[out++] = point.getDouble(0)
                points[out++] = point.getDouble(1)
            }
            if (points.size >= 4) {
                val bbox = item.optJSONArray("bbox")
                result += LocalReferenceLine(
                    kind = parse_kind(item.getString("kind")),
                    min_zoom = item.optDouble("minZoom", 2.0),
                    min_lon = bbox?.optDouble(0, -180.0) ?: -180.0,
                    min_lat = bbox?.optDouble(1, -85.0) ?: -85.0,
                    max_lon = bbox?.optDouble(2, 180.0) ?: 180.0,
                    max_lat = bbox?.optDouble(3, 85.0) ?: 85.0,
                    points = points
                )
            }
        }
        return result
    }

    private fun parse_labels(items: JSONArray): List<LocalReferenceLabel> {
        val result = ArrayList<LocalReferenceLabel>(items.length())
        for (index in 0 until items.length()) {
            val item = items.getJSONObject(index)
            result += LocalReferenceLabel(
                kind = parse_kind(item.getString("kind")),
                text = item.getString("text"),
                lat = item.getDouble("lat"),
                lon = item.getDouble("lon"),
                min_zoom = item.optDouble("minZoom", 3.0),
                max_zoom = item.optDouble("maxZoom", 13.0),
                rank = item.optInt("rank", 9),
                population = item.optInt("population", 0),
                capital = item.optBoolean("capital", false)
            )
        }
        return result
    }

    private fun parse_kind(value: String): LocalReferenceKind {
        return when (value.lowercase(Locale.US)) {
            "country" -> LocalReferenceKind.COUNTRY
            "region" -> LocalReferenceKind.REGION
            else -> LocalReferenceKind.PLACE
        }
    }

    private fun label_priority_bucket(label: LocalReferenceLabel): Int {
        return when (label.kind) {
            LocalReferenceKind.COUNTRY -> 0
            LocalReferenceKind.REGION -> 20
            LocalReferenceKind.PLACE -> if (label.capital) 35 else 40
        }
    }

    private fun draw_lines(
        canvas: Canvas,
        viewport: Viewport,
        lines: List<LocalReferenceLine>,
        detail: LocalReferenceDetail
    ): Int {
        paint.style = Paint.Style.STROKE
        paint.strokeCap = Paint.Cap.ROUND
        paint.strokeJoin = Paint.Join.ROUND
        val visible_bounds = visible_geo_bounds(viewport, padding_degrees = 2.0)
        var drawn = 0
        for (line in lines) {
            if (viewport.zoom < line.min_zoom) continue
            if (detail == LocalReferenceDetail.INTERACTION &&
                line.kind == LocalReferenceKind.REGION &&
                viewport.zoom < INTERACTION_REGION_LINE_MIN_ZOOM
            ) continue
            if (!line_intersects_bounds(line, visible_bounds)) continue
            val alpha = zoom_fade_in(viewport.zoom, line.min_zoom, LINE_FADE_ZOOM_SPAN)
            if (alpha <= 0.01f) continue
            val width = when (line.kind) {
                LocalReferenceKind.COUNTRY -> country_line_width(viewport.zoom)
                LocalReferenceKind.REGION -> region_line_width(viewport.zoom)
                LocalReferenceKind.PLACE -> region_line_width(viewport.zoom)
            }
            if (
                draw_line(
                    canvas = canvas,
                    viewport = viewport,
                    line = line,
                    halo_stroke_width = width + dp(1.8f),
                    halo_color = with_alpha(0xFF07100D.toInt(), (170f * alpha).roundToInt()),
                    stroke_width = width,
                    color = line_color(line.kind, alpha)
                )
            ) {
                drawn++
            }
        }
        paint.strokeCap = Paint.Cap.BUTT
        paint.strokeJoin = Paint.Join.MITER
        paint.style = Paint.Style.FILL
        return drawn
    }

    private fun visible_geo_bounds(viewport: Viewport, padding_degrees: Double): LocalGeoBounds {
        val left = viewport.center_x - viewport.width / 2.0
        val right = viewport.center_x + viewport.width / 2.0
        val top = viewport.center_y - viewport.height / 2.0
        val bottom = viewport.center_y + viewport.height / 2.0
        val top_left = MapProjection.world_to_lat_lon(left, top, viewport.zoom)
        val bottom_right = MapProjection.world_to_lat_lon(right, bottom, viewport.zoom)
        val lon_span = (right - left) / world_width(viewport.zoom) * 360.0
        return LocalGeoBounds(
            min_lat = (bottom_right.lat - padding_degrees).coerceAtLeast(-85.0),
            max_lat = (top_left.lat + padding_degrees).coerceAtMost(85.0),
            min_lon = normalize_lon(top_left.lon - padding_degrees),
            max_lon = normalize_lon(bottom_right.lon + padding_degrees),
            wraps = lon_span >= 356.0 || top_left.lon > bottom_right.lon
        )
    }

    private fun line_intersects_bounds(line: LocalReferenceLine, bounds: LocalGeoBounds): Boolean {
        if (line.max_lat < bounds.min_lat || line.min_lat > bounds.max_lat) return false
        return if (bounds.wraps) {
            line.max_lon >= bounds.min_lon || line.min_lon <= bounds.max_lon
        } else {
            line.max_lon >= bounds.min_lon && line.min_lon <= bounds.max_lon
        }
    }

    private fun line_color(kind: LocalReferenceKind, alpha: Float): Int {
        val base_alpha = when (kind) {
            LocalReferenceKind.COUNTRY -> 232
            LocalReferenceKind.REGION -> 178
            LocalReferenceKind.PLACE -> 178
        }
        val color = when (kind) {
            LocalReferenceKind.COUNTRY -> 0xFFF4F1DF.toInt()
            LocalReferenceKind.REGION -> 0xFFE5E5DA.toInt()
            LocalReferenceKind.PLACE -> 0xFFE5E5DA.toInt()
        }
        return with_alpha(color, (base_alpha * alpha).roundToInt().coerceIn(0, 255))
    }

    private fun draw_line(
        canvas: Canvas,
        viewport: Viewport,
        line: LocalReferenceLine,
        halo_stroke_width: Float,
        halo_color: Int,
        stroke_width: Float,
        color: Int
    ): Boolean {
        val world_width = world_width(viewport.zoom)
        val repeats = repeat_range(viewport, world_width)
        var drew_any = false
        for (repeat in repeats.first..repeats.second) {
            path.reset()
            var has_path = false
            var last_x = 0f
            var last_path_x = 0f
            var last_path_y = 0f
            var point_index = 0
            while (point_index < line.points.size) {
                val lon = line.points[point_index]
                val lat = line.points[point_index + 1]
                val world = MapProjection.lat_lon_to_world(lat, lon, viewport.zoom)
                val x = (world.x + repeat * world_width - viewport.center_x + viewport.width / 2.0).toFloat()
                val y = (world.y - viewport.center_y + viewport.height / 2.0).toFloat()
                if (!has_path || abs(x - last_x) > viewport.width * ANTIMERIDIAN_SCREEN_BREAK_FACTOR) {
                    path.moveTo(x, y)
                    has_path = true
                    last_path_x = x
                    last_path_y = y
                } else {
                    val is_last_point = point_index >= line.points.size - 2
                    if (
                        is_last_point ||
                        abs(x - last_path_x) >= MIN_LINE_POINT_DISTANCE_PX ||
                        abs(y - last_path_y) >= MIN_LINE_POINT_DISTANCE_PX
                    ) {
                        path.lineTo(x, y)
                        last_path_x = x
                        last_path_y = y
                    }
                }
                last_x = x
                point_index += 2
            }
            if (has_path) {
                paint.strokeWidth = halo_stroke_width
                paint.color = halo_color
                canvas.drawPath(path, paint)
                paint.strokeWidth = stroke_width
                paint.color = color
                canvas.drawPath(path, paint)
                drew_any = true
            }
        }
        return drew_any
    }

    private fun draw_labels(
        canvas: Canvas,
        viewport: Viewport,
        labels: List<LocalReferenceLabel>,
        detail: LocalReferenceDetail
    ): Int {
        label_bounds.clear()
        var drawn = 0
        val max_labels = max_labels_for_zoom(viewport.zoom, detail)
        val visible_bounds = visible_geo_bounds(viewport, padding_degrees = 1.0)
        val world_width = world_width(viewport.zoom)
        val repeats = repeat_range(viewport, world_width)
        for (label in labels) {
            if (drawn >= max_labels) break
            if (viewport.zoom < label.min_zoom || viewport.zoom > label.max_zoom) continue
            if (!label_allowed_for_detail(label, viewport.zoom, detail)) continue
            if (!label_intersects_bounds(label, visible_bounds)) continue
            val alpha = label_alpha(viewport.zoom, label)
            if (alpha <= 0.01f) continue
            val world = MapProjection.lat_lon_to_world(label.lat, label.lon, viewport.zoom)
            for (repeat in repeats.first..repeats.second) {
                val x = (world.x + repeat * world_width - viewport.center_x + viewport.width / 2.0).toFloat()
                val y = (world.y - viewport.center_y + viewport.height / 2.0).toFloat()
                if (draw_label(canvas, viewport, label, x, y, alpha)) {
                    drawn++
                    break
                }
            }
        }
        return drawn
    }

    private fun label_allowed_for_detail(
        label: LocalReferenceLabel,
        zoom: Double,
        detail: LocalReferenceDetail
    ): Boolean {
        if (detail == LocalReferenceDetail.SETTLED) return true
        return when (label.kind) {
            LocalReferenceKind.COUNTRY -> true
            LocalReferenceKind.REGION -> zoom >= INTERACTION_REGION_LABEL_MIN_ZOOM
            LocalReferenceKind.PLACE -> label.capital || label.population >= INTERACTION_PLACE_POPULATION_MIN
        }
    }

    private fun max_labels_for_zoom(zoom: Double, detail: LocalReferenceDetail): Int {
        val settled = when {
            zoom < 4.5 -> 34
            zoom < 5.8 -> 56
            zoom < 6.8 -> 72
            zoom < 8.5 -> 88
            else -> 104
        }
        return if (detail == LocalReferenceDetail.SETTLED) {
            settled
        } else {
            (settled * INTERACTION_LABEL_DENSITY).roundToInt().coerceAtLeast(18)
        }
    }

    private fun label_intersects_bounds(label: LocalReferenceLabel, bounds: LocalGeoBounds): Boolean {
        if (label.lat < bounds.min_lat || label.lat > bounds.max_lat) return false
        return if (bounds.wraps) {
            label.lon >= bounds.min_lon || label.lon <= bounds.max_lon
        } else {
            label.lon >= bounds.min_lon && label.lon <= bounds.max_lon
        }
    }

    private fun label_alpha(zoom: Double, label: LocalReferenceLabel): Float {
        return minOf(
            zoom_fade_in(zoom, label.min_zoom, LABEL_FADE_ZOOM_SPAN),
            zoom_fade_out(zoom, label.max_zoom, LABEL_FADE_ZOOM_SPAN)
        )
    }

    private fun draw_label(
        canvas: Canvas,
        viewport: Viewport,
        label: LocalReferenceLabel,
        x: Float,
        y: Float,
        alpha: Float
    ): Boolean {
        val label_text = when (label.kind) {
            LocalReferenceKind.COUNTRY -> label.text.uppercase(Locale.US)
            else -> label.text
        }
        val size = label_text_size(label, viewport.zoom)
        text_paint.textSize = size
        text_paint.typeface = when (label.kind) {
            LocalReferenceKind.COUNTRY -> Typeface.DEFAULT_BOLD
            LocalReferenceKind.REGION -> Typeface.DEFAULT
            LocalReferenceKind.PLACE -> if (label.capital || label.population >= MAJOR_PLACE_POPULATION) Typeface.DEFAULT_BOLD else Typeface.DEFAULT
        }
        text_paint.textAlign = Paint.Align.CENTER
        text_paint.isFakeBoldText = false
        val text_width = text_paint.measureText(label_text)
        val text_y = if (label.kind == LocalReferenceKind.PLACE) y - dp(5f) else y
        val bounds = RectF(
            x - text_width / 2f - label_horizontal_padding(label),
            text_y - size - label_vertical_padding(label),
            x + text_width / 2f + label_horizontal_padding(label),
            text_y + dp(6f)
        )
        if (!RectF.intersects(bounds, RectF(0f, 0f, viewport.width, viewport.height))) return false
        if (label_bounds.any { RectF.intersects(it, bounds) }) return false
        if (label.kind == LocalReferenceKind.PLACE && viewport.zoom >= label.min_zoom + 0.2) {
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(0xFF07100D.toInt(), (190f * alpha).roundToInt().coerceIn(0, 255))
            canvas.drawCircle(x, y, dp(3.1f), paint)
            paint.color = with_alpha(0xFFFFF7DB.toInt(), (235f * alpha).roundToInt().coerceIn(0, 255))
            canvas.drawCircle(x, y, dp(1.65f), paint)
        }
        draw_outlined_text(canvas, label_text, x, text_y, label, alpha)
        label_bounds += bounds
        return true
    }

    private fun label_text_size(label: LocalReferenceLabel, zoom: Double): Float {
        return when (label.kind) {
            LocalReferenceKind.COUNTRY -> sp((14.2f + (7 - label.rank).coerceAtLeast(0) * 0.95f + ((zoom - 3.7).coerceIn(0.0, 2.4) * 1.2).toFloat()).coerceIn(14.2f, 23.0f))
            LocalReferenceKind.REGION -> sp((10.8f + (6 - label.rank).coerceAtLeast(0) * 0.6f + ((zoom - 4.3).coerceIn(0.0, 2.5) * 0.85).toFloat()).coerceIn(10.8f, 16.2f))
            LocalReferenceKind.PLACE -> {
                val pop_boost = when {
                    label.population >= 5_000_000 -> 3.3f
                    label.population >= 1_000_000 -> 2.4f
                    label.population >= 250_000 -> 1.35f
                    else -> 0.0f
                }
                sp((9.8f + pop_boost + ((zoom - label.min_zoom).coerceIn(0.0, 2.0) * 0.75).toFloat()).coerceIn(9.8f, 17.5f))
            }
        }
    }

    private fun label_horizontal_padding(label: LocalReferenceLabel): Float {
        return when (label.kind) {
            LocalReferenceKind.COUNTRY -> dp(9f)
            LocalReferenceKind.REGION -> dp(7f)
            LocalReferenceKind.PLACE -> dp(6f)
        }
    }

    private fun label_vertical_padding(label: LocalReferenceLabel): Float {
        return when (label.kind) {
            LocalReferenceKind.COUNTRY -> dp(7f)
            LocalReferenceKind.REGION -> dp(5f)
            LocalReferenceKind.PLACE -> dp(4f)
        }
    }

    private fun country_line_width(zoom: Double): Float {
        return dp((1.25f + ((zoom - 3.0).coerceIn(0.0, 4.0) * 0.16).toFloat()).coerceIn(1.25f, 1.9f))
    }

    private fun region_line_width(zoom: Double): Float {
        return dp((0.72f + ((zoom - 4.0).coerceIn(0.0, 4.0) * 0.08).toFloat()).coerceIn(0.72f, 1.05f))
    }

    private fun draw_outlined_text(
        canvas: Canvas,
        text: String,
        x: Float,
        y: Float,
        label: LocalReferenceLabel,
        alpha: Float
    ) {
        val fill_alpha = when (label.kind) {
            LocalReferenceKind.COUNTRY -> 238
            LocalReferenceKind.REGION -> 212
            LocalReferenceKind.PLACE -> 240
        }
        text_paint.style = Paint.Style.STROKE
        text_paint.strokeWidth = when (label.kind) {
            LocalReferenceKind.COUNTRY -> dp(4.0f)
            LocalReferenceKind.REGION -> dp(3.2f)
            LocalReferenceKind.PLACE -> dp(3.4f)
        }
        text_paint.color = with_alpha(0xFF07100D.toInt(), (225f * alpha).roundToInt().coerceIn(0, 255))
        canvas.drawText(text, x, y, text_paint)
        text_paint.style = Paint.Style.FILL
        val fill_color = when (label.kind) {
            LocalReferenceKind.COUNTRY -> 0xFFF7F2D8.toInt()
            LocalReferenceKind.REGION -> 0xFFE8E9DF.toInt()
            LocalReferenceKind.PLACE -> 0xFFFFF8E6.toInt()
        }
        text_paint.color = with_alpha(fill_color, (fill_alpha * alpha).roundToInt().coerceIn(0, 255))
        canvas.drawText(text, x, y, text_paint)
        text_paint.strokeWidth = 0f
        text_paint.typeface = Typeface.DEFAULT
    }

    private fun zoom_fade_in(zoom: Double, min_zoom: Double, span: Double): Float {
        return ((zoom - min_zoom) / span).coerceIn(0.0, 1.0).toFloat()
    }

    private fun zoom_fade_out(zoom: Double, max_zoom: Double, span: Double): Float {
        return ((max_zoom - zoom) / span).coerceIn(0.0, 1.0).toFloat()
    }

    private fun world_width(zoom: Double): Double = TILE_SIZE * 2.0.pow(zoom)

    private fun normalize_lon(lon: Double): Double {
        return ((lon + 180.0) % 360.0 + 360.0) % 360.0 - 180.0
    }

    private fun repeat_range(viewport: Viewport, world_width: Double): Pair<Int, Int> {
        val left_world = viewport.center_x - viewport.width / 2.0
        val right_world = viewport.center_x + viewport.width / 2.0
        return floor((left_world - world_width) / world_width).toInt() to
            ceil((right_world + world_width) / world_width).toInt()
    }

    private companion object {
        val ASSET_PATHS = arrayOf(
            "reference/reference_labels_v1.json",
            "reference/reference_labels_v1.json.gz"
        )
        const val TILE_SIZE = 256.0
        const val LINE_FADE_ZOOM_SPAN = 0.65
        const val LABEL_FADE_ZOOM_SPAN = 0.45
        const val ANTIMERIDIAN_SCREEN_BREAK_FACTOR = 1.25f
        const val MIN_LINE_POINT_DISTANCE_PX = 0.85f
        const val MAJOR_PLACE_POPULATION = 1_000_000
        const val INTERACTION_REGION_LINE_MIN_ZOOM = 6.0
        const val INTERACTION_REGION_LABEL_MIN_ZOOM = 5.7
        const val INTERACTION_PLACE_POPULATION_MIN = 1_000_000
        const val INTERACTION_LABEL_DENSITY = 0.55f
    }
}


// Public facade kept stable for FlightMapView; source-specific behavior lives in the street/satellite renderers.
class MapTileRenderer(
    context: Context,
    paint: Paint,
    text_paint: Paint,
    dp: (Float) -> Float,
    sp: (Float) -> Float,
    with_alpha: (Int, Int) -> Int,
    report_status: (String) -> Unit,
    request_redraw: () -> Unit
) {
    private val street_renderer = StreetMapTileRenderer(
        context = context,
        paint = paint,
        text_paint = text_paint,
        sp = sp,
        with_alpha = with_alpha,
        report_status = report_status,
        request_redraw = request_redraw
    )
    private val satellite_renderer = SatelliteMapTileRenderer(
        context = context,
        paint = paint,
        text_paint = text_paint,
        dp = dp,
        sp = sp,
        with_alpha = with_alpha,
        report_status = report_status,
        request_redraw = request_redraw
    )

    var debug_last_tile_summary: String = ""
        private set
    var debug_collect_detail_timing: Boolean
        get() = satellite_renderer.debug_collect_detail_timing
        set(value) {
            satellite_renderer.debug_collect_detail_timing = value
        }

    fun draw_tiles(
        canvas: Canvas,
        viewport: Viewport,
        state: MapTileRenderState,
        style: MapTileRenderStyle
    ): String {
        val status = when (state.map_source) {
            TileSource.STREET -> street_renderer.draw_tiles(canvas, viewport, state, style)
            TileSource.SATELLITE -> satellite_renderer.draw_tiles(canvas, viewport, state, style)
        }
        debug_last_tile_summary = when (state.map_source) {
            TileSource.STREET -> street_renderer.debug_last_tile_summary
            TileSource.SATELLITE -> satellite_renderer.debug_last_tile_summary
        }
        return status
    }

    fun clear() {
        street_renderer.clear()
        satellite_renderer.clear()
        debug_last_tile_summary = ""
    }

    fun reset_transitions() {
        street_renderer.reset_transitions()
        satellite_renderer.reset_transitions()
        debug_last_tile_summary = ""
    }

    fun shutdown() {
        street_renderer.shutdown()
        satellite_renderer.shutdown()
    }
}


data class MapTileRenderState(
    val map_source: TileSource,
    val map_labels_enabled: Boolean,
    val map_borders_enabled: Boolean,
    val user_agent: String,
    val interaction_active: Boolean = false
) {
    val cache_key: String = map_source.cache_key(map_labels_enabled)
    val reference_overlay_layers: List<ReferenceTileOverlay> =
        map_source.reference_overlay_layers(map_labels_enabled, map_borders_enabled)
}

data class MapTileRenderStyle(
    val map_empty: Int,
    val panel_alt: Int,
    val text: Int
)


private data class TileFallback(
    val bitmap: Bitmap,
    val source_rect: Rect
)

private data class ChildTileFallback(
    val bitmap: Bitmap,
    val child_x: Int,
    val child_y: Int,
    val child_scale: Int
)

private data class InterimRasterTile(
    val cache_key: String,
    val z: Int,
    val x: Int,
    val y: Int,
    val bitmap: Bitmap,
    var last_used_ms: Long
)

private data class TileLayerDrawStats(
    val visible: Int,
    val loaded: Int,
    val requested: Int,
    val fallback_drawn: Int,
    val fading: Boolean,
    val debug_summary: String = ""
)

private data class ReferenceTileCoverage(
    val visible: Int,
    val loaded: Int,
    val ready: Int,
    val fallback_ready: Int,
    val center_visible: Int = 0,
    val center_loaded: Int = 0,
    val center_ready: Int = 0,
    val center_fallback_ready: Int = 0
) {
    val loaded_ratio: Float
        get() = if (visible <= 0) 1f else loaded.toFloat() / visible.toFloat()
    val ready_ratio: Float
        get() = if (visible <= 0) 1f else ready.toFloat() / visible.toFloat()
    val visual_ready: Int
        get() = (ready + fallback_ready).coerceAtMost(visible)
    val visual_ratio: Float
        get() = if (visible <= 0) 1f else visual_ready.toFloat() / visible.toFloat()
    val center_loaded_ratio: Float
        get() = if (center_visible <= 0) 1f else center_loaded.toFloat() / center_visible.toFloat()
    val center_ready_ratio: Float
        get() = if (center_visible <= 0) 1f else center_ready.toFloat() / center_visible.toFloat()
    val center_visual_ready: Int
        get() = (center_ready + center_fallback_ready).coerceAtMost(center_visible)
    val center_visual_ratio: Float
        get() = if (center_visible <= 0) 1f else center_visual_ready.toFloat() / center_visible.toFloat()
}

private data class ReferenceOverlayDrawPlan(
    val draw_tile_zoom: Int,
    val prefetch_tile_zooms: List<Int>,
    val coverage: ReferenceTileCoverage
)

private data class ReferencePrefetchGridPlan(
    val epoch: Long,
    val overlay: ReferenceTileOverlay,
    val cache_key: String,
    val user_agent: String,
    val tile_zoom: Int,
    val first_tile_x: Int,
    val first_tile_y: Int,
    val last_tile_x: Int,
    val last_tile_y: Int,
    val max_tile: Int,
    val request_priority: Int,
    val request_stale_generation_tolerance: Long,
    val request_generation: Long
)

private data class ReferencePrefetchDrainStats(
    var batch_count: Long = 0L,
    var plan_count: Long = 0L,
    var tile_count: Long = 0L,
    var memory_hit_count: Long = 0L,
    var miss_count: Long = 0L,
    var submitted_count: Long = 0L,
    var queued_count: Long = 0L,
    var memory_recheck_count: Long = 0L,
    var stale_count: Long = 0L,
    var superseded_count: Long = 0L
)

