    private data class AircraftSymbolOverlayCacheKey(
        val marker_bucket: Int,
        val icon_scale_bucket: Int,
        val dot_scale_bucket: Int,
        val aircraft_signature: Int,
        val appearance_bucket: Int,
        val theme_key: Int
    ) {
        fun visual_key_matches(other: AircraftSymbolOverlayCacheKey): Boolean {
            return marker_bucket == other.marker_bucket &&
                icon_scale_bucket == other.icon_scale_bucket &&
                dot_scale_bucket == other.dot_scale_bucket &&
                appearance_bucket == other.appearance_bucket &&
                theme_key == other.theme_key
        }

        fun visual_key(): AircraftSymbolOverlayVisualKey {
            return AircraftSymbolOverlayVisualKey(
                marker_bucket = marker_bucket,
                icon_scale_bucket = icon_scale_bucket,
                dot_scale_bucket = dot_scale_bucket,
                appearance_bucket = appearance_bucket,
                theme_key = theme_key
            )
        }
    }

    private data class AircraftSymbolOverlayVisualKey(
        val marker_bucket: Int,
        val icon_scale_bucket: Int,
        val dot_scale_bucket: Int,
        val appearance_bucket: Int,
        val theme_key: Int
    )

    private data class DotOverlayCacheKey(
        val source_signature: Int,
        val transform_scale_bucket: Int,
        val dot_radius_bucket: Int,
        val outline_extra_bucket: Int,
        val alpha_bucket: Int,
        val theme_key: Int
    ) {
        fun visual_key_matches(other: DotOverlayCacheKey): Boolean {
            return transform_scale_bucket == other.transform_scale_bucket &&
                dot_radius_bucket == other.dot_radius_bucket &&
                outline_extra_bucket == other.outline_extra_bucket &&
                alpha_bucket == other.alpha_bucket &&
                theme_key == other.theme_key
        }
    }

    private object AircraftSymbolOverlayRecorder {
        fun record(
            aircraft: List<TrafficAircraftOverlayState>,
            selected_aircraft_key: String?,
            viewport: Viewport,
            visual_theme: VisualTheme,
            marker_blend: Float,
            padding: Float,
            width_px: Int,
            height_px: Int,
            center_x: Double,
            center_y: Double,
            key: AircraftSymbolOverlayCacheKey,
            request_reason: String,
            collect_motion_horizon_debug: Boolean,
            dp_scale: Float
        ): AircraftSymbolOverlayAsyncResult {
            val bitmap = createBitmap(width_px, height_px, Bitmap.Config.ARGB_8888)
            val canvas = Canvas(bitmap)
            val masks = HashMap<RecorderMaskKey, RecorderMask>()
            val sprites = HashMap<RecorderSpriteKey, RecorderSprite>()
            val tile_size = SYMBOL_OVERLAY_TILE_SIZE_PX
            val tile_cols = ceil(width_px / tile_size.toFloat()).toInt().coerceAtLeast(1)
            val tile_rows = ceil(height_px / tile_size.toFloat()).toInt().coerceAtLeast(1)
            val occupied_tiles = BooleanArray(tile_cols * tile_rows)
            val cached_aircraft_keys = HashSet<String>()
            var has_motion_exclusions = false
            var recorded_aircraft_count = 0
            var motion_excluded_count = 0
            var motion_excluded_short_horizon_count = 0
            var motion_excluded_tiny_horizon_count = 0
            var rotorcraft_excluded_count = 0
            var offscreen_count = 0
            var max_motion_error_squared = 0f
            val max_motion_error_squared_allowed =
                SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_MAX_ERROR_PX * SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_MAX_ERROR_PX
            val now_ms = SystemClock.elapsedRealtime()
            try {
                val colors = visual_theme.colors
                val paint = Paint(Paint.ANTI_ALIAS_FLAG)
                val stroke_paint = Paint(Paint.ANTI_ALIAS_FLAG)
                val mask_paint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
                    isFilterBitmap = true
                    isDither = true
                }
                val dp: (Float) -> Float = { value -> value * dp_scale }
                for (item in aircraft) {
                    val selected = item.appearance_key == selected_aircraft_key
                    val elapsed_sec = traffic_motion_elapsed_seconds(item, now_ms)
                    val x = item.screen_point.x + item.screen_velocity_x_px_per_sec * elapsed_sec + padding
                    val y = item.screen_point.y + item.screen_velocity_y_px_per_sec * elapsed_sec + padding
                    val cull_padding = aircraft_cull_padding(item, viewport.zoom, selected, dp)
                    if (!is_on_screen(x, y, viewport, cull_padding)) {
                        offscreen_count++
                        continue
                    }
                    if (item.symbol == AircraftSymbol.ROTORCRAFT) {
                        rotorcraft_excluded_count++
                        has_motion_exclusions = true
                        continue
                    }
                    val motion_error_squared = motion_cache_error_squared(item)
                    if (motion_error_squared > max_motion_error_squared_allowed) {
                        motion_excluded_count++
                        if (motion_error_squared > max_motion_error_squared) max_motion_error_squared = motion_error_squared
                        if (collect_motion_horizon_debug) {
                            if (motion_cache_error_squared(
                                    item,
                                    SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_DEBUG_SHORT_HORIZON_SEC
                                ) <= max_motion_error_squared_allowed
                            ) {
                                motion_excluded_short_horizon_count++
                            }
                            if (motion_cache_error_squared(
                                    item,
                                    SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_DEBUG_TINY_HORIZON_SEC
                                ) <= max_motion_error_squared_allowed
                            ) {
                                motion_excluded_tiny_horizon_count++
                            }
                        }
                        has_motion_exclusions = true
                        continue
                    }
                    draw_aircraft_icon(
                        canvas = canvas,
                        x = x,
                        y = y,
                        item = item,
                        selected = selected,
                        marker_blend = marker_blend,
                        viewport_zoom = viewport.zoom,
                        colors = colors,
                        paint = paint,
                        stroke_paint = stroke_paint,
                        mask_paint = mask_paint,
                        masks = masks,
                        sprites = sprites,
                        dp = dp,
                        now_ms = now_ms
                    )
                    recorded_aircraft_count++
                    mark_occupied_tiles(
                        occupied_tiles = occupied_tiles,
                        tile_cols = tile_cols,
                        tile_rows = tile_rows,
                        center_x = x,
                        center_y = y,
                        radius = cull_padding,
                        tile_size = tile_size
                    )
                    cached_aircraft_keys += item.appearance_key
                }
            } finally {
                sprites.values.forEach { it.recycle() }
                masks.values.forEach { it.recycle() }
            }
            return AircraftSymbolOverlayAsyncResult(
                bitmap = bitmap,
                key = key,
                width_px = width_px,
                height_px = height_px,
                center_x = center_x,
                center_y = center_y,
                occupied_tiles = build_occupied_tile_rects(occupied_tiles, tile_cols, tile_rows, width_px, height_px, tile_size),
                cached_aircraft_keys = cached_aircraft_keys,
                has_motion_exclusions = has_motion_exclusions,
                padding_px = padding,
                source_aircraft_count = aircraft.size,
                recorded_aircraft_count = recorded_aircraft_count,
                motion_excluded_count = motion_excluded_count,
                motion_excluded_short_horizon_count = motion_excluded_short_horizon_count,
                motion_excluded_tiny_horizon_count = motion_excluded_tiny_horizon_count,
                rotorcraft_excluded_count = rotorcraft_excluded_count,
                offscreen_count = offscreen_count,
                max_motion_error_px = sqrt(max_motion_error_squared.toDouble()).toFloat(),
                recorded_elapsed_ms = now_ms,
                request_reason = request_reason
            )
        }

        private fun motion_cache_error_squared(item: TrafficAircraftOverlayState): Float {
            return motion_cache_error_squared(item, SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_HORIZON_SEC)
        }

        private fun motion_cache_error_squared(item: TrafficAircraftOverlayState, horizon_sec: Float): Float {
            if (item.motion_limit_sec <= 0f ||
                (item.screen_velocity_x_px_per_sec == 0f && item.screen_velocity_y_px_per_sec == 0f)
            ) {
                return 0f
            }
            val projection_sec = min(item.motion_limit_sec, horizon_sec.coerceAtLeast(0f))
            val dx = item.screen_velocity_x_px_per_sec * projection_sec
            val dy = item.screen_velocity_y_px_per_sec * projection_sec
            return dx * dx + dy * dy
        }

        private fun mark_occupied_tiles(
            occupied_tiles: BooleanArray,
            tile_cols: Int,
            tile_rows: Int,
            center_x: Float,
            center_y: Float,
            radius: Float,
            tile_size: Int
        ) {
            val left = floor((center_x - radius) / tile_size).toInt().coerceIn(0, tile_cols - 1)
            val top = floor((center_y - radius) / tile_size).toInt().coerceIn(0, tile_rows - 1)
            val right = floor((center_x + radius) / tile_size).toInt().coerceIn(0, tile_cols - 1)
            val bottom = floor((center_y + radius) / tile_size).toInt().coerceIn(0, tile_rows - 1)
            for (row in top..bottom) {
                val row_offset = row * tile_cols
                for (col in left..right) {
                    occupied_tiles[row_offset + col] = true
                }
            }
        }

        private fun build_occupied_tile_rects(
            occupied_tiles: BooleanArray,
            tile_cols: Int,
            tile_rows: Int,
            width_px: Int,
            height_px: Int,
            tile_size: Int
        ): List<AircraftSymbolOverlayTile> {
            val rects = ArrayList<AircraftSymbolOverlayTile>()
            for (row in 0 until tile_rows) {
                var col = 0
                while (col < tile_cols) {
                    val row_offset = row * tile_cols
                    while (col < tile_cols && !occupied_tiles[row_offset + col]) col++
                    val start_col = col
                    while (col < tile_cols && occupied_tiles[row_offset + col]) col++
                    if (start_col < col) {
                        rects += AircraftSymbolOverlayTile(
                            left = start_col * tile_size,
                            top = row * tile_size,
                            right = min(col * tile_size, width_px),
                            bottom = min((row + 1) * tile_size, height_px)
                        )
                    }
                }
            }
            return rects
        }

        private fun draw_aircraft_icon(
            canvas: Canvas,
            x: Float,
            y: Float,
            item: TrafficAircraftOverlayState,
            selected: Boolean,
            marker_blend: Float,
            viewport_zoom: Double,
            colors: ThemeColors,
            paint: Paint,
            stroke_paint: Paint,
            mask_paint: Paint,
            masks: MutableMap<RecorderMaskKey, RecorderMask>,
            sprites: MutableMap<RecorderSpriteKey, RecorderSprite>,
            dp: (Float) -> Float,
            now_ms: Long
        ) {
            val blend = marker_blend.coerceIn(0f, 1f)
            val appear = current_aircraft_appearance_progress(item, now_ms)
            val shape_progress = AircraftMarkerMorph.shape_progress(blend)
            val symbol_visibility = AircraftMarkerMorph.symbol_visibility(blend)
            val enter_scale = 0.18f + 0.82f * appear
            val alpha = (appear * 255).toInt().coerceIn(0, 255)
            val symbol_alpha = (appear * symbol_visibility * 255).toInt().coerceIn(0, 255)
            val base_icon_scale = AircraftMarkerMorph.blended_icon_scale(viewport_zoom, blend)
            val icon_scale = base_icon_scale * item.symbol_scale * enter_scale
            if (alpha <= 4 || symbol_alpha <= 4) return
            paint.style = Paint.Style.FILL
            paint.color = with_alpha(colors.scrim, (74 * appear * symbol_visibility).toInt().coerceIn(0, 74))
            canvas.drawCircle(
                x + dp(2f + 1f * shape_progress) * icon_scale,
                y + dp(2.5f + 1.5f * shape_progress) * icon_scale,
                dp(5f + 11f * shape_progress) * icon_scale,
                paint
            )
            if (selected) {
                stroke_paint.style = Paint.Style.STROKE
                stroke_paint.color = Color.argb(
                    (235 * appear * symbol_visibility).toInt().coerceIn(0, 235),
                    Color.red(colors.accent_green),
                    Color.green(colors.accent_green),
                    Color.blue(colors.accent_green)
                )
                stroke_paint.strokeWidth = dp(2.6f)
                canvas.drawCircle(x, y, dp(11f + 13f * shape_progress) * icon_scale, stroke_paint)
            }
            draw_cached_aircraft_symbol(
                canvas = canvas,
                x = x,
                y = y,
                symbol = item.symbol,
                track_deg = item.aircraft.track_deg,
                icon_scale = icon_scale,
                mask_resolution_scale = aircraft_symbol_mask_resolution_scale(base_icon_scale),
                shape_progress = shape_progress,
                fill = with_alpha(item.color, symbol_alpha),
                stroke = with_alpha(colors.scrim, (235 * appear * symbol_visibility).toInt().coerceIn(0, 235)),
                mask_paint = mask_paint,
                masks = masks,
                sprites = sprites,
                dp = dp
            )
        }

        private fun draw_cached_aircraft_symbol(
            canvas: Canvas,
            x: Float,
            y: Float,
            symbol: AircraftSymbol,
            track_deg: Double?,
            icon_scale: Float,
            mask_resolution_scale: Float,
            shape_progress: Float,
            fill: Int,
            stroke: Int,
            mask_paint: Paint,
            masks: MutableMap<RecorderMaskKey, RecorderMask>,
            sprites: MutableMap<RecorderSpriteKey, RecorderSprite>,
            dp: (Float) -> Float
        ) {
            val sprite = aircraft_symbol_sprite(symbol, shape_progress, mask_resolution_scale, fill, stroke, mask_paint, masks, sprites, dp)
            canvas.withTranslation(x, y) {
                val draw_scale = icon_scale / mask_resolution_scale.coerceAtLeast(0.001f)
                scale(draw_scale, draw_scale)
                if (track_deg != null && symbol != AircraftSymbol.SURFACE) rotate(track_deg.toFloat())
                drawBitmap(sprite.bitmap, -sprite.bitmap.width / 2f, -sprite.bitmap.height / 2f, null)
            }
        }

        private fun aircraft_symbol_sprite(
            symbol: AircraftSymbol,
            shape_progress: Float,
            mask_resolution_scale: Float,
            fill: Int,
            stroke: Int,
            mask_paint: Paint,
            masks: MutableMap<RecorderMaskKey, RecorderMask>,
            sprites: MutableMap<RecorderSpriteKey, RecorderSprite>,
            dp: (Float) -> Float
        ): RecorderSprite {
            val progress_bucket = aircraft_symbol_progress_bucket(shape_progress)
            val size_px = dp(SYMBOL_MASK_SIZE_DP * mask_resolution_scale.coerceAtLeast(0.001f))
                .roundToInt()
                .coerceAtLeast(1)
            val key = RecorderSpriteKey(symbol, progress_bucket, size_px, fill, stroke)
            sprites[key]?.let { return it }
            val mask = aircraft_symbol_mask(symbol, progress_bucket, size_px, mask_resolution_scale, masks, dp)
            val bitmap = createBitmap(size_px, size_px, Bitmap.Config.ARGB_8888)
            val canvas = Canvas(bitmap)
            mask_paint.color = fill
            canvas.drawBitmap(mask.fill, 0f, 0f, mask_paint)
            mask_paint.color = stroke
            canvas.drawBitmap(mask.stroke, 0f, 0f, mask_paint)
            mask_paint.alpha = 255
            return RecorderSprite(bitmap).also { sprites[key] = it }
        }

        private fun aircraft_symbol_mask(
            symbol: AircraftSymbol,
            shape_progress: Float,
            masks: MutableMap<RecorderMaskKey, RecorderMask>,
            dp: (Float) -> Float
        ): RecorderMask {
            val progress_bucket = aircraft_symbol_progress_bucket(shape_progress)
            val size_px = dp(SYMBOL_MASK_SIZE_DP).roundToInt().coerceAtLeast(1)
            return aircraft_symbol_mask(symbol, progress_bucket, size_px, 1f, masks, dp)
        }

        private fun aircraft_symbol_mask(
            symbol: AircraftSymbol,
            progress_bucket: Int,
            size_px: Int,
            mask_resolution_scale: Float,
            masks: MutableMap<RecorderMaskKey, RecorderMask>,
            dp: (Float) -> Float
        ): RecorderMask {
            val key = RecorderMaskKey(symbol, progress_bucket, size_px)
            masks[key]?.let { return it }
            val progress = progress_bucket / SYMBOL_MASK_PROGRESS_STEPS.toFloat()
            val fill = createBitmap(size_px, size_px, Bitmap.Config.ALPHA_8)
            val stroke = createBitmap(size_px, size_px, Bitmap.Config.ALPHA_8)
            val center = size_px / 2f
            val mask_dp_scale = mask_resolution_scale.coerceAtLeast(0.001f)
            val mask_dp: (Float) -> Float = { value -> dp(value) * mask_dp_scale }
            val fill_paint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
                style = Paint.Style.FILL
                color = Color.WHITE
            }
            val transparent_fill_paint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
                style = Paint.Style.FILL
                color = Color.TRANSPARENT
            }
            val stroke_paint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
                style = Paint.Style.STROKE
                strokeWidth = mask_dp(1.2f)
                color = Color.WHITE
            }
            val transparent_stroke_paint = Paint(Paint.ANTI_ALIAS_FLAG).apply {
                style = Paint.Style.STROKE
                strokeWidth = mask_dp(1.2f)
                color = Color.TRANSPARENT
            }
            Canvas(fill).withTranslation(center, center) {
                AircraftSymbolRenderer.draw(this, symbol, progress, fill_paint, transparent_stroke_paint, mask_dp)
            }
            Canvas(stroke).withTranslation(center, center) {
                AircraftSymbolRenderer.draw(this, symbol, progress, transparent_fill_paint, stroke_paint, mask_dp)
            }
            return RecorderMask(fill, stroke).also { masks[key] = it }
        }

        private fun aircraft_symbol_progress_bucket(shape_progress: Float): Int {
            return (shape_progress.coerceIn(0f, 1f) * SYMBOL_MASK_PROGRESS_STEPS)
                .roundToInt()
                .coerceIn(0, SYMBOL_MASK_PROGRESS_STEPS)
        }


        private fun current_aircraft_appearance_progress(item: TrafficAircraftOverlayState, now_ms: Long): Float {
            if (item.appearance_first_seen_ms <= 0L) return item.appearance_progress.coerceIn(0f, 1f)
            val elapsed = now_ms - item.appearance_first_seen_ms - item.appearance_delay_ms
            return smooth_step(0f, AIRCRAFT_APPEAR_DURATION_MS.toFloat(), elapsed.toFloat())
        }

        private fun aircraft_cull_padding(
            item: TrafficAircraftOverlayState,
            zoom: Double,
            selected: Boolean,
            dp: (Float) -> Float
        ): Float {
            val shape_radius_dp = when (item.symbol) {
                AircraftSymbol.GLIDER -> 31f
                AircraftSymbol.AIRLINER -> 29f
                AircraftSymbol.ROTORCRAFT -> 23f
                AircraftSymbol.UAV -> 26f
                AircraftSymbol.SURFACE -> 22f
                AircraftSymbol.GENERAL_AVIATION -> 25f
            }
            val selected_ring_dp = if (selected) 17f else 0f
            val max_icon_scale = max(AircraftMarkerMorph.aircraft_dot_scale(zoom), AircraftMarkerMorph.aircraft_icon_scale(zoom))
            return dp((shape_radius_dp + selected_ring_dp) * item.symbol_scale * max_icon_scale + AIRCRAFT_CULL_EXTRA_DP)
        }

        private fun is_on_screen(x: Float, y: Float, viewport: Viewport, padding: Float): Boolean {
            return is_inside_viewport(x, y, viewport, padding)
        }

        
        
        private data class RecorderMaskKey(
            val symbol: AircraftSymbol,
            val progress_bucket: Int,
            val size_px: Int
        )

        private data class RecorderSpriteKey(
            val symbol: AircraftSymbol,
            val progress_bucket: Int,
            val size_px: Int,
            val fill: Int,
            val stroke: Int
        )

        private data class RecorderMask(
            val fill: Bitmap,
            val stroke: Bitmap
        ) {
            fun recycle() {
                recycle_bitmap_pair(fill, stroke)
            }
        }

        private data class RecorderSprite(
            val bitmap: Bitmap
        ) {
            fun recycle() {
                bitmap.recycle()
            }
        }
    }

    private companion object {
        const val LABEL_AIRCRAFT_COUNT = 4
        const val AIRCRAFT_CULL_EXTRA_DP = 24f
        const val AIRCRAFT_FAST_DOT_BLEND = 0.995f
        const val AIRCRAFT_BATCH_DOT_BLEND = 0.995f
        const val ROTORCRAFT_BLADE_CYCLE_MS = 288L
        const val ROTORCRAFT_ICON_SCALE_MULTIPLIER = 0.82f
        const val MAX_BATCH_MOTION_SECONDS = 10f * 60f
        const val AIRCRAFT_DOT_RADIUS_DP = 3.6f
        const val BATCH_DOT_RADIUS_DP = AIRCRAFT_DOT_RADIUS_DP
        const val BATCH_DOT_OUTLINE_EXTRA_DP = 1.25f
        const val BATCH_DOT_OUTLINE_MIN_SCALE = 0.22f
        const val SYMBOL_MASK_SIZE_DP = 72f
        const val SYMBOL_MASK_PROGRESS_STEPS = 96
        const val SYMBOL_MASK_CACHE_MAX_ENTRIES = 640
        const val DIRECT_ICON_DETAIL_SAMPLE_PERIOD = 16
        const val SYMBOL_MASK_DETAIL_SAMPLE_PERIOD = 5
        const val SYMBOL_OVERLAY_CACHE_PADDING_DP = 220f
        const val SYMBOL_OVERLAY_TILE_SIZE_PX = 256
        const val SYMBOL_OVERLAY_WIDE_COVERAGE_MAX_ZOOM = 6.0
        const val SYMBOL_OVERLAY_WIDE_COVERAGE_PADDING_DP = 420f
        const val SYMBOL_OVERLAY_DIRECT_FALLBACK_PADDING_DP = 96f
        const val SYMBOL_OVERLAY_SPARSE_RECORDING_MIN_CURRENT_AIRCRAFT = 256
        const val SYMBOL_OVERLAY_SPARSE_RECORDING_MAX_CURRENT_RATIO = 8
        const val SYMBOL_OVERLAY_SCALE_BUCKET = 1000f
        const val SYMBOL_OVERLAY_PAN_SCALE_EPSILON = 0.0025f
        const val SYMBOL_OVERLAY_INTERACTION_SCALE_MIN = 0.62f
        const val SYMBOL_OVERLAY_INTERACTION_SCALE_MAX = 1.62f
        const val SYMBOL_OVERLAY_INTERACTION_MARKER_BUCKET_TOLERANCE = 18
        const val SYMBOL_OVERLAY_INTERACTION_SCALE_BUCKET_TOLERANCE = 120
        const val SYMBOL_OVERLAY_CENTER_EPSILON = 0.5
        const val SYMBOL_OVERLAY_APPEARANCE_READY_BUCKET = 1
        const val SYMBOL_OVERLAY_READY_APPEARANCE_MIN = 0.82f
        const val SYMBOL_OVERLAY_READY_AVERAGE_MIN = 0.74f
        const val SYMBOL_OVERLAY_READY_AIRCRAFT_FRACTION = 0.72f
        const val SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_MAX_ERROR_PX = 0.42f
        const val SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_HORIZON_SEC = 1.25f
        const val SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_DEBUG_SHORT_HORIZON_SEC = 0.85f
        const val SYMBOL_OVERLAY_DYNAMIC_EXCLUSION_DEBUG_TINY_HORIZON_SEC = 0.65f
        const val SYMBOL_OVERLAY_EXTERNAL_CENTER_JUMP_VIEWPORTS = 1.5f
        const val SYMBOL_OVERLAY_EXTERNAL_ZOOM_JUMP = 0.35
        const val DOT_OVERLAY_CACHE_MIN_DOTS = 3200
        const val DOT_OVERLAY_CACHE_MAX_ZOOM = 6.2
        const val DOT_OVERLAY_CACHE_MIN_ALPHA = 0.999f
        const val DOT_OVERLAY_CACHE_PADDING_DP = 320f
        const val DOT_OVERLAY_MAX_DIMENSION = 4096
        const val DOT_OVERLAY_CACHE_MAX_PIXELS = 8_000_000f
        const val DOT_OVERLAY_SCALE_BUCKET = 1000f
        const val DOT_OVERLAY_ALPHA_BUCKET = 1000f
        const val DOT_OVERLAY_RECORDING_PHASE_CLEAR = -2
        const val DOT_OVERLAY_RECORDING_PHASE_OUTLINE = -1
        const val DOT_OVERLAY_RECORDING_PHASE_DONE = TrafficDotBatchOverlayState.GROUP_COUNT
        const val DOT_OVERLAY_RECORDING_CHUNK_FLOATS = 4096
        const val DOT_OVERLAY_RECORDING_CLEAR_ROWS = 128
        const val DOT_OVERLAY_RECORDING_BUDGET_NS = 1_600_000L
        const val MIN_WORLD_REPEAT = -4
        const val MAX_WORLD_REPEAT = 4
        const val DOT_BATCH_GROUP_COUNT = TrafficDotBatchOverlayState.GROUP_COUNT
        fun aircraft_symbol_mask_resolution_scale(base_icon_scale: Float): Float {
            val scale = base_icon_scale.coerceAtLeast(0f)
            return when {
                scale < 0.40f -> 0.375f
                scale < 0.50f -> 0.50f
                scale < 0.74f -> 0.75f
                else -> 1.00f
            }
        }
    }
}


internal data class RestrictedAirspaceStyle(
    val panel_color: Int,
    val modal_panel_alpha: Int,
    val text_color: Int,
    val muted_color: Int,
    val accent_orange_color: Int
)

internal class RestrictedAirspaceInspector(
    private val text_paint: Paint,
    private val dp: (Float) -> Float,
    private val sp: (Float) -> Float,
    private val ellipsize: (String, Float) -> String,
    private val draw_panel_surface: (Canvas, RectF, Int, Int) -> Unit,
    private val draw_choice_button: (Canvas, RectF, String, Boolean) -> Unit,
    private val draw_wrapped_text: (Canvas, String, Float, Float, Float, Int) -> Float,
    private val lat_lon_to_world: (Double, Double, Double) -> WorldPoint,
    private val world_to_lat_lon: (Double, Double, Double) -> GeoPoint
) {
    fun draw_details_panel(
        canvas: Canvas,
        w: Float,
        h: Float,
        feature: AviationAirspaceFeature,
        style: RestrictedAirspaceStyle
    ) {
        val panel = panel_bounds(w, h)
        draw_panel_surface(canvas, panel, style.panel_color, style.modal_panel_alpha)
        draw_choice_button(canvas, close_button_bounds(panel), "Close", false)

        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(22f)
        text_paint.color = style.text_color
        val title_max_width = panel.width() - dp(142f)
        canvas.drawText(ellipsize(feature.name, title_max_width), panel.left + dp(18f), panel.top + dp(34f), text_paint)

        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(11f)
        text_paint.color = style.accent_orange_color
        canvas.drawText("FAA SPECIAL USE AIRSPACE", panel.left + dp(18f), panel.top + dp(55f), text_paint)

        val vertical = listOf(
            feature.lower_limit ?: "Lower unavailable",
            feature.upper_limit ?: "Upper unavailable"
        ).joinToString(" to ")
        var row_y = panel.top + dp(88f)
        row_y = draw_detail_row(canvas, panel, row_y, "Type", feature.type.ifBlank { "Unavailable" }, style)
        row_y = draw_detail_row(canvas, panel, row_y, "Vertical", vertical, style)
        row_y = draw_detail_row(canvas, panel, row_y, "Schedule", feature.schedule ?: "Unavailable from FAA feature", style)
        row_y = draw_detail_row(canvas, panel, row_y, "Location", location_label(feature), style)
        draw_detail_row(canvas, panel, row_y, "Source", RESTRICTED_AIRSPACE_SOURCE_LABEL, style)
    }

    fun panel_bounds(w: Float, h: Float): RectF {
        val panel_width = min(w - dp(32f), dp(620f)).coerceAtLeast(dp(280f))
        val panel_height = min(h - dp(72f), dp(286f)).coerceAtLeast(dp(236f))
        val left = (w - panel_width) / 2f
        val top = (h - panel_height - dp(24f)).coerceAtLeast(dp(24f))
        return RectF(left, top, left + panel_width, top + panel_height)
    }

    fun close_button_bounds(panel: RectF): RectF {
        return RectF(panel.right - dp(118f), panel.top + dp(14f), panel.right - dp(18f), panel.top + dp(48f))
    }

    fun airspace_at(
        x: Float,
        y: Float,
        snapshot: AviationLayerSnapshot,
        viewport: Viewport,
        visible_bounds: AviationGeoBounds
    ): AviationAirspaceFeature? {
        val geo = screen_to_geo_point(x, y, viewport)
        val candidates = snapshot.restricted_airspaces
            .asSequence()
            .filter { it.bounds.intersects(visible_bounds) }
            .take(MAX_RESTRICTED_AIRSPACE_HIT_TEST_FEATURES)
            .toList()
        val inside = candidates
            .filter { point_inside_airspace(geo, it) }
            .minByOrNull { airspace_bounds_area(it.bounds) }
        if (inside != null) return inside

        val max_distance_sq = dp(RESTRICTED_AIRSPACE_HIT_RADIUS_DP).let { it * it }
        return candidates
            .mapNotNull { feature ->
                val distance_sq = distance_to_airspace_screen_sq(x, y, feature, viewport) ?: return@mapNotNull null
                if (distance_sq <= max_distance_sq) feature to distance_sq else null
            }
            .minByOrNull { it.second }
            ?.first
    }

    private fun draw_detail_row(
        canvas: Canvas,
        panel: RectF,
        y: Float,
        label: String,
        value: String,
        style: RestrictedAirspaceStyle
    ): Float {
        text_paint.textAlign = Paint.Align.LEFT
        text_paint.isFakeBoldText = true
        text_paint.textSize = sp(12f)
        text_paint.color = style.muted_color
        canvas.drawText(label.uppercase(Locale.US), panel.left + dp(18f), y, text_paint)

        text_paint.isFakeBoldText = false
        text_paint.textSize = sp(14f)
        text_paint.color = style.text_color
        val value_x = panel.left + dp(112f)
        val max_width = panel.right - value_x - dp(18f)
        val bottom = draw_wrapped_text(canvas, value, value_x, y, max_width, 2)
        return max(bottom + dp(9f), y + dp(30f))
    }

    private fun location_label(feature: AviationAirspaceFeature): String {
        return listOfNotNull(feature.city, feature.state)
            .joinToString(", ")
            .ifBlank { "Unavailable from FAA feature" }
    }

    private fun screen_to_geo_point(x: Float, y: Float, viewport: Viewport): GeoPoint {
        val world_x = viewport.center_x - viewport.width / 2.0 + x
        val world_y = viewport.center_y - viewport.height / 2.0 + y
        return world_to_lat_lon(world_x, world_y, viewport.zoom)
    }

    private fun point_inside_airspace(point: GeoPoint, feature: AviationAirspaceFeature): Boolean {
        var crossings = 0
        feature.rings.forEach { ring ->
            if (point_inside_ring(point, ring)) crossings++
        }
        return crossings % 2 == 1
    }

    private fun point_inside_ring(point: GeoPoint, ring: List<AviationLayerPoint>): Boolean {
        if (ring.size < 3) return false
        var inside = false
        var previous = ring.last()
        ring.forEach { current ->
            val crosses_lat = (current.lat > point.lat) != (previous.lat > point.lat)
            if (crosses_lat) {
                val lon_at_lat = (previous.lon - current.lon) *
                    (point.lat - current.lat) /
                    (previous.lat - current.lat) +
                    current.lon
                if (point.lon < lon_at_lat) inside = !inside
            }
            previous = current
        }
        return inside
    }

    private fun distance_to_airspace_screen_sq(
        x: Float,
        y: Float,
        feature: AviationAirspaceFeature,
        viewport: Viewport
    ): Float? {
        var best: Float? = null
        feature.rings.take(MAX_RESTRICTED_AIRSPACE_HIT_RINGS).forEach { ring ->
            val points = airspace_ring_screen_points(ring, viewport)
            if (points.size < 2) return@forEach
            var previous = points.first()
            points.drop(1).forEach { current ->
                val distance = point_to_segment_distance_sq(x, y, previous, current)
                best = min(best ?: distance, distance)
                previous = current
            }
        }
        return best
    }

    private fun airspace_ring_screen_points(ring: List<AviationLayerPoint>, viewport: Viewport): List<ScreenPoint> {
        if (ring.isEmpty()) return emptyList()
        val step = max(1, ring.size / MAX_RESTRICTED_AIRSPACE_HIT_POINTS_PER_RING)
        val result = ArrayList<ScreenPoint>(min(ring.size, MAX_RESTRICTED_AIRSPACE_HIT_POINTS_PER_RING + 1))
        ring.forEachIndexed { index, point ->
            if (index % step == 0 || index == ring.lastIndex) {
                project_aviation_point_to_screen(point, viewport, lat_lon_to_world)?.let(result::add)
            }
        }
        return result
    }

    private fun point_to_segment_distance_sq(x: Float, y: Float, start: ScreenPoint, end: ScreenPoint): Float {
        val dx = end.x - start.x
        val dy = end.y - start.y
        val length_sq = dx * dx + dy * dy
        if (length_sq <= 0.0001f) {
            val px = x - start.x
            val py = y - start.y
            return px * px + py * py
        }
        val t = (((x - start.x) * dx + (y - start.y) * dy) / length_sq).coerceIn(0f, 1f)
        val closest_x = start.x + dx * t
        val closest_y = start.y + dy * t
        val px = x - closest_x
        val py = y - closest_y
        return px * px + py * py
    }

    private fun airspace_bounds_area(bounds: AviationGeoBounds): Double {
        return (bounds.max_lat - bounds.min_lat).coerceAtLeast(0.0) *
            (bounds.max_lon - bounds.min_lon).coerceAtLeast(0.0)
    }

    private companion object {
        const val TILE_SIZE = 256
        const val RESTRICTED_AIRSPACE_HIT_RADIUS_DP = 18f
        const val MAX_RESTRICTED_AIRSPACE_HIT_TEST_FEATURES = 180
        const val MAX_RESTRICTED_AIRSPACE_HIT_RINGS = 8
        const val MAX_RESTRICTED_AIRSPACE_HIT_POINTS_PER_RING = 160
        const val RESTRICTED_AIRSPACE_SOURCE_LABEL = "FAA AIS Special Use Airspace"
    }
}

// endregion

// region ROUTE REASONING

data class AircraftRouteTraceContext(
    val aircraft_id: String,
    val selected_trace_aircraft_id: String?,
    val trace: FlightTrace?,
    val segments: List<TraceSegment>?,
    val loading: Boolean
) {
    val matches_selected_trace: Boolean = selected_trace_aircraft_id == aircraft_id.lowercase(Locale.US)
}

object AircraftRoutePresenter {
    fun value(value: String?, loading: Boolean): String {
        return value ?: loading_or_unavailable(loading)
    }

    fun details_value(value: String?, loading: Boolean): String {
        return value ?: loading_or_unavailable(loading)
    }

    fun aircraft_type(details: AircraftDetails?, aircraft: Aircraft, loading: Boolean = false): String {
        return listOfNotNull(details?.manufacturer, details?.type, details?.type_code ?: aircraft.type_code)
            .distinct()
            .joinToString(" ")
            .ifEmpty { loading_or_unavailable(loading) }
    }

    fun airport(airport: AirportDetails?, loading: Boolean = false): String {
        return if (airport == null) {
            loading_or_unavailable(loading)
        } else {
            listOfNotNull(airport.name, airport.icao, airport.iata).joinToString(" / ")
        }
    }

    fun observed_path_span(context: AircraftRouteTraceContext): String {
        if (!context.matches_selected_trace) return loading_or_unavailable(context.loading)
        val points = context.segments?.flatMap { it.points }?.takeIf { it.size >= 2 } ?: return loading_or_unavailable(context.loading)
        val start = points.minOf { it.epoch_sec }
        val end = points.maxOf { it.epoch_sec }
        val minutes = ((end - start) / 60.0).coerceAtLeast(0.0)
        return String.format(Locale.US, "%.0f min", minutes)
    }

    fun trace_source(context: AircraftRouteTraceContext): String {
        val trace = context.trace?.takeIf { context.matches_selected_trace } ?: return loading_or_unavailable(context.loading)
        val history = trace.previous_segments.size.takeIf { it > 0 }?.let { count ->
            ", $count prior ${if (count == 1) "flight" else "flights"}"
        }.orEmpty()
        return "${trace.source}, ${trace.point_count} pts$history"
    }

    fun observed_flight_time(context: AircraftRouteTraceContext): String {
        if (!context.matches_selected_trace) return loading_or_unavailable(context.loading)
        val points = context.segments?.flatMap { it.points }?.takeIf { it.size >= 2 } ?: return loading_or_unavailable(context.loading)
        val start = points.minOf { it.epoch_sec }
        val latest = max(points.maxOf { it.epoch_sec }.toDouble(), System.currentTimeMillis() / 1000.0)
        return String.format(Locale.US, "Observed %.0f min", ((latest - start) / 60.0).coerceAtLeast(0.0))
    }

    fun route_completion(
        details: AircraftDetails?,
        aircraft: Aircraft,
        context: AircraftRouteTraceContext,
        details_loading: Boolean
    ): String {
        if (details == null && details_loading) return "Loading"
        if (context.loading) return "Loading"
        val origin = details?.origin_airport
        val destination = details?.destination_airport
        val origin_lat = origin?.latitude ?: return "Unavailable"
        val origin_lon = origin.longitude ?: return "Unavailable"
        val dest_lat = destination?.latitude ?: return "Unavailable"
        val dest_lon = destination.longitude ?: return "Unavailable"
        val total = MapProjection.distance_meters(origin_lat, origin_lon, dest_lat, dest_lon)
        if (total < 1000.0) return "Unavailable"
        trace_based_route_completion(context, origin_lat, origin_lon, dest_lat, dest_lon, total)?.let {
            return String.format(Locale.US, "~%.0f%% observed track", it)
        }
        val completed = (MapProjection.distance_meters(origin_lat, origin_lon, aircraft.lat, aircraft.lon) / total * 100.0)
            .coerceIn(0.0, 100.0)
        return String.format(Locale.US, "~%.0f%% direct estimate", completed)
    }

    fun trace_distance_meters(segments: List<TraceSegment>): Double {
        var distance = 0.0
        for (segment in segments) {
            val points = segment.points
            for (index in 1 until points.size) {
                val previous = points[index - 1]
                val current = points[index]
                distance += MapProjection.distance_meters(previous.lat, previous.lon, current.lat, current.lon)
            }
        }
        return distance
    }

    private fun trace_based_route_completion(
        context: AircraftRouteTraceContext,
        origin_lat: Double,
        origin_lon: Double,
        dest_lat: Double,
        dest_lon: Double,
        direct_route_meters: Double
    ): Double? {
        if (!context.matches_selected_trace) return null
        val segments = context.segments ?: return null
        if (segments.sumOf { it.points.size } < 2) return null
        val observed_meters = trace_distance_meters(segments)
        if (observed_meters < 1000.0) return null
        val first = segments.firstOrNull()?.points?.firstOrNull() ?: return null
        val first_from_origin_meters = MapProjection.distance_meters(origin_lat, origin_lon, first.lat, first.lon)
        val credited_departure_meters = first_from_origin_meters.takeIf {
            it <= max(25000.0, direct_route_meters * 0.12)
        } ?: 0.0
        val last = segments.lastOrNull()?.points?.lastOrNull() ?: return null
        val remaining_meters = MapProjection.distance_meters(last.lat, last.lon, dest_lat, dest_lon)
        val total_estimated_meters = credited_departure_meters + observed_meters + remaining_meters
        if (total_estimated_meters < 1000.0) return null
        return ((credited_departure_meters + observed_meters) / total_estimated_meters * 100.0).coerceIn(0.0, 100.0)
    }

    private fun loading_or_unavailable(loading: Boolean): String {
        return if (loading) "Loading" else "Unavailable"
    }
}


object CurrentRouteValidator {
    fun has_route_metadata(details: AircraftDetails): Boolean {
        return details.route != null || details.origin_airport != null || details.destination_airport != null
    }

    fun evaluate(
        details: AircraftDetails,
        aircraft_icao24: String,
        aircraft_callsign: String,
        selected_trace_aircraft_id: String?,
        trace_segments: List<TraceSegment>?
    ): CurrentRouteValidation {
        val id = aircraft_icao24.lowercase(Locale.US)
        if (selected_trace_aircraft_id != id) {
            return rejected("trace_not_ready selected_trace=${selected_trace_aircraft_id ?: "none"}", details, aircraft_icao24, aircraft_callsign)
        }
        val origin = details.origin_airport ?: return rejected("missing_origin", details, aircraft_icao24, aircraft_callsign)
        val origin_lat = origin.latitude ?: return rejected("missing_origin_lat", details, aircraft_icao24, aircraft_callsign)
        val origin_lon = origin.longitude ?: return rejected("missing_origin_lon", details, aircraft_icao24, aircraft_callsign)
        val points = trace_segments
            ?.flatMap { it.points }
            ?.sortedBy { it.epoch_sec }
            ?.takeIf { it.size >= 2 }
            ?: return rejected("no_trace_points", details, aircraft_icao24, aircraft_callsign)
        val first = points.firstOrNull() ?: return rejected("empty_trace", details, aircraft_icao24, aircraft_callsign)
        val destination = details.destination_airport
        val dest_lat = destination?.latitude
        val dest_lon = destination?.longitude
        val direct_route_meters = if (dest_lat != null && dest_lon != null) {
            distance_meters(origin_lat, origin_lon, dest_lat, dest_lon)
        } else {
            null
        }
        val origin_tolerance = direct_route_meters?.let { current_route_endpoint_tolerance(it) }
            ?: FlightAlertSettings.CurrentRoute.ORIGIN_MATCH_M
        val first_distance_meters = distance_meters(origin_lat, origin_lon, first.lat, first.lon)

        // ADSBdb callsign routes can be current even when the public trace starts mid-flight.
        if (first_distance_meters > origin_tolerance) {
            if (
                details.is_trusted_current_callsign_route() &&
                dest_lat != null &&
                dest_lon != null &&
                direct_route_meters != null &&
                trace_matches_partial_current_route(points, origin_lat, origin_lon, dest_lat, dest_lon, direct_route_meters)
            ) {
                return accepted(
                    "partial_trace distance_m=${first_distance_meters.toInt()} tolerance_m=${origin_tolerance.toInt()}",
                    details,
                    aircraft_icao24,
                    aircraft_callsign
                )
            }
            return rejected(
                "origin_mismatch distance_m=${first_distance_meters.toInt()} tolerance_m=${origin_tolerance.toInt()}",
                details,
                aircraft_icao24,
                aircraft_callsign
            )
        }
        if (
            dest_lat != null &&
            dest_lon != null &&
            !trace_direction_matches_route(points, origin_lat, origin_lon, dest_lat, dest_lon)
        ) {
            return rejected("direction_mismatch", details, aircraft_icao24, aircraft_callsign)
        }
        return accepted("current_flight", details, aircraft_icao24, aircraft_callsign)
    }

    private fun AircraftDetails.is_trusted_current_callsign_route(): Boolean {
        return route_source == AircraftRouteSource.ADSBDB_CALLSIGN
    }

    private fun trace_matches_partial_current_route(
        points: List<TrackPoint>,
        origin_lat: Double,
        origin_lon: Double,
        dest_lat: Double,
        dest_lon: Double,
        direct_route_meters: Double
    ): Boolean {
        val first = points.firstOrNull() ?: return false
        val last = points.lastOrNull() ?: return false
        val first_to_destination = distance_meters(first.lat, first.lon, dest_lat, dest_lon)
        val last_to_destination = distance_meters(last.lat, last.lon, dest_lat, dest_lon)
        val first_from_origin = distance_meters(origin_lat, origin_lon, first.lat, first.lon)
        val last_from_origin = distance_meters(origin_lat, origin_lon, last.lat, last.lon)
        val endpoint_tolerance = current_route_endpoint_tolerance(direct_route_meters)
        val progress_tolerance = current_route_progress_tolerance(direct_route_meters)
        val near_destination = min(first_to_destination, last_to_destination) <= endpoint_tolerance &&
            last_to_destination <= first_to_destination + progress_tolerance
        if (near_destination) return true

        val on_route_corridor = point_near_current_route_corridor(
            first,
            origin_lat,
            origin_lon,
            dest_lat,
            dest_lon,
            direct_route_meters
        ) || point_near_current_route_corridor(
            last,
            origin_lat,
            origin_lon,
            dest_lat,
            dest_lon,
            direct_route_meters
        )
        if (!on_route_corridor) return false
        val not_moving_away_from_route = last_to_destination <= first_to_destination + progress_tolerance ||
            last_from_origin >= first_from_origin - progress_tolerance
        return not_moving_away_from_route &&
            trace_direction_matches_route(points, origin_lat, origin_lon, dest_lat, dest_lon)
    }

    private fun point_near_current_route_corridor(
        point: TrackPoint,
        origin_lat: Double,
        origin_lon: Double,
        dest_lat: Double,
        dest_lon: Double,
        direct_route_meters: Double
    ): Boolean {
        val from_origin = distance_meters(origin_lat, origin_lon, point.lat, point.lon)
        val to_destination = distance_meters(point.lat, point.lon, dest_lat, dest_lon)
        val corridor_tolerance = max(
            FlightAlertSettings.CurrentRoute.CORRIDOR_MATCH_M,
            direct_route_meters * FlightAlertSettings.CurrentRoute.CORRIDOR_ROUTE_FRACTION
        ).coerceAtMost(FlightAlertSettings.CurrentRoute.CORRIDOR_MATCH_MAX_M)
        return from_origin <= direct_route_meters + corridor_tolerance &&
            to_destination <= direct_route_meters + corridor_tolerance &&
            from_origin + to_destination <= direct_route_meters + corridor_tolerance
    }

    private fun current_route_endpoint_tolerance(direct_route_meters: Double): Double {
        return max(
            FlightAlertSettings.CurrentRoute.ORIGIN_MATCH_M,
            direct_route_meters * FlightAlertSettings.CurrentRoute.ORIGIN_ROUTE_FRACTION
        ).coerceAtMost(FlightAlertSettings.CurrentRoute.ORIGIN_MATCH_MAX_M)
    }

    private fun current_route_progress_tolerance(direct_route_meters: Double): Double {
        return max(
            FlightAlertSettings.CurrentRoute.PROGRESS_MATCH_M,
            direct_route_meters * FlightAlertSettings.CurrentRoute.PROGRESS_ROUTE_FRACTION
        ).coerceAtMost(FlightAlertSettings.CurrentRoute.PROGRESS_MATCH_MAX_M)
    }

    private fun trace_direction_matches_route(
        points: List<TrackPoint>,
        origin_lat: Double,
        origin_lon: Double,
        dest_lat: Double,
        dest_lon: Double
    ): Boolean {
        val direct_route_meters = distance_meters(origin_lat, origin_lon, dest_lat, dest_lon)
        if (direct_route_meters < FlightAlertSettings.CurrentRoute.MIN_DIRECTION_M) return true
        val first = points.firstOrNull() ?: return false
        val last = points.lastOrNull() ?: return false
        val observed_meters = distance_meters(first.lat, first.lon, last.lat, last.lon)
        if (observed_meters < FlightAlertSettings.CurrentRoute.MIN_DIRECTION_M) return true
        val route_bearing = initial_bearing_degrees(origin_lat, origin_lon, dest_lat, dest_lon)
        val observed_bearing = initial_bearing_degrees(first.lat, first.lon, last.lat, last.lon)
        return angular_delta_degrees(route_bearing, observed_bearing) <= FlightAlertSettings.CurrentRoute.MAX_BEARING_DELTA_DEG
    }

    private fun accepted(reason: String, details: AircraftDetails, aircraft_icao24: String, aircraft_callsign: String): CurrentRouteValidation {
        return CurrentRouteValidation(true, diagnostic("accepted $reason", details, aircraft_icao24, aircraft_callsign))
    }

    private fun rejected(reason: String, details: AircraftDetails, aircraft_icao24: String, aircraft_callsign: String): CurrentRouteValidation {
        return CurrentRouteValidation(false, diagnostic("rejected $reason", details, aircraft_icao24, aircraft_callsign))
    }

    private fun diagnostic(result: String, details: AircraftDetails, aircraft_icao24: String, aircraft_callsign: String): String {
        return "Current route $result icao=$aircraft_icao24 callsign=${aircraft_callsign.ifBlank { "none" }} " +
            "route=${details.route ?: "none"} origin=${details.origin_airport?.icao ?: "none"} " +
            "destination=${details.destination_airport?.icao ?: "none"} source=${details.route_source ?: "none"}"
    }

    private fun distance_meters(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double =
        spherical_distance_meters(lat1, lon1, lat2, lon2)

    private fun initial_bearing_degrees(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double {
        val from_lat = Math.toRadians(lat1)
        val to_lat = Math.toRadians(lat2)
        val delta_lon = Math.toRadians(lon2 - lon1)
        val y = sin(delta_lon) * cos(to_lat)
        val x = cos(from_lat) * sin(to_lat) - sin(from_lat) * cos(to_lat) * cos(delta_lon)
        return (Math.toDegrees(atan2(y, x)) + 360.0) % 360.0
    }

    private fun angular_delta_degrees(first: Double, second: Double): Double {
        return abs((first - second + 540.0) % 360.0 - 180.0)
    }

}

data class CurrentRouteValidation(
    val accepted: Boolean,
    val diagnostic: String
)


// Owns selected aircraft trace state so FlightMapView can ask what to draw without editing trace internals.
class SelectedFlightPathController(
    private val now_epoch_seconds: () -> Double,
    private val max_projection_seconds: Double,
    private val path_trace_newer_than_feed_seconds: Long,
    private val max_trail_report_age_seconds: Double
) {
    var selected_aircraft_id: String? = null
        private set

    var selected_aircraft_snapshot: Aircraft? = null
        private set

    var selected_trace_aircraft_id: String? = null
        private set

    var trace: FlightTrace? = null
        private set

    var path_visible: Boolean = false
        private set

    var previous_flights_visible: Boolean = false
        private set

    val selected_aircraft_key: String?
        get() = selected_aircraft_id?.lowercase(Locale.US)

    fun trace_request_key(icao24: String): String? {
        return icao24.trim().lowercase(Locale.US).takeIf { it.isNotEmpty() }
    }

    fun is_selected_key(key: String): Boolean {
        return selected_aircraft_key == key.lowercase(Locale.US)
    }

    // Selection clears visible path state first; a path returns only after a matching real trace is fetched.
    fun select_aircraft(aircraft: Aircraft) {
        selected_aircraft_id = aircraft.icao24
        selected_aircraft_snapshot = aircraft
        clear_trace()
    }

    fun clear_selection() {
        selected_aircraft_id = null
        selected_aircraft_snapshot = null
        clear_trace()
    }

    fun update_selected_aircraft(aircraft: Aircraft) {
        if (selected_aircraft_key == aircraft.icao24.lowercase(Locale.US)) {
            selected_aircraft_snapshot = aircraft
        }
    }

    fun selected_snapshot_for_key(key: String): Aircraft? {
        return selected_aircraft_snapshot?.takeIf { it.icao24.equals(key, ignoreCase = true) }
    }

    // Accept trace responses only for the current key so old aircraft paths cannot appear.
    fun apply_trace_result(key: String, next_trace: FlightTrace?) {
        if (!is_selected_key(key)) return
        selected_trace_aircraft_id = if (next_trace != null) key.lowercase(Locale.US) else null
        trace = next_trace
        path_visible = false
        previous_flights_visible = false
    }

    fun clear_trace_for_key(key: String) {
        if (!is_selected_key(key)) return
        clear_trace()
    }

    fun clear_trace() {
        selected_trace_aircraft_id = null
        trace = null
        path_visible = false
        previous_flights_visible = false
    }

    fun close_visible_path(): Boolean {
        if (!path_visible) return false
        path_visible = false
        previous_flights_visible = false
        return true
    }

    // Show the path only when the selected aircraft has real current trace segments.
    fun show_path(current_aircraft: Aircraft?): Boolean {
        if (!has_path()) return false
        current_aircraft?.let { selected_aircraft_snapshot = it }
        path_visible = true
        return true
    }

    fun toggle_previous_flights(): Boolean {
        if (!should_show_previous_flights_button()) return false
        previous_flights_visible = !previous_flights_visible
        return previous_flights_visible
    }

    fun has_path(): Boolean {
        val id = selected_aircraft_key ?: return false
        val current_trace = trace ?: return false
        return selected_trace_aircraft_id == id && current_trace.segments.isNotEmpty()
    }

    fun has_previous_flights(): Boolean {
        val id = selected_aircraft_key ?: return false
        val current_trace = trace ?: return false
        return selected_trace_aircraft_id == id && current_trace.previous_segments.isNotEmpty()
    }

    fun should_show_clear_path_button(): Boolean {
        return path_visible && has_path()
    }

    fun should_show_previous_flights_button(): Boolean {
        return path_visible && has_previous_flights()
    }

    // Current-flight segments are the default path; previous legs are a separate opt-in context.
    fun selected_segments(visible_only: Boolean): List<TraceSegment>? {
        if (visible_only && !path_visible) return null
        if (!has_path()) return null
        return trace?.segments?.takeIf { it.isNotEmpty() }
    }

    fun previous_segments(visible_only: Boolean): List<TraceSegment>? {
        if (visible_only && (!path_visible || !previous_flights_visible)) return null
        if (!has_previous_flights()) return null
        return trace?.previous_segments?.takeIf { it.isNotEmpty() }
    }

    // Fit uses only real trace points and the projected endpoint already approved by this controller.
    fun bounds(): Bounds? {
        val points = selected_path_points()?.toMutableList() ?: return null
        if (previous_flights_visible) previous_flight_points()?.let { points += it }
        projected_endpoint()?.let { points += it }
        if (points.size < 2) return null
        return Bounds(
            min_lat = points.minOf { it.lat },
            min_lon = points.minOf { it.lon },
            max_lat = points.maxOf { it.lat },
            max_lon = points.maxOf { it.lon }
        )
    }

    // When a path is visible, pin the selected sprite to the trace/live endpoint chosen for that aircraft.
    fun display_position(aircraft: Aircraft): GeoPoint {
        return selected_path_display_endpoint(aircraft) ?: projected_aircraft_position(aircraft)
    }

    fun projected_endpoint(): GeoPoint? {
        val aircraft = selected_aircraft_snapshot?.takeIf {
            selected_aircraft_key == it.icao24.lowercase(Locale.US)
        } ?: return null
        if (!path_visible || !has_path()) return null
        val report_sec = aircraft.position_time_sec ?: aircraft.last_contact_sec ?: return null
        val age_seconds = now_epoch_seconds() - report_sec
        if (age_seconds > max_trail_report_age_seconds) return null
        return selected_path_display_endpoint(aircraft) ?: projected_aircraft_position(aircraft)
    }

    private fun selected_path_points(): List<GeoPoint>? {
        return selected_segments(visible_only = false)
            ?.flatMap { segment -> segment.points.map { GeoPoint(it.lat, it.lon) } }
            ?.takeIf { it.size >= 2 }
    }

    private fun previous_flight_points(): List<GeoPoint>? {
        return previous_segments(visible_only = false)
            ?.flatMap { segment -> segment.points.map { GeoPoint(it.lat, it.lon) } }
            ?.takeIf { it.size >= 2 }
    }

    private fun selected_path_display_endpoint(aircraft: Aircraft): GeoPoint? {
        if (!path_visible || selected_aircraft_key != aircraft.icao24.lowercase(Locale.US) || !has_path()) return null
        val last = selected_segment_points()?.maxByOrNull { it.epoch_sec } ?: return null
        val report_sec = (aircraft.position_time_sec ?: aircraft.last_contact_sec)?.toLong()
        if (report_sec == null || last.epoch_sec > report_sec + path_trace_newer_than_feed_seconds) {
            return GeoPoint(last.lat, last.lon)
        }
        return projected_aircraft_position(aircraft)
    }

    private fun selected_segment_points(): List<TrackPoint>? {
        return selected_segments(visible_only = false)
            ?.flatMap { it.points }
            ?.takeIf { it.size >= 2 }
    }

    private fun projected_aircraft_position(aircraft: Aircraft): GeoPoint {
        return AircraftPositionProjector.projected_display_position(
            aircraft = aircraft,
            now_epoch_sec = now_epoch_seconds(),
            max_projection_seconds = max_projection_seconds
        ).point
    }
}


data class FlightPathCameraUpdate(val zoom: Double, val center: GeoPoint)

// Frames selected real trace data inside the part of the map not blocked by panels.
internal class SelectedFlightPathViewportController(
    private val selected_path_controller: SelectedFlightPathController
) {
    fun fit_camera(width: Float, height: Float, usable: RectF): FlightPathCameraUpdate? {
        val bounds = selected_path_controller.bounds() ?: return null
        if (usable.width() <= 0f || usable.height() <= 0f) return null

        val top_left = MapProjection.lat_lon_to_world(bounds.max_lat, bounds.min_lon, 0.0)
        val bottom_right = MapProjection.lat_lon_to_world(bounds.min_lat, bounds.max_lon, 0.0)
        val path_width_at_zoom_zero = max(1.0, abs(bottom_right.x - top_left.x))
        val path_height_at_zoom_zero = max(1.0, abs(bottom_right.y - top_left.y))
        val width_fit = usable.width() / (path_width_at_zoom_zero * PATH_FIT_CONTEXT_MULTIPLIER)
        val height_fit = usable.height() / (path_height_at_zoom_zero * PATH_FIT_CONTEXT_MULTIPLIER)
        val zoom = (ln(min(width_fit, height_fit)) / ln(2.0)).coerceIn(MIN_ZOOM.toDouble(), MAX_ZOOM.toDouble())

        val center_lat = (bounds.min_lat + bounds.max_lat) / 2.0
        val center_lon = MapProjection.normalize_longitude((bounds.min_lon + bounds.max_lon) / 2.0)
        val center_world = MapProjection.lat_lon_to_world(center_lat, center_lon, zoom)
        val center = MapProjection.world_to_lat_lon(
            center_world.x + width / 2.0 - usable.centerX(),
            center_world.y + height / 2.0 - usable.centerY(),
            zoom
        )
        return FlightPathCameraUpdate(zoom = zoom, center = center)
    }

    fun should_show_path_button(viewport: Viewport, usable: RectF): Boolean {
        if (!selected_path_controller.has_path()) return false
        if (!selected_path_controller.path_visible) return true
        val bounds = selected_path_controller.bounds() ?: return false
        return !path_bounds_visible(viewport, bounds, usable)
    }

    private fun path_bounds_visible(viewport: Viewport, bounds: Bounds, usable: RectF): Boolean {
        if (usable.width() <= 0f || usable.height() <= 0f) return false
        val corners = listOf(
            GeoPoint(bounds.min_lat, bounds.min_lon),
            GeoPoint(bounds.min_lat, bounds.max_lon),
            GeoPoint(bounds.max_lat, bounds.min_lon),
            GeoPoint(bounds.max_lat, bounds.max_lon)
        )
        return corners.all { point ->
            val world = MapProjection.lat_lon_to_world(point.lat, point.lon, viewport.zoom)
            val sx = (world.x - viewport.center_x + viewport.width / 2.0).toFloat()
            val sy = (world.y - viewport.center_y + viewport.height / 2.0).toFloat()
            usable.contains(sx, sy)
        }
    }
}

