data class TrafficAltitudeColorPalette(
    val aggressive: Int,
    val aggressive_shade: Int,
    val distinct: Int,
    val calmest: Int
)

object AircraftColorResolver {
    fun aircraft_color(aircraft: Aircraft, theme: VisualTheme): Int {
        val altitude_feet = aircraft.altitude_m?.times(FEET_PER_METER)
        return if (aircraft.is_military) {
            military_altitude_color(altitude_feet, theme)
        } else {
            altitude_color(altitude_feet, theme)
        }
    }

    private fun altitude_color(altitude_feet: Double?, theme: VisualTheme): Int {
        val palette = altitude_color_palette(theme)
        val altitude = altitude_feet ?: return mix_color(palette.calmest, theme.colors.muted, 0.48f)
        return when {
            altitude < LOW_ALTITUDE_FEET -> {
                val progress = altitude_progress(altitude, 0.0, LOW_ALTITUDE_FEET)
                mix_color(palette.aggressive, palette.aggressive_shade, progress)
            }
            altitude < MID_ALTITUDE_FEET -> {
                val progress = altitude_progress(altitude, LOW_ALTITUDE_FEET, MID_ALTITUDE_FEET)
                mix_color(palette.aggressive_shade, palette.distinct, progress)
            }
            else -> {
                val progress = altitude_progress(altitude, MID_ALTITUDE_FEET, HIGH_ALTITUDE_FEET)
                mix_color(palette.distinct, palette.calmest, progress)
            }
        }
    }

    private fun military_altitude_color(altitude_feet: Double?, theme: VisualTheme): Int {
        val progress = altitude_feet?.let { altitude_progress(it, 0.0, HIGH_ALTITUDE_FEET) } ?: 0.55f
        val low_gray = mix_color(theme.colors.military, Color.WHITE, 0.34f)
        val high_gray = mix_color(theme.colors.military, theme.colors.scrim, 0.22f)
        return mix_color(low_gray, high_gray, progress)
    }

    private fun altitude_color_palette(theme: VisualTheme): TrafficAltitudeColorPalette {
        val colors = theme.colors
        return when (theme.style.treatment) {
            ThemeTreatment.RADAR_GRID -> TrafficAltitudeColorPalette(
                aggressive = colors.accent_orange,
                aggressive_shade = colors.accent_yellow,
                distinct = colors.accent_green,
                calmest = colors.accent_blue
            )
            ThemeTreatment.CRT_SCANLINE -> TrafficAltitudeColorPalette(
                aggressive = colors.danger,
                aggressive_shade = colors.accent_yellow,
                distinct = colors.accent_green,
                calmest = mix_color(colors.accent_blue, colors.muted, 0.25f)
            )
            ThemeTreatment.DAYLIGHT_CARD -> TrafficAltitudeColorPalette(
                aggressive = colors.danger,
                aggressive_shade = colors.accent_orange,
                distinct = colors.accent_green,
                calmest = colors.accent_blue
            )
            ThemeTreatment.STORM_BAND -> TrafficAltitudeColorPalette(
                aggressive = colors.danger,
                aggressive_shade = colors.accent_pink,
                distinct = colors.accent_green,
                calmest = colors.accent_blue
            )
            ThemeTreatment.GLASS -> TrafficAltitudeColorPalette(
                aggressive = colors.accent_orange,
                aggressive_shade = colors.accent_yellow,
                distinct = colors.accent_green,
                calmest = colors.accent_blue
            )
            ThemeTreatment.PLAIN -> TrafficAltitudeColorPalette(
                aggressive = colors.danger,
                aggressive_shade = colors.accent_orange,
                distinct = colors.accent_green,
                calmest = colors.accent_blue
            )
        }
    }

    private fun altitude_progress(altitude_feet: Double, lower_feet: Double, upper_feet: Double): Float {
        return smooth_step(0f, 1f, ((altitude_feet - lower_feet) / (upper_feet - lower_feet)).toFloat())
    }

    private fun smooth_step(edge0: Float, edge1: Float, value: Float): Float =
        safe_smooth_step(edge0, edge1, value)

    
    
    private const val FEET_PER_METER = 3.28084
    private const val LOW_ALTITUDE_FEET = 5000.0
    private const val MID_ALTITUDE_FEET = 25000.0
    private const val HIGH_ALTITUDE_FEET = 45000.0
}


class AircraftFilterController(private val prefs: SharedPreferences) {
    var search_query = AircraftFilterEngine.sanitize_search(
        prefs.getString(FlightAlertSettings.KEY_FILTER_SEARCH_QUERY, "").orEmpty()
    )
        private set
    var aircraft_type = read_enum_setting(FlightAlertSettings.KEY_FILTER_AIRCRAFT_TYPE, AircraftTypeFilter.ALL)
        private set
    var altitude = read_enum_setting(FlightAlertSettings.KEY_FILTER_ALTITUDE, AltitudeFilter.ANY)
        private set
    var distance = read_enum_setting(FlightAlertSettings.KEY_FILTER_DISTANCE, DistanceFilter.ANY)
        private set
    var flight_status = read_enum_setting(FlightAlertSettings.KEY_FILTER_FLIGHT_STATUS, FlightStatusFilter.AIRBORNE)
        private set
    var report_age = read_enum_setting(FlightAlertSettings.KEY_FILTER_REPORT_AGE, ReportAgeFilter.ANY)
        private set
    var alert_volume_only = prefs.getBoolean(FlightAlertSettings.KEY_FILTER_ALERT_VOLUME, false)
        private set

    fun set_search_query(value: String): Boolean {
        val sanitized = AircraftFilterEngine.sanitize_search(value)
        if (search_query == sanitized) return false
        search_query = sanitized
        prefs.edit { putString(FlightAlertSettings.KEY_FILTER_SEARCH_QUERY, search_query) }
        return true
    }

    fun set_aircraft_type(next: AircraftTypeFilter) {
        aircraft_type = next
        prefs.edit { putString(FlightAlertSettings.KEY_FILTER_AIRCRAFT_TYPE, next.name) }
    }

    fun set_altitude(next: AltitudeFilter) {
        altitude = next
        prefs.edit { putString(FlightAlertSettings.KEY_FILTER_ALTITUDE, next.name) }
    }

    fun set_distance(next: DistanceFilter) {
        distance = next
        prefs.edit { putString(FlightAlertSettings.KEY_FILTER_DISTANCE, next.name) }
    }

    fun set_flight_status(next: FlightStatusFilter) {
        flight_status = next
        prefs.edit { putString(FlightAlertSettings.KEY_FILTER_FLIGHT_STATUS, next.name) }
    }

    fun set_report_age(next: ReportAgeFilter) {
        report_age = next
        prefs.edit { putString(FlightAlertSettings.KEY_FILTER_REPORT_AGE, next.name) }
    }

    fun set_alert_volume_only(enabled: Boolean) {
        alert_volume_only = enabled
        prefs.edit { putBoolean(FlightAlertSettings.KEY_FILTER_ALERT_VOLUME, enabled) }
    }

    fun reset() {
        search_query = ""
        aircraft_type = AircraftTypeFilter.ALL
        altitude = AltitudeFilter.ANY
        distance = DistanceFilter.ANY
        flight_status = FlightStatusFilter.AIRBORNE
        report_age = ReportAgeFilter.ANY
        alert_volume_only = false
        prefs.edit {
            putString(FlightAlertSettings.KEY_FILTER_SEARCH_QUERY, search_query)
            putString(FlightAlertSettings.KEY_FILTER_AIRCRAFT_TYPE, aircraft_type.name)
            putString(FlightAlertSettings.KEY_FILTER_ALTITUDE, altitude.name)
            putString(FlightAlertSettings.KEY_FILTER_DISTANCE, distance.name)
            putString(FlightAlertSettings.KEY_FILTER_FLIGHT_STATUS, flight_status.name)
            putString(FlightAlertSettings.KEY_FILTER_REPORT_AGE, report_age.name)
            putBoolean(FlightAlertSettings.KEY_FILTER_ALERT_VOLUME, alert_volume_only)
        }
    }

    fun current_state(): AircraftFilterState {
        return AircraftFilterState(
            search_query = search_query,
            aircraft_type = aircraft_type,
            altitude = altitude,
            distance = distance,
            flight_status = flight_status,
            report_age = report_age,
            alert_volume_only = alert_volume_only
        )
    }

    fun is_active(): Boolean {
        return AircraftFilterEngine.is_active(current_state())
    }

    fun is_normal_airborne_mode(): Boolean {
        return AircraftFilterEngine.is_normal_airborne_mode(current_state())
    }

    fun restricts_aircraft(): Boolean {
        return AircraftFilterEngine.restricts_aircraft(current_state())
    }

    fun stats(
        aircraft: List<Aircraft>,
        now_epoch_sec: Double,
        distance_meters: (Aircraft) -> Double,
        is_hazard_aircraft: (Aircraft) -> Boolean
    ): FilterStats {
        return AircraftFilterEngine.stats(
            aircraft = aircraft,
            filters = current_state(),
            now_epoch_sec = now_epoch_sec,
            distance_meters = distance_meters,
            is_hazard_aircraft = is_hazard_aircraft
        )
    }

    fun stats_from_counts(total: Int, matched: Int): FilterStats {
        return AircraftFilterEngine.stats_from_counts(
            total = total,
            matched = matched,
            filters = current_state()
        )
    }

    fun passes(
        aircraft: Aircraft,
        now_epoch_sec: Double,
        distance_meters: (Aircraft) -> Double,
        is_hazard_aircraft: (Aircraft) -> Boolean
    ): Boolean {
        return AircraftFilterEngine.passes(
            aircraft = aircraft,
            filters = current_state(),
            now_epoch_sec = now_epoch_sec,
            distance_meters = distance_meters,
            is_hazard_aircraft = is_hazard_aircraft
        )
    }

    private inline fun <reified T : Enum<T>> read_enum_setting(key: String, default: T): T {
        val stored = prefs.getString(key, default.name) ?: default.name
        return enumValues<T>().firstOrNull { it.name == stored } ?: default
    }
}


data class AircraftFilterState(
    val search_query: String,
    val aircraft_type: AircraftTypeFilter,
    val altitude: AltitudeFilter,
    val distance: DistanceFilter,
    val flight_status: FlightStatusFilter,
    val report_age: ReportAgeFilter,
    val alert_volume_only: Boolean
) {
    companion object {
        val DEFAULT = AircraftFilterState(
            search_query = "",
            aircraft_type = AircraftTypeFilter.ALL,
            altitude = AltitudeFilter.ANY,
            distance = DistanceFilter.ANY,
            flight_status = FlightStatusFilter.AIRBORNE,
            report_age = ReportAgeFilter.ANY,
            alert_volume_only = false
        )
    }
}

data class FilterStats(val total: Int, val matched: Int, val summary: String)

enum class AircraftTypeFilter(val short_label: String) {
    ALL("All"),
    AIRPLANES("Airplanes"),
    ROTORCRAFT("Rotor"),
    GLIDER("Glider"),
    UAV("UAV"),
    SURFACE("Surface"),
    MILITARY("Military");

    fun next(): AircraftTypeFilter = entries[(ordinal + 1) % entries.size]
}

enum class AltitudeFilter(val short_label: String) {
    ANY("Any"),
    BELOW_1000("<1k ft"),
    FROM_1000_TO_5000("1k-5k ft"),
    FROM_5000_TO_18000("5k-18k ft"),
    ABOVE_18000("18k+ ft"),
    UNKNOWN("Unknown");

    fun next(): AltitudeFilter = entries[(ordinal + 1) % entries.size]
}

enum class DistanceFilter(val short_label: String) {
    ANY("Any"),
    WITHIN_5("<5 mi"),
    WITHIN_10("<10 mi"),
    WITHIN_25("<25 mi"),
    BEYOND_25(">25 mi");

    fun next(): DistanceFilter = entries[(ordinal + 1) % entries.size]
}

enum class FlightStatusFilter(val short_label: String) {
    ANY("Any"),
    AIRBORNE("Airborne"),
    ON_GROUND("Ground"),
    UNKNOWN("Unknown");

    fun next(): FlightStatusFilter = entries[(ordinal + 1) % entries.size]
}

enum class ReportAgeFilter(val short_label: String) {
    ANY("Any"),
    FRESH_30("Fresh <=30s"),
    STALE_60("Stale >=60s"),
    UNKNOWN("Unknown");

    fun next(): ReportAgeFilter = entries[(ordinal + 1) % entries.size]
}

object AircraftFilterEngine {
    fun sanitize_search(value: String): String {
        return value
            .uppercase(Locale.US)
            .filter { it.isLetterOrDigit() || it == '-' }
            .take(MAX_SEARCH_CHARS)
    }

    fun is_active(filters: AircraftFilterState): Boolean {
        return !is_normal_airborne_mode(filters)
    }

    fun is_normal_airborne_mode(filters: AircraftFilterState): Boolean {
        return filters.search_query.isBlank() &&
            filters.aircraft_type == AircraftTypeFilter.ALL &&
            filters.altitude == AltitudeFilter.ANY &&
            filters.distance == DistanceFilter.ANY &&
            filters.flight_status == FlightStatusFilter.AIRBORNE &&
            filters.report_age == ReportAgeFilter.ANY &&
            !filters.alert_volume_only
    }

    fun restricts_aircraft(filters: AircraftFilterState): Boolean {
        return filters.search_query.isNotBlank() ||
            filters.aircraft_type != AircraftTypeFilter.ALL ||
            filters.altitude != AltitudeFilter.ANY ||
            filters.distance != DistanceFilter.ANY ||
            filters.flight_status != FlightStatusFilter.ANY ||
            filters.report_age != ReportAgeFilter.ANY ||
            filters.alert_volume_only
    }

    fun stats(
        aircraft: List<Aircraft>,
        filters: AircraftFilterState,
        now_epoch_sec: Double,
        distance_meters: (Aircraft) -> Double,
        is_hazard_aircraft: (Aircraft) -> Boolean
    ): FilterStats {
        val matched = aircraft.count { passes(it, filters, now_epoch_sec, distance_meters, is_hazard_aircraft) }
        return stats_from_counts(
            total = aircraft.size,
            matched = matched,
            filters = filters
        )
    }

    fun stats_from_counts(
        total: Int,
        matched: Int,
        filters: AircraftFilterState
    ): FilterStats {
        val summary = when {
            is_normal_airborne_mode(filters) -> "$matched airborne aircraft in current feed"
            !restricts_aircraft(filters) -> "$total live aircraft in current feed"
            total == 0 -> "No live aircraft in current feed"
            matched == 0 -> "0 of $total live aircraft match filters"
            else -> "$matched of $total live aircraft match filters"
        }
        return FilterStats(total, matched, summary)
    }

    fun passes(
        aircraft: Aircraft,
        filters: AircraftFilterState,
        now_epoch_sec: Double,
        distance_meters: (Aircraft) -> Double,
        is_hazard_aircraft: (Aircraft) -> Boolean
    ): Boolean {
        if (!matches_search(aircraft, filters.search_query)) return false
        if (!matches_type(aircraft, filters.aircraft_type)) return false
        if (!matches_altitude(aircraft, filters.altitude)) return false
        if (!matches_distance(aircraft, filters.distance, distance_meters)) return false
        if (!matches_flight_status(aircraft, filters.flight_status)) return false
        if (!matches_report_age(aircraft, filters.report_age, now_epoch_sec)) return false
        if (filters.alert_volume_only && !is_hazard_aircraft(aircraft)) return false
        return true
    }

    private fun matches_search(aircraft: Aircraft, query: String): Boolean {
        if (query.isBlank()) return true
        return listOf(
            aircraft.callsign,
            aircraft.registration.orEmpty(),
            aircraft.icao24,
            aircraft.type_code.orEmpty()
        ).any { sanitize_search(it).contains(query) }
    }

    private fun matches_type(aircraft: Aircraft, filter: AircraftTypeFilter): Boolean {
        val symbol = AircraftSymbolClassifier.symbol_for(aircraft)
        return when (filter) {
            AircraftTypeFilter.ALL -> true
            AircraftTypeFilter.AIRPLANES -> symbol == AircraftSymbol.AIRLINER || symbol == AircraftSymbol.GENERAL_AVIATION
            AircraftTypeFilter.ROTORCRAFT -> symbol == AircraftSymbol.ROTORCRAFT
            AircraftTypeFilter.GLIDER -> symbol == AircraftSymbol.GLIDER
            AircraftTypeFilter.UAV -> symbol == AircraftSymbol.UAV
            AircraftTypeFilter.SURFACE -> symbol == AircraftSymbol.SURFACE
            AircraftTypeFilter.MILITARY -> aircraft.is_military
        }
    }

    private fun matches_altitude(aircraft: Aircraft, filter: AltitudeFilter): Boolean {
        if (filter == AltitudeFilter.ANY) return true
        val feet = aircraft.altitude_m?.times(FEET_PER_METER)
        return when (filter) {
            AltitudeFilter.ANY -> true
            AltitudeFilter.BELOW_1000 -> feet != null && feet < 1000.0
            AltitudeFilter.FROM_1000_TO_5000 -> feet != null && feet >= 1000.0 && feet < 5000.0
            AltitudeFilter.FROM_5000_TO_18000 -> feet != null && feet >= 5000.0 && feet < 18000.0
            AltitudeFilter.ABOVE_18000 -> feet != null && feet >= 18000.0
            AltitudeFilter.UNKNOWN -> feet == null
        }
    }

    private fun matches_distance(
        aircraft: Aircraft,
        filter: DistanceFilter,
        distance_meters: (Aircraft) -> Double
    ): Boolean {
        val meters = distance_meters(aircraft)
        return when (filter) {
            DistanceFilter.ANY -> true
            DistanceFilter.WITHIN_5 -> meters <= 5.0 * METERS_PER_STATUTE_MILE
            DistanceFilter.WITHIN_10 -> meters <= 10.0 * METERS_PER_STATUTE_MILE
            DistanceFilter.WITHIN_25 -> meters <= 25.0 * METERS_PER_STATUTE_MILE
            DistanceFilter.BEYOND_25 -> meters > 25.0 * METERS_PER_STATUTE_MILE
        }
    }

    private fun matches_flight_status(aircraft: Aircraft, filter: FlightStatusFilter): Boolean {
        return when (filter) {
            FlightStatusFilter.ANY -> true
            FlightStatusFilter.AIRBORNE -> aircraft.on_ground == false
            FlightStatusFilter.ON_GROUND -> aircraft.on_ground == true
            FlightStatusFilter.UNKNOWN -> aircraft.on_ground == null
        }
    }

    private fun matches_report_age(aircraft: Aircraft, filter: ReportAgeFilter, now_epoch_sec: Double): Boolean {
        val age = contact_age_seconds(aircraft, now_epoch_sec)
        return when (filter) {
            ReportAgeFilter.ANY -> true
            ReportAgeFilter.FRESH_30 -> age != null && age <= 30.0
            ReportAgeFilter.STALE_60 -> age != null && age >= 60.0
            ReportAgeFilter.UNKNOWN -> age == null
        }
    }

    private fun contact_age_seconds(aircraft: Aircraft, now_epoch_sec: Double): Double? {
        val contact = aircraft.last_contact_sec ?: aircraft.position_time_sec ?: return null
        return max(0.0, now_epoch_sec - contact)
    }

    private const val FEET_PER_METER = 3.28084
    private const val METERS_PER_STATUTE_MILE = 1609.344
    private const val MAX_SEARCH_CHARS = 18
}


data class AircraftDisplayPosition(
    val point: GeoPoint,
    val projected: Boolean,
    val motion_remaining_seconds: Double = 0.0
)

data class AircraftProjectionMotion(
    val speed_ms: Double,
    val track_deg: Double,
    val elapsed_seconds: Double,
    val remaining_seconds: Double
)

object AircraftPositionProjector {
    fun reported_position(aircraft: Aircraft): GeoPoint {
        return GeoPoint(aircraft.lat, aircraft.lon)
    }

    fun projected_display_position(
        aircraft: Aircraft,
        now_epoch_sec: Double,
        max_projection_seconds: Double
    ): AircraftDisplayPosition {
        val reported = reported_position(aircraft)
        val motion = projection_motion(aircraft, now_epoch_sec, max_projection_seconds)
            ?: return AircraftDisplayPosition(reported, projected = false)

        if (motion.elapsed_seconds <= 0.0) {
            return AircraftDisplayPosition(
                point = reported,
                projected = false,
                motion_remaining_seconds = motion.remaining_seconds
            )
        }

        return AircraftDisplayPosition(
            point = MapProjection.destination_point(
                aircraft.lat,
                aircraft.lon,
                motion.track_deg,
                motion.speed_ms * motion.elapsed_seconds
            ),
            projected = true,
            motion_remaining_seconds = motion.remaining_seconds
        )
    }

    fun projection_motion(
        aircraft: Aircraft,
        now_epoch_sec: Double,
        max_projection_seconds: Double
    ): AircraftProjectionMotion? {
        if (aircraft.on_ground == true || !aircraft.lat.isFinite() || !aircraft.lon.isFinite()) return null
        if (!now_epoch_sec.isFinite() || !max_projection_seconds.isFinite() || max_projection_seconds <= 0.0) return null
        val speed = aircraft.velocity_ms?.takeIf { it.isFinite() && it > MIN_PROJECTABLE_SPEED_MS && it <= MAX_PROJECTABLE_SPEED_MS } ?: return null
        val track = normalized_track_degrees(aircraft.track_deg) ?: return null
        val report_time = aircraft.position_time_sec?.takeIf { it.isFinite() } ?: return null
        val raw_elapsed = now_epoch_sec - report_time
        if (!raw_elapsed.isFinite()) return null
        val elapsed = raw_elapsed.coerceAtLeast(0.0)
        val remaining = if (raw_elapsed < 0.0) {
            0.0
        } else {
            max_projection_seconds
        }
        return AircraftProjectionMotion(
            speed_ms = speed,
            track_deg = track,
            elapsed_seconds = elapsed,
            remaining_seconds = remaining
        )
    }

    fun reported_distance_meters(aircraft: Aircraft, own_lat: Double?, own_lon: Double?): Double {
        if (own_lat == null || own_lon == null) return aircraft.distance_m
        return MapProjection.distance_meters(own_lat, own_lon, aircraft.lat, aircraft.lon)
    }

    fun contact_age_seconds(aircraft: Aircraft, now_epoch_sec: Double): Double? {
        val contact = aircraft.last_contact_sec ?: aircraft.position_time_sec ?: return null
        return (now_epoch_sec - contact).coerceAtLeast(0.0)
    }

    fun to_track_point(aircraft: Aircraft): TrackPoint? {
        val epoch_sec = (aircraft.position_time_sec ?: aircraft.last_contact_sec)?.toLong() ?: return null
        if (epoch_sec <= 0L) return null
        return TrackPoint(
            lat = aircraft.lat,
            lon = aircraft.lon,
            epoch_sec = epoch_sec,
            altitude_m = aircraft.altitude_m,
            track_deg = aircraft.track_deg,
            on_ground = aircraft.on_ground
        )
    }

    private fun normalized_track_degrees(track_deg: Double?): Double? {
        val track = track_deg?.takeIf { it.isFinite() } ?: return null
        return ((track % 360.0) + 360.0) % 360.0
    }

    private const val MIN_PROJECTABLE_SPEED_MS = 0.5
    private const val MAX_PROJECTABLE_SPEED_MS = 1_200.0
}


data class RegistryCountry(val iso_code: String, val name: String, val flag_code: String? = iso_code) {
    val label: String
        get() = flag_code?.let { "${flag_emoji(it)} $name" } ?: name

    private fun flag_emoji(code: String): String {
        val normalized = code.uppercase(Locale.US).take(2)
        if (normalized.length != 2 || normalized.any { it !in 'A'..'Z' }) return normalized
        val first = Character.toChars(0x1F1E6 + (normalized[0] - 'A')).concatToString()
        val second = Character.toChars(0x1F1E6 + (normalized[1] - 'A')).concatToString()
        return first + second
    }
}

data class IcaoRegistryRange(val start: Int, val end: Int, val country: RegistryCountry)

enum class RegistryCountrySource {
    REGISTRATION,
    ICAO_ALLOCATION
}

data class RegistryCountryMatch(val country: RegistryCountry, val source: RegistryCountrySource) {
    val label: String
        get() = country.label
}

object AircraftRegistryResolver {
    fun country_for(registration: String?, icao24: String): RegistryCountryMatch? {
        country_from_registration(registration)?.let {
            return RegistryCountryMatch(it, RegistryCountrySource.REGISTRATION)
        }
        country_from_icao24(icao24)?.let {
            return RegistryCountryMatch(it, RegistryCountrySource.ICAO_ALLOCATION)
        }
        return null
    }

    fun label_for(registration: String?, icao24: String): String? {
        return country_for(registration, icao24)?.label
    }

    private fun country_from_registration(registration: String?): RegistryCountry? {
        val reg = registration?.trim()?.uppercase(Locale.US) ?: return null
        return when {
            reg.startsWith("N") && reg.getOrNull(1)?.isDigit() == true -> REGISTRY_UNITED_STATES
            reg.startsWith("C-F") || reg.startsWith("C-G") || reg.startsWith("C-I") || reg.startsWith("CF") -> RegistryCountry("CA", "Canada")
            reg.startsWith("G-") -> RegistryCountry("GB", "United Kingdom")
            reg.startsWith("D-") -> RegistryCountry("DE", "Germany")
            reg.startsWith("F-") -> RegistryCountry("FR", "France")
            reg.startsWith("I-") -> RegistryCountry("IT", "Italy")
            reg.startsWith("EC-") -> RegistryCountry("ES", "Spain")
            reg.startsWith("PH-") -> RegistryCountry("NL", "Netherlands")
            reg.startsWith("HB-") -> RegistryCountry("CH", "Switzerland")
            reg.startsWith("OE-") -> RegistryCountry("AT", "Austria")
            reg.startsWith("OO-") -> RegistryCountry("BE", "Belgium")
            reg.startsWith("SE-") -> RegistryCountry("SE", "Sweden")
            reg.startsWith("LN-") -> RegistryCountry("NO", "Norway")
            reg.startsWith("OY-") -> RegistryCountry("DK", "Denmark")
            reg.startsWith("OH-") -> RegistryCountry("FI", "Finland")
            reg.startsWith("EI-") -> RegistryCountry("IE", "Ireland")
            reg.startsWith("CS-") -> RegistryCountry("PT", "Portugal")
            reg.startsWith("SP-") -> RegistryCountry("PL", "Poland")
            reg.startsWith("OK-") -> RegistryCountry("CZ", "Czechia")
            reg.startsWith("HA-") -> RegistryCountry("HU", "Hungary")
            reg.startsWith("SX-") -> RegistryCountry("GR", "Greece")
            reg.startsWith("TC-") -> RegistryCountry("TR", "Turkiye")
            reg.startsWith("RA-") || reg.startsWith("RF-") -> RegistryCountry("RU", "Russia")
            reg.startsWith("B-") -> RegistryCountry("CN", "China")
            reg.startsWith("JA") -> RegistryCountry("JP", "Japan")
            reg.startsWith("HL") -> RegistryCountry("KR", "South Korea")
            reg.startsWith("VH-") -> RegistryCountry("AU", "Australia")
            reg.startsWith("ZK-") -> RegistryCountry("NZ", "New Zealand")
            reg.startsWith("PT") || reg.startsWith("PR") || reg.startsWith("PP") || reg.startsWith("PS") -> RegistryCountry("BR", "Brazil")
            reg.startsWith("LV-") -> RegistryCountry("AR", "Argentina")
            reg.startsWith("XA") || reg.startsWith("XB") || reg.startsWith("XC") -> RegistryCountry("MX", "Mexico")
            reg.startsWith("HK-") -> RegistryCountry("CO", "Colombia")
            reg.startsWith("CC-") -> RegistryCountry("CL", "Chile")
            reg.startsWith("9M-") -> RegistryCountry("MY", "Malaysia")
            reg.startsWith("HS-") -> RegistryCountry("TH", "Thailand")
            reg.startsWith("VT-") -> RegistryCountry("IN", "India")
            reg.startsWith("RP-") -> RegistryCountry("PH", "Philippines")
            reg.startsWith("PK-") -> RegistryCountry("ID", "Indonesia")
            reg.startsWith("9V-") -> RegistryCountry("SG", "Singapore")
            reg.startsWith("A6-") -> RegistryCountry("AE", "United Arab Emirates")
            reg.startsWith("A7-") -> RegistryCountry("QA", "Qatar")
            reg.startsWith("HZ-") -> RegistryCountry("SA", "Saudi Arabia")
            reg.startsWith("ZS") || reg.startsWith("ZU") || reg.startsWith("ZT") -> RegistryCountry("ZA", "South Africa")
            else -> null
        }
    }

    private fun country_from_icao24(icao24: String): RegistryCountry? {
        val hex = icao24.trim()
        if (hex.startsWith("~")) return null
        val value = hex.toIntOrNull(16) ?: return null
        return ICAO_REGISTRY_RANGES.firstOrNull { value in it.start..it.end }?.country
    }

    private val REGISTRY_UNITED_STATES = country("US", "United States")

    private fun country(iso_code: String, name: String, flag_code: String? = iso_code): RegistryCountry {
        return RegistryCountry(iso_code, name, flag_code)
    }

    private fun icao_range(start: Int, end: Int, iso_code: String, name: String, flag_code: String? = iso_code): IcaoRegistryRange {
        return IcaoRegistryRange(start, end, country(iso_code, name, flag_code))
    }

    // Reserved and unallocated ICAO blocks are intentionally absent so unresolved addresses stay honest.
