// Chooses and merges live aircraft sources so FlightMapView can ask for traffic without knowing source policy.
class AircraftTrafficFeed(
    private val aircraft_feed_client: AircraftFeedClient,
    private val globe_bin_craft_aircraft_source: GlobeBinCraftAircraftSource?
) {
    // Keep the optional binCraft source pointed at the same broad inventory area as the visible map.
    fun update_viewport(
        feed_bounds: FeedBounds,
        center_lat: Double,
        center_lon: Double,
        zoom: Double,
        feed_mode: AircraftFeedMode
    ) {
        globe_bin_craft_aircraft_source
            ?.takeIf { feed_mode.uses_globe }
            ?.update_viewport(feed_bounds, center_lat, center_lon, zoom)
    }

    // Fetch according to the selected source mode, reporting intermediate real results when hybrid data arrives in stages.
    fun fetch_aircraft(
        feed_bounds: FeedBounds,
        safety_api_bounds: FeedBounds?,
        own_lat: Double,
        own_lon: Double,
        exact_search: String?,
        feed_mode: AircraftFeedMode,
        on_intermediate_result: (FeedResult) -> Unit
    ): FeedResult? {
        val globe_source = globe_bin_craft_aircraft_source?.takeIf { feed_mode.uses_globe }
        return when (feed_mode) {
            AircraftFeedMode.WEB -> {
                globe_source?.latest_snapshot(feed_bounds, own_lat, own_lon, exact_search)
                    ?: FeedResult(
                        status = FeedStatus.UNAVAILABLE,
                        source = FeedSource.AIRPLANES_LIVE_GLOBE,
                        partial_coverage = true
                    )
            }
            AircraftFeedMode.API -> {
                aircraft_feed_client.fetch_aircraft(feed_bounds, own_lat, own_lon, exact_search)
            }
            AircraftFeedMode.HYBRID -> {
                // Hybrid keeps binCraft as the wide-area inventory, then spends API queries on the safety bubble.
                val targeted_api_bounds = safety_api_bounds ?: feed_bounds
                val first_globe_result = globe_source?.latest_snapshot(feed_bounds, own_lat, own_lon, exact_search)
                    ?: globe_source?.await_latest_snapshot(feed_bounds, own_lat, own_lon, exact_search)
                if (first_globe_result?.status == FeedStatus.OK) {
                    on_intermediate_result(first_globe_result)
                }
                val api_result = aircraft_feed_client.fetch_aircraft(targeted_api_bounds, own_lat, own_lon, exact_search)
                val globe_result = globe_source?.latest_snapshot(feed_bounds, own_lat, own_lon, exact_search) ?: first_globe_result
                when {
                    api_result.status == FeedStatus.OK && globe_result?.status == FeedStatus.OK -> {
                        merge_hybrid_aircraft_feeds(api_result, globe_result)
                    }
                    api_result.status != FeedStatus.OK && globe_result?.status == FeedStatus.OK -> {
                        globe_result
                    }
                    api_result.status != FeedStatus.OK -> {
                        api_result
                    }
                    else -> api_result.copy(
                        source = FeedSource.HYBRID,
                        partial_coverage = true
                    )
                }
            }
        }
    }

    // Convert provider feed rows into map aircraft without inventing missing fields.
    fun map_aircraft(result: FeedResult): List<Aircraft> {
        return result.aircraft.map { it.to_map_aircraft() }
    }

    // Turn feed coverage into short UI text so partial coverage stays visible to the user.
    fun coverage_label(result: FeedResult): String {
        return when {
            result.source == FeedSource.HYBRID && result.partial_coverage -> " (loading binCraft supplement)"
            result.query_count > 1 && result.partial_coverage -> " (${result.query_count} areas, partial wide-area coverage)"
            result.query_count > 1 -> " (${result.query_count} areas)"
            result.partial_coverage -> " (partial wide-area coverage)"
            else -> ""
        }
    }

    // Keep globe/binCraft positions canonical, then fill missing metadata from the API safety query.
    private fun merge_hybrid_aircraft_feeds(api_result: FeedResult, globe_result: FeedResult): FeedResult {
        val merged = linkedMapOf<String, FeedAircraft>()
        globe_result.aircraft.forEach { item ->
            merged[item.hybrid_feed_key()] = item
        }
        api_result.aircraft.forEach { api_item ->
            val key = api_item.hybrid_feed_key()
            val globe_item = merged[key]
            merged[key] = if (globe_item == null) {
                api_item
            } else {
                merge_freshest_position_with_metadata(globe_item, api_item)
            }
        }
        return FeedResult(
            status = FeedStatus.OK,
            source = FeedSource.HYBRID,
            aircraft = merged.values.sortedBy { it.distance_m },
            epoch_sec = max_epoch(api_result.epoch_sec, globe_result.epoch_sec),
            query_count = api_result.query_count + globe_result.query_count,
            partial_coverage = globe_result.partial_coverage
        )
    }

    private fun merge_freshest_position_with_metadata(globe_item: FeedAircraft, api_item: FeedAircraft): FeedAircraft {
        val position_item = fresher_position_aircraft(globe_item, api_item)
        val metadata_item = if (position_item === globe_item) api_item else globe_item
        return position_item.copy(
            callsign = position_item.callsign.takeUnless { it.isBlank() || it.equals("Unknown", ignoreCase = true) }
                ?: metadata_item.callsign,
            registration = position_item.registration ?: metadata_item.registration,
            type_code = position_item.type_code ?: metadata_item.type_code,
            metadata = position_item.metadata ?: metadata_item.metadata,
            db_flags = position_item.db_flags ?: metadata_item.db_flags,
            on_ground = position_item.on_ground ?: metadata_item.on_ground,
            altitude_m = position_item.altitude_m ?: metadata_item.altitude_m,
            velocity_ms = position_item.velocity_ms ?: metadata_item.velocity_ms,
            track_deg = position_item.track_deg ?: metadata_item.track_deg,
            vertical_rate_ms = position_item.vertical_rate_ms ?: metadata_item.vertical_rate_ms,
            category = position_item.category ?: metadata_item.category,
            distance_m = position_item.distance_m.takeIf { it > 0.0 } ?: metadata_item.distance_m,
            telemetry = position_item.telemetry?.with_fallback(metadata_item.telemetry) ?: metadata_item.telemetry
        )
    }

    // Prefer real aircraft identifiers for merges, falling back to coarse position only when no ID exists.
    private fun FeedAircraft.hybrid_feed_key(): String {
        val hex = icao24.trim().lowercase(Locale.US)
        if (hex.isNotBlank()) return "hex:$hex"
        registration?.trim()?.uppercase(Locale.US)?.takeIf { it.isNotBlank() }?.let { return "reg:$it" }
        return "pos:${"%.4f".format(Locale.US, lat)}:${"%.4f".format(Locale.US, lon)}:${callsign.trim().uppercase(Locale.US)}"
    }

    private fun fresher_position_aircraft(first: FeedAircraft, second: FeedAircraft): FeedAircraft {
        val first_position_time = first.position_time_sec ?: first.last_contact_sec ?: 0.0
        val second_position_time = second.position_time_sec ?: second.last_contact_sec ?: 0.0
        if (abs(first_position_time - second_position_time) > POSITION_TIME_TIE_SECONDS) {
            return if (second_position_time > first_position_time) second else first
        }
        val first_contact_time = first.last_contact_sec ?: first.position_time_sec ?: 0.0
        val second_contact_time = second.last_contact_sec ?: second.position_time_sec ?: 0.0
        return if (second_contact_time >= first_contact_time) second else first
    }

    // Keep the shared Aircraft model as a direct translation of feed data with nullable unknowns preserved.
    private fun FeedAircraft.to_map_aircraft(): Aircraft {
        return Aircraft(
            icao24 = icao24,
            callsign = callsign,
            registration = registration,
            type_code = type_code,
            metadata_seed = metadata,
            is_military = db_flags?.let { it and DB_FLAG_MILITARY != 0 } == true,
            lat = lat,
            lon = lon,
            on_ground = on_ground,
            altitude_m = altitude_m,
            velocity_ms = velocity_ms,
            track_deg = track_deg,
            vertical_rate_ms = vertical_rate_ms,
            category = category,
            position_time_sec = position_time_sec,
            last_contact_sec = last_contact_sec,
            distance_m = distance_m,
            telemetry = telemetry
        )
    }

    
    private companion object {
        const val DB_FLAG_MILITARY = 1
        const val POSITION_TIME_TIE_SECONDS = FlightAlertSettings.AircraftFeed.POSITION_TIME_TIE_SECONDS
        const val HYBRID_GLOBE_STARTUP_GRACE_MS = FlightAlertSettings.AircraftFeed.HYBRID_GLOBE_STARTUP_GRACE_MS
        const val HYBRID_GLOBE_STARTUP_POLL_MS = FlightAlertSettings.AircraftFeed.HYBRID_GLOBE_STARTUP_POLL_MS
    }

    private fun GlobeBinCraftAircraftSource.await_latest_snapshot(
        feed_bounds: FeedBounds,
        own_lat: Double,
        own_lon: Double,
        exact_search: String?
    ): FeedResult? {
        val deadline = SystemClock.elapsedRealtime() + HYBRID_GLOBE_STARTUP_GRACE_MS
        var result = latest_snapshot(feed_bounds, own_lat, own_lon, exact_search)
        while (result?.status != FeedStatus.OK && SystemClock.elapsedRealtime() < deadline) {
            try {
                Thread.sleep(HYBRID_GLOBE_STARTUP_POLL_MS)
            } catch (_: InterruptedException) {
                Thread.currentThread().interrupt()
                return result
            }
            result = latest_snapshot(feed_bounds, own_lat, own_lon, exact_search)
        }
        return result
    }
}


internal data class CachedTraffic(
    val aircraft: List<Aircraft>,
    val nearest_aircraft: Aircraft?,
    val entries: List<TrafficSpatialEntry>,
    val spatial_index: TrafficSpatialIndex,
    val world_dot_batch: TrafficWorldDotBatch,
    val total: Int,
    val hazard_present: Boolean,
    val extreme_priority_aircraft: List<Aircraft>,
    val extreme_priority_keys: Set<String>,
    val max_projected_speed_zoom_zero: Double
)

internal data class TrafficSpatialEntry(
    val aircraft: Aircraft,
    val world_x_zoom_zero: Double,
    val world_y_zoom_zero: Double,
    val projected_velocity_x_zoom_zero: Double,
    val projected_velocity_y_zoom_zero: Double,
    val projected_motion_remaining_sec: Double,
    val projection_epoch_sec: Double,
    val appearance_key: String = aircraft.appearance_key(),
    val symbol: AircraftSymbol = AircraftSymbolClassifier.symbol_for(aircraft),
    val symbol_scale: Float = AircraftSymbolClassifier.size_multiplier(aircraft, symbol),
    val dot_group: Int = TrafficDotGrouper.dot_group(aircraft),
    val color: Int = 0,
    val color_theme_key: Int = 0
)

@Suppress("ArrayInDataClass")
internal data class TrafficWorldDotBatch(
    val outline_points: FloatArray,
    val outline_count: Int,
    val outline_velocities: FloatArray,
    val outline_motion_limits: FloatArray,
    val fill_points: Array<FloatArray>,
    val fill_counts: IntArray,
    val fill_velocities: Array<FloatArray>,
    val fill_motion_limits: Array<FloatArray>,
    val visible_count: Int,
    val built_elapsed_ms: Long
) {
    companion object {
        fun empty(): TrafficWorldDotBatch {
            return TrafficWorldDotBatch(
                outline_points = FloatArray(0),
                outline_count = 0,
                outline_velocities = FloatArray(0),
                outline_motion_limits = FloatArray(0),
                fill_points = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(0) },
                fill_counts = IntArray(TrafficDotBatchOverlayState.GROUP_COUNT),
                fill_velocities = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(0) },
                fill_motion_limits = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(0) },
                visible_count = 0,
                built_elapsed_ms = 0L
            )
        }
    }
}

internal class TrafficSpatialIndex(entries: List<TrafficSpatialEntry>) {
    private val cells = arrayOfNulls<MutableList<TrafficSpatialEntry>>(CELL_COUNT * CELL_COUNT)

    init {
        entries.forEach { entry ->
            val column = (entry.world_x_zoom_zero / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
            val row = (entry.world_y_zoom_zero / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
            val index = row * CELL_COUNT + column
            val cell = cells[index] ?: ArrayList<TrafficSpatialEntry>().also { cells[index] = it }
            cell += entry
        }
    }

    // Pan frames use this grid to ask only the cells near the viewport instead of scanning all aircraft.
    fun query(viewport: Viewport, padding_px: Float): List<TrafficSpatialEntry> {
        val scale = 2.0.pow(viewport.zoom)
        val min_y = ((viewport.center_y - viewport.height / 2.0 - padding_px) / scale).coerceIn(0.0, WORLD_SIZE)
        val max_y = ((viewport.center_y + viewport.height / 2.0 + padding_px) / scale).coerceIn(0.0, WORLD_SIZE)
        val raw_min_x = (viewport.center_x - viewport.width / 2.0 - padding_px) / scale
        val raw_max_x = (viewport.center_x + viewport.width / 2.0 + padding_px) / scale
        val result = ArrayList<TrafficSpatialEntry>()
        if (raw_max_x - raw_min_x >= WORLD_SIZE) {
            collect_range(0.0, WORLD_SIZE, min_y, max_y, result)
        } else {
            val min_x = normalize_world_x(raw_min_x)
            val max_x = normalize_world_x(raw_max_x)
            if (min_x <= max_x) {
                collect_range(min_x, max_x, min_y, max_y, result)
            } else {
                collect_range(min_x, WORLD_SIZE, min_y, max_y, result)
                collect_range(0.0, max_x, min_y, max_y, result)
            }
        }
        return result
    }

    fun query_count(viewport: Viewport, padding_px: Float): Int {
        val scale = 2.0.pow(viewport.zoom)
        val min_y = ((viewport.center_y - viewport.height / 2.0 - padding_px) / scale).coerceIn(0.0, WORLD_SIZE)
        val max_y = ((viewport.center_y + viewport.height / 2.0 + padding_px) / scale).coerceIn(0.0, WORLD_SIZE)
        val raw_min_x = (viewport.center_x - viewport.width / 2.0 - padding_px) / scale
        val raw_max_x = (viewport.center_x + viewport.width / 2.0 + padding_px) / scale
        return if (raw_max_x - raw_min_x >= WORLD_SIZE) {
            count_range(0.0, WORLD_SIZE, min_y, max_y)
        } else {
            val min_x = normalize_world_x(raw_min_x)
            val max_x = normalize_world_x(raw_max_x)
            if (min_x <= max_x) {
                count_range(min_x, max_x, min_y, max_y)
            } else {
                count_range(min_x, WORLD_SIZE, min_y, max_y) +
                    count_range(0.0, max_x, min_y, max_y)
            }
        }
    }

    private fun collect_range(
        min_x: Double,
        max_x: Double,
        min_y: Double,
        max_y: Double,
        result: MutableList<TrafficSpatialEntry>
    ) {
        val min_column = (min_x / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        val max_column = (max_x / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        val min_row = (min_y / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        val max_row = (max_y / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        for (row in min_row..max_row) {
            val row_offset = row * CELL_COUNT
            for (column in min_column..max_column) {
                cells[row_offset + column]?.let(result::addAll)
            }
        }
    }

    private fun count_range(
        min_x: Double,
        max_x: Double,
        min_y: Double,
        max_y: Double
    ): Int {
        val min_column = (min_x / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        val max_column = (max_x / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        val min_row = (min_y / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        val max_row = (max_y / CELL_WORLD_SIZE).toInt().coerceIn(0, CELL_COUNT - 1)
        var count = 0
        for (row in min_row..max_row) {
            val row_offset = row * CELL_COUNT
            for (column in min_column..max_column) {
                count += cells[row_offset + column]?.size ?: 0
            }
        }
        return count
    }

    private fun normalize_world_x(value: Double): Double {
        return ((value % WORLD_SIZE) + WORLD_SIZE) % WORLD_SIZE
    }

    private companion object {
        const val WORLD_SIZE = 256.0
        const val CELL_COUNT = 192
        const val CELL_WORLD_SIZE = WORLD_SIZE / CELL_COUNT
    }
}

internal object TrafficDotGrouper {
    fun dot_group(aircraft: Aircraft): Int {
        if (aircraft.is_military) return TrafficDotBatchOverlayState.GROUP_MILITARY
        val altitude_feet = aircraft.altitude_m?.times(FEET_PER_METER)
        return when {
            altitude_feet == null -> TrafficDotBatchOverlayState.GROUP_UNKNOWN
            altitude_feet < 5000.0 -> TrafficDotBatchOverlayState.GROUP_LOW
            altitude_feet < 25000.0 -> TrafficDotBatchOverlayState.GROUP_MID
            else -> TrafficDotBatchOverlayState.GROUP_HIGH
        }
    }

    private const val FEET_PER_METER = 3.28084
}


internal class TrafficCacheController(
    private val passes_aircraft_filters: (Aircraft, Double) -> Boolean,
    private val distance_meters: (Aircraft) -> Double,
    private val is_hazard_aircraft: (Aircraft) -> Boolean,
    private val aircraft_icao_key: (Aircraft) -> String,
    private val spatial_entry_for: (Aircraft, Double) -> TrafficSpatialEntry,
    private val alerts_enabled: () -> Boolean,
    private val now_epoch_seconds: () -> Double,
    private val now_elapsed_ms: () -> Long = { SystemClock.elapsedRealtime() }
) {
    private var traffic_cache_dirty = true
    private var cached_filtered_aircraft: List<Aircraft> = emptyList()
    private var cached_nearest_aircraft: Aircraft? = null
    private var cached_filtered_entries: List<TrafficSpatialEntry> = emptyList()
    private var cached_traffic_spatial_index = TrafficSpatialIndex(emptyList())
    private var cached_world_dot_batch = TrafficWorldDotBatch.empty()
    private var cached_aircraft_total = 0
    private var cached_hazard_present = false
    private var cached_extreme_priority_aircraft: List<Aircraft> = emptyList()
    private var cached_extreme_priority_keys: Set<String> = emptySet()
    private var cached_max_projected_speed_zoom_zero = 0.0

    val total: Int
        get() = cached_aircraft_total

    fun mark_dirty() {
        traffic_cache_dirty = true
    }

    fun is_dirty(): Boolean {
        return traffic_cache_dirty
    }

    fun cached_traffic(): CachedTraffic {
        return current_cached_traffic()
    }

    fun build_cached_traffic(all: List<Aircraft>): CachedTraffic {
        val now_epoch_sec = now_epoch_seconds()
        val filtered = ArrayList<Aircraft>(all.size)
        val entries = ArrayList<TrafficSpatialEntry>(all.size)
        var nearest: Aircraft? = null
        var nearest_distance = Double.POSITIVE_INFINITY
        all.forEach { item ->
            if (passes_aircraft_filters(item, now_epoch_sec)) {
                filtered += item
                entries += spatial_entry_for(item, now_epoch_sec)
                val distance = distance_meters(item)
                if (distance.isFinite() && distance < nearest_distance) {
                    nearest = item
                    nearest_distance = distance
                }
            }
        }
        val world_dot_batch = build_world_dot_batch(entries)
        val priority_aircraft = if (alerts_enabled()) {
            // Safety state is based on every real aircraft in the feed, not the current visual filter.
            all.filter(is_hazard_aircraft)
        } else {
            emptyList()
        }
        val priority_keys = priority_aircraft.mapTo(HashSet(priority_aircraft.size)) { aircraft_icao_key(it) }
        val max_projected_speed = max_projected_speed_zoom_zero(entries)
        return CachedTraffic(
            aircraft = filtered,
            nearest_aircraft = nearest ?: filtered.firstOrNull(),
            entries = entries,
            spatial_index = TrafficSpatialIndex(entries),
            world_dot_batch = world_dot_batch,
            total = all.size,
            hazard_present = priority_aircraft.isNotEmpty(),
            extreme_priority_aircraft = priority_aircraft,
            extreme_priority_keys = priority_keys,
            max_projected_speed_zoom_zero = max_projected_speed
        )
    }

    fun publish_cached_traffic(cache: CachedTraffic) {
        cached_filtered_aircraft = cache.aircraft
        cached_nearest_aircraft = cache.nearest_aircraft
        cached_filtered_entries = cache.entries
        cached_traffic_spatial_index = cache.spatial_index
        cached_world_dot_batch = cache.world_dot_batch
        cached_aircraft_total = cache.total
        cached_hazard_present = cache.hazard_present
        cached_extreme_priority_aircraft = cache.extreme_priority_aircraft
        cached_extreme_priority_keys = cache.extreme_priority_keys
        cached_max_projected_speed_zoom_zero = cache.max_projected_speed_zoom_zero
        traffic_cache_dirty = false
    }

    private fun current_cached_traffic(): CachedTraffic {
        return CachedTraffic(
            aircraft = cached_filtered_aircraft,
            nearest_aircraft = cached_nearest_aircraft,
            entries = cached_filtered_entries,
            spatial_index = cached_traffic_spatial_index,
            world_dot_batch = cached_world_dot_batch,
            total = cached_aircraft_total,
            hazard_present = cached_hazard_present,
            extreme_priority_aircraft = cached_extreme_priority_aircraft,
            extreme_priority_keys = cached_extreme_priority_keys,
            max_projected_speed_zoom_zero = cached_max_projected_speed_zoom_zero
        )
    }

    private fun max_projected_speed_zoom_zero(entries: List<TrafficSpatialEntry>): Double {
        var max_squared = 0.0
        for (entry in entries) {
            if (entry.projected_motion_remaining_sec <= 0.0) continue
            val dx = entry.projected_velocity_x_zoom_zero
            val dy = entry.projected_velocity_y_zoom_zero
            val speed_squared = dx * dx + dy * dy
            if (speed_squared > max_squared) max_squared = speed_squared
        }
        return if (max_squared > 0.0) sqrt(max_squared) else 0.0
    }

    private fun build_world_dot_batch(entries: List<TrafficSpatialEntry>): TrafficWorldDotBatch {
        if (entries.isEmpty()) return TrafficWorldDotBatch.empty()
        var outline_points = FloatArray(max(128, entries.size * 2))
        var outline_velocities = FloatArray(max(128, entries.size * 2))
        var outline_motion_limits = FloatArray(max(128, entries.size * 2))
        var outline_count = 0
        val fill_points = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(max(128, entries.size / 2)) }
        val fill_counts = IntArray(TrafficDotBatchOverlayState.GROUP_COUNT)
        val fill_velocities = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(max(128, entries.size / 2)) }
        val fill_motion_limits = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(max(128, entries.size / 2)) }
        for (entry in entries) {
            val x = entry.world_x_zoom_zero.toFloat()
            val y = entry.world_y_zoom_zero.toFloat()
            val motion_limit_sec = entry.projected_motion_remaining_sec.toFloat().coerceAtLeast(0f)
            outline_points = ensure_point_capacity(outline_points, outline_count + 2)
            outline_velocities = ensure_point_capacity(outline_velocities, outline_count + 2)
            outline_motion_limits = ensure_point_capacity(outline_motion_limits, outline_count + 2)
            outline_points[outline_count++] = x
            outline_points[outline_count++] = y
            outline_velocities[outline_count - 2] = entry.projected_velocity_x_zoom_zero.toFloat()
            outline_velocities[outline_count - 1] = entry.projected_velocity_y_zoom_zero.toFloat()
            outline_motion_limits[outline_count - 2] = motion_limit_sec
            outline_motion_limits[outline_count - 1] = motion_limit_sec
            val group = TrafficDotGrouper.dot_group(entry.aircraft)
            fill_points[group] = ensure_point_capacity(fill_points[group], fill_counts[group] + 2)
            fill_velocities[group] = ensure_point_capacity(fill_velocities[group], fill_counts[group] + 2)
            fill_motion_limits[group] = ensure_point_capacity(fill_motion_limits[group], fill_counts[group] + 2)
            fill_points[group][fill_counts[group]++] = x
            fill_points[group][fill_counts[group]++] = y
            fill_velocities[group][fill_counts[group] - 2] = entry.projected_velocity_x_zoom_zero.toFloat()
            fill_velocities[group][fill_counts[group] - 1] = entry.projected_velocity_y_zoom_zero.toFloat()
            fill_motion_limits[group][fill_counts[group] - 2] = motion_limit_sec
            fill_motion_limits[group][fill_counts[group] - 1] = motion_limit_sec
        }
        return TrafficWorldDotBatch(
            outline_points = outline_points,
            outline_count = outline_count,
            outline_velocities = outline_velocities,
            outline_motion_limits = outline_motion_limits,
            fill_points = fill_points,
            fill_counts = fill_counts,
            fill_velocities = fill_velocities,
            fill_motion_limits = fill_motion_limits,
            visible_count = outline_count / 2,
            built_elapsed_ms = now_elapsed_ms()
        )
    }

    }


internal data class TrafficOverlaySelection(
    val selected_aircraft_id: String?,
    val selected_aircraft_key: String?,
    val selected_aircraft_snapshot: Aircraft?,
    val path_visible: Boolean,
    val has_selected_flight_path: Boolean
)

internal data class TrafficOverlayInteraction(
    val pinch_in_progress: Boolean,
    val drag_started: Boolean,
    val last_map_interaction_ms: Long,
    val map_touch_active: Boolean = false
)

internal data class TrafficOverlayFrame(
    val viewport: Viewport,
    val cache: CachedTraffic,
    val now_epoch_sec: Double,
    val selection: TrafficOverlaySelection,
    val filters_restrict_aircraft: Boolean,
    val map_source: TileSource,
    val visual_theme_key: Int,
    val content_width: Float,
    val content_height: Float,
    val label_avoid_rects: List<RectF>,
    val interaction: TrafficOverlayInteraction
)

internal class TrafficOverlayStateBuilder(
    private val dp: (Float) -> Float,
    private val aircraft_color: (Aircraft) -> Int,
    private val aircraft_appearance_progress: (String, Aircraft) -> Float,
    private val aircraft_appearance: (String, Aircraft) -> AircraftAppearance?,
    private val display_aircraft_position: (Aircraft, Double) -> GeoPoint,
    private val spatial_entry_for: (Aircraft, Double) -> TrafficSpatialEntry,
    private val lat_lon_to_world: (Double, Double, Double) -> WorldPoint,
    private val now_elapsed_ms: () -> Long
) {
    // Projection rules stay canonical without changing the builder's original injected boundary.
    private val screen_projector = TrafficScreenProjector(
        dp = dp,
        max_estimation_seconds = MAX_ESTIMATION_SECONDS,
        world_width_zoom_zero = TILE_SIZE.toDouble(),
        lat_lon_to_world = lat_lon_to_world
    )
    private var dense_dot_outline_points = FloatArray(0)
    private var dense_dot_outline_velocities = FloatArray(0)
    private var dense_dot_outline_motion_limits = FloatArray(0)
    private var dense_dot_outline_count = 0
    private val dense_dot_fill_points = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(0) }
    private val dense_dot_fill_velocities = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(0) }
    private val dense_dot_fill_motion_limits = Array(TrafficDotBatchOverlayState.GROUP_COUNT) { FloatArray(0) }
    private val dense_dot_fill_counts = IntArray(TrafficDotBatchOverlayState.GROUP_COUNT)
    private var dense_dot_cache_aircraft: List<Aircraft>? = null
    private var dense_dot_cache_zoom = Double.NaN
    private var dense_dot_cache_center_x = 0.0
    private var dense_dot_cache_center_y = 0.0
    private var dense_dot_cache_width = 0f
    private var dense_dot_cache_height = 0f
    private var dense_dot_cache_reuse_padding_px = 0f
    private var dense_dot_cache_selected_key: String? = null
    private var dense_dot_cache_path_focus = false
    private var dense_dot_cache_selected_aircraft: TrafficAircraftOverlayState? = null
    private var dense_dot_cache_visible_count = 0
    private var dense_dot_cache_built_ms = 0L
    private var dense_symbol_cache_aircraft: List<Aircraft>? = null
    private var dense_symbol_cache_states: List<TrafficAircraftOverlayState> = emptyList()
    private var dense_symbol_cache_zoom = Double.NaN
    private var dense_symbol_cache_center_x = 0.0
    private var dense_symbol_cache_center_y = 0.0
    private var dense_symbol_cache_width = 0f
    private var dense_symbol_cache_height = 0f
    private var dense_symbol_cache_reuse_padding_px = 0f
    private var dense_symbol_cache_grid: DenseSymbolStateGrid? = null
    private var dense_symbol_cache_selected_key: String? = null
    private var dense_symbol_cache_path_focus = false
    private var dense_symbol_cache_built_ms = 0L
    var debug_collect_detail_timing = false
    var debug_last_detail_timing_summary: String = ""
        private set
    private var debug_state_dot_batch_ns = 0L
    private var debug_state_symbol_overlay_ns = 0L
    private var debug_state_symbol_shift_ns = 0L
    private var debug_state_symbol_shift_reason_ns = 0L
    private var debug_state_symbol_source_detail_ns = 0L
    private var debug_state_symbol_source_detail_frame_index = 0
    private var debug_state_symbol_source_detail_sample = false
    private var debug_state_symbol_shift_transform_ns = 0L
    private var debug_state_symbol_shift_coverage_ns = 0L
    private var debug_state_symbol_shift_visible_ns = 0L
    private var debug_state_symbol_query_ns = 0L
    private var debug_state_symbol_filter_ns = 0L
    private var debug_state_symbol_fallback_ns = 0L
    private var debug_state_symbol_grid_ns = 0L
    private var debug_state_symbol_cache_ns = 0L
    private var debug_state_symbol_query_count = 0
    private var debug_state_symbol_seen_tracking = 0
    private var debug_state_symbol_accepted_count = 0
    private var debug_state_aircraft_pick_ns = 0L
    private var debug_state_symbol_mode = "none"
    private var debug_state_symbol_build_reason = "none"

    // Build the renderer snapshot from cached traffic so pan frames only cull and interpolate.
    fun traffic_overlay_state(frame: TrafficOverlayFrame): TrafficOverlayState {
        reset_debug_detail_timing()
        val interaction_active = dense_dot_symbol_interacting(frame.interaction, now_elapsed_ms())
        val dot_start_ns = debug_detail_start_ns()
        val dot_batch = debug_trace_result(debug_collect_detail_timing, DEBUG_TRACE_DENSE_DOT_STATE) {
            dense_aircraft_dot_batch(frame)
        }
        debug_state_dot_batch_ns += debug_detail_elapsed_ns(dot_start_ns)
        val include_symbols = dot_batch == null || should_include_aircraft_symbols_with_dot_batch(frame, dot_batch)
        val adjusted_dot_batch = if (dot_batch != null && include_symbols && dot_batch.animate_motion) {
            dot_batch.copy(animate_motion = false)
        } else {
            dot_batch
        }
        val symbol_start_ns = debug_detail_start_ns()
        val dense_symbol_overlay = if (include_symbols && dot_batch != null) {
            debug_trace_result(debug_collect_detail_timing, DEBUG_TRACE_DENSE_SYMBOL_STATE) {
                dense_dot_symbol_overlay(frame)
            }
        } else {
            null
        }
        debug_state_symbol_overlay_ns += debug_detail_elapsed_ns(symbol_start_ns)
        val aircraft_start_ns = debug_detail_start_ns()
        val aircraft = if (include_symbols) {
            if (dot_batch == null) {
                visible_aircraft_overlay_states(frame)
            } else {
                dense_symbol_overlay?.states.orEmpty()
            }
        } else {
            emptyList()
        }
        debug_state_aircraft_pick_ns += debug_detail_elapsed_ns(aircraft_start_ns)
        return traffic_overlay_state_from_entries(
            frame = frame,
            aircraft = aircraft,
            dot_batch = adjusted_dot_batch,
            aircraft_transform_scale = dense_symbol_overlay?.transform_scale ?: 1f,
            aircraft_translation_x = dense_symbol_overlay?.translation_x ?: 0f,
            aircraft_translation_y = dense_symbol_overlay?.translation_y ?: 0f,
            interaction_active = interaction_active
        ).also { finish_debug_detail_timing() }
    }

    fun traffic_overlay_state_for_aircraft(
        frame: TrafficOverlayFrame,
        aircraft: List<Aircraft>
    ): TrafficOverlayState {
        val states = aircraft_overlay_states_from_aircraft(
            frame = frame,
            aircraft = aircraft,
            extreme_priority_keys = frame.cache.extreme_priority_keys
        )
        return traffic_overlay_state_from_entries(frame, states)
    }

    // Path focus narrows the map to selected and extreme-priority aircraft without losing selected fallback.
    fun visible_aircraft_snapshot(
        cache: CachedTraffic,
        selection: TrafficOverlaySelection,
        filters_restrict_aircraft: Boolean
    ): List<Aircraft> {
        val snapshot = cache.aircraft
        if (!selection.path_visible || !selection.has_selected_flight_path) {
            return with_selected_fallback(snapshot, selection, filters_restrict_aircraft)
        }
        val selected_id = selection.selected_aircraft_key ?: return snapshot
        return snapshot.filter { item ->
            screen_projector.aircraft_icao_key(item) == selected_id || cache.extreme_priority_keys.contains(screen_projector.aircraft_icao_key(item))
        }.let { with_selected_fallback(it, selection, filters_restrict_aircraft) }
    }

    private fun traffic_overlay_state_from_entries(
        frame: TrafficOverlayFrame,
        aircraft: List<TrafficAircraftOverlayState>,
        dot_batch: TrafficDotBatchOverlayState? = null,
        aircraft_transform_scale: Float = 1f,
        aircraft_translation_x: Float = 0f,
        aircraft_translation_y: Float = 0f,
        interaction_active: Boolean = false
    ): TrafficOverlayState {
        return TrafficOverlayState(
            viewport = frame.viewport,
            aircraft = aircraft,
            selected_aircraft_id = frame.selection.selected_aircraft_id,
            map_source = frame.map_source,
            content_width = frame.content_width,
            content_height = frame.content_height,
            label_avoid_rects = frame.label_avoid_rects,
            dot_batch = dot_batch,
            aircraft_transform_scale = aircraft_transform_scale,
            aircraft_translation_x = aircraft_translation_x,
            aircraft_translation_y = aircraft_translation_y,
            interaction_active = interaction_active
        )
    }

    private fun dense_aircraft_dot_batch(frame: TrafficOverlayFrame): TrafficDotBatchOverlayState? {
        val selection = frame.selection
        val selected_key = selection.selected_aircraft_key
        val path_focus = selection.path_visible && selection.has_selected_flight_path
        world_aircraft_dot_batch(frame, selected_key, path_focus)?.let { return it }
        shifted_dense_dot_batch(frame, selected_key, path_focus)?.let { return it }
        val base_padding_px = screen_projector.traffic_query_padding_px(frame.viewport)
        val initial_count = frame.cache.spatial_index.query_count(frame.viewport, base_padding_px)
        if (!should_prepare_dense_dot_batch(frame.viewport, initial_count)) {
            clear_dense_dot_cache()
            return null
        }
        val cache_reuse_padding_px = dp(DENSE_DOT_CACHE_MAX_REUSE_DP)
        val dense_padding_px = base_padding_px + cache_reuse_padding_px
        val query = frame.cache.spatial_index.query(frame.viewport, dense_padding_px)
        reset_dense_dot_batch_buffers()
        val scale = 2.0.pow(frame.viewport.zoom)
        val seen_keys = if (frame.cache.extreme_priority_aircraft.isNotEmpty() || selection.selected_aircraft_snapshot != null) {
            HashSet<String>()
        } else {
            null
        }
        var selected_aircraft: TrafficAircraftOverlayState? = null
        for (entry in query) {
            val item = entry.aircraft
            if (path_focus && !should_draw_aircraft_with_path_focus(item, selected_key, frame.cache.extreme_priority_keys)) continue
            val added_selected = add_aircraft_dense_dot(
                aircraft = item,
                entry = entry,
                scale = scale,
                extra_padding_px = cache_reuse_padding_px,
                frame = frame,
                selected_key = selected_key,
                seen_keys = seen_keys
            )
            if (added_selected != null) selected_aircraft = added_selected
        }
        if (!path_focus) {
            selected_aircraft = add_missing_priority_dense_dots(
                current_selected = selected_aircraft,
                frame = frame,
                selected_key = selected_key,
                scale = scale,
                extra_padding_px = cache_reuse_padding_px,
                seen_keys = seen_keys
            )
        }
        selected_aircraft = add_selected_dense_dot_fallback(
            current_selected = selected_aircraft,
            frame = frame,
            selected_key = selected_key,
            scale = scale,
            extra_padding_px = cache_reuse_padding_px,
            seen_keys = seen_keys
        )
        cache_dense_dot_batch(frame, selected_key, path_focus, selected_aircraft, cache_reuse_padding_px)
        return TrafficDotBatchOverlayState(
            outline_points = dense_dot_outline_points,
            outline_count = dense_dot_outline_count,
            outline_velocities = dense_dot_outline_velocities,
            outline_motion_limits = dense_dot_outline_motion_limits,
            fill_points = dense_dot_fill_points,
            fill_counts = dense_dot_fill_counts,
            fill_velocities = dense_dot_fill_velocities,
            fill_motion_limits = dense_dot_fill_motion_limits,
            selected_aircraft = selected_aircraft,
            visible_count = dense_dot_outline_count / 2,
            built_elapsed_ms = dense_dot_cache_built_ms,
            animate_motion = false
        )
    }

    private fun world_aircraft_dot_batch(
        frame: TrafficOverlayFrame,
        selected_key: String?,
        path_focus: Boolean
    ): TrafficDotBatchOverlayState? {
        if (path_focus || frame.viewport.zoom > DENSE_DOT_WORLD_BATCH_MAX_ZOOM) return null
        val batch = frame.cache.world_dot_batch
        if (batch.visible_count <= 0) return null
        val scale = 2.0.pow(frame.viewport.zoom)
        val transform_scale = scale.toFloat()
        if (transform_scale <= 0f || transform_scale.isNaN() || transform_scale.isInfinite()) return null
        val translation_x = (-frame.viewport.center_x + frame.viewport.width / 2.0).toFloat()
        val translation_y = (-frame.viewport.center_y + frame.viewport.height / 2.0).toFloat()
        return TrafficDotBatchOverlayState(
            outline_points = batch.outline_points,
            outline_count = batch.outline_count,
            outline_velocities = batch.outline_velocities,
            outline_motion_limits = batch.outline_motion_limits,
            fill_points = batch.fill_points,
            fill_counts = batch.fill_counts,
            fill_velocities = batch.fill_velocities,
            fill_motion_limits = batch.fill_motion_limits,
            selected_aircraft = selected_world_dot_overlay(frame, selected_key, scale),
            visible_count = batch.visible_count,
            transform_scale = transform_scale,
            translation_x = translation_x,
            translation_y = translation_y,
            repeat_x_spacing = TILE_SIZE.toFloat(),
            built_elapsed_ms = batch.built_elapsed_ms,
            animate_motion = false
        )
    }

    private fun selected_world_dot_overlay(
        frame: TrafficOverlayFrame,
        selected_key: String?,
        scale: Double
    ): TrafficAircraftOverlayState? {
        if (selected_key == null || frame.filters_restrict_aircraft) return null
        val selected = frame.selection.selected_aircraft_snapshot ?: return null
        if (frame.selection.selected_aircraft_id == null) return null
        if (screen_projector.aircraft_icao_key(selected) != selected_key) return null
        val display_position = display_aircraft_position(selected, frame.now_epoch_sec)
        val world = screen_projector.world_point_for(display_position.lat, display_position.lon, 0.0)
        val center_x_zoom_zero = frame.viewport.center_x / scale
        val wrapped_x = screen_projector.nearest_wrapped_world_x(world.x, center_x_zoom_zero)
        val screen_x = (wrapped_x * scale - frame.viewport.center_x + frame.viewport.width / 2.0).toFloat()
        val screen_y = (world.y * scale - frame.viewport.center_y + frame.viewport.height / 2.0).toFloat()
        if (!screen_projector.screen_neighborhood_contains(screen_x, screen_y, selected = true, viewport = frame.viewport)) return null
        return traffic_aircraft_overlay_state(selected, ScreenPoint(wrapped_x.toFloat(), world.y.toFloat()), visual_theme_key = frame.visual_theme_key)
    }

    
    private fun shifted_dense_dot_batch(
        frame: TrafficOverlayFrame,
        selected_key: String?,
        path_focus: Boolean
    ): TrafficDotBatchOverlayState? {
        if (!can_reuse_dense_dot_cache_during_interaction(frame.interaction)) return null
        val zoom_delta = frame.viewport.zoom - dense_dot_cache_zoom
        val zoom_changed = abs(zoom_delta) > DENSE_DOT_CACHE_ZOOM_EPSILON
        if (dense_dot_cache_width != frame.viewport.width || dense_dot_cache_height != frame.viewport.height) return null
        if (dense_dot_cache_selected_key != selected_key || dense_dot_cache_path_focus != path_focus) return null
        if (zoom_changed && abs(zoom_delta) > DENSE_DOT_CACHE_INTERACTION_ZOOM_STEPS) return null
        val transform_scale_double = 2.0.pow(zoom_delta)
        val transform_scale = transform_scale_double.toFloat()
        if (transform_scale <= 0f || transform_scale.isNaN() || transform_scale.isInfinite()) return null
        val translation_x = (
            dense_dot_cache_center_x * transform_scale_double -
                frame.viewport.center_x +
                frame.viewport.width / 2.0 -
                dense_dot_cache_width * transform_scale_double / 2.0
            ).toFloat()
        val translation_y = (
            dense_dot_cache_center_y * transform_scale_double -
                frame.viewport.center_y +
                frame.viewport.height / 2.0 -
                dense_dot_cache_height * transform_scale_double / 2.0
            ).toFloat()
        if (!dense_dot_cache_covers_viewport(frame.viewport, transform_scale, translation_x, translation_y)) return null
        return TrafficDotBatchOverlayState(
            outline_points = dense_dot_outline_points,
            outline_count = dense_dot_outline_count,
            outline_velocities = dense_dot_outline_velocities,
            outline_motion_limits = dense_dot_outline_motion_limits,
            fill_points = dense_dot_fill_points,
            fill_counts = dense_dot_fill_counts,
            fill_velocities = dense_dot_fill_velocities,
            fill_motion_limits = dense_dot_fill_motion_limits,
            selected_aircraft = dense_dot_cache_selected_aircraft,
            visible_count = dense_dot_cache_visible_count,
            transform_scale = transform_scale,
            translation_x = translation_x,
            translation_y = translation_y,
            built_elapsed_ms = dense_dot_cache_built_ms,
            animate_motion = false
        )
    }

    private fun can_reuse_dense_dot_cache_during_interaction(interaction: TrafficOverlayInteraction): Boolean {
        if (dense_dot_cache_aircraft == null || dense_dot_cache_visible_count <= 0) return false
        val now = now_elapsed_ms()
        if (now - dense_dot_cache_built_ms > DENSE_DOT_CACHE_INTERACTION_STALE_MS) return false
        return interaction.pinch_in_progress ||
            interaction.map_touch_active ||
            interaction.drag_started ||
            now - interaction.last_map_interaction_ms <= DENSE_DOT_CACHE_INTERACTION_SETTLE_MS
    }

    private fun dense_dot_cache_covers_viewport(
        viewport: Viewport,
        transform_scale: Float,
        translation_x: Float,
        translation_y: Float
    ): Boolean {
        val padding = dense_dot_cache_reuse_padding_px
        val min_x = -translation_x / transform_scale
        val max_x = (viewport.width - translation_x) / transform_scale
        val min_y = -translation_y / transform_scale
        val max_y = (viewport.height - translation_y) / transform_scale
        return min_x >= -padding &&
            max_x <= dense_dot_cache_width + padding &&
            min_y >= -padding &&
            max_y <= dense_dot_cache_height + padding
    }

    private fun cache_dense_dot_batch(
        frame: TrafficOverlayFrame,
        selected_key: String?,
        path_focus: Boolean,
        selected_aircraft: TrafficAircraftOverlayState?,
        reuse_padding_px: Float
    ) {
        dense_dot_cache_aircraft = frame.cache.aircraft
        dense_dot_cache_zoom = frame.viewport.zoom
        dense_dot_cache_center_x = frame.viewport.center_x
        dense_dot_cache_center_y = frame.viewport.center_y
        dense_dot_cache_width = frame.viewport.width
        dense_dot_cache_height = frame.viewport.height
        dense_dot_cache_reuse_padding_px = reuse_padding_px
        dense_dot_cache_selected_key = selected_key
        dense_dot_cache_path_focus = path_focus
        dense_dot_cache_selected_aircraft = selected_aircraft
        dense_dot_cache_visible_count = dense_dot_outline_count / 2
        dense_dot_cache_built_ms = now_elapsed_ms()
    }

    private fun clear_dense_dot_cache() {
        dense_dot_cache_aircraft = null
        dense_dot_cache_selected_aircraft = null
        dense_dot_cache_visible_count = 0
        dense_dot_cache_reuse_padding_px = 0f
        dense_dot_cache_built_ms = 0L
    }

    private fun should_prepare_dense_dot_batch(viewport: Viewport, candidate_count: Int): Boolean {
        if (viewport.zoom <= DENSE_DOT_BATCH_MAX_ZOOM) return true
        val density_per_ten_thousand_px = candidate_count / max(1f, viewport.width * viewport.height / 10000f)
        return density_per_ten_thousand_px >= DENSE_DOT_BATCH_DENSITY_FULL
    }

    private fun should_include_aircraft_symbols_with_dot_batch(
        frame: TrafficOverlayFrame,
        dot_batch: TrafficDotBatchOverlayState
    ): Boolean {
        val now = now_elapsed_ms()
        val interacting = dense_dot_symbol_interacting(frame.interaction, now)
        val symbol_progress = AircraftMarkerMorph.symbol_progress(
            AircraftMarkerMorph.marker_dot_blend(frame.viewport)
        )
        val min_symbol_progress = if (interacting) {
            AircraftMarkerMorph.SYMBOL_ACTIVE_MIN_PROGRESS
        } else {
            AircraftMarkerMorph.SYMBOL_IDLE_MIN_PROGRESS
        }
        if (symbol_progress < min_symbol_progress) return false
        return true
    }

    private fun dense_dot_symbol_overlay(frame: TrafficOverlayFrame): DenseSymbolOverlay {
        val selected_key = frame.selection.selected_aircraft_key
        val path_focus = frame.selection.path_visible && frame.selection.has_selected_flight_path
        val shift_start_ns = debug_detail_start_ns()
        val shifted = shifted_dense_symbol_overlay(frame, selected_key, path_focus)
        debug_state_symbol_shift_ns += debug_detail_elapsed_ns(shift_start_ns)
        shifted?.let {
            debug_state_symbol_mode = "shift"
            return it
        }
        debug_state_symbol_mode = "build"
        val cache_reuse_padding_px = dense_symbol_cache_reuse_padding_px(frame.viewport)
        val states = dense_dot_symbol_overlay_states(frame, cache_reuse_padding_px)
        val cache_start_ns = debug_detail_start_ns()
        cache_dense_symbol_overlay(frame, selected_key, path_focus, states, cache_reuse_padding_px)
        debug_state_symbol_cache_ns += debug_detail_elapsed_ns(cache_start_ns)
        return DenseSymbolOverlay(states)
    }

    private fun shifted_dense_symbol_overlay(
        frame: TrafficOverlayFrame,
        selected_key: String?,
        path_focus: Boolean
    ): DenseSymbolOverlay? {
        // Reuse dense symbol state only while visual keys and padded coverage still describe the current viewport.
        val source_changed = dense_symbol_cache_aircraft !== frame.cache.aircraft
        val zoom_delta = frame.viewport.zoom - dense_symbol_cache_zoom
        val zoom_changed = abs(zoom_delta) > DENSE_DOT_CACHE_ZOOM_EPSILON
        val interaction_reuse = can_reuse_dense_symbol_cache_during_interaction(frame.interaction)
        val interaction_zoom_reuse = interaction_reuse &&
            abs(zoom_delta) <= DENSE_SYMBOL_CACHE_INTERACTION_ZOOM_STEPS
        val idle_reuse = can_reuse_dense_symbol_cache_while_idle(source_changed, zoom_changed)
        if (!interaction_reuse && !idle_reuse) {
            if (debug_collect_detail_timing) {
                val reason_start_ns = debug_detail_start_ns()
                val reason = debug_dense_symbol_reuse_reason(
                    prefix = "reuse_off",
                    frame = frame,
                    source_changed = source_changed,
                    zoom_changed = zoom_changed,
                    interaction_reuse = interaction_reuse,
                    idle_reuse = idle_reuse
                )
                debug_state_symbol_shift_reason_ns += debug_detail_elapsed_ns(reason_start_ns)
                debug_dense_symbol_build_reason(reason)
            }
            return null
        }
        if (dense_symbol_cache_width != frame.viewport.width || dense_symbol_cache_height != frame.viewport.height) {
            debug_dense_symbol_build_reason("viewport_size")
            return null
        }
        if (dense_symbol_cache_selected_key != selected_key || dense_symbol_cache_path_focus != path_focus) {
            debug_dense_symbol_build_reason("selection_or_path")
            return null
        }
        if (zoom_changed && !interaction_zoom_reuse) {
            if (debug_collect_detail_timing) {
                debug_dense_symbol_build_reason(
                    "zoom_gate dz=${String.format(Locale.US, "%.2f", zoom_delta)}"
                )
            }
            return null
        }
        if (source_changed && !interaction_reuse) {
            debug_dense_symbol_build_reason("source_idle")
            return null
        }
        val transform_start_ns = debug_detail_start_ns()
        val transform_scale_double = 2.0.pow(zoom_delta)
        val transform_scale = transform_scale_double.toFloat()
        if (transform_scale <= 0f || transform_scale.isNaN() || transform_scale.isInfinite()) {
            debug_state_symbol_shift_transform_ns += debug_detail_elapsed_ns(transform_start_ns)
            debug_dense_symbol_build_reason("invalid_scale")
            return null
        }
        val translation_x = (
            dense_symbol_cache_center_x * transform_scale_double -
                frame.viewport.center_x +
                frame.viewport.width / 2.0 -
                dense_symbol_cache_width * transform_scale_double / 2.0
            ).toFloat()
        val translation_y = (
            dense_symbol_cache_center_y * transform_scale_double -
                frame.viewport.center_y +
                frame.viewport.height / 2.0 -
                dense_symbol_cache_height * transform_scale_double / 2.0
            ).toFloat()
        debug_state_symbol_shift_transform_ns += debug_detail_elapsed_ns(transform_start_ns)
        val coverage_start_ns = debug_detail_start_ns()
        val covers_viewport = dense_symbol_cache_covers_viewport(frame.viewport, transform_scale, translation_x, translation_y)
        debug_state_symbol_shift_coverage_ns += debug_detail_elapsed_ns(coverage_start_ns)
        if (!covers_viewport) {
            if (debug_collect_detail_timing) {
                debug_dense_symbol_build_reason(
                    "coverage scale=${String.format(Locale.US, "%.2f", transform_scale)} " +
                        "tx=${String.format(Locale.US, "%.2f", translation_x)} " +
                        "ty=${String.format(Locale.US, "%.2f", translation_y)}"
                )
            }
            return null
        }
        val visible_start_ns = debug_detail_start_ns()
        val states = if (interaction_reuse && abs(transform_scale - 1f) > DENSE_SYMBOL_VISIBLE_FILTER_SCALE_EPSILON) {
            visible_scaled_dense_symbol_states(
                states = dense_symbol_cache_states,
                viewport = frame.viewport,
                transform_scale = transform_scale,
                translation_x = translation_x,
                translation_y = translation_y
            )
        } else {
            dense_symbol_cache_states
        }
        debug_state_symbol_shift_visible_ns += debug_detail_elapsed_ns(visible_start_ns)
        return DenseSymbolOverlay(
            states = states,
            transform_scale = transform_scale,
            translation_x = translation_x,
            translation_y = translation_y
        )
    }

    private fun debug_dense_symbol_build_reason(reason: String) {
        if (debug_collect_detail_timing) {
            debug_state_symbol_build_reason = reason
        }
    }

    private fun debug_dense_symbol_reuse_reason(
        prefix: String,
        frame: TrafficOverlayFrame,
        source_changed: Boolean,
        zoom_changed: Boolean,
        interaction_reuse: Boolean,
        idle_reuse: Boolean
    ): String {
        val now = now_elapsed_ms()
        val cache_age_ms = now - dense_symbol_cache_built_ms
        val interaction_age_ms = now - frame.interaction.last_map_interaction_ms
        val source_detail = when {
            !source_changed -> ""
            debug_state_symbol_source_detail_sample -> {
                val source_start_ns = debug_detail_start_ns()
                ("srcSample=1 " + dense_symbol_source_change_detail(frame.cache.aircraft)).also {
                    debug_state_symbol_source_detail_ns += debug_detail_elapsed_ns(source_start_ns)
                }
            }
            else -> "srcSample=0 "
        }
        return "$prefix source=$source_changed zoom=$zoom_changed " +
            "iReuse=$interaction_reuse idle=$idle_reuse " +
            "cacheAge=$cache_age_ms intAge=$interaction_age_ms " +
            source_detail +
            "pinch=${frame.interaction.pinch_in_progress} " +
            "touch=${frame.interaction.map_touch_active} drag=${frame.interaction.drag_started}"
    }

    private fun dense_symbol_source_change_detail(current_aircraft: List<Aircraft>): String {
        val cached_aircraft = dense_symbol_cache_aircraft
        if (cached_aircraft.isNullOrEmpty()) {
            return "srcCur=${current_aircraft.size}/0 srcCached=0/0 srcSame=0 srcAdd=0 srcDrop=0 " +
                "srcBound=0 srcCurS=0 srcCachedS=0 srcCurStep=0 srcCachedStep=0 "
        }
        val current_count = current_aircraft.size
        val cached_count = cached_aircraft.size
        val current_step = dense_symbol_source_detail_step(current_count)
        val cached_step = dense_symbol_source_detail_step(cached_count)
        val cached_sample_capacity = dense_symbol_source_detail_sample_count(cached_count, cached_step)
        val cached_by_key = HashMap<String, Aircraft>(cached_sample_capacity * 2)
        var cached_sample_count = 0
        var cached_index = 0
        while (cached_index < cached_count && cached_sample_count < SYMBOL_SOURCE_DETAIL_MAX_SAMPLE) {
            val item = cached_aircraft[cached_index]
            val key = item.appearance_key()
            if (!cached_by_key.containsKey(key)) {
                cached_by_key[key] = item
            }
            cached_sample_count++
            cached_index += cached_step
        }
        val current_sample_capacity = dense_symbol_source_detail_sample_count(current_count, current_step)
        val current_keys = HashSet<String>(current_sample_capacity * 2)
        var current_sample_count = 0
        var same_count = 0
        var changed_position_count = 0
        var changed_motion_count = 0
        var changed_freshness_count = 0
        var same_reference_count = 0
        var same_index_reference_count = 0
        var max_abs_lat_delta_e6 = 0.0
        var max_abs_lon_delta_e6 = 0.0
        var current_index = 0
        while (current_index < current_count && current_sample_count < SYMBOL_SOURCE_DETAIL_MAX_SAMPLE) {
            val item = current_aircraft[current_index]
            val key = item.appearance_key()
            val cached_item = cached_by_key[key]
            if (current_keys.add(key) && cached_item != null) {
                same_count++
                if (cached_item === item) {
                    same_reference_count++
                }
                if (current_index < cached_count && cached_aircraft[current_index] === item) {
                    same_index_reference_count++
                }
                val lat_delta_e6 = abs(item.lat - cached_item.lat) * 1_000_000.0
                val lon_delta_e6 = abs(item.lon - cached_item.lon) * 1_000_000.0
                if (lat_delta_e6 > max_abs_lat_delta_e6) max_abs_lat_delta_e6 = lat_delta_e6
                if (lon_delta_e6 > max_abs_lon_delta_e6) max_abs_lon_delta_e6 = lon_delta_e6
                if (lat_delta_e6 > 1.0 || lon_delta_e6 > 1.0) {
                    changed_position_count++
                }
                if (nullable_double_changed(item.velocity_ms, cached_item.velocity_ms, 0.2) ||
                    nullable_double_changed(item.track_deg, cached_item.track_deg, 0.1) ||
                    nullable_double_changed(item.altitude_m, cached_item.altitude_m, 1.0) ||
                    item.on_ground != cached_item.on_ground
                ) {
                    changed_motion_count++
                }
                if (nullable_double_changed(item.position_time_sec, cached_item.position_time_sec, 0.1) ||
                    nullable_double_changed(item.last_contact_sec, cached_item.last_contact_sec, 0.1)
                ) {
                    changed_freshness_count++
                }
            }
            current_sample_count++
            current_index += current_step
        }
        val added_count = (current_keys.size - same_count).coerceAtLeast(0)
        val dropped_count = (cached_by_key.size - same_count).coerceAtLeast(0)
        val bounded = current_count > current_sample_count || cached_count > cached_sample_count
        return "srcCur=$current_count/${current_keys.size} " +
            "srcCached=$cached_count/${cached_by_key.size} " +
            "srcSame=$same_count srcAdd=$added_count srcDrop=$dropped_count " +
            "srcPos=$changed_position_count srcMove=$changed_motion_count srcFresh=$changed_freshness_count " +
            "srcRef=$same_reference_count srcIdxRef=$same_index_reference_count " +
            "srcMaxLatE6=${String.format(Locale.US, "%.1f", max_abs_lat_delta_e6)} " +
            "srcMaxLonE6=${String.format(Locale.US, "%.1f", max_abs_lon_delta_e6)} " +
            "srcBound=${if (bounded) 1 else 0} " +
            "srcCurS=$current_sample_count srcCachedS=$cached_sample_count " +
            "srcCurStep=$current_step srcCachedStep=$cached_step "
    }

    private fun dense_symbol_source_detail_step(count: Int): Int {
        if (count <= SYMBOL_SOURCE_DETAIL_MAX_SAMPLE) return 1
        return ceil(count.toDouble() / SYMBOL_SOURCE_DETAIL_MAX_SAMPLE.toDouble()).toInt().coerceAtLeast(1)
    }

    private fun dense_symbol_source_detail_sample_count(count: Int, step: Int): Int {
        if (count <= 0) return 0
        return ((count - 1) / step + 1).coerceAtMost(SYMBOL_SOURCE_DETAIL_MAX_SAMPLE)
    }

    private fun nullable_double_changed(current: Double?, cached: Double?, tolerance: Double): Boolean {
        if (current == null || cached == null) return current != cached
        return abs(current - cached) > tolerance
    }

    private fun visible_scaled_dense_symbol_states(
        states: List<TrafficAircraftOverlayState>,
        viewport: Viewport,
        transform_scale: Float,
        translation_x: Float,
        translation_y: Float
    ): List<TrafficAircraftOverlayState> {
        val grid = dense_symbol_cache_grid ?: return states
        val render_padding = dense_symbol_max_render_padding_px(viewport.zoom)
        val motion_padding = dense_symbol_cache_motion_query_padding_px(grid)
        val min_x = (-render_padding - translation_x) / transform_scale - motion_padding
        val max_x = (viewport.width + render_padding - translation_x) / transform_scale + motion_padding
        val min_y = (-render_padding - translation_y) / transform_scale - motion_padding
        val max_y = (viewport.height + render_padding - translation_y) / transform_scale + motion_padding
        return grid.query(min_x, min_y, max_x, max_y)
    }

    private fun dense_symbol_cache_motion_query_padding_px(grid: DenseSymbolStateGrid): Float {
        if (grid.max_axis_motion_speed_px_per_sec <= 0f || grid.max_motion_limit_sec <= 0f) return 0f
        val age_sec = ((now_elapsed_ms() - dense_symbol_cache_built_ms).coerceAtLeast(0L) / 1000f)
            .coerceAtMost(grid.max_motion_limit_sec)
        if (age_sec <= 0f) return 0f
        return grid.max_axis_motion_speed_px_per_sec * age_sec
    }

    private fun dense_symbol_max_render_padding_px(zoom: Double): Float {
        val max_icon_scale = max(AircraftMarkerMorph.aircraft_dot_scale(zoom), AircraftMarkerMorph.aircraft_icon_scale(zoom))
        return dp((DENSE_SYMBOL_MAX_SHAPE_RADIUS_DP + DENSE_SYMBOL_SELECTED_RING_DP) * DENSE_SYMBOL_MAX_TYPE_SCALE * max_icon_scale + DENSE_SYMBOL_RENDER_CULL_EXTRA_DP)
    }

    private fun build_dense_symbol_cache_grid(states: List<TrafficAircraftOverlayState>): DenseSymbolStateGrid? {
        if (states.isEmpty()) return null
        var min_x = Float.POSITIVE_INFINITY
        var min_y = Float.POSITIVE_INFINITY
        var max_x = Float.NEGATIVE_INFINITY
        var max_y = Float.NEGATIVE_INFINITY
        var max_axis_motion_speed_px_per_sec = 0f
        var max_motion_limit_sec = 0f
        for (item in states) {
            val x = item.screen_point.x
            val y = item.screen_point.y
            if (x < min_x) min_x = x
            if (y < min_y) min_y = y
            if (x > max_x) max_x = x
            if (y > max_y) max_y = y
            val axis_speed = max(abs(item.screen_velocity_x_px_per_sec), abs(item.screen_velocity_y_px_per_sec))
            if (axis_speed.isFinite() && axis_speed > max_axis_motion_speed_px_per_sec) {
                max_axis_motion_speed_px_per_sec = axis_speed
            }
            if (item.motion_limit_sec.isFinite() && item.motion_limit_sec > max_motion_limit_sec) {
                max_motion_limit_sec = item.motion_limit_sec
            }
        }
        if (!min_x.isFinite() || !min_y.isFinite() || !max_x.isFinite() || !max_y.isFinite()) return null
        val cell_size = dp(DENSE_SYMBOL_GRID_CELL_DP).coerceAtLeast(1f)
        val origin_x = floor(min_x / cell_size) * cell_size
        val origin_y = floor(min_y / cell_size) * cell_size
        val columns = (floor((max_x - origin_x) / cell_size).toInt() + 1).coerceAtLeast(1)
        val rows = (floor((max_y - origin_y) / cell_size).toInt() + 1).coerceAtLeast(1)
        val cells = Array(columns * rows) { ArrayList<TrafficAircraftOverlayState>() }
        for (item in states) {
            val column = floor((item.screen_point.x - origin_x) / cell_size).toInt().coerceIn(0, columns - 1)
            val row = floor((item.screen_point.y - origin_y) / cell_size).toInt().coerceIn(0, rows - 1)
            cells[row * columns + column].add(item)
        }
        return DenseSymbolStateGrid(
            origin_x = origin_x,
            origin_y = origin_y,
            cell_size = cell_size,
            columns = columns,
            rows = rows,
            max_axis_motion_speed_px_per_sec = max_axis_motion_speed_px_per_sec,
            max_motion_limit_sec = max_motion_limit_sec,
            cells = cells
        )
    }

    private fun cache_dense_symbol_overlay(
        frame: TrafficOverlayFrame,
        selected_key: String?,
        path_focus: Boolean,
        states: List<TrafficAircraftOverlayState>,
        reuse_padding_px: Float
    ) {
        dense_symbol_cache_aircraft = frame.cache.aircraft
        dense_symbol_cache_states = states
        dense_symbol_cache_zoom = frame.viewport.zoom
        dense_symbol_cache_center_x = frame.viewport.center_x
        dense_symbol_cache_center_y = frame.viewport.center_y
        dense_symbol_cache_width = frame.viewport.width
        dense_symbol_cache_height = frame.viewport.height
        dense_symbol_cache_reuse_padding_px = reuse_padding_px
        val grid_start_ns = debug_detail_start_ns()
        dense_symbol_cache_grid = build_dense_symbol_cache_grid(states)
        debug_state_symbol_grid_ns += debug_detail_elapsed_ns(grid_start_ns)
        dense_symbol_cache_selected_key = selected_key
        dense_symbol_cache_path_focus = path_focus
        dense_symbol_cache_built_ms = now_elapsed_ms()
    }


    private fun can_reuse_dense_symbol_cache_during_interaction(interaction: TrafficOverlayInteraction): Boolean {
        if (dense_symbol_cache_aircraft == null || dense_symbol_cache_states.isEmpty()) return false
        val now = now_elapsed_ms()
        if (now - dense_symbol_cache_built_ms > DENSE_SYMBOL_CACHE_INTERACTION_STALE_MS) return false
        return interaction.pinch_in_progress ||
            interaction.map_touch_active ||
            interaction.drag_started ||
            now - interaction.last_map_interaction_ms <= DENSE_SYMBOL_CACHE_INTERACTION_SETTLE_MS
    }

    private fun can_reuse_dense_symbol_cache_while_idle(source_changed: Boolean, zoom_changed: Boolean): Boolean {
        if (source_changed || zoom_changed) return false
        if (dense_symbol_cache_aircraft == null || dense_symbol_cache_states.isEmpty()) return false
        val now = now_elapsed_ms()
        return now - dense_symbol_cache_built_ms <= DENSE_SYMBOL_CACHE_IDLE_STALE_MS
    }

    private fun dense_symbol_cache_covers_viewport(
        viewport: Viewport,
        transform_scale: Float,
        translation_x: Float,
        translation_y: Float
    ): Boolean {
        val padding = dense_symbol_cache_reuse_padding_px
        val min_x = -translation_x / transform_scale
        val max_x = (viewport.width - translation_x) / transform_scale
        val min_y = -translation_y / transform_scale
        val max_y = (viewport.height - translation_y) / transform_scale
        return min_x >= -padding &&
            max_x <= dense_symbol_cache_width + padding &&
            min_y >= -padding &&
            max_y <= dense_symbol_cache_height + padding
    }

    private fun dense_symbol_cache_reuse_padding_px(viewport: Viewport): Float {
        val padding_dp = if (viewport.zoom < DENSE_SYMBOL_CACHE_WIDE_COVERAGE_MAX_ZOOM) {
            DENSE_SYMBOL_CACHE_WIDE_COVERAGE_REUSE_DP
        } else {
            DENSE_SYMBOL_CACHE_MAX_REUSE_DP
        }
        return dp(padding_dp)
    }

    private fun dense_dot_symbol_overlay_states(
        frame: TrafficOverlayFrame,
        extra_padding_px: Float
    ): List<TrafficAircraftOverlayState> {
        val selected_key = frame.selection.selected_aircraft_key
        val extreme_keys = frame.cache.extreme_priority_keys
        val path_focus = frame.selection.path_visible && frame.selection.has_selected_flight_path
        val scale = 2.0.pow(frame.viewport.zoom)
        val query_start_ns = debug_detail_start_ns()
        val query = frame.cache.spatial_index.query(frame.viewport, screen_projector.traffic_query_padding_px(frame.viewport) + extra_padding_px)
        debug_state_symbol_query_ns += debug_detail_elapsed_ns(query_start_ns)
        val result = ArrayList<TrafficAircraftOverlayState>(VISIBLE_AIRCRAFT_INITIAL_CAPACITY)
        val seen_keys = HashSet<String>()
        var accepted_count = 0
        val filter_start_ns = debug_detail_start_ns()
        for (entry in query) {
            val item = entry.aircraft
            if (path_focus && !should_draw_aircraft_with_path_focus(item, selected_key, extreme_keys)) continue
            val screen = screen_projector.screen_point_for(entry, frame.viewport, scale, frame.now_epoch_sec)
            val selected = selected_key != null && screen_projector.aircraft_icao_key(item) == selected_key
            if (!screen_projector.screen_neighborhood_contains(screen.x, screen.y, selected, frame.viewport, extra_padding_px)) continue
            val key = entry.appearance_key
            if (seen_keys.add(key)) {
                result += traffic_aircraft_overlay_state(item, screen, entry, scale, frame.visual_theme_key)
                accepted_count++
            }
        }
        debug_state_symbol_filter_ns += debug_detail_elapsed_ns(filter_start_ns)
        val fallback_start_ns = debug_detail_start_ns()
        if (!path_focus) {
            add_missing_priority_symbol_states(result, seen_keys, frame, selected_key, extra_padding_px)
        }
        add_selected_symbol_state_fallback(result, seen_keys, frame, selected_key, extra_padding_px)
        debug_state_symbol_fallback_ns += debug_detail_elapsed_ns(fallback_start_ns)
        if (debug_collect_detail_timing) {
            debug_state_symbol_query_count = query.size
            debug_state_symbol_seen_tracking = 1
            debug_state_symbol_accepted_count = accepted_count
        }
        return result
    }

    private fun add_missing_priority_symbol_states(
        result: MutableList<TrafficAircraftOverlayState>,
        seen_keys: MutableSet<String>,
        frame: TrafficOverlayFrame,
        selected_key: String?,
        extra_padding_px: Float
    ) {
        if (frame.cache.extreme_priority_aircraft.isEmpty()) return
        for (aircraft in frame.cache.extreme_priority_aircraft) {
            val key = aircraft.appearance_key()
            if (seen_keys.contains(key)) continue
            val state = traffic_aircraft_overlay_state_in_neighborhood(aircraft, frame, selected_key, extra_padding_px) ?: continue
            if (seen_keys.add(key)) result += state
        }
    }

    private fun add_selected_symbol_state_fallback(
        result: MutableList<TrafficAircraftOverlayState>,
        seen_keys: MutableSet<String>,
        frame: TrafficOverlayFrame,
        selected_key: String?,
        extra_padding_px: Float
    ) {
        if (frame.filters_restrict_aircraft) return
        val selected = frame.selection.selected_aircraft_snapshot ?: return
        if (frame.selection.selected_aircraft_id == null) return
        val key = selected.appearance_key()
        if (seen_keys.contains(key)) return
        val state = traffic_aircraft_overlay_state_in_neighborhood(selected, frame, selected_key, extra_padding_px) ?: return
        if (seen_keys.add(key)) result += state
    }

    private fun traffic_aircraft_overlay_state_in_neighborhood(
        aircraft: Aircraft,
        frame: TrafficOverlayFrame,
        selected_key: String?,
        extra_padding_px: Float
    ): TrafficAircraftOverlayState? {
        val scale = 2.0.pow(frame.viewport.zoom)
        val entry = spatial_entry_for(aircraft, frame.now_epoch_sec)
        val screen = screen_projector.screen_point_for(entry, frame.viewport, scale, frame.now_epoch_sec)
        val selected = selected_key != null && screen_projector.aircraft_icao_key(aircraft) == selected_key
        if (!screen_projector.screen_neighborhood_contains(screen.x, screen.y, selected, frame.viewport, extra_padding_px)) return null
        return traffic_aircraft_overlay_state(aircraft, screen, entry, scale, frame.visual_theme_key)
    }

    private data class DenseSymbolOverlay(
        val states: List<TrafficAircraftOverlayState>,
        val transform_scale: Float = 1f,
        val translation_x: Float = 0f,
        val translation_y: Float = 0f
    )

    @Suppress("ArrayInDataClass")
    private data class DenseSymbolStateGrid(
        val origin_x: Float,
        val origin_y: Float,
        val cell_size: Float,
        val columns: Int,
        val rows: Int,
        val max_axis_motion_speed_px_per_sec: Float,
        val max_motion_limit_sec: Float,
        val cells: Array<ArrayList<TrafficAircraftOverlayState>>
    ) {
        fun query(min_x: Float, min_y: Float, max_x: Float, max_y: Float): List<TrafficAircraftOverlayState> {
            if (max_x < min_x || max_y < min_y || columns <= 0 || rows <= 0) return emptyList()
            val start_column = floor((min_x - origin_x) / cell_size).toInt().coerceIn(0, columns - 1)
            val end_column = floor((max_x - origin_x) / cell_size).toInt().coerceIn(0, columns - 1)
            val start_row = floor((min_y - origin_y) / cell_size).toInt().coerceIn(0, rows - 1)
            val end_row = floor((max_y - origin_y) / cell_size).toInt().coerceIn(0, rows - 1)
            if (start_column > end_column || start_row > end_row) return emptyList()
            var count = 0
            for (row in start_row..end_row) {
                val row_offset = row * columns
                for (column in start_column..end_column) {
                    count += cells[row_offset + column].size
                }
            }
            if (count <= 0) return emptyList()
            val result = ArrayList<TrafficAircraftOverlayState>(count)
            for (row in start_row..end_row) {
                val row_offset = row * columns
                for (column in start_column..end_column) {
                    result.addAll(cells[row_offset + column])
                }
            }
            return result
        }
    }

    private fun dense_dot_symbol_interacting(interaction: TrafficOverlayInteraction, now: Long): Boolean {
        return interaction.pinch_in_progress ||
            interaction.map_touch_active ||
            interaction.drag_started ||
            now - interaction.last_map_interaction_ms <= DENSE_DOT_SYMBOL_SETTLE_MS
    }

